{
  "name": "@node/chat",
  "version": "1.0.0",
  "description": "Multi-room chat with message history, unread indicators, and text formatting",
  "modnet": {
    "contentType": "social",
    "structure": "stream",
    "mechanics": ["post", "reply"],
    "boundary": "ask",
    "scale": 2
  },
  "dependencies": {
    "plaited": "latest"
  }
}

export type Room = {
  id: string
  name: string
  createdAt: string
}

export type Message = {
  id: string
  roomId: string
  sender: string
  text: string
  timestamp: string
}

export type ReadState = Record<string, string> // roomId -> last read timestamp

export type TypingState = {
  roomId: string
  user: string
  expiresAt: number
}

export type RoomWithUnread = Room & {
  unreadCount: number
}

import type { Room } from './types'

const ROOMS_PATH = './data/rooms.json'

const generateId = (): string =>
  crypto.randomUUID()

const readRooms = async (): Promise<Room[]> => {
  const file = Bun.file(ROOMS_PATH)
  if (!(await file.exists())) return []
  return file.json()
}

const writeRooms = async (rooms: Room[]): Promise<void> => {
  await Bun.write(ROOMS_PATH, JSON.stringify(rooms, null, 2))
}

export const createRoom = async (name: string): Promise<Room> => {
  const rooms = await readRooms()
  const existing = rooms.find((r) => r.name === name)
  if (existing) return existing

  const room: Room = {
    id: generateId(),
    name,
    createdAt: new Date().toISOString(),
  }
  rooms.push(room)
  await writeRooms(rooms)
  return room
}

export const listRooms = async (): Promise<Room[]> => {
  return readRooms()
}

export const getRoom = async (roomId: string): Promise<Room | undefined> => {
  const rooms = await readRooms()
  return rooms.find((r) => r.id === roomId)
}

export const deleteRoom = async (roomId: string): Promise<boolean> => {
  const rooms = await readRooms()
  const filtered = rooms.filter((r) => r.id !== roomId)
  if (filtered.length === rooms.length) return false
  await writeRooms(filtered)
  return true
}

import type { Message, ReadState } from './types'

const messagesPath = (roomId: string): string =>
  `./data/messages/${roomId}.jsonl`

const READ_STATE_PATH = './data/read-state.json'

const generateId = (): string =>
  crypto.randomUUID()

export const sendMessage = async (
  roomId: string,
  sender: string,
  text: string
): Promise<Message> => {
  const message: Message = {
    id: generateId(),
    roomId,
    sender,
    text,
    timestamp: new Date().toISOString(),
  }
  const path = messagesPath(roomId)
  const file = Bun.file(path)
  const existing = (await file.exists()) ? await file.text() : ''
  const line = JSON.stringify(message) + '\n'
  await Bun.write(path, existing + line)
  return message
}

export const getMessages = async (
  roomId: string,
  limit = 50
): Promise<Message[]> => {
  const file = Bun.file(messagesPath(roomId))
  if (!(await file.exists())) return []

  const text = await file.text()
  const lines = text.trim().split('\n').filter(Boolean)
  const messages = lines.map((line) => JSON.parse(line) as Message)
  return messages.slice(-limit)
}

export const getMessageCount = async (roomId: string): Promise<number> => {
  const file = Bun.file(messagesPath(roomId))
  if (!(await file.exists())) return 0

  const text = await file.text()
  return text.trim().split('\n').filter(Boolean).length
}

const readReadState = async (): Promise<ReadState> => {
  const file = Bun.file(READ_STATE_PATH)
  if (!(await file.exists())) return {}
  return file.json()
}

const writeReadState = async (state: ReadState): Promise<void> => {
  await Bun.write(READ_STATE_PATH, JSON.stringify(state, null, 2))
}

export const markAsRead = async (roomId: string): Promise<void> => {
  const state = await readReadState()
  state[roomId] = new Date().toISOString()
  await writeReadState(state)
}

export const getUnreadCount = async (roomId: string): Promise<number> => {
  const state = await readReadState()
  const lastRead = state[roomId]
  const messages = await getMessages(roomId, 1000)

  if (!lastRead) return messages.length
  return messages.filter((m) => m.timestamp > lastRead).length
}

import { h } from 'plaited'
import type { FT } from 'plaited'

/**
 * Parses markdown-style bold (**text**) and italic (*text*) into
 * plaited template elements. Handles nested bold-within-italic
 * and vice versa.
 */
export const formatMessageText = (text: string): FT.TemplateObject => {
  const children = parseInlineFormatting(text)
  return h('span', { class: 'message-text' }, ...children)
}

const parseInlineFormatting = (text: string): (string | FT.TemplateObject)[] => {
  const result: (string | FT.TemplateObject)[] = []
  let remaining = text

  while (remaining.length > 0) {
    // Bold: **text**
    const boldMatch = remaining.match(/\*\*(.+?)\*\*/)
    // Italic: *text* (not preceded/followed by another *)
    const italicMatch = remaining.match(/(?<!\*)\*(?!\*)(.+?)(?<!\*)\*(?!\*)/)

    const boldIndex = boldMatch?.index ?? Infinity
    const italicIndex = italicMatch?.index ?? Infinity

    if (boldIndex === Infinity && italicIndex === Infinity) {
      if (remaining) result.push(remaining)
      break
    }

    if (boldIndex <= italicIndex && boldMatch) {
      if (boldIndex > 0) result.push(remaining.slice(0, boldIndex))
      result.push(h('strong', {}, boldMatch[1]))
      remaining = remaining.slice(boldIndex + boldMatch[0].length)
    } else if (italicMatch) {
      if (italicIndex > 0) result.push(remaining.slice(0, italicIndex))
      result.push(h('em', {}, italicMatch[1]))
      remaining = remaining.slice(italicIndex + italicMatch[0].length)
    }
  }

  return result
}

export const formatTimestamp = (iso: string): string => {
  const date = new Date(iso)
  const now = new Date()
  const isToday =
    date.getFullYear() === now.getFullYear() &&
    date.getMonth() === now.getMonth() &&
    date.getDate() === now.getDate()

  const time = date.toLocaleTimeString(undefined, {
    hour: '2-digit',
    minute: '2-digit',
  })

  if (isToday) return time
  return `${date.toLocaleDateString(undefined, { month: 'short', day: 'numeric' })} ${time}`
}

