    'div',
    {
      style: { ...styles.roomItem, ...(isActive ? styles.roomItemActive : {}) },
      'p-trigger': `room-select:${room.id}`,
    },
    h('span', { style: styles.roomName }, `# ${room.name}`),
    renderUnreadBadge(room.unreadCount)
  )

const renderMessage = (msg: Message): FT.TemplateObject =>
  h(
    'div',
    { style: styles.messageItem },
    h(
      'div',
      { style: styles.messageMeta },
      h('span', { style: styles.senderName }, msg.sender),
      h('span', { style: styles.timestamp }, formatTimestamp(msg.timestamp))
    ),
    h('div', { style: styles.messageText }, formatMessageText(msg.text))
  )

const renderTypingIndicator = (typingUsers: string[]): FT.TemplateObject | string => {
  if (typingUsers.length === 0) return ''
  const text =
    typingUsers.length === 1
      ? `${typingUsers[0]} is typing...`
      : `${typingUsers.join(', ')} are typing...`
  return h('div', { style: styles.typingIndicator, 'p-target': 'typing-indicator' }, text)
}

