    'div',
    { style: styles.container },
    // Sidebar
    h(
      'div',
      { style: styles.sidebar },
      h('div', { style: styles.sidebarHeader }, 'Chat Rooms'),
      h(
        'div',
        { style: styles.roomList, 'p-target': 'room-list' },
        ...rooms.map((room) => renderRoomItem(room, room.id === activeRoomId))
      ),
      h(
        'div',
        { style: styles.createRoomInput },
        h('input', {
          style: styles.createInput,
          type: 'text',
          placeholder: 'New room name',
          'p-target': 'new-room-input',
        }),
        h('button', { style: styles.createButton, 'p-trigger': 'create-room' }, '+')
      )
    ),
    // Chat area
    activeRoomId
      ? h(
          'div',
          { style: styles.chatArea },
          h(
            'div',
            { style: styles.chatHeader },
            `# ${rooms.find((r) => r.id === activeRoomId)?.name ?? 'Unknown'}`
          ),
          h(
            'div',
            { style: styles.messageList, 'p-target': 'message-list' },
            ...messages.map(renderMessage)
          ),
          renderTypingIndicator(typingUsers),
          renderInputArea(activeRoomId)
        )
      : h(
          'div',
          { style: styles.chatArea },
          h('div', { style: styles.emptyState }, 'Select or create a room to start chatting')
        )
  )

export const renderToHTML = (
  rooms: RoomWithUnread[],
  activeRoomId: string | null,
  messages: Message[],
  typingUsers: string[] = []
): string => {
  const template = renderChatView(rooms, activeRoomId, messages, typingUsers)
  const ssr = createSSR()
  return ssr.render(template)
}

import type { TypingState } from './types'

const TYPING_TIMEOUT_MS = 3000

let typingStates: TypingState[] = []

export const setTyping = (roomId: string, user: string): void => {
  typingStates = typingStates.filter(
    (s) => !(s.roomId === roomId && s.user === user)
  )
  typingStates.push({
    roomId,
    user,
    expiresAt: Date.now() + TYPING_TIMEOUT_MS,
  })
}

export const clearTyping = (roomId: string, user: string): void => {
  typingStates = typingStates.filter(
    (s) => !(s.roomId === roomId && s.user === user)
  )
}

export const getTypingUsers = (roomId: string, excludeUser?: string): string[] => {
  const now = Date.now()
  typingStates = typingStates.filter((s) => s.expiresAt > now)
  return typingStates
    .filter((s) => s.roomId === roomId && s.user !== excludeUser)
    .map((s) => s.user)
}

import type { RoomWithUnread } from './types'
import { createRoom, listRooms, getRoom, deleteRoom } from './rooms'
import { sendMessage, getMessages, markAsRead, getUnreadCount } from './messages'
import { setTyping, clearTyping, getTypingUsers } from './typing'
import { renderToHTML } from './render'

export type ChatAction =
  | { type: 'create-room'; name: string }
  | { type: 'list-rooms' }
  | { type: 'join-room'; roomId: string; user: string }
  | { type: 'send-message'; roomId: string; sender: string; text: string }
  | { type: 'get-messages'; roomId: string; limit?: number }
  | { type: 'set-typing'; roomId: string; user: string }
  | { type: 'clear-typing'; roomId: string; user: string }
  | { type: 'delete-room'; roomId: string }
  | { type: 'render'; activeRoomId?: string; user?: string }

const getRoomsWithUnread = async (): Promise<RoomWithUnread[]> => {
  const rooms = await listRooms()
  return Promise.all(
    rooms.map(async (room) => ({
      ...room,
      unreadCount: await getUnreadCount(room.id),
    }))
  )
}

export const handleAction = async (action: ChatAction): Promise<unknown> => {
  switch (action.type) {
    case 'create-room': {
      const room = await createRoom(action.name)
      return { ok: true, room }
    }

    case 'list-rooms': {
      const rooms = await getRoomsWithUnread()
      return { ok: true, rooms }
    }

    case 'join-room': {
      const room = await getRoom(action.roomId)
      if (!room) return { ok: false, error: 'Room not found' }
      await markAsRead(action.roomId)
      const messages = await getMessages(action.roomId)
      return { ok: true, room, messages }
    }

    case 'send-message': {
      if (!action.text.trim()) return { ok: false, error: 'Empty message' }
      const message = await sendMessage(action.roomId, action.sender, action.text)
      clearTyping(action.roomId, action.sender)
      return { ok: true, message }
    }

    case 'get-messages': {
      const messages = await getMessages(action.roomId, action.limit)
      return { ok: true, messages }
    }

    case 'set-typing': {
      setTyping(action.roomId, action.user)
      return { ok: true }
    }

    case 'clear-typing': {
      clearTyping(action.roomId, action.user)
      return { ok: true }
    }

    case 'delete-room': {
      const deleted = await deleteRoom(action.roomId)
      return { ok: deleted, error: deleted ? undefined : 'Room not found' }
    }

    case 'render': {
      const rooms = await getRoomsWithUnread()
      const activeRoomId = action.activeRoomId ?? null
      const messages = activeRoomId ? await getMessages(activeRoomId) : []
      const typingUsers = activeRoomId
        ? getTypingUsers(activeRoomId, action.user)
        : []

      if (activeRoomId) await markAsRead(activeRoomId)

      const html = renderToHTML(rooms, activeRoomId, messages, typingUsers)
      return { ok: true, html }
    }

    default:
      return { ok: false, error: 'Unknown action' }
  }
}

export { createRoom, listRooms, getRoom, deleteRoom } from './rooms'
export { sendMessage, getMessages, markAsRead, getUnreadCount } from './messages'
export { setTyping, clearTyping, getTypingUsers } from './typing'
export { renderToHTML, renderChatView } from './render'
export { formatMessageText, formatTimestamp } from './format'

