import { h } from '@plaited/template'
import type { TemplateObject } from '@plaited/template'

/**
 * Parses markdown-style bold (**text**) and italic (*text*) into
 * template objects. Handles nested bold-inside-italic and vice versa.
 */
export const formatMessageText = (raw: string): TemplateObject[] => {
  const tokens: TemplateObject[] = []
  let cursor = 0

  const pushText = (t: string) => {
    if (t) tokens.push(h('span', {}, t))
  }

  while (cursor < raw.length) {
    const boldStart = raw.indexOf('**', cursor)
    const italicStart = raw.indexOf('*', cursor)

    // bold match takes priority when ** is found first or at the same position
    if (boldStart !== -1 && (italicStart === -1 || boldStart <= italicStart)) {
      const boldEnd = raw.indexOf('**', boldStart + 2)
      if (boldEnd !== -1) {
        pushText(raw.slice(cursor, boldStart))
        const inner = raw.slice(boldStart + 2, boldEnd)
        tokens.push(h('strong', {}, inner))
        cursor = boldEnd + 2
        continue
      }
    }

    // italic match — ensure it's a single * not part of **
    if (italicStart !== -1 && raw[italicStart + 1] !== '*') {
      const italicEnd = raw.indexOf('*', italicStart + 1)
      if (italicEnd !== -1 && raw[italicEnd + 1] !== '*') {
        pushText(raw.slice(cursor, italicStart))
        const inner = raw.slice(italicStart + 1, italicEnd)
        tokens.push(h('em', {}, inner))
        cursor = italicEnd + 1
        continue
      }
    }

    // no more matches — flush remainder
    pushText(raw.slice(cursor))
    break
  }

  if (tokens.length === 0) {
    tokens.push(h('span', {}, raw))
  }

  return tokens
}

import type { Message, Room, RoomMeta } from './types'

const DATA_DIR = './data'

const roomFilePath = (roomId: string): string =>
  `${DATA_DIR}/room-${roomId}.jsonl`

const roomsIndexPath = (): string =>
  `${DATA_DIR}/rooms.json`

const metaPath = (user: string): string =>
  `${DATA_DIR}/meta-${user}.json`

/** Ensure the data directory exists */
const ensureDataDir = async (): Promise<void> => {
  const dir = Bun.file(DATA_DIR)
  try {
    await Bun.$`mkdir -p ${DATA_DIR}`
  } catch {
    // directory already exists
  }
}

// ── Rooms ──────────────────────────────────────────────

export const loadRooms = async (): Promise<Room[]> => {
  await ensureDataDir()
  const file = Bun.file(roomsIndexPath())
  if (!(await file.exists())) return []
  const text = await file.text()
  return JSON.parse(text) as Room[]
}

export const saveRooms = async (rooms: Room[]): Promise<void> => {
  await ensureDataDir()
  await Bun.write(roomsIndexPath(), JSON.stringify(rooms, null, 2))
}

export const createRoom = async (name: string): Promise<Room> => {
  const rooms = await loadRooms()
  const id = crypto.randomUUID().slice(0, 8)
  const room: Room = { id, name, createdAt: Date.now() }
  rooms.push(room)
  await saveRooms(rooms)
  return room
}

// ── Messages ───────────────────────────────────────────

export const loadMessages = async (roomId: string): Promise<Message[]> => {
  await ensureDataDir()
  const file = Bun.file(roomFilePath(roomId))
  if (!(await file.exists())) return []
  const text = await file.text()
  return text
    .split('\n')
    .filter(Boolean)
    .map((line) => JSON.parse(line) as Message)
}

export const appendMessage = async (
  roomId: string,
  sender: string,
  text: string,
): Promise<Message> => {
  await ensureDataDir()
  const msg: Message = {
    id: crypto.randomUUID().slice(0, 12),
    roomId,
    sender,
    text,
    timestamp: Date.now(),
  }
  const file = Bun.file(roomFilePath(roomId))
  const existing = (await file.exists()) ? await file.text() : ''
  await Bun.write(roomFilePath(roomId), existing + JSON.stringify(msg) + '\n')
  return msg
}

// ── Room metadata (per-user read state) ────────────────

export const loadRoomMeta = async (user: string): Promise<Map<string, RoomMeta>> => {
  await ensureDataDir()
  const file = Bun.file(metaPath(user))
  if (!(await file.exists())) return new Map()
  const text = await file.text()
  const entries = JSON.parse(text) as RoomMeta[]
  return new Map(entries.map((m) => [m.roomId, m]))
}

export const saveRoomMeta = async (
  user: string,
  meta: Map<string, RoomMeta>,
): Promise<void> => {
  await ensureDataDir()
  await Bun.write(metaPath(user), JSON.stringify([...meta.values()], null, 2))
}

export const markRoomRead = async (
  user: string,
  roomId: string,
): Promise<void> => {
  const meta = await loadRoomMeta(user)
  meta.set(roomId, { roomId, lastReadTimestamp: Date.now(), unreadCount: 0 })
  await saveRoomMeta(user, meta)
}

export const computeUnreadCount = async (
  user: string,
  roomId: string,
): Promise<number> => {
  const meta = await loadRoomMeta(user)
  const roomMeta = meta.get(roomId)
  const lastRead = roomMeta?.lastReadTimestamp ?? 0
  const messages = await loadMessages(roomId)
  return messages.filter((m) => m.timestamp > lastRead && m.sender !== user).length
}

import { h, Fragment, createSSR } from '@plaited/template'
import type { TemplateObject } from '@plaited/template'
import type { Message, Room } from './types'
import { formatMessageText } from './format'

