import type { ChatState, Room, Message, TypingState } from './types'
import {
  loadRooms,
  createRoom,
  loadMessages,
  appendMessage,
  loadRoomMeta,
  markRoomRead,
  computeUnreadCount,
} from './store'
import { renderChatView, renderToHtml } from './render'

// ── State management ───────────────────────────────────

const createInitialState = (user: string): ChatState => ({
  rooms: [],
  roomMeta: new Map(),
  activeRoomId: null,
  currentUser: user,
  typingStates: [],
})

export const initChat = async (user: string): Promise<ChatState> => {
  const state = createInitialState(user)
  state.rooms = await loadRooms()
  state.roomMeta = await loadRoomMeta(user)
  return state
}

// ── Actions ────────────────────────────────────────────

export const handleCreateRoom = async (
  state: ChatState,
  roomName: string,
): Promise<ChatState> => {
  const room = await createRoom(roomName)
  state.rooms.push(room)
  state.activeRoomId = room.id
  await markRoomRead(state.currentUser, room.id)
  return { ...state }
}

export const handleJoinRoom = async (
  state: ChatState,
  roomId: string,
): Promise<ChatState> => {
  state.activeRoomId = roomId
  await markRoomRead(state.currentUser, roomId)
  return { ...state }
}

export const handleSendMessage = async (
  state: ChatState,
  text: string,
): Promise<{ state: ChatState; message: Message }> => {
  if (!state.activeRoomId) {
    throw new Error('No active room selected')
  }
  const trimmed = text.trim()
  if (!trimmed) {
    throw new Error('Message cannot be empty')
  }
  const message = await appendMessage(state.activeRoomId, state.currentUser, trimmed)
  await markRoomRead(state.currentUser, state.activeRoomId)
  return { state: { ...state }, message }
}

export const handleSetTyping = (
  state: ChatState,
  user: string,
  roomId: string,
): ChatState => {
  const expiresAt = Date.now() + 3000
  const existing = state.typingStates.findIndex(
    (t) => t.user === user && t.roomId === roomId,
  )
  if (existing !== -1) {
    state.typingStates[existing].expiresAt = expiresAt
  } else {
    state.typingStates.push({ roomId, user, expiresAt })
  }
  return { ...state }
}

export const cleanExpiredTyping = (state: ChatState): ChatState => {
  const now = Date.now()
  state.typingStates = state.typingStates.filter((t) => t.expiresAt > now)
  return { ...state }
}

// ── Queries ────────────────────────────────────────────

export const getActiveRoom = (state: ChatState): Room | null =>
  state.rooms.find((r) => r.id === state.activeRoomId) ?? null

export const getActiveMessages = async (state: ChatState): Promise<Message[]> => {
  if (!state.activeRoomId) return []
  return loadMessages(state.activeRoomId)
}

export const getUnreadCounts = async (
  state: ChatState,
): Promise<Map<string, number>> => {
  const counts = new Map<string, number>()
  for (const room of state.rooms) {
    const count = await computeUnreadCount(state.currentUser, room.id)
    counts.set(room.id, count)
  }
  return counts
}

export const getTypingUsers = (state: ChatState): string[] => {
  const now = Date.now()
  return state.typingStates
    .filter(
      (t) =>
        t.roomId === state.activeRoomId &&
        t.user !== state.currentUser &&
        t.expiresAt > now,
    )
    .map((t) => t.user)
}

// ── Render ─────────────────────────────────────────────

export const renderChat = async (state: ChatState): Promise<string> => {
  const activeRoom = getActiveRoom(state)
  const messages = await getActiveMessages(state)
  const unreadCounts = await getUnreadCounts(state)
  const typingUsers = getTypingUsers(state)

  const template = renderChatView(
    state.rooms,
    activeRoom,
    messages,
    unreadCounts,
    typingUsers,
  )
  return renderToHtml(template)
}

