import { h } from 'plaited'
import type { TemplateObject } from 'plaited'

/**
 * Parse markdown-style bold and italic in plain text and return
 * an array of TemplateObjects / strings suitable as h() children.
 *
 * Supported syntax:
 *   **bold**
 *   *italic*
 */
const INLINE_RE = /(\*\*(.+?)\*\*|\*(.+?)\*)/g

export const formatText = (raw: string): (TemplateObject | string)[] => {
  const parts: (TemplateObject | string)[] = []
  let lastIndex = 0
  let match: RegExpExecArray | null

  while ((match = INLINE_RE.exec(raw)) !== null) {
    // text before the match
    if (match.index > lastIndex) {
      parts.push(raw.slice(lastIndex, match.index))
    }

    if (match[2] !== undefined) {
      // **bold**
      parts.push(h('strong', {}, match[2]))
    } else if (match[3] !== undefined) {
      // *italic*
      parts.push(h('em', {}, match[3]))
    }

    lastIndex = match.index + match[0].length
  }

  // trailing text
  if (lastIndex < raw.length) {
    parts.push(raw.slice(lastIndex))
  }

  return parts.length > 0 ? parts : [raw]
}

import type { Room, ReadCursors, Message, RoomWithUnread } from './types'

const ROOMS_PATH = 'data/rooms.json'
const CURSORS_PATH = 'data/read-cursors.json'

const generateId = (): string => crypto.randomUUID()

// ---- Room persistence ----

export const loadRooms = async (): Promise<Room[]> => {
  const file = Bun.file(ROOMS_PATH)
  if (!(await file.exists())) return []
  return file.json()
}

const saveRooms = async (rooms: Room[]): Promise<void> => {
  await Bun.write(ROOMS_PATH, JSON.stringify(rooms, null, 2))
}

// ---- Read-cursor persistence ----

export const loadCursors = async (): Promise<ReadCursors> => {
  const file = Bun.file(CURSORS_PATH)
  if (!(await file.exists())) return {}
  return file.json()
}

const saveCursors = async (cursors: ReadCursors): Promise<void> => {
  await Bun.write(CURSORS_PATH, JSON.stringify(cursors, null, 2))
}

// ---- Room operations ----

export const createRoom = async (name: string, createdBy: string): Promise<Room> => {
  const rooms = await loadRooms()
  const room: Room = {
    id: generateId(),
    name,
    createdBy,
    createdAt: new Date().toISOString(),
    members: [createdBy],
  }
  rooms.push(room)
  await saveRooms(rooms)
  return room
}

export const joinRoom = async (roomId: string, userId: string): Promise<Room | null> => {
  const rooms = await loadRooms()
  const room = rooms.find((r) => r.id === roomId)
  if (!room) return null
  if (!room.members.includes(userId)) {
    room.members.push(userId)
    await saveRooms(rooms)
  }
  return room
}

export const getRoom = async (roomId: string): Promise<Room | null> => {
  const rooms = await loadRooms()
  return rooms.find((r) => r.id === roomId) ?? null
}

// ---- Unread tracking ----

export const markRead = async (userId: string, roomId: string): Promise<void> => {
  const cursors = await loadCursors()
  if (!cursors[userId]) cursors[userId] = {}
  cursors[userId][roomId] = Date.now()
  await saveCursors(cursors)
}

export const getUnreadCount = async (
  userId: string,
  roomId: string,
  messages: Message[],
): Promise<number> => {
  const cursors = await loadCursors()
  const lastRead = cursors[userId]?.[roomId] ?? 0
  return messages.filter((m) => new Date(m.timestamp).getTime() > lastRead).length
}

export const listRoomsWithUnread = async (userId: string): Promise<RoomWithUnread[]> => {
  const rooms = await loadRooms()
  const cursors = await loadCursors()
  const lastReadMap = cursors[userId] ?? {}

  const results: RoomWithUnread[] = []
  for (const room of rooms) {
    const msgs = await loadMessagesForRoom(room.id)
    const lastRead = lastReadMap[room.id] ?? 0
    const unreadCount = msgs.filter((m) => new Date(m.timestamp).getTime() > lastRead).length
    results.push({ ...room, unreadCount })
  }
  return results
}

// Thin helper to avoid circular imports — messages.ts is the authority
const loadMessagesForRoom = async (roomId: string): Promise<Message[]> => {
  const path = `data/messages/${roomId}.jsonl`
  const file = Bun.file(path)
  if (!(await file.exists())) return []
  const text = await file.text()
  return text
    .trim()
    .split('\n')
    .filter(Boolean)
    .map((line) => JSON.parse(line) as Message)
}

import type { Message } from './types'

const generateId = (): string => crypto.randomUUID()

const messagesPath = (roomId: string): string => `data/messages/${roomId}.jsonl`

export const loadMessages = async (roomId: string): Promise<Message[]> => {
  const file = Bun.file(messagesPath(roomId))
  if (!(await file.exists())) return []
  const text = await file.text()
  return text
    .trim()
    .split('\n')
    .filter(Boolean)
    .map((line) => JSON.parse(line) as Message)
}

export const postMessage = async (
  roomId: string,
  sender: string,
  text: string,
): Promise<Message> => {
  const msg: Message = {
    id: generateId(),
    roomId,
    sender,
    text,
    timestamp: new Date().toISOString(),
  }
  const path = messagesPath(roomId)
  const file = Bun.file(path)
  const existing = (await file.exists()) ? await file.text() : ''
  await Bun.write(path, existing + JSON.stringify(msg) + '\n')
  return msg
}

