export type FoodCategory = 'protein' | 'carbs' | 'fat' | 'fiber'

export type MealEntry = {
  id: string
  timestamp: string
  name: string
  calories: number
  categories: FoodCategory[]
}

export type DailyGoal = {
  calories: number
}

export type DailySummary = {
  date: string
  totalCalories: number
  goalCalories: number
  meals: MealEntry[]
  categoryBreakdown: Record<FoodCategory, number>
}

export type WeeklySummary = {
  days: DailySummary[]
  weekStart: string
  weekEnd: string
  averageCalories: number
}

import type { MealEntry, DailyGoal } from './types'

const DATA_DIR = import.meta.dir + '/data'
const MEALS_PATH = `${DATA_DIR}/meals.jsonl`
const GOALS_PATH = `${DATA_DIR}/goals.json`

const ensureDataDir = async () => {
  const dir = Bun.file(DATA_DIR)
  if (!await dir.exists()) {
    await Bun.$`mkdir -p ${DATA_DIR}`
  }
}

export const loadMeals = async (): Promise<MealEntry[]> => {
  await ensureDataDir()
  const file = Bun.file(MEALS_PATH)
  if (!await file.exists()) return []
  const text = await file.text()
  return text
    .trim()
    .split('\n')
    .filter(Boolean)
    .map((line) => JSON.parse(line) as MealEntry)
}

export const saveMeal = async (meal: MealEntry): Promise<void> => {
  await ensureDataDir()
  const file = Bun.file(MEALS_PATH)
  const existing = await file.exists() ? await file.text() : ''
  await Bun.write(MEALS_PATH, existing + JSON.stringify(meal) + '\n')
}

export const deleteMeal = async (id: string): Promise<void> => {
  const meals = await loadMeals()
  const filtered = meals.filter((m) => m.id !== id)
  await Bun.write(MEALS_PATH, filtered.map((m) => JSON.stringify(m)).join('\n') + (filtered.length ? '\n' : ''))
}

export const loadGoal = async (): Promise<DailyGoal> => {
  await ensureDataDir()
  const file = Bun.file(GOALS_PATH)
  if (!await file.exists()) return { calories: 2000 }
  const text = await file.text()
  return JSON.parse(text) as DailyGoal
}

export const saveGoal = async (goal: DailyGoal): Promise<void> => {
  await ensureDataDir()
  await Bun.write(GOALS_PATH, JSON.stringify(goal, null, 2))
}

import type { MealEntry, DailyGoal, DailySummary, WeeklySummary, FoodCategory } from './types'

const toDateString = (timestamp: string): string =>
  new Date(timestamp).toISOString().slice(0, 10)

const CATEGORIES: FoodCategory[] = ['protein', 'carbs', 'fat', 'fiber']

export const buildDailySummary = (
  date: string,
  meals: MealEntry[],
  goal: DailyGoal
): DailySummary => {
  const dayMeals = meals.filter((m) => toDateString(m.timestamp) === date)
  const totalCalories = dayMeals.reduce((sum, m) => sum + m.calories, 0)

  const categoryBreakdown = CATEGORIES.reduce((acc, cat) => {
    acc[cat] = dayMeals
      .filter((m) => m.categories.includes(cat))
      .reduce((sum, m) => sum + m.calories, 0)
    return acc
  }, {} as Record<FoodCategory, number>)

  return {
    date,
    totalCalories,
    goalCalories: goal.calories,
    meals: dayMeals.sort((a, b) => a.timestamp.localeCompare(b.timestamp)),
    categoryBreakdown,
  }
}

export const buildWeeklySummary = (
  referenceDate: string,
  meals: MealEntry[],
  goal: DailyGoal
): WeeklySummary => {
  const ref = new Date(referenceDate)
  const dayOfWeek = ref.getDay()
  const weekStart = new Date(ref)
  weekStart.setDate(ref.getDate() - dayOfWeek)

  const days: DailySummary[] = []
  for (let i = 0; i < 7; i++) {
    const d = new Date(weekStart)
    d.setDate(weekStart.getDate() + i)
    const dateStr = d.toISOString().slice(0, 10)
    days.push(buildDailySummary(dateStr, meals, goal))
  }

  const totalCals = days.reduce((s, d) => s + d.totalCalories, 0)
  const daysWithData = days.filter((d) => d.totalCalories > 0).length

  return {
    days,
    weekStart: days[0].date,
    weekEnd: days[6].date,
    averageCalories: daysWithData > 0 ? Math.round(totalCals / daysWithData) : 0,
  }
}

export const getTodayString = (): string =>
  new Date().toISOString().slice(0, 10)

