const DAY_LABELS = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat']

const BAR_MAX_HEIGHT = 160

const barColor = (calories: number, goal: number): string => {
  if (calories === 0) return '#e2e8f0'
  if (calories <= goal) return '#22c55e'
  if (calories <= goal * 1.15) return '#eab308'
  return '#ef4444'
}

export const renderWeeklyChart = (weekly: WeeklySummary) => {
  const maxCal = Math.max(
    ...weekly.days.map((d) => d.totalCalories),
    weekly.days[0].goalCalories
  )
  const scale = maxCal > 0 ? BAR_MAX_HEIGHT / maxCal : 1

  const goalLineBottom = Math.round(weekly.days[0].goalCalories * scale)

  const bars = weekly.days.map((day, i) => {
    const barHeight = Math.max(Math.round(day.totalCalories * scale), 2)
    return h('div', {
      style: {
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        gap: '4px',
        flex: '1',
      },
    },
      h('span', {
        style: { fontSize: '11px', color: '#64748b', minHeight: '16px' },
      }, day.totalCalories > 0 ? String(day.totalCalories) : ''),
      h('div', {
        style: {
          width: '28px',
          height: `${barHeight}px`,
          backgroundColor: barColor(day.totalCalories, day.goalCalories),
          borderRadius: '4px 4px 0 0',
          transition: 'height 0.3s ease',
        },
      }),
      h('span', {
        style: { fontSize: '12px', fontWeight: '600', color: '#334155' },
      }, DAY_LABELS[i]),
    )
  })

  return h('div', {
    style: {
      position: 'relative',
      padding: '16px',
      backgroundColor: '#f8fafc',
      borderRadius: '12px',
      border: '1px solid #e2e8f0',
    },
  },
    h('div', {
      style: {
        display: 'flex',
        justifyContent: 'space-between',
        marginBottom: '8px',
      },
    },
      h('span', {
        style: { fontSize: '14px', fontWeight: '600', color: '#1e293b' },
      }, `Week: ${weekly.weekStart} — ${weekly.weekEnd}`),
      h('span', {
        style: { fontSize: '12px', color: '#64748b' },
      }, `Avg: ${weekly.averageCalories} kcal/day`),
    ),
    h('div', {
      style: {
        position: 'relative',
        display: 'flex',
        alignItems: 'flex-end',
        height: `${BAR_MAX_HEIGHT + 40}px`,
        gap: '8px',
        paddingTop: '20px',
      },
    },
      ...bars,
      h('div', {
        style: {
          position: 'absolute',
          bottom: `${goalLineBottom + 20}px`,
          left: '0',
          right: '0',
          height: '2px',
          backgroundColor: '#3b82f6',
          opacity: '0.5',
          borderTop: '2px dashed #3b82f6',
        },
      }),
