    h('div', {
      style: {
        display: 'flex',
        justifyContent: 'center',
        gap: '16px',
        marginTop: '8px',
        fontSize: '11px',
        color: '#64748b',
      },
    },
      h('span', {}, '🟢 Under goal'),
      h('span', {}, '🟡 Slightly over'),
      h('span', {}, '🔴 Over goal'),
