import { createSSR } from 'plaited';
import type { FoodItem, Meal, FoodCategory } from './types';
import {
  appendMeal,
  deleteMeal,
  getDailySummary,
  getWeeklyData,
  loadSettings,
  setDailyGoal,
} from './data';
import { renderDailySummary, renderWeeklyChart, renderMealForm } from './render';

// ── Helpers ─────────────────────────────────────────────────────────

const generateId = (): string => crypto.randomUUID();

const todayStr = (): string => new Date().toISOString().slice(0, 10);

const VALID_TAGS: FoodCategory[] = ['protein', 'carbs', 'fat', 'fiber'];

const validateTags = (tags: string[]): FoodCategory[] =>
  tags.filter((t): t is FoodCategory => VALID_TAGS.includes(t as FoodCategory));

// ── Public API ──────────────────────────────────────────────────────

export const logMeal = async (
  name: string,
  items: { name: string; calories: number; tags: string[] }[],
  timestamp?: string,
): Promise<Meal> => {
  const validatedItems: FoodItem[] = items.map((item) => ({
    name: item.name,
    calories: Math.max(0, Math.round(item.calories)),
    tags: validateTags(item.tags),
  }));

  const meal: Meal = {
    id: generateId(),
    name,
    items: validatedItems,
    timestamp: timestamp ?? new Date().toISOString(),
    totalCalories: validatedItems.reduce((sum, item) => sum + item.calories, 0),
  };

  await appendMeal(meal);
  return meal;
};

export const removeMeal = async (id: string): Promise<{ success: boolean }> => {
  const removed = await deleteMeal(id);
  return { success: removed };
};

export const updateDailyGoal = async (goal: number): Promise<{ dailyGoal: number }> => {
  const clamped = Math.max(500, Math.min(10000, Math.round(goal)));
  const settings = await setDailyGoal(clamped);
  return { dailyGoal: settings.dailyGoal };
};

export const getDaySummary = async (date?: string): Promise<ReturnType<typeof getDailySummary>> =>
  getDailySummary(date ?? todayStr());

export const getWeeklySummary = async (endDate?: string): Promise<ReturnType<typeof getWeeklyData>> =>
  getWeeklyData(endDate ?? todayStr());

// ── Rendering ───────────────────────────────────────────────────────

export const renderDay = async (date?: string): Promise<string> => {
  const summary = await getDailySummary(date ?? todayStr());
  const template = renderDailySummary(summary);
  const ssr = createSSR();
  return ssr(template);
};

export const renderWeek = async (endDate?: string): Promise<string> => {
  const data = await getWeeklyData(endDate ?? todayStr());
  const template = renderWeeklyChart(data);
  const ssr = createSSR();
  return ssr(template);
};

export const renderForm = async (): Promise<string> => {
  const settings = await loadSettings();
  const template = renderMealForm(settings.dailyGoal);
  const ssr = createSSR();
  return ssr(template);
};

// ── CLI entry point ─────────────────────────────────────────────────

const main = async () => {
  const command = process.argv[2];

  switch (command) {
    case 'log': {
      const name = process.argv[3] ?? 'Meal';
      const item = process.argv[4] ?? 'Food item';
      const calories = parseInt(process.argv[5] ?? '200', 10);
      const tags = (process.argv[6] ?? 'protein').split(',');
      const meal = await logMeal(name, [{ name: item, calories, tags }]);
      console.log(`Logged: ${meal.name} — ${meal.totalCalories} kcal`);
      break;
    }
    case 'summary': {
      const date = process.argv[3] ?? todayStr();
      const html = await renderDay(date);
      console.log(html);
      break;
    }
    case 'week': {
      const endDate = process.argv[3] ?? todayStr();
      const html = await renderWeek(endDate);
      console.log(html);
      break;
    }
    case 'goal': {
      const goal = parseInt(process.argv[3] ?? '2000', 10);
      const result = await updateDailyGoal(goal);
      console.log(`Daily goal set to ${result.dailyGoal} kcal`);
      break;
    }
    case 'form': {
      const html = await renderForm();
      console.log(html);
      break;
    }
    default:
      console.log('Usage: diet-tracker <log|summary|week|goal|form> [args]');
  }
};

main();

