export type Category = 'food' | 'transport' | 'housing' | 'entertainment' | 'utilities' | 'other'

export const CATEGORIES: Category[] = ['food', 'transport', 'housing', 'entertainment', 'utilities', 'other']

export const CATEGORY_COLORS: Record<Category, string> = {
  food: '#ef4444',
  transport: '#3b82f6',
  housing: '#22c55e',
  entertainment: '#a855f7',
  utilities: '#f59e0b',
  other: '#6b7280',
}

export const CATEGORY_LABELS: Record<Category, string> = {
  food: 'Food',
  transport: 'Transport',
  housing: 'Housing',
  entertainment: 'Entertainment',
  utilities: 'Utilities',
  other: 'Other',
}

export type Expense = {
  id: string
  amount: number
  category: Category
  date: string // YYYY-MM-DD
  notes: string
  createdAt: string
}

export type DateRange = {
  start: string
  end: string
}

export type FilterOptions = {
  dateRange?: DateRange
  category?: Category
}

export type MonthlySummary = {
  month: string // YYYY-MM
  total: number
  byCategory: Record<Category, number>
}

import { type Expense, type Category, type FilterOptions, type MonthlySummary, CATEGORIES } from './types'

const DATA_PATH = `${import.meta.dir}/data/expenses.jsonl`

const generateId = (): string => crypto.randomUUID()

const readExpenses = async (): Promise<Expense[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  if (!text.trim()) return []
  return text
    .trim()
    .split('\n')
    .map((line) => JSON.parse(line) as Expense)
}

const appendExpense = async (expense: Expense): Promise<void> => {
  const file = Bun.file(DATA_PATH)
  const existing = (await file.exists()) ? await file.text() : ''
  await Bun.write(DATA_PATH, existing + JSON.stringify(expense) + '\n')
}

const writeAllExpenses = async (expenses: Expense[]): Promise<void> => {
  const content = expenses.map((e) => JSON.stringify(e)).join('\n') + (expenses.length ? '\n' : '')
  await Bun.write(DATA_PATH, content)
}

export const addExpense = async (
  amount: number,
  category: Category,
  date: string,
  notes = '',
): Promise<Expense> => {
  const expense: Expense = {
    id: generateId(),
    amount: Math.round(amount * 100) / 100,
    category,
    date,
    notes,
    createdAt: new Date().toISOString(),
  }
  await appendExpense(expense)
  return expense
}

export const deleteExpense = async (id: string): Promise<boolean> => {
  const expenses = await readExpenses()
  const filtered = expenses.filter((e) => e.id !== id)
  if (filtered.length === expenses.length) return false
  await writeAllExpenses(filtered)
  return true
}

export const getExpenses = async (filters?: FilterOptions): Promise<Expense[]> => {
  let expenses = await readExpenses()

  if (filters?.category) {
    expenses = expenses.filter((e) => e.category === filters.category)
  }

  if (filters?.dateRange) {
    const { start, end } = filters.dateRange
    if (start) expenses = expenses.filter((e) => e.date >= start)
    if (end) expenses = expenses.filter((e) => e.date <= end)
  }

  return expenses.sort((a, b) => b.date.localeCompare(a.date))
}

export const getMonthlySummary = async (month: string): Promise<MonthlySummary> => {
  const expenses = await readExpenses()
  const monthExpenses = expenses.filter((e) => e.date.startsWith(month))

  const byCategory = Object.fromEntries(CATEGORIES.map((c) => [c, 0])) as Record<Category, number>
  let total = 0

  for (const expense of monthExpenses) {
    byCategory[expense.category] += expense.amount
    total += expense.amount
  }

  // Round values
  for (const cat of CATEGORIES) {
    byCategory[cat] = Math.round(byCategory[cat] * 100) / 100
  }

  return {
    month,
    total: Math.round(total * 100) / 100,
    byCategory,
  }
}

export const exportCSV = async (filters?: FilterOptions): Promise<string> => {
  const expenses = await getExpenses(filters)
  const header = 'ID,Amount,Category,Date,Notes,Created At'
  const rows = expenses.map((e) => {
    const escapedNotes = `"${e.notes.replace(/"/g, '""')}"`
    return `${e.id},${e.amount},${e.category},${e.date},${escapedNotes},${e.createdAt}`
  })
  return [header, ...rows].join('\n')
}

import { h } from 'plaited'
import { type MonthlySummary, CATEGORIES, CATEGORY_COLORS, CATEGORY_LABELS, type Category } from './types'

type SliceData = {
  category: Category
  amount: number
  percentage: number
  startAngle: number
  endAngle: number
  color: string
}

const describeArc = (cx: number, cy: number, r: number, startAngle: number, endAngle: number): string => {
  const start = polarToCartesian(cx, cy, r, endAngle)
  const end = polarToCartesian(cx, cy, r, startAngle)
  const largeArc = endAngle - startAngle > 180 ? 1 : 0
  return `M ${cx} ${cy} L ${start.x} ${start.y} A ${r} ${r} 0 ${largeArc} 0 ${end.x} ${end.y} Z`
}

const polarToCartesian = (cx: number, cy: number, r: number, angleDeg: number) => {
  const rad = ((angleDeg - 90) * Math.PI) / 180
  return {
    x: cx + r * Math.cos(rad),
    y: cy + r * Math.sin(rad),
  }
}

const computeSlices = (summary: MonthlySummary): SliceData[] => {
  if (summary.total === 0) return []

  const slices: SliceData[] = []
  let currentAngle = 0

  for (const cat of CATEGORIES) {
    const amount = summary.byCategory[cat]
    if (amount <= 0) continue
    const percentage = (amount / summary.total) * 100
    const angle = (percentage / 100) * 360
    slices.push({
      category: cat,
      amount,
      percentage: Math.round(percentage * 10) / 10,
      startAngle: currentAngle,
      endAngle: currentAngle + angle,
      color: CATEGORY_COLORS[cat],
    })
    currentAngle += angle
  }

  return slices
}

export const renderPieChart = (summary: MonthlySummary) => {
  const slices = computeSlices(summary)
  const cx = 100
  const cy = 100
  const r = 90

  if (slices.length === 0) {
    return h('div', { style: { textAlign: 'center', padding: '40px', color: '#9ca3af' } },
      h('p', {}, 'No expenses recorded this month'),
    )
  }

  // Single category — full circle
  const paths = slices.length === 1
    ? [h('circle', { cx: `${cx}`, cy: `${cy}`, r: `${r}`, fill: slices[0].color })]
    : slices.map((slice) =>
        h('path', {
          d: describeArc(cx, cy, r, slice.startAngle, slice.endAngle),
          fill: slice.color,
        }),
      )

  const legend = slices.map((slice) =>
    h('div', { style: { display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '4px' } },
      h('span', {
        style: {
          width: '12px',
          height: '12px',
          borderRadius: '2px',
          backgroundColor: slice.color,
          display: 'inline-block',
          flexShrink: '0',
        },
      }),
      h('span', { style: { fontSize: '14px', color: '#374151' } },
        `${CATEGORY_LABELS[slice.category]}: $${slice.amount.toFixed(2)} (${slice.percentage}%)`,
      ),
    ),
  )

  return h('div', { style: { display: 'flex', flexWrap: 'wrap', gap: '24px', alignItems: 'center', justifyContent: 'center' } },
    h('svg', { viewBox: '0 0 200 200', width: '200', height: '200' }, ...paths),
    h('div', {}, ...legend),
  )
}

