import { createSSR } from 'plaited'
import { type Category, type FilterOptions, CATEGORIES } from './types'
import { addExpense, deleteExpense, getExpenses, getMonthlySummary, exportCSV } from './store'
import { renderPage } from './ui'

type AppState = {
  filters: FilterOptions
  summaryMonth: string
}

const state: AppState = {
  filters: {},
  summaryMonth: new Date().toISOString().slice(0, 7),
}

const isValidCategory = (val: unknown): val is Category =>
  typeof val === 'string' && CATEGORIES.includes(val as Category)

const isValidDate = (val: unknown): val is string =>
  typeof val === 'string' && /^\d{4}-\d{2}-\d{2}$/.test(val)

const isValidMonth = (val: unknown): val is string =>
  typeof val === 'string' && /^\d{4}-\d{2}$/.test(val)

const shiftMonth = (month: string, delta: number): string => {
  const [y, m] = month.split('-').map(Number)
  const date = new Date(y, m - 1 + delta, 1)
  return date.toISOString().slice(0, 7)
}

const renderApp = async (): Promise<string> => {
  const [expenses, summary] = await Promise.all([
    getExpenses(state.filters),
    getMonthlySummary(state.summaryMonth),
  ])
  const ssr = createSSR()
  return ssr(renderPage(expenses, summary, state.filters))
}

export const handlers = {
  addExpense: async (data: { amount: string; category: string; date: string; notes?: string }) => {
    const amount = parseFloat(data.amount)
    if (isNaN(amount) || amount <= 0) return { error: 'Invalid amount' }
    if (!isValidCategory(data.category)) return { error: 'Invalid category' }
    if (!isValidDate(data.date)) return { error: 'Invalid date' }

    await addExpense(amount, data.category, data.date, data.notes ?? '')
    return { html: await renderApp() }
  },

  deleteExpense: async (id: string) => {
    await deleteExpense(id)
    return { html: await renderApp() }
  },

  applyFilters: async (data: { startDate?: string; endDate?: string; category?: string }) => {
    state.filters = {}

    if (data.startDate || data.endDate) {
      state.filters.dateRange = {
        start: data.startDate || '',
        end: data.endDate || '',
      }
    }

    if (data.category && isValidCategory(data.category)) {
      state.filters.category = data.category
    }

    return { html: await renderApp() }
  },

  clearFilters: async () => {
    state.filters = {}
    return { html: await renderApp() }
  },

  prevMonth: async () => {
    state.summaryMonth = shiftMonth(state.summaryMonth, -1)
    return { html: await renderApp() }
  },

  nextMonth: async () => {
    state.summaryMonth = shiftMonth(state.summaryMonth, 1)
    return { html: await renderApp() }
  },

  setMonth: async (month: string) => {
    if (!isValidMonth(month)) return { error: 'Invalid month format' }
    state.summaryMonth = month
    return { html: await renderApp() }
  },

  exportCSV: async () => {
    const csv = await exportCSV(state.filters)
    return {
      data: csv,
      contentType: 'text/csv',
      filename: `expenses-${new Date().toISOString().slice(0, 10)}.csv`,
    }
  },

  render: async () => {
    return { html: await renderApp() }
  },
}

export default handlers

