import type { Expense, ExpenseFilter, MonthlySummary, Category, CategorySummary } from './types'
import { CATEGORIES } from './types'

const DATA_PATH = `${import.meta.dir}/data/expenses.jsonl`

const generateId = (): string => crypto.randomUUID()

export const readExpenses = async (): Promise<Expense[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  if (!text.trim()) return []
  return text
    .trim()
    .split('\n')
    .map((line) => JSON.parse(line) as Expense)
}

export const writeExpense = async (expense: Omit<Expense, 'id' | 'createdAt'>): Promise<Expense> => {
  const record: Expense = {
    ...expense,
    id: generateId(),
    createdAt: new Date().toISOString(),
  }
  const file = Bun.file(DATA_PATH)
  const existing = (await file.exists()) ? await file.text() : ''
  const newContent = existing.endsWith('\n') || existing === ''
    ? `${existing}${JSON.stringify(record)}\n`
    : `${existing}\n${JSON.stringify(record)}\n`
  await Bun.write(DATA_PATH, newContent)
  return record
}

export const deleteExpense = async (id: string): Promise<boolean> => {
  const expenses = await readExpenses()
  const filtered = expenses.filter((e) => e.id !== id)
  if (filtered.length === expenses.length) return false
  const content = filtered.map((e) => JSON.stringify(e)).join('\n') + (filtered.length ? '\n' : '')
  await Bun.write(DATA_PATH, content)
  return true
}

export const filterExpenses = (expenses: Expense[], filter: ExpenseFilter): Expense[] => {
  return expenses.filter((e) => {
    if (filter.startDate && e.date < filter.startDate) return false
    if (filter.endDate && e.date > filter.endDate) return false
    if (filter.category && e.category !== filter.category) return false
    return true
  })
}

export const getMonthlySummary = (expenses: Expense[], month: string): MonthlySummary => {
  const monthExpenses = expenses.filter((e) => e.date.startsWith(month))
  const total = monthExpenses.reduce((sum, e) => sum + e.amount, 0)

  const categories: CategorySummary[] = CATEGORIES.map((category) => {
    const catExpenses = monthExpenses.filter((e) => e.category === category)
    const catTotal = catExpenses.reduce((sum, e) => sum + e.amount, 0)
    return {
      category,
      total: catTotal,
      percentage: total > 0 ? (catTotal / total) * 100 : 0,
      count: catExpenses.length,
    }
  }).filter((c) => c.count > 0)

  return { month, total, categories }
}

export const getAvailableMonths = (expenses: Expense[]): string[] => {
  const months = new Set(expenses.map((e) => e.date.slice(0, 7)))
  return Array.from(months).sort().reverse()
}

export const expensesToCsv = (expenses: Expense[]): string => {
  const header = 'id,amount,category,date,notes,createdAt'
  const rows = expenses.map((e) => {
    const escapedNotes = `"${e.notes.replace(/"/g, '""')}"`
    return `${e.id},${e.amount},${e.category},${e.date},${escapedNotes},${e.createdAt}`
  })
  return [header, ...rows].join('\n')
}

import { h } from 'plaited'
import type { CategorySummary } from './types'
import { CATEGORY_COLORS, CATEGORY_LABELS } from './types'

type PieSlice = {
  category: string
  percentage: number
  color: string
  startAngle: number
  endAngle: number
}

const describeArc = (cx: number, cy: number, r: number, startAngle: number, endAngle: number): string => {
  const start = polarToCartesian(cx, cy, r, endAngle)
  const end = polarToCartesian(cx, cy, r, startAngle)
  const largeArc = endAngle - startAngle > 180 ? 1 : 0
  return `M ${cx} ${cy} L ${start.x} ${start.y} A ${r} ${r} 0 ${largeArc} 0 ${end.x} ${end.y} Z`
}

const polarToCartesian = (cx: number, cy: number, r: number, angleDeg: number) => {
  const angleRad = ((angleDeg - 90) * Math.PI) / 180
  return {
    x: cx + r * Math.cos(angleRad),
    y: cy + r * Math.sin(angleRad),
  }
}

export const renderPieChart = (categories: CategorySummary[]) => {
  if (categories.length === 0) {
    return h('p', { style: { color: '#9ca3af', textAlign: 'center', padding: '2rem' } }, 'No data for this month')
  }

  const cx = 100
  const cy = 100
  const r = 90

  const slices: PieSlice[] = []
  let currentAngle = 0

  for (const cat of categories) {
    const sliceAngle = (cat.percentage / 100) * 360
    slices.push({
      category: cat.category,
      percentage: cat.percentage,
      color: CATEGORY_COLORS[cat.category],
      startAngle: currentAngle,
      endAngle: currentAngle + sliceAngle,
    })
    currentAngle += sliceAngle
  }

  // Handle single-category case (full circle)
  const paths = slices.map((slice) => {
    if (slice.percentage >= 99.99) {
      return h('circle', {
        cx: String(cx),
        cy: String(cy),
        r: String(r),
        fill: slice.color,
      })
    }
    return h('path', {
      d: describeArc(cx, cy, r, slice.startAngle, slice.endAngle),
      fill: slice.color,
    })
  })

  const legend = categories.map((cat) =>
    h('div', { style: { display: 'flex', alignItems: 'center', gap: '0.5rem', fontSize: '0.875rem' } },
      h('span', {
        style: {
          width: '12px',
          height: '12px',
          borderRadius: '2px',
          backgroundColor: CATEGORY_COLORS[cat.category],
          display: 'inline-block',
          flexShrink: '0',
        },
      }),
      h('span', { style: { color: '#e5e7eb' } },
        `${CATEGORY_LABELS[cat.category]}: $${cat.total.toFixed(2)} (${cat.percentage.toFixed(1)}%)`
      ),
    )
  )

  return h('div', { style: { display: 'flex', gap: '2rem', alignItems: 'center', flexWrap: 'wrap', justifyContent: 'center' } },
    h('svg', {
      viewBox: '0 0 200 200',
      width: '200',
      height: '200',
      style: { flexShrink: '0' },
    }, ...paths),
    h('div', { style: { display: 'flex', flexDirection: 'column', gap: '0.375rem' } }, ...legend),
  )
}

