const formatMonth = (month: string): string => {
  const [year, m] = month.split('-')
  const names = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec']
  return `${names[parseInt(m, 10) - 1]} ${year}`
}

const formatDate = (date: string): string => {
  const [year, m, d] = date.split('-')
  const names = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec']
  return `${names[parseInt(m, 10) - 1]} ${parseInt(d, 10)}, ${year}`
}

const buildExportUrl = (filter: ExpenseFilter): string => {
  const params = new URLSearchParams()
  if (filter.startDate) params.set('startDate', filter.startDate)
  if (filter.endDate) params.set('endDate', filter.endDate)
  if (filter.category) params.set('category', filter.category)
  const qs = params.toString()
  return `/export${qs ? `?${qs}` : ''}`
}

import { createSSR } from 'plaited'
import type { Category, ExpenseFilter } from './types'
import { CATEGORIES } from './types'
import {
  readExpenses,
  writeExpense,
  deleteExpense,
  filterExpenses,
  getMonthlySummary,
  getAvailableMonths,
  expensesToCsv,
} from './store'
import {
  renderPage,
  renderExpenseForm,
  renderFilterBar,
  renderMonthlySummary,
  renderExpenseTable,
} from './render'

const ssr = createSSR()

const parseFilter = (url: URL): ExpenseFilter => {
  const filter: ExpenseFilter = {}
  const startDate = url.searchParams.get('startDate')
  const endDate = url.searchParams.get('endDate')
  const category = url.searchParams.get('category')
  if (startDate) filter.startDate = startDate
  if (endDate) filter.endDate = endDate
  if (category && CATEGORIES.includes(category as Category)) {
    filter.category = category as Category
  }
  return filter
}

const parseFormData = async (request: Request): Promise<Record<string, string>> => {
  const formData = await request.formData()
  const data: Record<string, string> = {}
  formData.forEach((value, key) => {
    data[key] = value.toString()
  })
  return data
}

const handleIndex = async (url: URL): Promise<Response> => {
  const expenses = await readExpenses()
  const filter = parseFilter(url)
  const filtered = filterExpenses(expenses, filter)
  const months = getAvailableMonths(expenses)

  const selectedMonth = url.searchParams.get('month')
    ?? months[0]
    ?? new Date().toISOString().slice(0, 7)

  const summary = getMonthlySummary(expenses, selectedMonth)

  const page = renderPage([
    renderExpenseForm(),
    renderFilterBar(filter, months.length > 0 ? months : [selectedMonth]),
    renderMonthlySummary(summary),
    renderExpenseTable(filtered),
  ])

  return new Response(`<!DOCTYPE html>${ssr(page)}`, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })
}

const handleAdd = async (request: Request): Promise<Response> => {
  const data = await parseFormData(request)
  const amount = parseFloat(data.amount)
  const category = data.category as Category
  const date = data.date
  const notes = data.notes ?? ''

  if (isNaN(amount) || amount <= 0) {
    return new Response('Invalid amount', { status: 400 })
  }
  if (!CATEGORIES.includes(category)) {
    return new Response('Invalid category', { status: 400 })
  }
  if (!date || !/^\d{4}-\d{2}-\d{2}$/.test(date)) {
    return new Response('Invalid date', { status: 400 })
  }

  await writeExpense({ amount, category, date, notes })

  return new Response(null, {
    status: 303,
    headers: { Location: '/' },
  })
}

const handleDelete = async (request: Request): Promise<Response> => {
  const data = await parseFormData(request)
  const id = data.id
  if (id) {
    await deleteExpense(id)
  }
  return new Response(null, {
    status: 303,
    headers: { Location: '/' },
  })
}

const handleExport = async (url: URL): Promise<Response> => {
  const expenses = await readExpenses()
  const filter = parseFilter(url)
  const filtered = filterExpenses(expenses, filter)
  const csv = expensesToCsv(filtered)
  const filename = `expenses-${new Date().toISOString().slice(0, 10)}.csv`

  return new Response(csv, {
    headers: {
      'Content-Type': 'text/csv; charset=utf-8',
      'Content-Disposition': `attachment; filename="${filename}"`,
    },
  })
}

export default {
  port: 3000,
  async fetch(request: Request): Promise<Response> {
    const url = new URL(request.url)
    const method = request.method

    if (method === 'GET' && url.pathname === '/') {
      return handleIndex(url)
    }
    if (method === 'POST' && url.pathname === '/add') {
      return handleAdd(request)
    }
    if (method === 'POST' && url.pathname === '/delete') {
      return handleDelete(request)
    }
    if (method === 'GET' && url.pathname === '/export') {
      return handleExport(url)
    }

    return new Response('Not Found', { status: 404 })
  },
}

