import { type Expense, type ExpenseInput } from './types'

const DATA_PATH = new URL('./data/expenses.jsonl', import.meta.url).pathname

const generateId = (): string => crypto.randomUUID()

const todayISO = (): string => new Date().toISOString().slice(0, 10)

export const loadExpenses = async (): Promise<Expense[]> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return []

  const text = await file.text()
  return text
    .trim()
    .split('\n')
    .filter(Boolean)
    .map((line) => JSON.parse(line) as Expense)
}

export const saveExpense = async (input: ExpenseInput): Promise<Expense> => {
  const expense: Expense = {
    id: generateId(),
    amount: Math.round(input.amount * 100) / 100,
    category: input.category,
    date: input.date ?? todayISO(),
    notes: input.notes,
    createdAt: new Date().toISOString(),
  }

  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  const existing = exists ? await file.text() : ''
  const newContent = existing + JSON.stringify(expense) + '\n'
  await Bun.write(DATA_PATH, newContent)

  return expense
}

export const deleteExpense = async (id: string): Promise<boolean> => {
  const expenses = await loadExpenses()
  const filtered = expenses.filter((e) => e.id !== id)
  if (filtered.length === expenses.length) return false

  const content = filtered.map((e) => JSON.stringify(e)).join('\n') + (filtered.length > 0 ? '\n' : '')
  await Bun.write(DATA_PATH, content)
  return true
}

import { loadExpenses, saveExpense, deleteExpense } from './store'
import {
  type Expense,
  type ExpenseInput,
  type FilterCriteria,
  type MonthlySummary,
  type CategorySummary,
  CATEGORIES,
} from './types'

export const addExpense = async (input: ExpenseInput): Promise<Expense> => {
  if (input.amount <= 0) throw new Error('Amount must be greater than zero')
  if (!CATEGORIES.includes(input.category)) throw new Error(`Invalid category: ${input.category}`)
  return saveExpense(input)
}

export const removeExpense = async (id: string): Promise<boolean> => {
  return deleteExpense(id)
}

export const filterExpenses = (expenses: Expense[], criteria: FilterCriteria): Expense[] => {
  return expenses.filter((expense) => {
    if (criteria.category && expense.category !== criteria.category) return false
    if (criteria.dateRange?.start && expense.date < criteria.dateRange.start) return false
    if (criteria.dateRange?.end && expense.date > criteria.dateRange.end) return false
    return true
  })
}

export const getFilteredExpenses = async (criteria: FilterCriteria): Promise<Expense[]> => {
  const all = await loadExpenses()
  const filtered = filterExpenses(all, criteria)
  return filtered.sort((a, b) => b.date.localeCompare(a.date))
}

export const getMonthlySummary = async (month: string): Promise<MonthlySummary> => {
  const all = await loadExpenses()
  const monthExpenses = all.filter((e) => e.date.startsWith(month))

  const total = monthExpenses.reduce((sum, e) => sum + e.amount, 0)

  const categories: CategorySummary[] = CATEGORIES.map((cat) => {
    const catExpenses = monthExpenses.filter((e) => e.category === cat)
    const catTotal = catExpenses.reduce((sum, e) => sum + e.amount, 0)
    return {
      category: cat,
      total: Math.round(catTotal * 100) / 100,
      count: catExpenses.length,
      percentage: total > 0 ? Math.round((catTotal / total) * 1000) / 10 : 0,
    }
  }).filter((c) => c.count > 0)

  return {
    month,
    total: Math.round(total * 100) / 100,
    categories,
  }
}

export const getAvailableMonths = async (): Promise<string[]> => {
  const all = await loadExpenses()
  const months = new Set(all.map((e) => e.date.slice(0, 7)))
  return [...months].sort().reverse()
}

export const exportCSV = (expenses: Expense[]): string => {
  const header = 'id,amount,category,date,notes,createdAt'
  const rows = expenses.map((e) => {
    const notes = e.notes ? `"${e.notes.replace(/"/g, '""')}"` : ''
    return `${e.id},${e.amount},${e.category},${e.date},${notes},${e.createdAt}`
  })
  return [header, ...rows].join('\n')
}

export const exportFilteredCSV = async (criteria: FilterCriteria): Promise<string> => {
  const expenses = await getFilteredExpenses(criteria)
  return exportCSV(expenses)
}

import { h } from 'plaited'
import { type CategorySummary, CATEGORY_COLORS, CATEGORY_LABELS } from './types'

type PieSlice = {
  category: string
  percentage: number
  color: string
  startAngle: number
  endAngle: number
}

const degreesToRadians = (deg: number): number => (deg * Math.PI) / 180

const polarToCartesian = (cx: number, cy: number, r: number, angleDeg: number) => ({
  x: cx + r * Math.cos(degreesToRadians(angleDeg - 90)),
  y: cy + r * Math.sin(degreesToRadians(angleDeg - 90)),
})

const describeArc = (cx: number, cy: number, r: number, startAngle: number, endAngle: number): string => {
  const start = polarToCartesian(cx, cy, r, endAngle)
  const end = polarToCartesian(cx, cy, r, startAngle)
  const largeArcFlag = endAngle - startAngle > 180 ? 1 : 0

  return [
    `M ${cx} ${cy}`,
    `L ${start.x} ${start.y}`,
    `A ${r} ${r} 0 ${largeArcFlag} 0 ${end.x} ${end.y}`,
    'Z',
  ].join(' ')
}

const computeSlices = (categories: CategorySummary[]): PieSlice[] => {
  let currentAngle = 0
  return categories.map((cat) => {
    const sliceAngle = (cat.percentage / 100) * 360
    const slice: PieSlice = {
      category: cat.category,
      percentage: cat.percentage,
      color: CATEGORY_COLORS[cat.category],
      startAngle: currentAngle,
      endAngle: currentAngle + sliceAngle,
    }
    currentAngle += sliceAngle
    return slice
  })
}

export const renderPieChart = (categories: CategorySummary[], size = 200) => {
  const cx = size / 2
  const cy = size / 2
  const r = size / 2 - 4

  if (categories.length === 0) {
    return h('div', { style: { textAlign: 'center', padding: '2rem', color: '#999' } }, 'No expenses to chart')
  }

  // Single-category case: full circle
  if (categories.length === 1) {
    const cat = categories[0]
    return h('div', { style: { display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '1rem' } },
      h('svg', { viewBox: `0 0 ${size} ${size}`, width: String(size), height: String(size) },
        h('circle', {
          cx: String(cx),
          cy: String(cy),
          r: String(r),
          fill: CATEGORY_COLORS[cat.category],
        }),
      ),
      renderLegend(categories),
    )
  }

  const slices = computeSlices(categories)

  return h('div', { style: { display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '1rem' } },
    h('svg', { viewBox: `0 0 ${size} ${size}`, width: String(size), height: String(size) },
      ...slices.map((slice) =>
        h('path', {
          d: describeArc(cx, cy, r, slice.startAngle, slice.endAngle),
          fill: slice.color,
        }),
      ),
    ),
    renderLegend(categories),
  )
}

const renderLegend = (categories: CategorySummary[]) => {
  return h('div', { style: { display: 'flex', flexWrap: 'wrap', gap: '0.5rem 1rem', justifyContent: 'center' } },
    ...categories.map((cat) =>
      h('div', { style: { display: 'flex', alignItems: 'center', gap: '0.25rem', fontSize: '0.85rem' } },
        h('span', {
          style: {
            width: '12px',
            height: '12px',
            borderRadius: '2px',
            backgroundColor: CATEGORY_COLORS[cat.category],
            display: 'inline-block',
          },
        }),
        h('span', {}, `${CATEGORY_LABELS[cat.category]} ${cat.percentage}%`),
      ),
    ),
  )
}

