import { createSSR } from 'plaited'
import {
  addExpense,
  removeExpense,
  getFilteredExpenses,
  getMonthlySummary,
  getAvailableMonths,
  exportFilteredCSV,
} from './actions'
import {
  renderExpenseForm,
  renderFilterBar,
  renderExpenseTable,
  renderMonthlySummary,
  renderMonthSelector,
  renderExportButton,
  renderPage,
} from './views'
import { type Category, type FilterCriteria, CATEGORIES } from './types'

export type AppState = {
  filterCategory?: Category
  filterStartDate?: string
  filterEndDate?: string
  selectedMonth?: string
}

const state: AppState = {}

const buildFilterCriteria = (): FilterCriteria => {
  const criteria: FilterCriteria = {}
  if (state.filterCategory) criteria.category = state.filterCategory
  if (state.filterStartDate || state.filterEndDate) {
    criteria.dateRange = {
      start: state.filterStartDate,
      end: state.filterEndDate,
    }
  }
  return criteria
}

export const renderApp = async (): Promise<string> => {
  const months = await getAvailableMonths()
  const currentMonth = state.selectedMonth ?? months[0] ?? new Date().toISOString().slice(0, 7)
  state.selectedMonth = currentMonth

  const criteria = buildFilterCriteria()
  const expenses = await getFilteredExpenses(criteria)
  const summary = await getMonthlySummary(currentMonth)

  const ssr = createSSR()
  const html = ssr(
    renderPage({
      form: renderExpenseForm(),
      filters: renderFilterBar(state.filterCategory, state.filterStartDate, state.filterEndDate),
      monthSelector: renderMonthSelector(months, currentMonth),
      summary: renderMonthlySummary(summary),
      table: renderExpenseTable(expenses),
      exportBtn: renderExportButton(),
    }),
  )

  return html
}

export const handleAddExpense = async (data: {
  amount: string
  category: string
  date: string
  notes?: string
}) => {
  const amount = parseFloat(data.amount)
  if (isNaN(amount) || amount <= 0) throw new Error('Invalid amount')
  if (!CATEGORIES.includes(data.category as Category)) throw new Error('Invalid category')

  await addExpense({
    amount,
    category: data.category as Category,
    date: data.date,
    notes: data.notes || undefined,
  })
}

export const handleDeleteExpense = async (id: string) => {
  await removeExpense(id)
}

export const handleApplyFilter = (data: {
  category?: string
  startDate?: string
  endDate?: string
}) => {
  state.filterCategory = (data.category as Category) || undefined
  state.filterStartDate = data.startDate || undefined
  state.filterEndDate = data.endDate || undefined
}

export const handleClearFilter = () => {
  state.filterCategory = undefined
  state.filterStartDate = undefined
  state.filterEndDate = undefined
}

export const handleSelectMonth = (month: string) => {
  state.selectedMonth = month
}

export const handleExportCSV = async (): Promise<string> => {
  const criteria = buildFilterCriteria()
  return exportFilteredCSV(criteria)
}

