export type ReadingStatus = "want-to-read" | "reading" | "completed";

export type Book = {
  id: string;
  title: string;
  author: string;
  genre: string;
  pageCount: number;
  currentPage: number;
  coverUrl: string;
  status: ReadingStatus;
  addedAt: string;
  completedAt: string | null;
};

export type ReadingStats = {
  totalBooks: number;
  wantToRead: number;
  reading: number;
  completed: number;
  totalPagesRead: number;
  totalPages: number;
  averageProgress: number;
};

export type FilterOptions = {
  status?: ReadingStatus;
  genre?: string;
};

export type AddBookInput = {
  title: string;
  author: string;
  genre: string;
  pageCount: number;
  coverUrl?: string;
};

import type { Book, ReadingStats, ReadingStatus, FilterOptions, AddBookInput } from "./types";

const DATA_PATH = `${import.meta.dir}/data/books.json`;

const loadBooks = async (): Promise<Book[]> => {
  const file = Bun.file(DATA_PATH);
  if (!(await file.exists())) return [];
  const text = await file.text();
  return text.trim() ? JSON.parse(text) : [];
};

const saveBooks = async (books: Book[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(books, null, 2));
};

const generateId = (): string =>
  `book_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;

export const addBook = async (input: AddBookInput): Promise<Book> => {
  const books = await loadBooks();
  const book: Book = {
    id: generateId(),
    title: input.title,
    author: input.author,
    genre: input.genre,
    pageCount: input.pageCount,
    currentPage: 0,
    coverUrl: input.coverUrl ?? "",
    status: "want-to-read",
    addedAt: new Date().toISOString(),
    completedAt: null,
  };
  books.push(book);
  await saveBooks(books);
  return book;
};

export const updateProgress = async (
  bookId: string,
  currentPage: number
): Promise<Book | null> => {
  const books = await loadBooks();
  const book = books.find((b) => b.id === bookId);
  if (!book) return null;

  book.currentPage = Math.min(Math.max(0, currentPage), book.pageCount);

  if (book.currentPage >= book.pageCount) {
    book.status = "completed";
    book.completedAt = book.completedAt ?? new Date().toISOString();
  } else if (book.currentPage > 0 && book.status === "want-to-read") {
    book.status = "reading";
  }

  await saveBooks(books);
  return book;
};

export const updateStatus = async (
  bookId: string,
  status: ReadingStatus
): Promise<Book | null> => {
  const books = await loadBooks();
  const book = books.find((b) => b.id === bookId);
  if (!book) return null;

  book.status = status;
  if (status === "completed") {
    book.currentPage = book.pageCount;
    book.completedAt = book.completedAt ?? new Date().toISOString();
  }

  await saveBooks(books);
  return book;
};

export const removeBook = async (bookId: string): Promise<boolean> => {
  const books = await loadBooks();
  const idx = books.findIndex((b) => b.id === bookId);
  if (idx === -1) return false;
  books.splice(idx, 1);
  await saveBooks(books);
  return true;
};

export const getBooks = async (filters?: FilterOptions): Promise<Book[]> => {
  const books = await loadBooks();
  return books.filter((book) => {
    if (filters?.status && book.status !== filters.status) return false;
    if (filters?.genre && book.genre.toLowerCase() !== filters.genre.toLowerCase()) return false;
    return true;
  });
};

export const getGenres = async (): Promise<string[]> => {
  const books = await loadBooks();
  const genres = new Set(books.map((b) => b.genre));
  return [...genres].sort();
};

export const getStats = async (): Promise<ReadingStats> => {
  const books = await loadBooks();
  const totalPagesRead = books.reduce((sum, b) => sum + b.currentPage, 0);
  const totalPages = books.reduce((sum, b) => sum + b.pageCount, 0);
  const averageProgress =
    books.length > 0
      ? books.reduce((sum, b) => sum + (b.pageCount > 0 ? b.currentPage / b.pageCount : 0), 0) /
        books.length
      : 0;

  return {
    totalBooks: books.length,
    wantToRead: books.filter((b) => b.status === "want-to-read").length,
    reading: books.filter((b) => b.status === "reading").length,
    completed: books.filter((b) => b.status === "completed").length,
    totalPagesRead,
    totalPages,
    averageProgress: Math.round(averageProgress * 100),
  };
};

export const getBook = async (bookId: string): Promise<Book | null> => {
  const books = await loadBooks();
  return books.find((b) => b.id === bookId) ?? null;
};

