import { createSSR } from "plaited";
import { renderPage } from "./render";
import {
  addBook,
  getBooks,
  getGenres,
  getStats,
  updateProgress,
  updateStatus,
  removeBook,
} from "./store";
import type { ReadingStatus, FilterOptions } from "./types";

const parseAction = (trigger: string): { action: string; params: string[] } => {
  const parts = trigger.split(":");
  return { action: parts[0], params: parts.slice(1) };
};

const isValidStatus = (s: string): s is ReadingStatus =>
  ["want-to-read", "reading", "completed"].includes(s);

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url);
  const method = req.method;

  if (method === "POST" && url.pathname === "/api/books") {
    const body = await req.json();
    const book = await addBook({
      title: body.title,
      author: body.author,
      genre: body.genre,
      pageCount: Number(body.pageCount),
      coverUrl: body.coverUrl,
    });
    return Response.json(book, { status: 201 });
  }

  if (method === "PATCH" && url.pathname.startsWith("/api/books/")) {
    const parts = url.pathname.split("/");
    const bookId = parts[3];
    const action = parts[4];
    const body = await req.json();

    if (action === "progress") {
      const book = await updateProgress(bookId, Number(body.currentPage));
      if (!book) return Response.json({ error: "Book not found" }, { status: 404 });
      return Response.json(book);
    }

    if (action === "status") {
      if (!isValidStatus(body.status)) {
        return Response.json({ error: "Invalid status" }, { status: 400 });
      }
      const book = await updateStatus(bookId, body.status);
      if (!book) return Response.json({ error: "Book not found" }, { status: 404 });
      return Response.json(book);
    }

    return Response.json({ error: "Unknown action" }, { status: 400 });
  }

  if (method === "DELETE" && url.pathname.startsWith("/api/books/")) {
    const bookId = url.pathname.split("/")[3];
    const removed = await removeBook(bookId);
    if (!removed) return Response.json({ error: "Book not found" }, { status: 404 });
    return Response.json({ success: true });
  }

  if (method === "GET" && url.pathname === "/api/books") {
    const filters: FilterOptions = {};
    const status = url.searchParams.get("status");
    const genre = url.searchParams.get("genre");
    if (status && isValidStatus(status)) filters.status = status;
    if (genre) filters.genre = genre;
    const books = await getBooks(filters);
    return Response.json(books);
  }

  if (method === "GET" && url.pathname === "/api/stats") {
    const stats = await getStats();
    return Response.json(stats);
  }

  // Render HTML page
  const filters: FilterOptions = {};
  const statusParam = url.searchParams.get("status");
  const genreParam = url.searchParams.get("genre");
  if (statusParam && isValidStatus(statusParam)) filters.status = statusParam;
  if (genreParam) filters.genre = genreParam;

  const [books, stats, genres] = await Promise.all([
    getBooks(filters),
    getStats(),
    getGenres(),
  ]);

  const ssr = createSSR();
  const html = ssr(renderPage(books, stats, genres, filters));

  const page = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Reading List</title>
  <style>
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    body { background: #f3f4f6; min-height: 100vh; }
    button { cursor: pointer; }
    input:focus { outline: 2px solid #2563eb; outline-offset: -1px; }
  </style>
</head>
<body>
  ${html}
  <script>
    const API = '/api/books';

    const getInputs = () => ({
      title: document.querySelector('[p-target="input-title"]')?.value?.trim(),
      author: document.querySelector('[p-target="input-author"]')?.value?.trim(),
      genre: document.querySelector('[p-target="input-genre"]')?.value?.trim(),
      pageCount: document.querySelector('[p-target="input-pages"]')?.value?.trim(),
      coverUrl: document.querySelector('[p-target="input-cover"]')?.value?.trim(),
    });

    document.addEventListener('click', async (e) => {
      const trigger = e.target.getAttribute('p-trigger');
      if (!trigger) return;

      const [action, ...params] = trigger.split(':');

      if (action === 'add-book') {
        const inputs = getInputs();
        if (!inputs.title || !inputs.author || !inputs.genre || !inputs.pageCount) {
          alert('Please fill in title, author, genre, and page count.');
          return;
        }
        await fetch(API, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(inputs),
        });
        location.reload();
      }

      if (action === 'set-status') {
        const [bookId, status] = params;
        await fetch(API + '/' + bookId + '/status', {
          method: 'PATCH',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ status }),
        });
        location.reload();
      }

      if (action === 'update-progress') {
        const [bookId] = params;
        const page = prompt('Enter current page number:');
        if (page === null) return;
        await fetch(API + '/' + bookId + '/progress', {
          method: 'PATCH',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ currentPage: parseInt(page, 10) }),
        });
        location.reload();
      }

      if (action === 'remove') {
        const [bookId] = params;
        if (!confirm('Remove this book?')) return;
        await fetch(API + '/' + bookId, { method: 'DELETE' });
        location.reload();
      }

      if (action === 'filter-status') {
        const [status] = params;
        const url = new URL(location.href);
        if (status === 'all') url.searchParams.delete('status');
        else url.searchParams.set('status', status);
        location.href = url.toString();
      }

      if (action === 'filter-genre') {
        const [genre] = params;
        const url = new URL(location.href);
        const current = url.searchParams.get('genre');
        if (current === genre) url.searchParams.delete('genre');
        else url.searchParams.set('genre', genre);
        location.href = url.toString();
      }
    });
  </script>
</body>
</html>`;

  return new Response(page, {
    headers: { "Content-Type": "text/html; charset=utf-8" },
  });
};

export default {
  port: 3000,
  fetch: handleRequest,
};

