import type { ReadingStatus } from './types'
import {
  handleListBooks,
  handleGetBook,
  handleAddBook,
  handleUpdateProgress,
  handleUpdateStatus,
  handleRemoveBook,
} from './handlers'

const parseQuery = (url: URL) => {
  const status = url.searchParams.get('status') as ReadingStatus | null
  const genre = url.searchParams.get('genre')
  return {
    ...(status ? { status } : {}),
    ...(genre ? { genre } : {}),
  }
}

const jsonResponse = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const htmlResponse = (html: string, status = 200) =>
  new Response(html, {
    status,
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url)
    const { pathname } = url
    const method = req.method

    // GET / — render full reading list page
    if (method === 'GET' && pathname === '/') {
      const filters = parseQuery(url)
      const html = await handleListBooks(filters)
      return htmlResponse(html)
    }

    // GET /api/books — list books as JSON
    if (method === 'GET' && pathname === '/api/books') {
      const filters = parseQuery(url)
      const { getBooks } = await import('./store')
      const books = await getBooks(filters)
      return jsonResponse(books)
    }

    // GET /api/books/:id — single book
    if (method === 'GET' && pathname.startsWith('/api/books/')) {
      const id = pathname.split('/').pop()!
      const book = await handleGetBook(id)
      if (!book) return jsonResponse({ error: 'Book not found' }, 404)
      return jsonResponse(book)
    }

    // POST /api/books — add a book
    if (method === 'POST' && pathname === '/api/books') {
      const body = await req.json() as {
        title: string
        author: string
        genre: string
        pageCount: number
        coverUrl?: string
      }

      if (!body.title || !body.author || !body.genre || !body.pageCount) {
        return jsonResponse({ error: 'title, author, genre, and pageCount are required' }, 400)
      }

      const book = await handleAddBook({
        title: body.title,
        author: body.author,
        genre: body.genre,
        pageCount: Number(body.pageCount),
        coverUrl: body.coverUrl,
      })
      return jsonResponse(book, 201)
    }

    // PATCH /api/books/:id/progress — update reading progress
    if (method === 'PATCH' && pathname.match(/^\/api\/books\/[^/]+\/progress$/)) {
      const id = pathname.split('/')[3]
      const body = await req.json() as { currentPage: number }

      if (body.currentPage === undefined) {
        return jsonResponse({ error: 'currentPage is required' }, 400)
      }

      const book = await handleUpdateProgress(id, Number(body.currentPage))
      if (!book) return jsonResponse({ error: 'Book not found' }, 404)
      return jsonResponse(book)
    }

    // PATCH /api/books/:id/status — update reading status
    if (method === 'PATCH' && pathname.match(/^\/api\/books\/[^/]+\/status$/)) {
      const id = pathname.split('/')[3]
      const body = await req.json() as { status: ReadingStatus }

      const validStatuses: ReadingStatus[] = ['want-to-read', 'reading', 'completed']
      if (!body.status || !validStatuses.includes(body.status)) {
        return jsonResponse({ error: 'status must be want-to-read, reading, or completed' }, 400)
      }

      const book = await handleUpdateStatus(id, body.status)
      if (!book) return jsonResponse({ error: 'Book not found' }, 404)
      return jsonResponse(book)
    }

    // DELETE /api/books/:id — remove a book
    if (method === 'DELETE' && pathname.startsWith('/api/books/')) {
      const id = pathname.split('/').pop()!
      const removed = await handleRemoveBook(id)
      if (!removed) return jsonResponse({ error: 'Book not found' }, 404)
      return jsonResponse({ success: true })
    }

    // GET /api/stats — reading stats
    if (method === 'GET' && pathname === '/api/stats') {
      const { getStats } = await import('./store')
      const stats = await getStats()
      return jsonResponse(stats)
    }

    // GET /api/genres — list genres
    if (method === 'GET' && pathname === '/api/genres') {
      const { getGenres } = await import('./store')
      const genres = await getGenres()
      return jsonResponse(genres)
    }

    return jsonResponse({ error: 'Not found' }, 404)
  },
})

