import type { Book, BookInput, BookFilters, ReadingStats, ReadingStatus } from './types'

const DATA_PATH = './data/books.json'

const loadBooks = async (): Promise<Book[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  return text.trim() ? JSON.parse(text) : []
}

const saveBooks = async (books: Book[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(books, null, 2))
}

const generateId = (): string => crypto.randomUUID()

export const addBook = async (input: BookInput): Promise<Book> => {
  const books = await loadBooks()
  const book: Book = {
    id: generateId(),
    title: input.title,
    author: input.author,
    genre: input.genre,
    pageCount: input.pageCount,
    currentPage: 0,
    coverImageUrl: input.coverImageUrl ?? '',
    status: 'want-to-read',
    dateAdded: new Date().toISOString(),
    dateCompleted: null,
  }
  books.push(book)
  await saveBooks(books)
  return book
}

export const updateProgress = async (id: string, currentPage: number): Promise<Book | null> => {
  const books = await loadBooks()
  const book = books.find((b) => b.id === id)
  if (!book) return null
  book.currentPage = Math.max(0, Math.min(currentPage, book.pageCount))
  if (book.currentPage > 0 && book.status === 'want-to-read') {
    book.status = 'reading'
  }
  if (book.currentPage >= book.pageCount) {
    book.status = 'completed'
    book.dateCompleted = book.dateCompleted ?? new Date().toISOString()
  }
  await saveBooks(books)
  return book
}

export const updateStatus = async (id: string, status: ReadingStatus): Promise<Book | null> => {
  const books = await loadBooks()
  const book = books.find((b) => b.id === id)
  if (!book) return null
  book.status = status
  if (status === 'completed') {
    book.currentPage = book.pageCount
    book.dateCompleted = book.dateCompleted ?? new Date().toISOString()
  }
  if (status === 'want-to-read') {
    book.currentPage = 0
    book.dateCompleted = null
  }
  await saveBooks(books)
  return book
}

export const removeBook = async (id: string): Promise<boolean> => {
  const books = await loadBooks()
  const idx = books.findIndex((b) => b.id === id)
  if (idx === -1) return false
  books.splice(idx, 1)
  await saveBooks(books)
  return true
}

export const getBooks = async (filters?: BookFilters): Promise<Book[]> => {
  let books = await loadBooks()
  if (filters?.status) {
    books = books.filter((b) => b.status === filters.status)
  }
  if (filters?.genre) {
    books = books.filter((b) => b.genre.toLowerCase() === filters.genre!.toLowerCase())
  }
  return books
}

export const getBook = async (id: string): Promise<Book | null> => {
  const books = await loadBooks()
  return books.find((b) => b.id === id) ?? null
}

export const getGenres = async (): Promise<string[]> => {
  const books = await loadBooks()
  const genres = new Set(books.map((b) => b.genre))
  return [...genres].sort()
}

export const getStats = async (): Promise<ReadingStats> => {
  const books = await loadBooks()
  const totalBooks = books.length
  const booksCompleted = books.filter((b) => b.status === 'completed').length
  const booksReading = books.filter((b) => b.status === 'reading').length
  const booksWantToRead = books.filter((b) => b.status === 'want-to-read').length
  const totalPagesRead = books.reduce((sum, b) => sum + b.currentPage, 0)
  const averageProgress = totalBooks > 0
    ? books.reduce((sum, b) => sum + (b.pageCount > 0 ? b.currentPage / b.pageCount : 0), 0) / totalBooks * 100
    : 0

  return {
    totalBooks,
    booksCompleted,
    booksReading,
    booksWantToRead,
    totalPagesRead,
    averageProgress: Math.round(averageProgress),
  }
}

