import { createSSR } from 'plaited'
import type { BookFilters, BookInput, ReadingStatus } from './types'
import { addBook, updateProgress, updateStatus, removeBook, getBooks, getStats, getGenres } from './data'
import { renderPage } from './render'

export type RouteParams = {
  action?: string
  id?: string
  status?: ReadingStatus | 'all'
  genre?: string
  title?: string
  author?: string
  pageCount?: string
  coverImageUrl?: string
  currentPage?: string
}

const parseStatus = (val?: string): ReadingStatus | null => {
  if (val === 'want-to-read' || val === 'reading' || val === 'completed') return val
  return null
}

export const handleRequest = async (params: RouteParams): Promise<string> => {
  const { action } = params

  if (action === 'add' && params.title && params.author && params.genre && params.pageCount) {
    const input: BookInput = {
      title: params.title,
      author: params.author,
      genre: params.genre,
      pageCount: parseInt(params.pageCount, 10),
      coverImageUrl: params.coverImageUrl || undefined,
    }
    await addBook(input)
  }

  if (action === 'update-progress' && params.id && params.currentPage) {
    await updateProgress(params.id, parseInt(params.currentPage, 10))
  }

  if (action === 'update-status' && params.id && params.status) {
    const s = parseStatus(params.status)
    if (s) await updateStatus(params.id, s)
  }

  if (action === 'remove' && params.id) {
    await removeBook(params.id)
  }

  const activeStatus = parseStatus(params.status)
  const activeGenre = params.genre || null

  const filters: BookFilters = {}
  if (activeStatus) filters.status = activeStatus
  if (activeGenre) filters.genre = activeGenre

  const [books, stats, genres] = await Promise.all([
    getBooks(Object.keys(filters).length > 0 ? filters : undefined),
    getStats(),
    getGenres(),
  ])

  const ssr = createSSR()
  const page = renderPage(books, stats, genres, activeStatus, activeGenre)
  return ssr(page)
}

export { addBook, updateProgress, updateStatus, removeBook, getBooks, getStats, getGenres }

