# Bluesky Client

A social client for the Bluesky network built on the AT Protocol.

## Features

- **Authentication** — Log in with Bluesky handle and app password. Sessions are persisted locally.
- **Timeline Feed** — View your home timeline with author info, timestamps, and engagement counts.
- **Create Posts** — Publish new text posts (up to 300 characters with facet detection for mentions/links).
- **Like / Unlike** — Toggle likes on any post in your feed.
- **View Profiles** — See any user's profile with bio, follower/following counts, and recent posts.
- **Follow / Unfollow** — Manage your social graph by following or unfollowing users.

## Usage

```ts
import { BlueskyClient } from "./client";

const client = new BlueskyClient();
await client.login("handle.bsky.social", "app-password");

// Get timeline
const feed = await client.getTimeline();

// Create a post
await client.createPost("Hello from modnet!");

// Like a post
await client.likePost(postUri, postCid);

// View a profile
const profile = await client.getProfile("alice.bsky.social");

// Follow a user
await client.follow(profile.did);
```

## Data Storage

Session credentials are stored in `data/session.json` for automatic re-authentication.

export type SessionData = {
  handle: string;
  did: string;
  accessJwt: string;
  refreshJwt: string;
  service: string;
};

export type AuthorView = {
  did: string;
  handle: string;
  displayName?: string;
  avatar?: string;
};

export type PostRecord = {
  text: string;
  createdAt: string;
  langs?: string[];
  facets?: PostFacet[];
};

export type PostFacet = {
  index: { byteStart: number; byteEnd: number };
  features: PostFacetFeature[];
};

export type PostFacetFeature =
  | { $type: "app.bsky.richtext.facet#mention"; did: string }
  | { $type: "app.bsky.richtext.facet#link"; uri: string }
  | { $type: "app.bsky.richtext.facet#tag"; tag: string };

export type PostView = {
  uri: string;
  cid: string;
  author: AuthorView;
  record: PostRecord;
  replyCount: number;
  repostCount: number;
  likeCount: number;
  indexedAt: string;
  viewer?: {
    like?: string;
    repost?: string;
    muted?: boolean;
    blockedBy?: boolean;
  };
};

export type FeedItem = {
  post: PostView;
  reason?: {
    $type: string;
    by?: AuthorView;
    indexedAt?: string;
  };
  reply?: {
    root: PostView;
    parent: PostView;
  };
};

export type ProfileView = {
  did: string;
  handle: string;
  displayName?: string;
  description?: string;
  avatar?: string;
  banner?: string;
  followersCount: number;
  followsCount: number;
  postsCount: number;
  viewer?: {
    muted?: boolean;
    blockedBy?: boolean;
    following?: string;
    followedBy?: string;
  };
};

export type TimelineResponse = {
  feed: FeedItem[];
  cursor?: string;
};

export type ProfileResponse = {
  profile: ProfileView;
  feed: PostView[];
};

import { BskyAgent, RichText } from "@atproto/api";
import type { SessionData, TimelineResponse, FeedItem, ProfileView, PostView } from "./types";

const SESSION_PATH = "./data/session.json";
const DEFAULT_SERVICE = "https://bsky.social";

export const loadSession = async (): Promise<SessionData | null> => {
  try {
    const file = Bun.file(SESSION_PATH);
    const data = await file.json();
    if (data && data.did && data.accessJwt) {
      return data as SessionData;
    }
    return null;
  } catch {
    return null;
  }
};

export const saveSession = async (session: SessionData): Promise<void> => {
  await Bun.write(SESSION_PATH, JSON.stringify(session, null, 2));
};

export const clearSession = async (): Promise<void> => {
  await Bun.write(SESSION_PATH, "{}");
};

export class BlueskyClient {
  private agent: BskyAgent;
  private _did: string | null = null;

  constructor(service: string = DEFAULT_SERVICE) {
    this.agent = new BskyAgent({
      service,
      persistSession: (_evt, sessionData) => {
        if (sessionData) {
          saveSession({
            handle: sessionData.handle,
            did: sessionData.did,
            accessJwt: sessionData.accessJwt,
            refreshJwt: sessionData.refreshJwt,
            service,
          });
        }
      },
    });
  }

  get did(): string | null {
    return this._did;
  }

  get isAuthenticated(): boolean {
    return this._did !== null;
  }

  login = async (identifier: string, password: string): Promise<{ success: boolean; error?: string }> => {
    try {
      const response = await this.agent.login({ identifier, password });
      this._did = response.data.did;
      await saveSession({
        handle: response.data.handle,
        did: response.data.did,
        accessJwt: response.data.accessJwt,
        refreshJwt: response.data.refreshJwt,
        service: DEFAULT_SERVICE,
      });
      return { success: true };
    } catch (err) {
      const message = err instanceof Error ? err.message : "Unknown login error";
      return { success: false, error: message };
    }
  };

  resumeSession = async (): Promise<boolean> => {
    const session = await loadSession();
    if (!session) return false;
    try {
      await this.agent.resumeSession({
        did: session.did,
        handle: session.handle,
        accessJwt: session.accessJwt,
        refreshJwt: session.refreshJwt,
        active: true,
      });
      this._did = session.did;
      return true;
    } catch {
      await clearSession();
      return false;
    }
  };

  logout = async (): Promise<void> => {
    this._did = null;
    await clearSession();
  };

  getTimeline = async (cursor?: string, limit: number = 30): Promise<TimelineResponse> => {
    const response = await this.agent.getTimeline({ cursor, limit });
    const feed: FeedItem[] = response.data.feed.map((item) => ({
      post: mapPostView(item.post),
      reason: item.reason as FeedItem["reason"],
      reply: item.reply
        ? {
            root: mapPostView(item.reply.root),
            parent: mapPostView(item.reply.parent),
          }
        : undefined,
    }));
    return { feed, cursor: response.data.cursor };
  };

  createPost = async (text: string): Promise<{ uri: string; cid: string }> => {
    const rt = new RichText({ text });
    await rt.detectFacets(this.agent);
    const response = await this.agent.post({
      text: rt.text,
      facets: rt.facets,
      createdAt: new Date().toISOString(),
    });
    return { uri: response.uri, cid: response.cid };
  };

  likePost = async (uri: string, cid: string): Promise<string> => {
    const response = await this.agent.like(uri, cid);
    return response.uri;
  };

  unlikePost = async (likeUri: string): Promise<void> => {
    await this.agent.deleteLike(likeUri);
  };

  getProfile = async (actor: string): Promise<ProfileView> => {
    const response = await this.agent.getProfile({ actor });
    return {
      did: response.data.did,
      handle: response.data.handle,
      displayName: response.data.displayName,
      description: response.data.description,
      avatar: response.data.avatar,
      banner: response.data.banner,
      followersCount: response.data.followersCount ?? 0,
      followsCount: response.data.followsCount ?? 0,
      postsCount: response.data.postsCount ?? 0,
      viewer: response.data.viewer as ProfileView["viewer"],
    };
  };

  getAuthorFeed = async (
    actor: string,
    cursor?: string,
    limit: number = 30
  ): Promise<{ feed: PostView[]; cursor?: string }> => {
    const response = await this.agent.getAuthorFeed({ actor, cursor, limit });
    const feed = response.data.feed.map((item) => mapPostView(item.post));
    return { feed, cursor: response.data.cursor };
  };

  follow = async (did: string): Promise<string> => {
    const response = await this.agent.follow(did);
    return response.uri;
  };

  unfollow = async (followUri: string): Promise<void> => {
    await this.agent.deleteFollow(followUri);
  };

  searchUsers = async (term: string, limit: number = 10): Promise<ProfileView[]> => {
    const response = await this.agent.searchActors({ term, limit });
    return response.data.actors.map((actor) => ({
      did: actor.did,
      handle: actor.handle,
      displayName: actor.displayName,
      description: actor.description,
      avatar: actor.avatar,
      banner: undefined,
      followersCount: actor.viewer ? 0 : 0,
      followsCount: 0,
      postsCount: 0,
      viewer: actor.viewer as ProfileView["viewer"],
    }));
  };
}

const mapPostView = (post: Record<string, unknown>): PostView => {
  const author = post.author as Record<string, unknown>;
  const record = post.record as Record<string, unknown>;
  const viewer = post.viewer as Record<string, unknown> | undefined;
  return {
    uri: post.uri as string,
    cid: post.cid as string,
    author: {
      did: author.did as string,
      handle: author.handle as string,
      displayName: author.displayName as string | undefined,
      avatar: author.avatar as string | undefined,
    },
    record: {
      text: record.text as string,
      createdAt: record.createdAt as string,
      langs: record.langs as string[] | undefined,
      facets: record.facets as PostView["record"]["facets"],
    },
    replyCount: (post.replyCount as number) ?? 0,
    repostCount: (post.repostCount as number) ?? 0,
    likeCount: (post.likeCount as number) ?? 0,
    indexedAt: post.indexedAt as string,
    viewer: viewer
      ? {
          like: viewer.like as string | undefined,
          repost: viewer.repost as string | undefined,
          muted: viewer.muted as boolean | undefined,
          blockedBy: viewer.blockedBy as boolean | undefined,
        }
      : undefined,
  };
};

