  const sizeStyle = size === "large" ? styles.profileAvatar : styles.avatar;
  if (author.avatar) {
    return h("img", { src: author.avatar, alt: author.displayName ?? author.handle, style: sizeStyle });
  }
  const placeholderStyle = size === "large"
    ? { ...styles.avatarPlaceholder, width: "72px", height: "72px", fontSize: "24px", border: "3px solid #ffffff" }
    : styles.avatarPlaceholder;
  return h("div", { style: placeholderStyle }, getInitial(author));
};

