  return h(Fragment, null,
    repostedBy
      ? h("div", { style: styles.repostIndicator }, `Reposted by ${repostedBy.displayName || repostedBy.handle}`)
      : null,
    h("div", { style: styles.post, "data-post-uri": post.uri, "data-post-cid": post.cid },
      renderAvatar(post.author),
      h("div", { style: styles.postBody },
        h("div", { style: styles.authorRow },
          h("span", { style: styles.displayName }, post.author.displayName || post.author.handle),
          h("span", { style: styles.handle }, `@${post.author.handle}`),
          h("span", { style: styles.timestamp }, ` · ${formatTimestamp(post.record.createdAt)}`)
        ),
        h("div", { style: styles.postText }, post.record.text),
        h("div", { style: styles.actions },
          h("button", {
            style: styles.actionBtn,
            "p-trigger": "click:reply",
            "data-uri": post.uri,
          }, `💬 ${post.replyCount}`),
          h("button", {
            style: styles.actionBtn,
            "p-trigger": "click:repost",
