import { BlueskyClient } from "./client";
import {
  renderFeed,
  renderCompose,
  renderProfile,
  renderLogin,
  renderPost,
} from "./ui";
import type { PostView, FeedItem } from "./types";

export type AppView = "login" | "feed" | "compose" | "profile";

export type AppState = {
  view: AppView;
  client: BlueskyClient;
  feedItems: FeedItem[];
  feedCursor?: string;
  profileHandle?: string;
  composeText: string;
  error?: string;
};

const createState = (): AppState => ({
  view: "login",
  client: new BlueskyClient(),
  feedItems: [],
  composeText: "",
});

let state = createState();

export const initialize = async (): Promise<string> => {
  state = createState();
  const resumed = await state.client.resumeSession();
  if (resumed) {
    return await showFeed();
  }
  return renderLogin();
};

export const handleLogin = async (handle: string, password: string): Promise<string> => {
  const result = await state.client.login(handle, password);
  if (!result.success) {
    state.error = result.error;
    return renderLogin(result.error);
  }
  return await showFeed();
};

export const handleLogout = async (): Promise<string> => {
  await state.client.logout();
  state = createState();
  return renderLogin();
};

const showFeed = async (): Promise<string> => {
  state.view = "feed";
  const timeline = await state.client.getTimeline();
  state.feedItems = timeline.feed;
  state.feedCursor = timeline.cursor;

  const items = state.feedItems.map((item) => ({
    post: item.post,
    repostedBy:
      item.reason?.$type === "app.bsky.feed.defs#reasonRepost"
        ? item.reason.by
        : undefined,
  }));

  return renderFeed(items);
};

export const loadMoreFeed = async (): Promise<string> => {
  if (!state.feedCursor) return "";
  const timeline = await state.client.getTimeline(state.feedCursor);
  state.feedItems = [...state.feedItems, ...timeline.feed];
  state.feedCursor = timeline.cursor;

  const newItems = timeline.feed.map((item) => ({
    post: item.post,
    repostedBy:
      item.reason?.$type === "app.bsky.feed.defs#reasonRepost"
        ? item.reason.by
        : undefined,
  }));

  return newItems.map(({ post, repostedBy }) => renderPost(post, repostedBy)).join("");
};

export const refreshFeed = async (): Promise<string> => {
  return await showFeed();
};

export const showCompose = (): string => {
  state.view = "compose";
  state.composeText = "";
  return renderCompose(0);
};

export const submitPost = async (text: string): Promise<string> => {
  if (!text || text.length > 300) {
    return renderCompose(text?.length ?? 0);
  }
  await state.client.createPost(text);
  return await showFeed();
};

export const toggleLike = async (
  postUri: string,
  postCid: string,
  existingLikeUri?: string
): Promise<{ liked: boolean; likeUri?: string }> => {
  if (existingLikeUri) {
    await state.client.unlikePost(existingLikeUri);
    updateFeedItemViewer(postUri, { like: undefined }, -1);
    return { liked: false };
  }
  const likeUri = await state.client.likePost(postUri, postCid);
  updateFeedItemViewer(postUri, { like: likeUri }, 1);
  return { liked: true, likeUri };
};

const updateFeedItemViewer = (
  postUri: string,
  viewerUpdate: Partial<PostView["viewer"]>,
  likeDelta: number
) => {
  state.feedItems = state.feedItems.map((item) => {
    if (item.post.uri === postUri) {
      return {
        ...item,
        post: {
          ...item.post,
          likeCount: item.post.likeCount + likeDelta,
          viewer: { ...item.post.viewer, ...viewerUpdate },
        },
      };
    }
    return item;
  });
};

export const showProfile = async (actor: string): Promise<string> => {
  state.view = "profile";
  state.profileHandle = actor;
  const profile = await state.client.getProfile(actor);
  const authorFeed = await state.client.getAuthorFeed(actor, undefined, 20);
  return renderProfile(profile, authorFeed.feed);
};

export const toggleFollow = async (
  did: string,
  existingFollowUri?: string
): Promise<{ following: boolean; followUri?: string }> => {
  if (existingFollowUri) {
    await state.client.unfollow(existingFollowUri);
    return { following: false };
  }
  const followUri = await state.client.follow(did);
  return { following: true, followUri };
};

export const searchUsers = async (query: string) => {
  return await state.client.searchUsers(query);
};

