import { BskyAgent } from '@atproto/api'
import type { SessionData } from './types'

const SESSION_PATH = './data/session.json'

const agent = new BskyAgent({ service: 'https://bsky.social' })

export const getAgent = (): BskyAgent => agent

export const saveSession = async (session: SessionData): Promise<void> => {
  await Bun.write(SESSION_PATH, JSON.stringify(session, null, 2))
}

export const loadSession = async (): Promise<SessionData | null> => {
  const file = Bun.file(SESSION_PATH)
  if (!(await file.exists())) return null
  try {
    return await file.json() as SessionData
  } catch {
    return null
  }
}

export const login = async (identifier: string, password: string): Promise<SessionData> => {
  const response = await agent.login({ identifier, password })
  const session: SessionData = {
    did: response.data.did,
    handle: response.data.handle,
    accessJwt: response.data.accessJwt,
    refreshJwt: response.data.refreshJwt,
  }
  await saveSession(session)
  return session
}

export const resumeSession = async (): Promise<SessionData | null> => {
  const stored = await loadSession()
  if (!stored) return null
  try {
    await agent.resumeSession({
      did: stored.did,
      handle: stored.handle,
      accessJwt: stored.accessJwt,
      refreshJwt: stored.refreshJwt,
      active: true,
    })
    const refreshed: SessionData = {
      did: agent.session?.did ?? stored.did,
      handle: agent.session?.handle ?? stored.handle,
      accessJwt: agent.session?.accessJwt ?? stored.accessJwt,
      refreshJwt: agent.session?.refreshJwt ?? stored.refreshJwt,
    }
    await saveSession(refreshed)
    return refreshed
  } catch {
    return null
  }
}

export const logout = async (): Promise<void> => {
  const file = Bun.file(SESSION_PATH)
  if (await file.exists()) {
    await Bun.write(SESSION_PATH, '{}')
  }
}

export const isAuthenticated = (): boolean => agent.hasSession

import type { AppBskyFeedDefs } from '@atproto/api'
import { getAgent } from './auth'
import type { FeedItem, PostView, TimelineResponse } from './types'

const CACHE_PATH = './data/feed-cache.jsonl'

const mapPostView = (pv: AppBskyFeedDefs.PostView): PostView => {
  const record = pv.record as { text: string; createdAt: string; langs?: string[] }
  return {
    uri: pv.uri,
    cid: pv.cid,
    author: {
      did: pv.author.did,
      handle: pv.author.handle,
      displayName: pv.author.displayName,
      avatar: pv.author.avatar,
    },
    record: {
      text: record.text,
      createdAt: record.createdAt,
      langs: record.langs,
    },
    likeCount: pv.likeCount ?? 0,
    repostCount: pv.repostCount ?? 0,
    replyCount: pv.replyCount ?? 0,
    viewerLike: pv.viewer?.like,
    indexedAt: pv.indexedAt,
  }
}

const mapFeedItem = (item: AppBskyFeedDefs.FeedViewPost): FeedItem => {
  const feedItem: FeedItem = {
    post: mapPostView(item.post),
  }
  if (item.reason && '$type' in item.reason && item.reason.$type === 'app.bsky.feed.defs#reasonRepost') {
    const repostReason = item.reason as AppBskyFeedDefs.ReasonRepost
    feedItem.reason = {
      type: 'repost',
      by: {
        did: repostReason.by.did,
        handle: repostReason.by.handle,
        displayName: repostReason.by.displayName,
        avatar: repostReason.by.avatar,
      },
      indexedAt: repostReason.indexedAt,
    }
  }
  return feedItem
}

export const getTimeline = async (limit = 25, cursor?: string): Promise<TimelineResponse> => {
  const agent = getAgent()
  const params: { limit: number; cursor?: string } = { limit }
  if (cursor) params.cursor = cursor

  const response = await agent.getTimeline(params)
  const feed = response.data.feed.map(mapFeedItem)

  await cacheFeed(feed)

  return {
    feed,
    cursor: response.data.cursor,
  }
}

export const getAuthorFeed = async (actor: string, limit = 25, cursor?: string): Promise<TimelineResponse> => {
  const agent = getAgent()
  const params: { actor: string; limit: number; cursor?: string } = { actor, limit }
  if (cursor) params.cursor = cursor

  const response = await agent.getAuthorFeed(params)
  const feed = response.data.feed.map(mapFeedItem)

  return {
    feed,
    cursor: response.data.cursor,
  }
}

const cacheFeed = async (items: FeedItem[]): Promise<void> => {
  const lines = items.map((item) => JSON.stringify(item))
  await Bun.write(CACHE_PATH, lines.join('\n') + '\n')
}

export const loadCachedFeed = async (): Promise<FeedItem[]> => {
  const file = Bun.file(CACHE_PATH)
  if (!(await file.exists())) return []
  try {
    const text = await file.text()
    return text
      .trim()
      .split('\n')
      .filter(Boolean)
      .map((line) => JSON.parse(line) as FeedItem)
  } catch {
    return []
  }
}

import type { AppBskyFeedPost } from '@atproto/api'
import { RichText } from '@atproto/api'
import { getAgent } from './auth'
import type { CreatePostResult, LikeResult } from './types'

const MAX_POST_LENGTH = 300

export const createPost = async (text: string): Promise<CreatePostResult> => {
  if (text.length === 0) {
    throw new Error('Post text cannot be empty')
  }
  if (text.length > MAX_POST_LENGTH) {
    throw new Error(`Post text exceeds ${MAX_POST_LENGTH} characters (got ${text.length})`)
  }

  const agent = getAgent()

  const rt = new RichText({ text })
  await rt.detectFacets(agent)

  const postRecord: Partial<AppBskyFeedPost.Record> & { $type: string } = {
    $type: 'app.bsky.feed.post',
    text: rt.text,
    facets: rt.facets,
    createdAt: new Date().toISOString(),
  }

  const response = await agent.post(postRecord)
  return {
    uri: response.uri,
    cid: response.cid,
  }
}

export const likePost = async (uri: string, cid: string): Promise<LikeResult> => {
  const agent = getAgent()
  const response = await agent.like(uri, cid)
  return { uri: response.uri }
}

export const unlikePost = async (likeUri: string): Promise<void> => {
  const agent = getAgent()
  await agent.deleteLike(likeUri)
}

export const toggleLike = async (
  uri: string,
  cid: string,
  existingLikeUri?: string,
): Promise<{ liked: boolean; likeUri?: string }> => {
  if (existingLikeUri) {
    await unlikePost(existingLikeUri)
    return { liked: false }
  }
  const result = await likePost(uri, cid)
  return { liked: true, likeUri: result.uri }
}

export const deletePost = async (postUri: string): Promise<void> => {
  const agent = getAgent()
  await agent.deletePost(postUri)
}

export const repost = async (uri: string, cid: string): Promise<{ uri: string }> => {
  const agent = getAgent()
  const response = await agent.repost(uri, cid)
  return { uri: response.uri }
}

export const undoRepost = async (repostUri: string): Promise<void> => {
  const agent = getAgent()
  await agent.deleteRepost(repostUri)
}

import { getAgent } from './auth'
import type { FollowResult, ProfileView } from './types'

const mapProfile = (data: {
  did: string
  handle: string
  displayName?: string
  description?: string
  avatar?: string
  banner?: string
  followersCount?: number
  followsCount?: number
  postsCount?: number
  viewer?: { following?: string; followedBy?: string }
}): ProfileView => ({
  did: data.did,
  handle: data.handle,
  displayName: data.displayName,
  description: data.description,
  avatar: data.avatar,
  banner: data.banner,
  followersCount: data.followersCount ?? 0,
  followsCount: data.followsCount ?? 0,
  postsCount: data.postsCount ?? 0,
  viewerFollowing: data.viewer?.following,
  viewerFollowedBy: data.viewer?.followedBy,
})

export const getProfile = async (actor: string): Promise<ProfileView> => {
  const agent = getAgent()
  const response = await agent.getProfile({ actor })
  return mapProfile(response.data)
}

export const getProfiles = async (actors: string[]): Promise<ProfileView[]> => {
  const agent = getAgent()
  const response = await agent.getProfiles({ actors })
  return response.data.profiles.map(mapProfile)
}

export const followUser = async (did: string): Promise<FollowResult> => {
  const agent = getAgent()
  const response = await agent.follow(did)
  return { uri: response.uri }
}

export const unfollowUser = async (followUri: string): Promise<void> => {
  const agent = getAgent()
  await agent.deleteFollow(followUri)
}

export const toggleFollow = async (
  did: string,
  existingFollowUri?: string,
): Promise<{ following: boolean; followUri?: string }> => {
  if (existingFollowUri) {
    await unfollowUser(existingFollowUri)
    return { following: false }
  }
  const result = await followUser(did)
  return { following: true, followUri: result.uri }
}

export const searchUsers = async (query: string, limit = 10): Promise<ProfileView[]> => {
  const agent = getAgent()
  const response = await agent.searchActors({ term: query, limit })
  return response.data.actors.map(mapProfile)
}

