const formatTimestamp = (iso: string): string => {
  const date = new Date(iso)
  const now = new Date()
  const diffMs = now.getTime() - date.getTime()
  const diffSec = Math.floor(diffMs / 1000)
  const diffMin = Math.floor(diffSec / 60)
  const diffHour = Math.floor(diffMin / 60)
  const diffDay = Math.floor(diffHour / 24)

  if (diffSec < 60) return `${diffSec}s`
  if (diffMin < 60) return `${diffMin}m`
  if (diffHour < 24) return `${diffHour}h`
  if (diffDay < 7) return `${diffDay}d`
  return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })
}

const avatarInitial = (name?: string, handle?: string): string => {
  const source = name || handle || '?'
  return source.charAt(0).toUpperCase()
}

const renderAvatar = (url?: string, displayName?: string, handle?: string, size: 'small' | 'large' = 'small') => {
  const sty = size === 'large' ? styles.profileAvatar : styles.avatar
  const placeholderSty = size === 'large' ? styles.profileAvatarPlaceholder : styles.avatarPlaceholder
  if (url) {
    return h('img', { src: url, alt: `${displayName || handle} avatar`, style: sty })
  }
  return h('div', { style: placeholderSty }, avatarInitial(displayName, handle))
}

export const renderPost = (post: PostView): ReturnType<typeof h> =>
  h('div', { style: styles.post },
    renderAvatar(post.author.avatar, post.author.displayName, post.author.handle),
    h('div', { style: styles.postContent },
      h('div', { style: styles.authorRow },
        h('span', { style: styles.displayName }, post.author.displayName || post.author.handle),
        h('span', { style: styles.handle }, `@${post.author.handle}`),
        h('span', { style: styles.timestamp }, formatTimestamp(post.record.createdAt)),
      ),
      h('div', { style: styles.postText }, post.record.text),
      h('div', { style: styles.actions },
        h('button', {
          style: styles.actionBtn,
          'p-trigger': `reply:${post.uri}`,
        }, `Reply ${post.replyCount || ''}`),
        h('button', {
          style: styles.actionBtn,
          'p-trigger': `repost:${post.uri}:${post.cid}`,
        }, `Repost ${post.repostCount || ''}`),
        h('button', {
          style: post.viewerLike ? styles.actionBtnLiked : styles.actionBtn,
          'p-trigger': post.viewerLike
            ? `unlike:${post.uri}:${post.cid}:${post.viewerLike}`
            : `like:${post.uri}:${post.cid}`,
        }, `${post.viewerLike ? 'Liked' : 'Like'} ${post.likeCount || ''}`),
