export const bootstrap = async (): Promise<string> => {
  const session = await resumeSession()
  if (!session) {
    return renderToString(renderLoginForm())
  }
  return renderTimelinePage()
}

export const handleLogin = async (handle: string, appPassword: string): Promise<string> => {
  try {
    await login(handle, appPassword)
    return renderTimelinePage()
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Login failed'
    return renderToString(renderLoginForm(message))
  }
}

const renderTimelinePage = async (): Promise<string> => {
  const timeline = await getTimeline()
  const { h, Fragment } = await import('@anthropic-ai/template')
  const page = h(Fragment, null,
    renderCompose(),
    renderTimeline(timeline.feed, !!timeline.cursor),
  )
  return renderToString(page)
}

export const handleViewProfile = async (actor: string): Promise<string> => {
  const profile = await getProfile(actor)
  return renderToString(renderProfile(profile))
}

