import { AtpAgent } from '@atproto/api'
import type { AuthCredentials, SessionData } from './types'

const SESSION_PATH = './data/session.json'

const agent = new AtpAgent({ service: 'https://bsky.social' })

export const getAgent = (): AtpAgent => agent

export const loadSession = async (): Promise<SessionData | null> => {
  const file = Bun.file(SESSION_PATH)
  const exists = await file.exists()
  if (!exists) return null
  try {
    const data: SessionData = await file.json()
    await agent.resumeSession({
      did: data.did,
      handle: data.handle,
      accessJwt: data.accessJwt,
      refreshJwt: data.refreshJwt,
      active: true,
    })
    return data
  } catch {
    return null
  }
}

export const saveSession = async (session: SessionData): Promise<void> => {
  await Bun.write(SESSION_PATH, JSON.stringify(session, null, 2))
}

export const clearSession = async (): Promise<void> => {
  const file = Bun.file(SESSION_PATH)
  const exists = await file.exists()
  if (exists) {
    await Bun.write(SESSION_PATH, '')
  }
}

export const login = async (credentials: AuthCredentials): Promise<SessionData> => {
  const response = await agent.login({
    identifier: credentials.identifier,
    password: credentials.password,
  })

  const session: SessionData = {
    did: response.data.did,
    handle: response.data.handle,
    accessJwt: response.data.accessJwt,
    refreshJwt: response.data.refreshJwt,
  }

  await saveSession(session)
  return session
}

export const logout = async (): Promise<void> => {
  await clearSession()
}

export const isAuthenticated = (): boolean => {
  return agent.session !== undefined
}

import type { AppBskyFeedDefs, AppBskyActorDefs } from '@atproto/api'
import { getAgent } from './auth'
import type { PostView, ProfileView, TimelineResponse } from './types'

const mapPost = (feedItem: AppBskyFeedDefs.FeedViewPost): PostView | null => {
  const post = feedItem.post
  if (!post || typeof post.record !== 'object' || post.record === null) return null

  const record = post.record as { text?: string; createdAt?: string }
  const author = post.author

  return {
    uri: post.uri,
    cid: post.cid,
    author: {
      did: author.did,
      handle: author.handle,
      displayName: author.displayName || undefined,
      avatar: author.avatar || undefined,
    },
    text: record.text ?? '',
    createdAt: record.createdAt ?? new Date().toISOString(),
    likeCount: post.likeCount ?? 0,
    repostCount: post.repostCount ?? 0,
    replyCount: post.replyCount ?? 0,
    likeUri: post.viewer?.like || undefined,
  }
}

export const getTimeline = async (cursor?: string, limit = 30): Promise<TimelineResponse> => {
  const agent = getAgent()
  const response = await agent.getTimeline({ cursor, limit })

  const posts = response.data.feed
    .map(mapPost)
    .filter((p): p is PostView => p !== null)

  return {
    posts,
    cursor: response.data.cursor,
  }
}

export const getProfile = async (actor: string): Promise<ProfileView> => {
  const agent = getAgent()
  const response = await agent.getProfile({ actor })
  const profile: AppBskyActorDefs.ProfileViewDetailed = response.data

  return {
    did: profile.did,
    handle: profile.handle,
    displayName: profile.displayName || undefined,
    description: profile.description || undefined,
    avatar: profile.avatar || undefined,
    banner: profile.banner || undefined,
    followersCount: profile.followersCount ?? 0,
    followsCount: profile.followsCount ?? 0,
    postsCount: profile.postsCount ?? 0,
    followUri: profile.viewer?.following || undefined,
  }
}

export const getAuthorFeed = async (actor: string, cursor?: string, limit = 20): Promise<TimelineResponse> => {
  const agent = getAgent()
  const response = await agent.getAuthorFeed({ actor, cursor, limit })

  const posts = response.data.feed
    .map(mapPost)
    .filter((p): p is PostView => p !== null)

  return {
    posts,
    cursor: response.data.cursor,
  }
}

