import { loadSession, login, logout, isAuthenticated } from './auth'
import { getTimeline, getProfile, getAuthorFeed } from './client'
import { createPost, likePost, unlikePost, followUser, unfollowUser } from './actions'
import {
  renderTimeline,
  renderProfile,
  renderComposer,
  renderLoginForm,
  renderToHtml,
} from './render'
import { h } from '@plaited/template'

type RouteHandler = (req: Request) => Promise<Response>

const json = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const html = (content: string, status = 200) =>
  new Response(content, {
    status,
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const wrapPage = (body: string, title = 'Bluesky') => `
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>${title}</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { background: #f5f5f5; }
  </style>
</head>
<body>${body}</body>
</html>`

const routes: Record<string, RouteHandler> = {
  'GET /': async () => {
    await loadSession()
    if (!isAuthenticated()) {
      return html(wrapPage(renderToHtml(renderLoginForm())))
    }
    const timeline = await getTimeline()
    const composerHtml = renderToHtml(renderComposer())
    const timelineHtml = renderToHtml(renderTimeline(timeline))
    return html(wrapPage(composerHtml + timelineHtml))
  },

  'POST /api/login': async (req: Request) => {
    const body = await req.json() as { identifier: string; password: string }
    try {
      const session = await login(body)
      return json({ ok: true, handle: session.handle, did: session.did })
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Login failed'
      return json({ ok: false, error: message }, 401)
    }
  },

  'POST /api/logout': async () => {
    await logout()
    return json({ ok: true })
  },

  'GET /api/timeline': async (req: Request) => {
    const url = new URL(req.url)
    const cursor = url.searchParams.get('cursor') || undefined
    const limit = Number(url.searchParams.get('limit')) || 30
    const timeline = await getTimeline(cursor, limit)
    return json(timeline)
  },

  'GET /api/profile/:actor': async (req: Request) => {
    const url = new URL(req.url)
    const actor = url.pathname.split('/api/profile/')[1]
    if (!actor) return json({ error: 'Actor required' }, 400)
    const profile = await getProfile(decodeURIComponent(actor))
    return json(profile)
  },

  'GET /profile/:actor': async (req: Request) => {
    await loadSession()
    if (!isAuthenticated()) {
      return html(wrapPage(renderToHtml(renderLoginForm())))
    }
    const url = new URL(req.url)
    const actor = url.pathname.split('/profile/')[1]
    if (!actor) return json({ error: 'Actor required' }, 400)
    const decoded = decodeURIComponent(actor)
    const profile = await getProfile(decoded)
    const authorFeed = await getAuthorFeed(decoded)
    const profileHtml = renderToHtml(renderProfile(profile))
    const feedHtml = renderToHtml(renderTimeline(authorFeed))
    return html(wrapPage(profileHtml + feedHtml, `${profile.displayName || profile.handle} — Bluesky`))
  },

  'POST /api/post': async (req: Request) => {
    const body = await req.json() as { text: string }
    if (!body.text?.trim()) return json({ error: 'Text required' }, 400)
    if (body.text.length > 300) return json({ error: 'Post too long (max 300 chars)' }, 400)
    const result = await createPost(body.text)
    return json({ ok: true, ...result })
  },

  'POST /api/like': async (req: Request) => {
    const body = await req.json() as { uri: string; cid: string }
    const likeUri = await likePost(body.uri, body.cid)
    return json({ ok: true, likeUri })
  },

  'POST /api/unlike': async (req: Request) => {
    const body = await req.json() as { likeUri: string }
    await unlikePost(body.likeUri)
    return json({ ok: true })
  },

  'POST /api/follow': async (req: Request) => {
    const body = await req.json() as { did: string }
    const followUri = await followUser(body.did)
    return json({ ok: true, followUri })
  },

  'POST /api/unfollow': async (req: Request) => {
    const body = await req.json() as { followUri: string }
    await unfollowUser(body.followUri)
    return json({ ok: true })
  },
}

const matchRoute = (method: string, pathname: string): RouteHandler | null => {
  const key = `${method} ${pathname}`
  if (routes[key]) return routes[key]

  // Match parameterized routes
  for (const [pattern, handler] of Object.entries(routes)) {
    const [routeMethod, routePath] = pattern.split(' ')
    if (routeMethod !== method) continue
    if (!routePath.includes(':')) continue

    const routeParts = routePath.split('/')
    const pathParts = pathname.split('/')

    // For prefix matching (e.g., /api/profile/:actor matches /api/profile/user.bsky.social)
    const prefix = routePath.split('/:')[0]
    if (pathname.startsWith(prefix + '/') && pathParts.length >= routeParts.length) {
      return handler
    }
  }

  return null
}

export const startServer = (port = 3000) => {
  return Bun.serve({
    port,
    fetch: async (req: Request) => {
      const url = new URL(req.url)
      const handler = matchRoute(req.method, url.pathname)

      if (!handler) {
        return json({ error: 'Not found' }, 404)
      }

      try {
        return await handler(req)
      } catch (err) {
        const message = err instanceof Error ? err.message : 'Internal error'
        console.error(`Error handling ${req.method} ${url.pathname}:`, message)
        return json({ error: message }, 500)
      }
    },
  })
}

// Auto-start if run directly
const server = startServer()
console.log(`Bluesky client running at http://localhost:${server.port}`)

