import type { InventoryItem, NewItemInput, BulkImportInput, DashboardStats, SearchParams } from './types'

const DATA_PATH = new URL('./data/items.json', import.meta.url).pathname

const readItems = async (): Promise<InventoryItem[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  return text.trim() ? JSON.parse(text) : []
}

const writeItems = async (items: InventoryItem[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(items, null, 2))
}

const generateId = (): string => crypto.randomUUID()

const now = (): string => new Date().toISOString()

export const getAll = async (params?: SearchParams): Promise<InventoryItem[]> => {
  let items = await readItems()

  if (params?.query) {
    const q = params.query.toLowerCase()
    items = items.filter(
      (item) => item.name.toLowerCase().includes(q) || item.sku.toLowerCase().includes(q),
    )
  }

  if (params?.category) {
    items = items.filter((item) => item.category === params.category)
  }

  if (params?.lowStockOnly) {
    items = items.filter((item) => item.quantity <= item.reorderThreshold)
  }

  const sortBy = params?.sortBy ?? 'name'
  const sortOrder = params?.sortOrder ?? 'asc'
  const multiplier = sortOrder === 'asc' ? 1 : -1

  items.sort((a, b) => {
    const aVal = a[sortBy]
    const bVal = b[sortBy]
    if (typeof aVal === 'string' && typeof bVal === 'string') {
      return aVal.localeCompare(bVal) * multiplier
    }
    return ((aVal as number) - (bVal as number)) * multiplier
  })

  return items
}

export const getById = async (id: string): Promise<InventoryItem | undefined> => {
  const items = await readItems()
  return items.find((item) => item.id === id)
}

export const getBySku = async (sku: string): Promise<InventoryItem | undefined> => {
  const items = await readItems()
  return items.find((item) => item.sku.toLowerCase() === sku.toLowerCase())
}

export const addItem = async (input: NewItemInput): Promise<InventoryItem> => {
  const items = await readItems()
  const existing = items.find((item) => item.sku.toLowerCase() === input.sku.toLowerCase())
  if (existing) {
    throw new Error(`Item with SKU "${input.sku}" already exists`)
  }

  const item: InventoryItem = {
    id: generateId(),
    ...input,
    createdAt: now(),
    updatedAt: now(),
  }

  items.push(item)
  await writeItems(items)
  return item
}

export const updateItem = async (
  id: string,
  updates: Partial<NewItemInput>,
): Promise<InventoryItem> => {
  const items = await readItems()
  const index = items.findIndex((item) => item.id === id)
  if (index === -1) throw new Error(`Item with id "${id}" not found`)

  if (updates.sku) {
    const skuConflict = items.find(
      (item) => item.sku.toLowerCase() === updates.sku!.toLowerCase() && item.id !== id,
    )
    if (skuConflict) throw new Error(`SKU "${updates.sku}" is already in use`)
  }

  items[index] = { ...items[index], ...updates, updatedAt: now() }
  await writeItems(items)
  return items[index]
}

export const deleteItem = async (id: string): Promise<void> => {
  const items = await readItems()
  const filtered = items.filter((item) => item.id !== id)
  if (filtered.length === items.length) throw new Error(`Item with id "${id}" not found`)
  await writeItems(filtered)
}

export const bulkImport = async (inputs: BulkImportInput): Promise<{
  imported: number
  skipped: string[]
}> => {
  const items = await readItems()
  const existingSkus = new Set(items.map((item) => item.sku.toLowerCase()))
  const skipped: string[] = []
  const timestamp = now()

  for (const input of inputs) {
    if (existingSkus.has(input.sku.toLowerCase())) {
      skipped.push(input.sku)
      continue
    }

    items.push({
      id: generateId(),
      ...input,
      createdAt: timestamp,
      updatedAt: timestamp,
    })
    existingSkus.add(input.sku.toLowerCase())
  }

  await writeItems(items)
  return { imported: inputs.length - skipped.length, skipped }
}

export const getStats = async (): Promise<DashboardStats> => {
  const items = await readItems()

  const categories: Record<string, number> = {}
  let totalQuantity = 0
  let lowStockCount = 0
  let outOfStockCount = 0

  for (const item of items) {
    totalQuantity += item.quantity
    categories[item.category] = (categories[item.category] ?? 0) + 1
    if (item.quantity === 0) outOfStockCount++
    else if (item.quantity <= item.reorderThreshold) lowStockCount++
  }

  return {
    totalItems: items.length,
    totalQuantity,
    lowStockCount,
    outOfStockCount,
    categories,
  }
}

export const getLowStockItems = async (): Promise<InventoryItem[]> => {
  const items = await readItems()
  return items
    .filter((item) => item.quantity <= item.reorderThreshold)
    .sort((a, b) => a.quantity - b.quantity)
}

export const getCategories = async (): Promise<string[]> => {
  const items = await readItems()
  return [...new Set(items.map((item) => item.category))].sort()
}

