import * as store from './store'
import { renderDashboard, renderBarcodeResult } from './ui'
import type { NewItemInput } from './types'

const html = (body: string): Response =>
  new Response(body, { headers: { 'Content-Type': 'text/html; charset=utf-8' } })

const redirect = (path: string): Response =>
  new Response(null, { status: 302, headers: { Location: path } })

const parseFormData = async (req: Request): Promise<Record<string, string>> => {
  const formData = await req.formData()
  const data: Record<string, string> = {}
  formData.forEach((value, key) => {
    data[key] = String(value)
  })
  return data
}

const encodeMsg = (type: 'success' | 'error', text: string): string =>
  `msg=${encodeURIComponent(type)}:${encodeURIComponent(text)}`

const decodeMsg = (url: URL): { type: 'success' | 'error'; text: string } | undefined => {
  const msg = url.searchParams.get('msg')
  if (!msg) return undefined
  const [type, ...rest] = msg.split(':')
  return { type: type as 'success' | 'error', text: rest.join(':') }
}

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const path = url.pathname
  const method = req.method

  // GET / — Dashboard
  if (method === 'GET' && path === '/') {
    const query = url.searchParams.get('q') ?? undefined
    const category = url.searchParams.get('category') ?? undefined
    const message = decodeMsg(url)

    const [stats, lowStockItems, items, categories] = await Promise.all([
      store.getStats(),
      store.getLowStockItems(),
      store.getAll({
        query,
        category: category || undefined,
      }),
      store.getCategories(),
    ])

    return html(renderDashboard(stats, lowStockItems, items, categories, message, query, category))
  }

  // POST /items — Add item
  if (method === 'POST' && path === '/items') {
    const data = await parseFormData(req)
    const input: NewItemInput = {
      name: data.name,
      sku: data.sku,
      quantity: parseInt(data.quantity, 10) || 0,
      category: data.category,
      reorderThreshold: parseInt(data.reorderThreshold, 10) || 0,
    }

    try {
      await store.addItem(input)
      return redirect(`/?${encodeMsg('success', `Item "${input.name}" added successfully`)}`)
    } catch (err) {
      const errMsg = err instanceof Error ? err.message : 'Failed to add item'
      return redirect(`/?${encodeMsg('error', errMsg)}`)
    }
  }

  // POST /items/:id/increment — Increase quantity by 1
  const incrementMatch = path.match(/^\/items\/([^/]+)\/increment$/)
  if (method === 'POST' && incrementMatch) {
    const id = incrementMatch[1]
    try {
      const item = await store.getById(id)
      if (!item) throw new Error('Item not found')
      await store.updateItem(id, { quantity: item.quantity + 1 })
      return redirect(`/?${encodeMsg('success', `${item.name} quantity increased to ${item.quantity + 1}`)}`)
    } catch (err) {
      const errMsg = err instanceof Error ? err.message : 'Failed to update'
      return redirect(`/?${encodeMsg('error', errMsg)}`)
    }
  }

  // POST /items/:id/decrement — Decrease quantity by 1
  const decrementMatch = path.match(/^\/items\/([^/]+)\/decrement$/)
  if (method === 'POST' && decrementMatch) {
    const id = decrementMatch[1]
    try {
      const item = await store.getById(id)
      if (!item) throw new Error('Item not found')
      const newQty = Math.max(0, item.quantity - 1)
      await store.updateItem(id, { quantity: newQty })
      return redirect(`/?${encodeMsg('success', `${item.name} quantity decreased to ${newQty}`)}`)
    } catch (err) {
      const errMsg = err instanceof Error ? err.message : 'Failed to update'
      return redirect(`/?${encodeMsg('error', errMsg)}`)
    }
  }

  // POST /items/:id/delete — Delete item
  const deleteMatch = path.match(/^\/items\/([^/]+)\/delete$/)
  if (method === 'POST' && deleteMatch) {
    const id = deleteMatch[1]
    try {
      await store.deleteItem(id)
      return redirect(`/?${encodeMsg('success', 'Item deleted')}`)
    } catch (err) {
      const errMsg = err instanceof Error ? err.message : 'Failed to delete'
      return redirect(`/?${encodeMsg('error', errMsg)}`)
    }
  }

  // GET /barcode — SKU lookup
  if (method === 'GET' && path === '/barcode') {
    const sku = url.searchParams.get('sku') ?? ''
    const item = sku ? await store.getBySku(sku) : undefined
    return html(renderBarcodeResult(item, sku))
  }

  // POST /import — Bulk import
  if (method === 'POST' && path === '/import') {
    const data = await parseFormData(req)
    try {
      const parsed = JSON.parse(data.json)
      if (!Array.isArray(parsed)) throw new Error('Expected a JSON array')

      const inputs: NewItemInput[] = parsed.map((item: Record<string, unknown>) => ({
        name: String(item.name ?? ''),
        sku: String(item.sku ?? ''),
        quantity: Number(item.quantity) || 0,
        category: String(item.category ?? ''),
        reorderThreshold: Number(item.reorderThreshold) || 0,
      }))

      const result = await store.bulkImport(inputs)
      const msg = result.skipped.length > 0
        ? `Imported ${result.imported} items. Skipped ${result.skipped.length} (duplicate SKUs: ${result.skipped.join(', ')})`
        : `Successfully imported ${result.imported} items`
      return redirect(`/?${encodeMsg('success', msg)}`)
    } catch (err) {
      const errMsg = err instanceof Error ? err.message : 'Invalid JSON'
      return redirect(`/?${encodeMsg('error', `Import failed: ${errMsg}`)}`)
    }
  }

  // API: GET /api/items — JSON list
  if (method === 'GET' && path === '/api/items') {
    const query = url.searchParams.get('q') ?? undefined
    const category = url.searchParams.get('category') ?? undefined
    const lowStockOnly = url.searchParams.get('lowStock') === 'true'
    const sortBy = (url.searchParams.get('sortBy') as 'name' | 'sku' | 'quantity') ?? undefined
    const sortOrder = (url.searchParams.get('sortOrder') as 'asc' | 'desc') ?? undefined

    const items = await store.getAll({ query, category, lowStockOnly, sortBy, sortOrder })
    return new Response(JSON.stringify(items), {
      headers: { 'Content-Type': 'application/json' },
    })
  }

  // API: GET /api/stats
  if (method === 'GET' && path === '/api/stats') {
    const stats = await store.getStats()
    return new Response(JSON.stringify(stats), {
      headers: { 'Content-Type': 'application/json' },
    })
  }

  return new Response('Not Found', { status: 404 })
}

