import type { InventoryItem, InventoryStore } from './types'

const DATA_PATH = `${import.meta.dir}/data/inventory.json`

const generateId = (): string => crypto.randomUUID()

const now = (): string => new Date().toISOString()

export const loadStore = async (): Promise<InventoryStore> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) {
    return { items: [] }
  }
  const text = await file.text()
  return JSON.parse(text) as InventoryStore
}

export const saveStore = async (store: InventoryStore): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(store, null, 2))
}

export const addItem = async (item: Omit<InventoryItem, 'id' | 'createdAt' | 'updatedAt'>): Promise<InventoryItem> => {
  const store = await loadStore()
  const existing = store.items.find((i) => i.sku === item.sku)
  if (existing) {
    throw new Error(`Item with SKU "${item.sku}" already exists`)
  }
  const newItem: InventoryItem = {
    ...item,
    id: generateId(),
    createdAt: now(),
    updatedAt: now(),
  }
  store.items.push(newItem)
  await saveStore(store)
  return newItem
}

export const updateItem = async (id: string, updates: Partial<Omit<InventoryItem, 'id' | 'createdAt'>>): Promise<InventoryItem> => {
  const store = await loadStore()
  const index = store.items.findIndex((i) => i.id === id)
  if (index === -1) {
    throw new Error(`Item with ID "${id}" not found`)
  }
  if (updates.sku && updates.sku !== store.items[index].sku) {
    const skuConflict = store.items.find((i) => i.sku === updates.sku && i.id !== id)
    if (skuConflict) {
      throw new Error(`Item with SKU "${updates.sku}" already exists`)
    }
  }
  store.items[index] = {
    ...store.items[index],
    ...updates,
    updatedAt: now(),
  }
  await saveStore(store)
  return store.items[index]
}

export const deleteItem = async (id: string): Promise<void> => {
  const store = await loadStore()
  const index = store.items.findIndex((i) => i.id === id)
  if (index === -1) {
    throw new Error(`Item with ID "${id}" not found`)
  }
  store.items.splice(index, 1)
  await saveStore(store)
}

export const getItemBySku = async (sku: string): Promise<InventoryItem | undefined> => {
  const store = await loadStore()
  return store.items.find((i) => i.sku === sku)
}

export const getItemById = async (id: string): Promise<InventoryItem | undefined> => {
  const store = await loadStore()
  return store.items.find((i) => i.id === id)
}

export const getLowStockItems = async (): Promise<InventoryItem[]> => {
  const store = await loadStore()
  return store.items.filter((i) => i.quantity <= i.reorderThreshold)
}

export const getCategories = async (): Promise<string[]> => {
  const store = await loadStore()
  const cats = new Set(store.items.map((i) => i.category))
  return [...cats].sort()
}

import type { InventoryItem, SearchParams, SortField, SortDirection, DashboardFilters } from './types'
import { loadStore } from './store'

const matchesSearch = (item: InventoryItem, query: string, field: SearchParams['field'] = 'all'): boolean => {
  const q = query.toLowerCase().trim()
  if (!q) return true
  if (field === 'name') return item.name.toLowerCase().includes(q)
  if (field === 'sku') return item.sku.toLowerCase().includes(q)
  return item.name.toLowerCase().includes(q) || item.sku.toLowerCase().includes(q)
}

const compareItems = (a: InventoryItem, b: InventoryItem, sortBy: SortField, direction: SortDirection): number => {
  let cmp = 0
  switch (sortBy) {
    case 'name':
      cmp = a.name.localeCompare(b.name)
      break
    case 'sku':
      cmp = a.sku.localeCompare(b.sku)
      break
    case 'quantity':
      cmp = a.quantity - b.quantity
      break
    case 'category':
      cmp = a.category.localeCompare(b.category)
      break
    case 'updatedAt':
      cmp = a.updatedAt.localeCompare(b.updatedAt)
      break
  }
  return direction === 'desc' ? -cmp : cmp
}

export const searchItems = async (params: SearchParams): Promise<InventoryItem[]> => {
  const store = await loadStore()
  return store.items.filter((item) => matchesSearch(item, params.query, params.field))
}

export const filterAndSort = async (filters: DashboardFilters): Promise<InventoryItem[]> => {
  const store = await loadStore()
  let items = [...store.items]

  if (filters.search) {
    items = items.filter((item) => matchesSearch(item, filters.search!))
  }

  if (filters.category) {
    items = items.filter((item) => item.category === filters.category)
  }

  if (filters.lowStockOnly) {
    items = items.filter((item) => item.quantity <= item.reorderThreshold)
  }

  const sortBy = filters.sortBy ?? 'name'
  const sortDir = filters.sortDirection ?? 'asc'
  items.sort((a, b) => compareItems(a, b, sortBy, sortDir))

  return items
}

import type { InventoryItem } from './types'
import { loadStore, saveStore } from './store'

type ImportRecord = {
  name: string
  sku: string
  quantity: number
  category: string
  reorderThreshold: number
}

type ImportResult = {
  added: number
  skipped: number
  errors: string[]
}

const validateRecord = (record: unknown, index: number): ImportRecord | string => {
  if (!record || typeof record !== 'object') {
    return `Row ${index}: invalid record`
  }
  const r = record as Record<string, unknown>
  if (typeof r.name !== 'string' || !r.name.trim()) {
    return `Row ${index}: missing or invalid "name"`
  }
  if (typeof r.sku !== 'string' || !r.sku.trim()) {
    return `Row ${index}: missing or invalid "sku"`
  }
  if (typeof r.quantity !== 'number' || r.quantity < 0 || !Number.isFinite(r.quantity)) {
    return `Row ${index}: missing or invalid "quantity"`
  }
  if (typeof r.category !== 'string' || !r.category.trim()) {
    return `Row ${index}: missing or invalid "category"`
  }
  if (typeof r.reorderThreshold !== 'number' || r.reorderThreshold < 0 || !Number.isFinite(r.reorderThreshold)) {
    return `Row ${index}: missing or invalid "reorderThreshold"`
  }
  return {
    name: r.name.trim(),
    sku: r.sku.trim(),
    quantity: Math.floor(r.quantity),
    category: r.category.trim(),
    reorderThreshold: Math.floor(r.reorderThreshold),
  }
}

export const bulkImport = async (jsonData: string): Promise<ImportResult> => {
  let records: unknown[]
  try {
    const parsed = JSON.parse(jsonData)
    if (!Array.isArray(parsed)) {
      return { added: 0, skipped: 0, errors: ['JSON must be an array of items'] }
    }
    records = parsed
  } catch {
    return { added: 0, skipped: 0, errors: ['Invalid JSON format'] }
  }

  const store = await loadStore()
  const existingSkus = new Set(store.items.map((i) => i.sku))
  const result: ImportResult = { added: 0, skipped: 0, errors: [] }
  const seenSkus = new Set<string>()

  for (let i = 0; i < records.length; i++) {
    const validated = validateRecord(records[i], i + 1)
    if (typeof validated === 'string') {
      result.errors.push(validated)
      continue
    }
    if (existingSkus.has(validated.sku) || seenSkus.has(validated.sku)) {
      result.skipped++
      result.errors.push(`Row ${i + 1}: SKU "${validated.sku}" already exists, skipped`)
      continue
    }
    seenSkus.add(validated.sku)
    const now = new Date().toISOString()
    const newItem: InventoryItem = {
      ...validated,
      id: crypto.randomUUID(),
      createdAt: now,
      updatedAt: now,
    }
    store.items.push(newItem)
    result.added++
  }

  await saveStore(store)
  return result
}

