import { createSSR } from 'plaited'
import type { DashboardFilters } from './types'
import { addItem, updateItem, deleteItem, getItemBySku } from './store'
import { renderDashboard } from './dashboard'
import { bulkImport } from './import'
import { searchItems } from './search'

export { addItem, updateItem, deleteItem, getItemBySku } from './store'
export { searchItems, filterAndSort } from './search'
export { bulkImport } from './import'
export { renderDashboard } from './dashboard'

export type { InventoryItem, InventoryStore, SearchParams, DashboardFilters } from './types'

const render = createSSR()

const parseFormData = (body: Record<string, string>) => ({
  name: body.name?.trim() ?? '',
  sku: body.sku?.trim() ?? '',
  quantity: parseInt(body.quantity ?? '0', 10),
  category: body.category?.trim() ?? '',
  reorderThreshold: parseInt(body.reorderThreshold ?? '10', 10),
})

const jsonResponse = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const htmlResponse = async (filters: DashboardFilters = {}) => {
  const dashboard = await renderDashboard(filters)
  const html = render(dashboard)
  return new Response(html, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })
}

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const path = url.pathname

  // Dashboard
  if (path === '/' && req.method === 'GET') {
    const filters: DashboardFilters = {
      search: url.searchParams.get('search') ?? undefined,
      category: url.searchParams.get('category') ?? undefined,
      lowStockOnly: url.searchParams.get('lowStock') === 'true',
      sortBy: (url.searchParams.get('sortBy') as DashboardFilters['sortBy']) ?? undefined,
      sortDirection: (url.searchParams.get('sortDir') as DashboardFilters['sortDirection']) ?? undefined,
    }
    return htmlResponse(filters)
  }

  // Search API
  if (path === '/api/search' && req.method === 'GET') {
    const query = url.searchParams.get('q') ?? ''
    const field = (url.searchParams.get('field') as 'name' | 'sku' | 'all') ?? 'all'
    const results = await searchItems({ query, field })
    return jsonResponse(results)
  }

  // Barcode lookup
  if (path === '/api/barcode' && req.method === 'GET') {
    const sku = url.searchParams.get('sku') ?? ''
    const item = await getItemBySku(sku)
    if (item) {
      return jsonResponse({ found: true, item })
    }
    return jsonResponse({ found: false, sku })
  }

  // Add item
  if (path === '/api/items' && req.method === 'POST') {
    try {
      const body = await req.json()
      const data = parseFormData(body)
      if (!data.name || !data.sku) {
        return jsonResponse({ error: 'Name and SKU are required' }, 400)
      }
      const item = await addItem(data)
      return jsonResponse(item, 201)
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Unknown error'
      return jsonResponse({ error: message }, 400)
    }
  }

  // Update item
  if (path.startsWith('/api/items/') && req.method === 'PATCH') {
    const id = path.replace('/api/items/', '')
    try {
      const body = await req.json()
      const item = await updateItem(id, body)
      return jsonResponse(item)
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Unknown error'
      return jsonResponse({ error: message }, 400)
    }
  }

  // Delete item
  if (path.startsWith('/api/items/') && req.method === 'DELETE') {
    const id = path.replace('/api/items/', '')
    try {
      await deleteItem(id)
      return jsonResponse({ success: true })
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Unknown error'
      return jsonResponse({ error: message }, 400)
    }
  }

  // Bulk import
  if (path === '/api/import' && req.method === 'POST') {
    try {
      const body = await req.text()
      const result = await bulkImport(body)
      return jsonResponse(result)
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Unknown error'
      return jsonResponse({ error: message }, 400)
    }
  }

  return jsonResponse({ error: 'Not found' }, 404)
}

// Standalone server
if (import.meta.main) {
  const PORT = parseInt(process.env.PORT ?? '3000', 10)
  Bun.serve({
    port: PORT,
    fetch: handleRequest,
  })
  console.log(`Inventory Manager running at http://localhost:${PORT}`)
}

