import type { InventoryItem, NewItemInput, BulkImportEntry, SearchParams, DashboardStats, SortConfig } from './types'

const DATA_PATH = `${import.meta.dir}/data/items.json`

const generateId = (): string => crypto.randomUUID()

const now = (): string => new Date().toISOString()

export const loadItems = async (): Promise<InventoryItem[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  if (!text.trim()) return []
  return JSON.parse(text) as InventoryItem[]
}

export const saveItems = async (items: InventoryItem[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(items, null, 2))
}

export const addItem = async (input: NewItemInput): Promise<InventoryItem> => {
  const items = await loadItems()
  const existing = items.find((i) => i.sku === input.sku)
  if (existing) {
    throw new Error(`Item with SKU "${input.sku}" already exists`)
  }
  const item: InventoryItem = {
    id: generateId(),
    name: input.name,
    sku: input.sku,
    quantity: input.quantity,
    category: input.category,
    reorderThreshold: input.reorderThreshold,
    createdAt: now(),
    updatedAt: now(),
  }
  items.push(item)
  await saveItems(items)
  return item
}

export const updateItem = async (id: string, updates: Partial<NewItemInput>): Promise<InventoryItem> => {
  const items = await loadItems()
  const index = items.findIndex((i) => i.id === id)
  if (index === -1) throw new Error(`Item with id "${id}" not found`)
  if (updates.sku && updates.sku !== items[index].sku) {
    const skuConflict = items.find((i) => i.sku === updates.sku && i.id !== id)
    if (skuConflict) throw new Error(`SKU "${updates.sku}" is already in use`)
  }
  items[index] = { ...items[index], ...updates, updatedAt: now() }
  await saveItems(items)
  return items[index]
}

export const removeItem = async (id: string): Promise<void> => {
  const items = await loadItems()
  const filtered = items.filter((i) => i.id !== id)
  if (filtered.length === items.length) throw new Error(`Item with id "${id}" not found`)
  await saveItems(filtered)
}

export const adjustQuantity = async (id: string, delta: number): Promise<InventoryItem> => {
  const items = await loadItems()
  const index = items.findIndex((i) => i.id === id)
  if (index === -1) throw new Error(`Item with id "${id}" not found`)
  const newQty = items[index].quantity + delta
  if (newQty < 0) throw new Error(`Cannot reduce quantity below 0`)
  items[index].quantity = newQty
  items[index].updatedAt = now()
  await saveItems(items)
  return items[index]
}

export const findBySku = async (sku: string): Promise<InventoryItem | undefined> => {
  const items = await loadItems()
  return items.find((i) => i.sku === sku)
}

export const bulkImport = async (entries: BulkImportEntry[]): Promise<{ imported: number; skipped: string[] }> => {
  const items = await loadItems()
  const existingSkus = new Set(items.map((i) => i.sku))
  const skipped: string[] = []
  const timestamp = now()

  for (const entry of entries) {
    if (existingSkus.has(entry.sku)) {
      skipped.push(entry.sku)
      continue
    }
    items.push({
      id: generateId(),
      name: entry.name,
      sku: entry.sku,
      quantity: entry.quantity,
      category: entry.category,
      reorderThreshold: entry.reorderThreshold,
      createdAt: timestamp,
      updatedAt: timestamp,
    })
    existingSkus.add(entry.sku)
  }

  await saveItems(items)
  return { imported: entries.length - skipped.length, skipped }
}

const sortItems = (items: InventoryItem[], config: SortConfig): InventoryItem[] => {
  const { field, direction } = config
  const multiplier = direction === 'asc' ? 1 : -1
  return [...items].sort((a, b) => {
    const aVal = a[field]
    const bVal = b[field]
    if (typeof aVal === 'string' && typeof bVal === 'string') {
      return multiplier * aVal.localeCompare(bVal)
    }
    if (typeof aVal === 'number' && typeof bVal === 'number') {
      return multiplier * (aVal - bVal)
    }
    return 0
  })
}

export const searchItems = async (params: SearchParams): Promise<InventoryItem[]> => {
  let items = await loadItems()
  if (params.query) {
    const q = params.query.toLowerCase()
    items = items.filter(
      (i) => i.name.toLowerCase().includes(q) || i.sku.toLowerCase().includes(q)
    )
  }
  if (params.category) {
    items = items.filter((i) => i.category === params.category)
  }
  if (params.lowStockOnly) {
    items = items.filter((i) => i.quantity <= i.reorderThreshold)
  }
  if (params.sort) {
    items = sortItems(items, params.sort)
  }
  return items
}

export const getLowStockItems = async (): Promise<InventoryItem[]> => {
  const items = await loadItems()
  return items.filter((i) => i.quantity <= i.reorderThreshold)
}

export const getDashboardStats = async (): Promise<DashboardStats> => {
  const items = await loadItems()
  const categories: Record<string, number> = {}
  let totalQuantity = 0
  let lowStockCount = 0

  for (const item of items) {
    totalQuantity += item.quantity
    categories[item.category] = (categories[item.category] || 0) + 1
    if (item.quantity <= item.reorderThreshold) lowStockCount++
  }

  return {
    totalItems: items.length,
    totalQuantity,
    lowStockCount,
    categories,
  }
}

export const getCategories = async (): Promise<string[]> => {
  const items = await loadItems()
  return [...new Set(items.map((i) => i.category))].sort()
}

