import type { NewItemInput, BulkImportEntry, SortField, SearchParams } from './types'
import {
  addItem,
  removeItem,
  adjustQuantity,
  findBySku,
  bulkImport,
  searchItems,
  getLowStockItems,
  getDashboardStats,
  getCategories,
} from './store'
import { renderDashboard, renderImportPage } from './ui'

const parseFormData = async (req: Request): Promise<Record<string, string>> => {
  const text = await req.text()
  const params = new URLSearchParams(text)
  const result: Record<string, string> = {}
  for (const [key, value] of params.entries()) {
    result[key] = value
  }
  return result
}

const html = (body: string, status = 200): Response =>
  new Response(body, {
    status,
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const redirect = (url: string): Response =>
  new Response(null, { status: 303, headers: { Location: url } })

const json = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data, null, 2), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const VALID_SORT_FIELDS: SortField[] = ['name', 'sku', 'quantity', 'category', 'reorderThreshold']

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const { pathname } = url
  const method = req.method

  // GET / — Dashboard
  if (method === 'GET' && pathname === '/') {
    const query = url.searchParams.get('query') || undefined
    const barcode = url.searchParams.get('barcode') || undefined
    const category = url.searchParams.get('category') || undefined
    const lowStockOnly = url.searchParams.get('lowStockOnly') === 'true'
    const sortParam = url.searchParams.get('sort') as SortField | null
    const msgType = url.searchParams.get('msg') as 'success' | 'error' | null
    const msgText = url.searchParams.get('msgText') || undefined

    // Barcode lookup redirects to search by SKU
    const effectiveQuery = barcode || query

    const searchParams: SearchParams = {
      query: effectiveQuery,
      category,
      lowStockOnly,
    }
    if (sortParam && VALID_SORT_FIELDS.includes(sortParam)) {
      searchParams.sort = { field: sortParam, direction: 'asc' }
    }

    const [items, lowStockItems, stats, categories] = await Promise.all([
      searchItems(searchParams),
      getLowStockItems(),
      getDashboardStats(),
      getCategories(),
    ])

    const message = msgType && msgText ? { type: msgType, text: msgText } : undefined
    return html(renderDashboard(stats, lowStockItems, items, categories, message))
  }

  // GET /import — Import page
  if (method === 'GET' && pathname === '/import') {
    const msgType = url.searchParams.get('msg') as 'success' | 'error' | null
    const msgText = url.searchParams.get('msgText') || undefined
    const message = msgType && msgText ? { type: msgType, text: msgText } : undefined
    return html(renderImportPage(message))
  }

  // POST /items — Add item
  if (method === 'POST' && pathname === '/items') {
    const form = await parseFormData(req)
    const input: NewItemInput = {
      name: form.name?.trim() || '',
      sku: form.sku?.trim() || '',
      quantity: parseInt(form.quantity || '0', 10),
      category: form.category?.trim() || '',
      reorderThreshold: parseInt(form.reorderThreshold || '10', 10),
    }

    if (!input.name || !input.sku || !input.category) {
      return redirect(`/?msg=error&msgText=${encodeURIComponent('Name, SKU, and category are required')}`)
    }

    try {
      await addItem(input)
      return redirect(`/?msg=success&msgText=${encodeURIComponent(`Added "${input.name}" (${input.sku})`)}`)
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Failed to add item'
      return redirect(`/?msg=error&msgText=${encodeURIComponent(message)}`)
    }
  }

  // POST /items/:id/adjust — Adjust quantity
  const adjustMatch = pathname.match(/^\/items\/([^/]+)\/adjust$/)
  if (method === 'POST' && adjustMatch) {
    const id = adjustMatch[1]
    const form = await parseFormData(req)
    const delta = parseInt(form.delta || '0', 10)

    try {
      await adjustQuantity(id, delta)
      return redirect('/')
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Failed to adjust quantity'
      return redirect(`/?msg=error&msgText=${encodeURIComponent(message)}`)
    }
  }

  // POST /items/:id/delete — Remove item
  const deleteMatch = pathname.match(/^\/items\/([^/]+)\/delete$/)
  if (method === 'POST' && deleteMatch) {
    const id = deleteMatch[1]
    try {
      await removeItem(id)
      return redirect(`/?msg=success&msgText=${encodeURIComponent('Item removed')}`)
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Failed to remove item'
      return redirect(`/?msg=error&msgText=${encodeURIComponent(message)}`)
    }
  }

  // POST /import — Bulk import
  if (method === 'POST' && pathname === '/import') {
    const form = await parseFormData(req)
    const jsonData = form.jsonData || ''

    let entries: BulkImportEntry[]
    try {
      entries = JSON.parse(jsonData)
      if (!Array.isArray(entries)) throw new Error('Expected a JSON array')
      for (const entry of entries) {
        if (!entry.name || !entry.sku || typeof entry.quantity !== 'number' || !entry.category || typeof entry.reorderThreshold !== 'number') {
          throw new Error(`Invalid entry: each item needs name, sku, quantity, category, reorderThreshold`)
        }
      }
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Invalid JSON'
      return redirect(`/import?msg=error&msgText=${encodeURIComponent(message)}`)
    }

    const result = await bulkImport(entries)
    const skippedMsg = result.skipped.length > 0 ? ` (skipped ${result.skipped.length} duplicate SKUs)` : ''
    return redirect(`/import?msg=success&msgText=${encodeURIComponent(`Imported ${result.imported} items${skippedMsg}`)}`)
  }

  // API: GET /api/items — JSON search
  if (method === 'GET' && pathname === '/api/items') {
    const query = url.searchParams.get('query') || undefined
    const category = url.searchParams.get('category') || undefined
    const lowStockOnly = url.searchParams.get('lowStockOnly') === 'true'
    const items = await searchItems({ query, category, lowStockOnly })
    return json(items)
  }

  // API: GET /api/items/sku/:sku — Barcode/SKU lookup
  const skuMatch = pathname.match(/^\/api\/items\/sku\/(.+)$/)
  if (method === 'GET' && skuMatch) {
    const sku = decodeURIComponent(skuMatch[1])
    const item = await findBySku(sku)
    if (!item) return json({ error: 'Item not found' }, 404)
    return json(item)
  }

  // API: GET /api/stats — Dashboard stats
  if (method === 'GET' && pathname === '/api/stats') {
    const stats = await getDashboardStats()
    return json(stats)
  }

  // API: GET /api/low-stock — Low stock items
  if (method === 'GET' && pathname === '/api/low-stock') {
    const items = await getLowStockItems()
    return json(items)
  }

  // API: POST /api/import — JSON bulk import
  if (method === 'POST' && pathname === '/api/import') {
    try {
      const entries: BulkImportEntry[] = await req.json()
      if (!Array.isArray(entries)) return json({ error: 'Expected a JSON array' }, 400)
      const result = await bulkImport(entries)
      return json(result)
    } catch {
      return json({ error: 'Invalid JSON body' }, 400)
    }
  }

  return html('<h1>404 Not Found</h1>', 404)
}

import { handleRequest } from './routes'

const PORT = parseInt(process.env.PORT || '3000', 10)

const server = Bun.serve({
  port: PORT,
  fetch: handleRequest,
})

console.log(`Inventory Manager running at http://localhost:${server.port}`)

