export type ConversionResult = {
  value: number
  formatted: string
  formula: string
}

export const convert = (
  value: number,
  fromSymbol: string,
  toSymbol: string,
  category: Category
): ConversionResult => {
  const cat = categories[category]
  const fromUnit = cat.units.find((u) => u.symbol === fromSymbol)
  const toUnit = cat.units.find((u) => u.symbol === toSymbol)

  if (!fromUnit || !toUnit) {
    return { value: NaN, formatted: 'Invalid unit', formula: '' }
  }

  if (fromSymbol === toSymbol) {
    return { value, formatted: formatNumber(value), formula: `1 ${fromSymbol} = 1 ${toSymbol}` }
  }

  const baseValue = fromUnit.toBase(value)
  const result = toUnit.fromBase(baseValue)

  const formula = buildFormula(fromUnit, toUnit, category)

  return {
    value: result,
    formatted: formatNumber(result),
    formula,
  }
}

const formatNumber = (n: number): string => {
  if (Number.isNaN(n)) return 'NaN'
  if (!Number.isFinite(n)) return 'Infinity'
  if (Number.isInteger(n)) return n.toLocaleString()
  const magnitude = Math.abs(n)
  if (magnitude >= 0.01 && magnitude < 1e12) {
    const decimalPlaces = magnitude >= 100 ? 2 : magnitude >= 1 ? 4 : 6
    return parseFloat(n.toFixed(decimalPlaces)).toLocaleString(undefined, { maximumFractionDigits: decimalPlaces })
  }
  return n.toExponential(6)
}

const buildFormula = (
  from: UnitDefinition,
  to: UnitDefinition,
  category: Category
): string => {
  if (category === 'temperature') {
    return buildTemperatureFormula(from.symbol, to.symbol)
  }

  // For non-temperature: compute direct conversion factor
  const factor = to.fromBase(from.toBase(1))
  return `1 ${from.symbol} = ${formatNumber(factor)} ${to.symbol}`
}

const buildTemperatureFormula = (from: string, to: string): string => {
  const formulas: Record<string, string> = {
    'C→F': '°F = (°C × 9/5) + 32',
    'F→C': '°C = (°F - 32) × 5/9',
    'C→K': 'K = °C + 273.15',
    'K→C': '°C = K - 273.15',
    'F→K': 'K = (°F - 32) × 5/9 + 273.15',
    'K→F': '°F = (K - 273.15) × 9/5 + 32',
  }
  return formulas[`${from}→${to}`] ?? `${from} = ${to}`
}

import { categories, convert, type Category, type ConversionResult } from './units.ts'
import { renderConverter, getDefaultUnitsForCategory, defaultState, type ConverterState } from './converter.ts'

export { categories, convert, renderConverter, getDefaultUnitsForCategory, defaultState }
export type { Category, ConversionResult, ConverterState }

// Server entry point
export const handleRequest = (req: Request): Response => {
  const url = new URL(req.url)

  if (url.pathname === '/api/convert') {
    return handleConvertAPI(url)
  }

  const category = (url.searchParams.get('category') ?? 'length') as Category
  const value = url.searchParams.get('value') ?? '1'
  const defaults = getDefaultUnitsForCategory(category)
  const fromUnit = url.searchParams.get('from') ?? defaults.from
  const toUnit = url.searchParams.get('to') ?? defaults.to

  const state: ConverterState = {
    activeCategory: category,
    value,
    fromUnit,
    toUnit,
  }

  const html = renderConverter(state)

  return new Response(html, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })
}

const handleConvertAPI = (url: URL): Response => {
  const category = url.searchParams.get('category') as Category | null
  const value = parseFloat(url.searchParams.get('value') ?? '')
  const from = url.searchParams.get('from') ?? ''
  const to = url.searchParams.get('to') ?? ''

  if (!category || !categories[category]) {
    return Response.json(
      { error: 'Invalid category. Use: length, weight, temperature, volume, time' },
      { status: 400 }
    )
  }

  if (Number.isNaN(value)) {
    return Response.json({ error: 'Invalid value' }, { status: 400 })
  }

  const result = convert(value, from, to, category)

  if (Number.isNaN(result.value)) {
    return Response.json({ error: 'Invalid units for this category' }, { status: 400 })
  }

  return Response.json({
    input: { value, unit: from },
    output: { value: result.value, formatted: result.formatted, unit: to },
    formula: result.formula,
    category,
  })
}

// Bun server bootstrap
if (typeof Bun !== 'undefined') {
  const port = parseInt(process.env.PORT ?? '3000', 10)
  Bun.serve({
    port,
    fetch: handleRequest,
  })
}

