  volume: { label: "Volume", units: volumeUnits },
  time: { label: "Time", units: timeUnits },
};

const convertTemperature = (value: number, from: TempUnit, to: TempUnit): number => {
  if (from === to) return value;

  // Convert to Celsius first
  let celsius: number;
  if (from === "C") celsius = value;
  else if (from === "F") celsius = (value - 32) * 5 / 9;
  else celsius = value - 273.15; // K

  // Convert from Celsius to target
  if (to === "C") return celsius;
  if (to === "F") return celsius * 9 / 5 + 32;
  return celsius + 273.15; // K
};

const getTemperatureFormula = (from: TempUnit, to: TempUnit): string => {
  const formulas: Record<string, string> = {
    "C->F": "°F = °C × 9/5 + 32",
    "C->K": "K = °C + 273.15",
    "F->C": "°C = (°F − 32) × 5/9",
    "F->K": "K = (°F − 32) × 5/9 + 273.15",
    "K->C": "°C = K − 273.15",
    "K->F": "°F = (K − 273.15) × 9/5 + 32",
  };
  if (from === to) return `1 ${from} = 1 ${to}`;
  return formulas[`${from}->${to}`] ?? "";
};

const formatNumber = (n: number): number => {
  return Math.abs(n) < 0.0001 && n !== 0
    ? Number(n.toExponential(6))
    : Number(n.toPrecision(10));
};

export const convert = (
  category: Category,
  fromSymbol: string,
  toSymbol: string,
  value: number,
): ConversionResult => {
  const catDef = categories[category];
  const fromUnit = catDef.units.find((u) => u.symbol === fromSymbol);
  const toUnit = catDef.units.find((u) => u.symbol === toSymbol);

  if (!fromUnit || !toUnit) {
    return {
      from: fromSymbol,
      to: toSymbol,
      inputValue: value,
      outputValue: NaN,
      formula: "Unknown unit",
    };
  }

  if (category === "temperature") {
    const result = convertTemperature(value, fromSymbol as TempUnit, toSymbol as TempUnit);
    return {
      from: fromUnit.symbol,
      to: toUnit.symbol,
      inputValue: value,
      outputValue: formatNumber(result),
      formula: getTemperatureFormula(fromSymbol as TempUnit, toSymbol as TempUnit),
    };
  }

  const factor = fromUnit.toBase / toUnit.toBase;
  const result = value * factor;

  return {
    from: fromUnit.symbol,
    to: toUnit.symbol,
    inputValue: value,
    outputValue: formatNumber(result),
    formula: `1 ${fromUnit.symbol} = ${formatNumber(factor)} ${toUnit.symbol}`,
  };
};

