      { symbol: 'day', name: 'Day' },
      { symbol: 'week', name: 'Week' },
    ],
  },
}

const factorMaps: Record<string, Record<string, number>> = {
  length: lengthToBase,
  weight: weightToBase,
  volume: volumeToBase,
  time: timeToBase,
}

const formatNumber = (n: number): string => {
  if (Number.isInteger(n)) return n.toString()
  const s = n.toPrecision(10)
  return parseFloat(s).toString()
}

const convertTemperature = (value: number, from: string, to: string): ConversionResult => {
  if (from === to) return { value, formula: `${from} = ${to}` }

  const conversions: Record<string, { calc: (v: number) => number; formula: string }> = {
    'C→F': { calc: (v) => v * 9 / 5 + 32, formula: '°F = °C × 9/5 + 32' },
    'C→K': { calc: (v) => v + 273.15, formula: 'K = °C + 273.15' },
    'F→C': { calc: (v) => (v - 32) * 5 / 9, formula: '°C = (°F − 32) × 5/9' },
    'F→K': { calc: (v) => (v - 32) * 5 / 9 + 273.15, formula: 'K = (°F − 32) × 5/9 + 273.15' },
    'K→C': { calc: (v) => v - 273.15, formula: '°C = K − 273.15' },
    'K→F': { calc: (v) => (v - 273.15) * 9 / 5 + 32, formula: '°F = (K − 273.15) × 9/5 + 32' },
  }

  const key = `${from}→${to}`
  const conv = conversions[key]
  if (!conv) return { value: NaN, formula: 'Unknown conversion' }

  return { value: conv.calc(value), formula: conv.formula }
}

const convertByFactor = (
  value: number,
  from: string,
  to: string,
  category: string,
): ConversionResult => {
  const map = factorMaps[category]
  if (!map || !map[from] || !map[to]) return { value: NaN, formula: 'Unknown conversion' }

  if (from === to) return { value, formula: `1 ${from} = 1 ${to}` }

  const factor = map[from] / map[to]
  const result = value * factor
  const formulaFactor = formatNumber(factor)

  return {
    value: result,
    formula: `1 ${from} = ${formulaFactor} ${to}`,
  }
}

export const convert = (
  value: number,
  from: string,
  to: string,
  category: Category,
): ConversionResult => {
  if (category === 'temperature') {
    return convertTemperature(value, from, to)
  }
  return convertByFactor(value, from, to, category)
}

