const formatResult = (n: number): string => {
  if (Number.isNaN(n)) return '—'
  if (Number.isInteger(n)) return n.toLocaleString()
  if (Math.abs(n) < 0.0001 || Math.abs(n) > 1e12) return n.toExponential(6)
  return parseFloat(n.toPrecision(10)).toLocaleString(undefined, { maximumFractionDigits: 8 })
}

export const render = (params: RenderParams = {}): string => {
  const activeCategory: Category = params.category ?? 'length'
  const inputValue = params.value ?? '1'
  const numericValue = parseFloat(inputValue) || 0
  const catDef = categories[activeCategory]
  const fromUnit = params.from ?? catDef.units[0].symbol
  const toUnit = params.to ?? (catDef.units[1]?.symbol ?? catDef.units[0].symbol)

  const result: ConversionResult = convert(numericValue, fromUnit, toUnit, activeCategory)

  const categoryKeys = Object.keys(categories) as Category[]

  const tabElements = categoryKeys.map((key) =>
    h('button', {
      style: key === activeCategory ? styles.tabActive : styles.tab,
      'p-trigger': JSON.stringify({ click: `category-${key}` }),
      type: 'button',
    }, categories[key].label)
  )

  const fromOptions = catDef.units.map((u) =>
    h('option', {
      value: u.symbol,
      ...(u.symbol === fromUnit ? { selected: '' } : {}),
    }, `${u.symbol} — ${u.name}`)
  )

  const toOptions = catDef.units.map((u) =>
    h('option', {
      value: u.symbol,
      ...(u.symbol === toUnit ? { selected: '' } : {}),
    }, `${u.symbol} — ${u.name}`)
  )

  const template = h('div', { style: styles.container },
    h('h1', { style: styles.title }, 'Unit Converter'),
    h('nav', { style: styles.tabs, 'p-target': 'tabs' }, ...tabElements),
    h('div', { style: styles.inputGroup },
      h('label', { style: styles.label }, 'Value'),
      h('input', {
        style: styles.input,
        type: 'number',
        value: inputValue,
        placeholder: 'Enter a value',
        'p-trigger': JSON.stringify({ input: 'value-change' }),
        'p-target': 'value-input',
      }),
    ),
    h('div', { style: styles.row },
      h('div', { style: styles.selectWrap },
        h('label', { style: styles.label }, 'From'),
        h('select', {
          style: styles.select,
          'p-trigger': JSON.stringify({ change: 'from-change' }),
          'p-target': 'from-select',
        }, ...fromOptions),
      ),
      h('button', {
        style: styles.swapBtn,
        type: 'button',
        title: 'Swap units',
        'p-trigger': JSON.stringify({ click: 'swap-units' }),
      }, '\u21C4'),
      h('div', { style: styles.selectWrap },
        h('label', { style: styles.label }, 'To'),
        h('select', {
          style: styles.select,
          'p-trigger': JSON.stringify({ change: 'to-change' }),
