      h('p', { style: styles.formula }, `Formula: ${result.formula}`),
    ),
  )

  return createSSR(template)
}

import { render } from './ui.ts'
import type { Category } from './converter.ts'
import { categories } from './converter.ts'

type State = {
  category: Category
  value: string
  from: string
  to: string
}

const defaultState = (): State => ({
  category: 'length',
  value: '1',
  from: 'mm',
  to: 'cm',
})

const categoryKeys = Object.keys(categories) as Category[]

const handleTrigger = (state: State, trigger: string, payload?: string): State => {
  for (const key of categoryKeys) {
    if (trigger === `category-${key}`) {
      const units = categories[key].units
      return {
        ...state,
        category: key,
        from: units[0].symbol,
        to: units[1]?.symbol ?? units[0].symbol,
      }
    }
  }

  switch (trigger) {
    case 'value-change':
      return { ...state, value: payload ?? state.value }
    case 'from-change':
      return { ...state, from: payload ?? state.from }
    case 'to-change':
      return { ...state, to: payload ?? state.to }
    case 'swap-units':
      return { ...state, from: state.to, to: state.from }
    default:
      return state
  }
}

const serve = Bun.serve({
  port: Number(process.env.PORT) || 3000,
  fetch: async (req) => {
    const url = new URL(req.url)

    if (url.pathname === '/' && req.method === 'GET') {
      const state = defaultState()
      const html = render(state)
      return new Response(html, {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      })
    }

    if (url.pathname === '/convert' && req.method === 'POST') {
      const body = await req.json() as { state: State; trigger: string; payload?: string }
      const newState = handleTrigger(body.state, body.trigger, body.payload)
      const html = render(newState)
      return Response.json({ html, state: newState })
    }

    return new Response('Not Found', { status: 404 })
  },
})

