import type { ForumData, Thread, Reply, Vote, SortMode } from './types'

const DATA_PATH = './data/forum.json'

const generateId = (): string => crypto.randomUUID()

const loadData = async (): Promise<ForumData> => {
  const file = Bun.file(DATA_PATH)
  if (await file.exists()) {
    return file.json()
  }
  return { threads: [] }
}

const saveData = async (data: ForumData): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(data, null, 2))
}

const getVoteScore = (votes: Vote[]): number =>
  votes.reduce((sum, v) => sum + v.value, 0)

const getLatestActivity = (thread: Thread): string => {
  if (thread.replies.length === 0) return thread.createdAt
  return thread.replies.reduce((latest, r) =>
    r.createdAt > latest ? r.createdAt : latest,
    thread.createdAt
  )
}

export const getThreads = async (
  sort: SortMode = 'newest',
  search?: string
): Promise<Thread[]> => {
  const data = await loadData()
  let threads = data.threads

  if (search && search.trim()) {
    const query = search.toLowerCase().trim()
    threads = threads.filter(t =>
      t.title.toLowerCase().includes(query)
    )
  }

  switch (sort) {
    case 'newest':
      return threads.sort((a, b) =>
        new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
      )
    case 'most-upvoted':
      return threads.sort((a, b) =>
        getVoteScore(b.votes) - getVoteScore(a.votes)
      )
    case 'most-active':
      return threads.sort((a, b) =>
        new Date(getLatestActivity(b)).getTime() - new Date(getLatestActivity(a)).getTime()
      )
    default:
      return threads
  }
}

export const getThread = async (id: string): Promise<Thread | null> => {
  const data = await loadData()
  return data.threads.find(t => t.id === id) ?? null
}

export const createThread = async (
  title: string,
  body: string,
  author: string
): Promise<Thread> => {
  const data = await loadData()
  const thread: Thread = {
    id: generateId(),
    title: title.trim(),
    body: body.trim(),
    author: author.trim(),
    createdAt: new Date().toISOString(),
    votes: [],
    replies: [],
  }
  data.threads.push(thread)
  await saveData(data)
  return thread
}

export const createReply = async (
  threadId: string,
  body: string,
  author: string,
  parentReplyId: string | null = null
): Promise<Reply | null> => {
  const data = await loadData()
  const thread = data.threads.find(t => t.id === threadId)
  if (!thread) return null

  if (parentReplyId) {
    const parentReply = thread.replies.find(r => r.id === parentReplyId)
    if (!parentReply) return null
    if (parentReply.parentReplyId !== null) return null
  }

  const reply: Reply = {
    id: generateId(),
    threadId,
    parentReplyId,
    body: body.trim(),
    author: author.trim(),
    createdAt: new Date().toISOString(),
    votes: [],
  }
  thread.replies.push(reply)
  await saveData(data)
  return reply
}

export const voteOnThread = async (
  threadId: string,
  userId: string,
  value: 1 | -1
): Promise<Thread | null> => {
  const data = await loadData()
  const thread = data.threads.find(t => t.id === threadId)
  if (!thread) return null

  const existing = thread.votes.findIndex(v => v.userId === userId)
  if (existing >= 0) {
    if (thread.votes[existing].value === value) {
      thread.votes.splice(existing, 1)
    } else {
      thread.votes[existing].value = value
    }
  } else {
    thread.votes.push({ userId, value })
  }
  await saveData(data)
  return thread
}

export const voteOnReply = async (
  threadId: string,
  replyId: string,
  userId: string,
  value: 1 | -1
): Promise<Reply | null> => {
  const data = await loadData()
  const thread = data.threads.find(t => t.id === threadId)
  if (!thread) return null

  const reply = thread.replies.find(r => r.id === replyId)
  if (!reply) return null

  const existing = reply.votes.findIndex(v => v.userId === userId)
  if (existing >= 0) {
    if (reply.votes[existing].value === value) {
      reply.votes.splice(existing, 1)
    } else {
      reply.votes[existing].value = value
    }
  } else {
    reply.votes.push({ userId, value })
  }
  await saveData(data)
  return reply
}

