import type { SortMode } from './types'
import {
  getThreads,
  getThread,
  createThread,
  createReply,
  voteOnThread,
  voteOnReply,
} from './store'
import {
  renderThreadList,
  renderThreadDetail,
  renderNewThreadForm,
} from './render'

type RouteResult = {
  html?: string
  json?: unknown
  status?: number
  error?: string
}

export const handleRequest = async (
  method: string,
  path: string,
  params: Record<string, string>,
  body?: Record<string, unknown>
): Promise<RouteResult> => {

  // GET / — thread list
  if (method === 'GET' && (path === '/' || path === '/threads')) {
    const sort = (params.sort as SortMode) || 'newest'
    const search = params.search || ''
    const threads = await getThreads(sort, search)
    return { html: renderThreadList(threads, sort, search) }
  }

  // GET /threads/new — new thread form
  if (method === 'GET' && path === '/threads/new') {
    return { html: renderNewThreadForm() }
  }

  // GET /threads/:id — thread detail
  if (method === 'GET' && path.startsWith('/threads/')) {
    const id = path.replace('/threads/', '')
    const thread = await getThread(id)
    if (!thread) return { status: 404, error: 'Thread not found' }
    return { html: renderThreadDetail(thread) }
  }

  // POST /threads — create thread
  if (method === 'POST' && path === '/threads') {
    const { title, body: threadBody, author } = body as Record<string, string>
    if (!title?.trim() || !threadBody?.trim() || !author?.trim()) {
      return { status: 400, error: 'Title, body, and author are required' }
    }
    const thread = await createThread(title, threadBody, author)
    return { json: thread, status: 201 }
  }

  // POST /threads/:id/replies — create reply
  if (method === 'POST' && path.match(/^\/threads\/[^/]+\/replies$/)) {
    const threadId = path.split('/')[2]
    const { body: replyBody, author, parentReplyId } = body as Record<string, string>
    if (!replyBody?.trim() || !author?.trim()) {
      return { status: 400, error: 'Body and author are required' }
    }
    const reply = await createReply(threadId, replyBody, author, parentReplyId || null)
    if (!reply) return { status: 404, error: 'Thread or parent reply not found' }
    return { json: reply, status: 201 }
  }

  // POST /threads/:id/vote — vote on thread
  if (method === 'POST' && path.match(/^\/threads\/[^/]+\/vote$/)) {
    const threadId = path.split('/')[2]
    const { userId, value } = body as { userId: string; value: number }
    if (!userId || (value !== 1 && value !== -1)) {
      return { status: 400, error: 'userId and value (1 or -1) are required' }
    }
    const thread = await voteOnThread(threadId, userId, value as 1 | -1)
    if (!thread) return { status: 404, error: 'Thread not found' }
    return { json: thread }
  }

  // POST /threads/:id/replies/:replyId/vote — vote on reply
  if (method === 'POST' && path.match(/^\/threads\/[^/]+\/replies\/[^/]+\/vote$/)) {
    const parts = path.split('/')
    const threadId = parts[2]
    const replyId = parts[4]
    const { userId, value } = body as { userId: string; value: number }
    if (!userId || (value !== 1 && value !== -1)) {
      return { status: 400, error: 'userId and value (1 or -1) are required' }
    }
    const reply = await voteOnReply(threadId, replyId, userId, value as 1 | -1)
    if (!reply) return { status: 404, error: 'Thread or reply not found' }
    return { json: reply }
  }

  return { status: 404, error: 'Not found' }
}

import { handleRequest } from './routes'

const parseBody = async (req: Request): Promise<Record<string, unknown> | undefined> => {
  const contentType = req.headers.get('content-type') || ''
  if (contentType.includes('application/json')) {
    return req.json()
  }
  if (contentType.includes('application/x-www-form-urlencoded')) {
    const text = await req.text()
    const params = new URLSearchParams(text)
    const result: Record<string, string> = {}
    params.forEach((v, k) => { result[k] = v })
    return result
  }
  return undefined
}

const server = Bun.serve({
  port: Number(process.env.PORT) || 3000,
  fetch: async (req) => {
    const url = new URL(req.url)
    const method = req.method
    const path = url.pathname
    const params: Record<string, string> = {}
    url.searchParams.forEach((v, k) => { params[k] = v })

    const body = method === 'POST' ? await parseBody(req) : undefined
    const result = await handleRequest(method, path, params, body)

    if (result.error) {
      return new Response(JSON.stringify({ error: result.error }), {
        status: result.status || 500,
        headers: { 'Content-Type': 'application/json' },
      })
    }

    if (result.html) {
      const page = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Discussion Forum</title>
  <style>
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    body { background: #f8f9fa; }
    a { color: inherit; text-decoration: none; }
    button { cursor: pointer; }
    input, textarea { font-family: inherit; }
  </style>
</head>
<body>${result.html}</body>
</html>`
      return new Response(page, {
        status: result.status || 200,
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      })
    }

    if (result.json) {
      return new Response(JSON.stringify(result.json), {
        status: result.status || 200,
        headers: { 'Content-Type': 'application/json' },
      })
    }

    return new Response('Not Found', { status: 404 })
  },
})

