import type { Thread, ForumState, CreateThreadInput, CreateReplyInput, VoteInput, Reply, SortMode } from './types'

const DATA_PATH = `${import.meta.dir}/data/threads.json`

const generateId = (): string => crypto.randomUUID()

const readState = async (): Promise<ForumState> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return { threads: [] }
  const threads = await file.json() as Thread[]
  return { threads }
}

const writeState = async (state: ForumState): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(state.threads, null, 2))
}

export const getThreads = async (): Promise<Thread[]> => {
  const state = await readState()
  return state.threads
}

export const getThread = async (id: string): Promise<Thread | undefined> => {
  const state = await readState()
  return state.threads.find(t => t.id === id)
}

export const createThread = async (input: CreateThreadInput): Promise<Thread> => {
  const state = await readState()
  const thread: Thread = {
    id: generateId(),
    title: input.title,
    body: input.body,
    author: input.author,
    votes: [],
    replies: [],
    createdAt: new Date().toISOString(),
  }
  state.threads.push(thread)
  await writeState(state)
  return thread
}

export const createReply = async (input: CreateReplyInput): Promise<Reply | null> => {
  const state = await readState()
  const thread = state.threads.find(t => t.id === input.threadId)
  if (!thread) return null

  if (input.parentReplyId) {
    const parentReply = thread.replies.find(r => r.id === input.parentReplyId)
    if (!parentReply) return null
    if (parentReply.parentReplyId !== null) return null // enforce one level deep
  }

  const reply: Reply = {
    id: generateId(),
    threadId: input.threadId,
    parentReplyId: input.parentReplyId,
    author: input.author,
    body: input.body,
    votes: [],
    createdAt: new Date().toISOString(),
  }
  thread.replies.push(reply)
  await writeState(state)
  return reply
}

export const vote = async (input: VoteInput): Promise<boolean> => {
  const state = await readState()
  const thread = state.threads.find(t => t.id === input.threadId)
  if (!thread) return false

  const isThreadVote = input.targetId === input.threadId
  const target = isThreadVote
    ? thread
    : thread.replies.find(r => r.id === input.targetId)

  if (!target) return false

  const existingIdx = target.votes.findIndex(v => v.userId === input.userId)
  if (existingIdx !== -1) {
    if (target.votes[existingIdx].value === input.value) {
      target.votes.splice(existingIdx, 1) // toggle off
    } else {
      target.votes[existingIdx].value = input.value // flip vote
    }
  } else {
    target.votes.push({ userId: input.userId, value: input.value })
  }

  await writeState(state)
  return true
}

export const getVoteScore = (votes: { value: 1 | -1 }[]): number =>
  votes.reduce((sum, v) => sum + v.value, 0)

export const sortThreads = (threads: Thread[], mode: SortMode): Thread[] => {
  const sorted = [...threads]
  switch (mode) {
    case 'newest':
      return sorted.sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime())
    case 'most-upvoted':
      return sorted.sort((a, b) => getVoteScore(b.votes) - getVoteScore(a.votes))
    case 'most-active':
      return sorted.sort((a, b) => b.replies.length - a.replies.length)
  }
}

export const searchThreads = (threads: Thread[], query: string): Thread[] => {
  const lower = query.toLowerCase()
  return threads.filter(t => t.title.toLowerCase().includes(lower))
}

