const parseBody = async (req: Request): Promise<Record<string, string>> => {
  const contentType = req.headers.get('content-type') ?? ''
  if (contentType.includes('application/json')) {
    return await req.json() as Record<string, string>
  }
  const form = await req.formData()
  const result: Record<string, string> = {}
  form.forEach((v, k) => { result[k] = String(v) })
  return result
}

export const startServer = (port = 3000) => {
  const server = Bun.serve({
    port,
    fetch: async (req) => {
      const url = new URL(req.url)
      const path = url.pathname
      const method = req.method

      // Thread list view
      if (path === '/' && method === 'GET') {
        const sortMode = (url.searchParams.get('sort') ?? 'newest') as SortMode
        const search = url.searchParams.get('q') ?? ''
        let threads = await getThreads()
        if (search) threads = searchThreads(threads, search)
        threads = sortThreads(threads, sortMode)
        return html(renderThreadList(threads, sortMode, search))
      }

      // New thread form
      if (path === '/new' && method === 'GET') {
        return html(renderNewThreadForm())
      }

      // Create thread
      if (path === '/threads' && method === 'POST') {
        const body = await parseBody(req)
        const thread = await createThread({
          title: body.title ?? '',
          body: body.body ?? '',
          author: body.author ?? 'Anonymous',
        })
        return json(thread, 201)
      }

      // View thread
      const threadMatch = path.match(/^\/threads\/([^/]+)$/)
      if (threadMatch && method === 'GET') {
        const thread = await getThread(threadMatch[1])
        if (!thread) return json({ error: 'Thread not found' }, 404)
        return html(renderThreadDetail(thread))
      }

      // Reply form
      const replyFormMatch = path.match(/^\/threads\/([^/]+)\/reply-form$/)
      if (replyFormMatch && method === 'GET') {
        const parentReplyId = url.searchParams.get('parentReplyId') ?? null
        return html(renderReplyForm(replyFormMatch[1], parentReplyId))
      }

      // Create reply
      const replyMatch = path.match(/^\/threads\/([^/]+)\/replies$/)
      if (replyMatch && method === 'POST') {
        const body = await parseBody(req)
        const reply = await createReply({
          threadId: replyMatch[1],
          parentReplyId: body.parentReplyId === 'null' ? null : (body.parentReplyId ?? null),
          author: body.author ?? 'Anonymous',
          body: body.body ?? '',
        })
        if (!reply) return json({ error: 'Thread or parent reply not found' }, 404)
        return json(reply, 201)
      }

      // Vote
      const voteMatch = path.match(/^\/threads\/([^/]+)\/vote$/)
      if (voteMatch && method === 'POST') {
        const body = await parseBody(req)
        const success = await vote({
          threadId: voteMatch[1],
          targetId: body.targetId ?? voteMatch[1],
          userId: body.userId ?? 'anonymous',
          value: body.value === '-1' ? -1 : 1,
        })
        if (!success) return json({ error: 'Target not found' }, 404)
        return json({ success: true })
      }

      // API: list threads (JSON)
      if (path === '/api/threads' && method === 'GET') {
        const sortMode = (url.searchParams.get('sort') ?? 'newest') as SortMode
        const search = url.searchParams.get('q') ?? ''
        let threads = await getThreads()
        if (search) threads = searchThreads(threads, search)
        threads = sortThreads(threads, sortMode)
        return json(threads)
      }

      return json({ error: 'Not found' }, 404)
    },
  })

  console.log(`Discussion Forum running at http://localhost:${port}`)
  return server
}

