const DATA_DIR = import.meta.dir + '/data'

const readJson = async <T>(filename: string): Promise<T[]> => {
  const file = Bun.file(`${DATA_DIR}/${filename}`)
  const exists = await file.exists()
  if (!exists) return []
  const text = await file.text()
  return JSON.parse(text) as T[]
}

const writeJson = async <T>(filename: string, data: T[]): Promise<void> => {
  await Bun.write(`${DATA_DIR}/${filename}`, JSON.stringify(data, null, 2))
}

export const getThreadsStore = () => readJson<Thread>('threads.json')
export const setThreadsStore = (threads: Thread[]) => writeJson('threads.json', threads)

export const getRepliesStore = () => readJson<Reply>('replies.json')
export const setRepliesStore = (replies: Reply[]) => writeJson('replies.json', replies)

export const getVotesStore = () => readJson<Vote>('votes.json')
export const setVotesStore = (votes: Vote[]) => writeJson('votes.json', votes)

