  getThreadsStore,
  setThreadsStore,
  getRepliesStore,
  setRepliesStore,
  getVotesStore,
  setVotesStore,
} from './store'

const generateId = (): string => crypto.randomUUID()

export const createThread = async (input: CreateThreadInput): Promise<Thread> => {
  const threads = await getThreadsStore()
  const now = new Date().toISOString()
  const thread: Thread = {
    id: generateId(),
    title: input.title,
    body: input.body,
    author: input.author,
    createdAt: now,
    upvotes: 0,
    downvotes: 0,
    score: 0,
    replyCount: 0,
    lastActivityAt: now,
  }
  threads.push(thread)
  await setThreadsStore(threads)
  return thread
}

export const getThread = async (threadId: string): Promise<Thread | undefined> => {
  const threads = await getThreadsStore()
  return threads.find((t) => t.id === threadId)
}

export const getThreads = async (options: GetThreadsOptions = {}): Promise<Thread[]> => {
  const { sort = 'newest', search } = options
  let threads = await getThreadsStore()

  if (search) {
    const query = search.toLowerCase()
    threads = threads.filter((t) => t.title.toLowerCase().includes(query))
  }

  return sortThreads(threads, sort)
}

const sortThreads = (threads: Thread[], mode: SortMode): Thread[] => {
  const sorted = [...threads]
  switch (mode) {
    case 'newest':
      return sorted.sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime())
    case 'most-upvoted':
      return sorted.sort((a, b) => b.score - a.score)
    case 'most-active':
      return sorted.sort((a, b) => new Date(b.lastActivityAt).getTime() - new Date(a.lastActivityAt).getTime())
  }
}

export const replyToThread = async (input: CreateReplyInput): Promise<Reply> => {
  const threads = await getThreadsStore()
  const threadIndex = threads.findIndex((t) => t.id === input.threadId)
  if (threadIndex === -1) throw new Error(`Thread not found: ${input.threadId}`)

  if (input.parentId) {
    const replies = await getRepliesStore()
    const parent = replies.find((r) => r.id === input.parentId)
    if (!parent) throw new Error(`Parent reply not found: ${input.parentId}`)
    if (parent.parentId !== null) throw new Error('Cannot nest replies more than one level deep')
  }

  const now = new Date().toISOString()
  const reply: Reply = {
    id: generateId(),
    threadId: input.threadId,
    parentId: input.parentId ?? null,
    body: input.body,
    author: input.author,
    createdAt: now,
    upvotes: 0,
    downvotes: 0,
    score: 0,
  }

  const replies = await getRepliesStore()
  replies.push(reply)
  await setRepliesStore(replies)

  threads[threadIndex].replyCount += 1
  threads[threadIndex].lastActivityAt = now
  await setThreadsStore(threads)

  return reply
}

export const getRepliesForThread = async (threadId: string): Promise<Reply[]> => {
  const replies = await getRepliesStore()
  return replies
    .filter((r) => r.threadId === threadId)
    .sort((a, b) => new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime())
}

export const vote = async (input: VoteInput): Promise<void> => {
  const votes = await getVotesStore()

  const existingIndex = votes.findIndex(
    (v) => v.targetId === input.targetId && v.voterId === input.voterId
  )

  if (existingIndex !== -1) {
    const existing = votes[existingIndex]
    if (existing.direction === input.direction) {
      votes.splice(existingIndex, 1)
    } else {
      votes[existingIndex] = { ...existing, direction: input.direction }
    }
  } else {
    votes.push({
      id: generateId(),
      targetId: input.targetId,
      targetType: input.targetType,
      direction: input.direction,
      voterId: input.voterId,
    })
  }

  await setVotesStore(votes)
  await recalculateScore(input.targetId, input.targetType)
}

const recalculateScore = async (targetId: string, targetType: 'thread' | 'reply'): Promise<void> => {
  const votes = await getVotesStore()
  const targetVotes = votes.filter((v) => v.targetId === targetId)
  const upvotes = targetVotes.filter((v) => v.direction === 'up').length
  const downvotes = targetVotes.filter((v) => v.direction === 'down').length
  const score = upvotes - downvotes

  if (targetType === 'thread') {
    const threads = await getThreadsStore()
    const index = threads.findIndex((t) => t.id === targetId)
    if (index !== -1) {
      threads[index].upvotes = upvotes
      threads[index].downvotes = downvotes
      threads[index].score = score
      await setThreadsStore(threads)
    }
  } else {
    const replies = await getRepliesStore()
    const index = replies.findIndex((r) => r.id === targetId)
    if (index !== -1) {
      replies[index].upvotes = upvotes
      replies[index].downvotes = downvotes
      replies[index].score = score
      await setRepliesStore(replies)
    }
  }
}

export const deleteThread = async (threadId: string): Promise<void> => {
  const threads = await getThreadsStore()
  const filtered = threads.filter((t) => t.id !== threadId)
  await setThreadsStore(filtered)

  const replies = await getRepliesStore()
  const filteredReplies = replies.filter((r) => r.threadId !== threadId)
  await setRepliesStore(filteredReplies)

  const votes = await getVotesStore()
  const replyIds = replies.filter((r) => r.threadId === threadId).map((r) => r.id)
  const targetIds = new Set([threadId, ...replyIds])
  const filteredVotes = votes.filter((v) => !targetIds.has(v.targetId))
  await setVotesStore(filteredVotes)
}

