            style: { ...styles.textarea, minHeight: '60px' },
            'p-trigger': 'reply-body-input',
            'p-target': 'reply-body',
          }),
        ),
        h('button', {
          style: styles.submitButton,
          'p-trigger': 'submit-reply',
        }, 'Reply'),
      ),
      topLevel.length > 0
        ? h(Fragment, {},
            ...topLevel.map((reply) => renderReplyItem(reply, getChildren(reply.id))),
          )
        : h('div', { style: { ...styles.emptyState, padding: '20px' } },
            'No replies yet. Be the first to respond!',
          ),
    ),
  )
}

import { createSSR } from 'plaited'
import {
  createThread,
  getThread,
  getThreads,
  getRepliesForThread,
  replyToThread,
  vote,
  deleteThread,
} from './forum'
import {
  renderThreadList,
  renderThreadDetail,
  renderCreateThreadForm,
} from './ui'
import type { SortMode, VoteInput, CreateThreadInput, CreateReplyInput } from './types'

const ssr = createSSR()

const renderPage = (content: string): string => `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Discussion Forum</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { background: #f9fafb; min-height: 100vh; }
  </style>
</head>
<body>${content}</body>
</html>`

const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const path = url.pathname

  // API routes
  if (path.startsWith('/api/')) {
    return handleApi(req, path)
  }

  // Page routes
  if (path === '/' || path === '/threads') {
    const sort = (url.searchParams.get('sort') as SortMode) || 'newest'
    const search = url.searchParams.get('search') || ''
    const threads = await getThreads({ sort, search })
    const html = ssr(renderThreadList(threads, sort, search))
    return new Response(renderPage(html), { headers: { 'Content-Type': 'text/html' } })
  }

  if (path === '/threads/new') {
    const html = ssr(renderCreateThreadForm())
    return new Response(renderPage(html), { headers: { 'Content-Type': 'text/html' } })
  }

  const threadMatch = path.match(/^\/threads\/([a-f0-9-]+)$/)
  if (threadMatch) {
    const thread = await getThread(threadMatch[1])
    if (!thread) return new Response('Thread not found', { status: 404 })
    const replies = await getRepliesForThread(thread.id)
    const html = ssr(renderThreadDetail(thread, replies))
    return new Response(renderPage(html), { headers: { 'Content-Type': 'text/html' } })
  }

  return new Response('Not Found', { status: 404 })
}

const handleApi = async (req: Request, path: string): Promise<Response> => {
  const json = <T>() => req.json() as Promise<T>
  const respond = (data: unknown, status = 200) =>
    new Response(JSON.stringify(data), {
      status,
      headers: { 'Content-Type': 'application/json' },
    })

  // POST /api/threads — create a thread
  if (path === '/api/threads' && req.method === 'POST') {
    const input = await json<CreateThreadInput>()
    if (!input.title?.trim() || !input.body?.trim() || !input.author?.trim()) {
      return respond({ error: 'title, body, and author are required' }, 400)
    }
    const thread = await createThread(input)
    return respond(thread, 201)
  }

  // GET /api/threads — list threads
  if (path === '/api/threads' && req.method === 'GET') {
    const url = new URL(req.url)
    const sort = (url.searchParams.get('sort') as SortMode) || 'newest'
    const search = url.searchParams.get('search') || ''
    const threads = await getThreads({ sort, search })
    return respond(threads)
  }

  // GET /api/threads/:id — get single thread with replies
  const threadGetMatch = path.match(/^\/api\/threads\/([a-f0-9-]+)$/)
  if (threadGetMatch && req.method === 'GET') {
    const thread = await getThread(threadGetMatch[1])
    if (!thread) return respond({ error: 'Thread not found' }, 404)
    const replies = await getRepliesForThread(thread.id)
    return respond({ thread, replies })
  }

  // DELETE /api/threads/:id — delete a thread
  const threadDeleteMatch = path.match(/^\/api\/threads\/([a-f0-9-]+)$/)
  if (threadDeleteMatch && req.method === 'DELETE') {
    await deleteThread(threadDeleteMatch[1])
    return respond({ ok: true })
  }

  // POST /api/threads/:id/replies — reply to a thread
  const replyMatch = path.match(/^\/api\/threads\/([a-f0-9-]+)\/replies$/)
  if (replyMatch && req.method === 'POST') {
    const input = await json<Omit<CreateReplyInput, 'threadId'>>()
    if (!input.body?.trim() || !input.author?.trim()) {
      return respond({ error: 'body and author are required' }, 400)
    }
    const reply = await replyToThread({ ...input, threadId: replyMatch[1] })
    return respond(reply, 201)
  }

  // POST /api/vote — vote on a thread or reply
  if (path === '/api/vote' && req.method === 'POST') {
    const input = await json<VoteInput>()
    if (!input.targetId || !input.targetType || !input.direction || !input.voterId) {
      return respond({ error: 'targetId, targetType, direction, and voterId are required' }, 400)
    }
    if (!['up', 'down'].includes(input.direction)) {
      return respond({ error: 'direction must be "up" or "down"' }, 400)
    }
    if (!['thread', 'reply'].includes(input.targetType)) {
      return respond({ error: 'targetType must be "thread" or "reply"' }, 400)
    }
    await vote(input)
    return respond({ ok: true })
  }

  return new Response(JSON.stringify({ error: 'Not found' }), {
    status: 404,
    headers: { 'Content-Type': 'application/json' },
  })
}

export default {
  port: 3000,
  fetch: handleRequest,
}

