const WEATHER_ICONS: Record<string, string> = {
  '01d': '\u2600\uFE0F', '01n': '\uD83C\uDF19',
  '02d': '\u26C5', '02n': '\uD83C\uDF19',
  '03d': '\u2601\uFE0F', '03n': '\u2601\uFE0F',
  '04d': '\uD83C\uDF25\uFE0F', '04n': '\uD83C\uDF25\uFE0F',
  '09d': '\uD83C\uDF27\uFE0F', '09n': '\uD83C\uDF27\uFE0F',
  '10d': '\uD83C\uDF26\uFE0F', '10n': '\uD83C\uDF27\uFE0F',
  '11d': '\u26C8\uFE0F', '11n': '\u26C8\uFE0F',
  '13d': '\u2744\uFE0F', '13n': '\u2744\uFE0F',
  '50d': '\uD83C\uDF2B\uFE0F', '50n': '\uD83C\uDF2B\uFE0F',
}

const getIconEmoji = (iconCode: string): string => WEATHER_ICONS[iconCode] ?? '\u2601\uFE0F'

const CITY_DATA: Record<string, { lat: number; lon: number; country: string; baseTemp: number; conditions: string[] }> = {
  london: { lat: 51.51, lon: -0.13, country: 'GB', baseTemp: 12, conditions: ['overcast clouds', 'light rain', 'broken clouds', 'few clouds', 'moderate rain'] },
  'new york': { lat: 40.71, lon: -74.01, country: 'US', baseTemp: 18, conditions: ['clear sky', 'few clouds', 'scattered clouds', 'light rain', 'clear sky'] },
  tokyo: { lat: 35.68, lon: 139.69, country: 'JP', baseTemp: 22, conditions: ['few clouds', 'clear sky', 'scattered clouds', 'light rain', 'broken clouds'] },
  paris: { lat: 48.86, lon: 2.35, country: 'FR', baseTemp: 15, conditions: ['scattered clouds', 'clear sky', 'overcast clouds', 'light rain', 'few clouds'] },
  sydney: { lat: -33.87, lon: 151.21, country: 'AU', baseTemp: 25, conditions: ['clear sky', 'few clouds', 'clear sky', 'scattered clouds', 'light rain'] },
}

const DEFAULT_CITY = { lat: 0, lon: 0, country: 'XX', baseTemp: 20, conditions: ['clear sky', 'few clouds', 'scattered clouds', 'broken clouds', 'overcast clouds'] }

const conditionToIcon = (desc: string): string => {
  if (desc.includes('clear')) return '01d'
  if (desc.includes('few clouds')) return '02d'
  if (desc.includes('scattered')) return '03d'
  if (desc.includes('broken') || desc.includes('overcast')) return '04d'
  if (desc.includes('rain')) return '10d'
  if (desc.includes('thunder')) return '11d'
  if (desc.includes('snow')) return '13d'
  if (desc.includes('mist') || desc.includes('fog')) return '50d'
  return '03d'
}

const generateCurrentWeather = (city: string): CurrentWeather => {
  const key = city.toLowerCase()
  const info = CITY_DATA[key] ?? DEFAULT_CITY
  const temp = info.baseTemp + Math.round((Math.random() - 0.5) * 6)
  const iconCode = conditionToIcon(info.conditions[0])

  return {
    coord: { lon: info.lon, lat: info.lat },
    weather: [{
      id: 800,
      main: info.conditions[0].split(' ').map(w => w[0].toUpperCase() + w.slice(1)).join(' '),
      description: info.conditions[0],
      icon: iconCode,
    }],
    main: {
      temp,
      feels_like: temp - 2,
      temp_min: temp - 3,
      temp_max: temp + 3,
      pressure: 1013 + Math.round((Math.random() - 0.5) * 20),
      humidity: 50 + Math.round(Math.random() * 40),
    },
    visibility: 10000,
    wind: { speed: 3 + Math.round(Math.random() * 8), deg: Math.round(Math.random() * 360) },
    clouds: { all: Math.round(Math.random() * 100) },
    dt: Math.floor(Date.now() / 1000),
    sys: {
      country: info.country,
      sunrise: Math.floor(Date.now() / 1000) - 21600,
      sunset: Math.floor(Date.now() / 1000) + 21600,
    },
    name: city.split(' ').map(w => w[0].toUpperCase() + w.slice(1)).join(' '),
  }
}

const generateForecast = (city: string): ForecastResponse => {
  const key = city.toLowerCase()
  const info = CITY_DATA[key] ?? DEFAULT_CITY
  const now = Date.now()
  const list: ForecastEntry[] = []

  for (let day = 0; day < 5; day++) {
    for (let hour = 0; hour < 24; hour += 3) {
      const dt = Math.floor((now + (day * 86400000) + (hour * 3600000)) / 1000)
      const date = new Date(dt * 1000)
      const tempVariation = Math.sin((hour - 6) * Math.PI / 12) * 5
      const dayVariation = (Math.random() - 0.5) * 4
      const temp = Math.round((info.baseTemp + tempVariation + dayVariation) * 10) / 10
      const condition = info.conditions[day % info.conditions.length]
      const iconCode = conditionToIcon(condition)

      list.push({
        dt,
        main: {
          temp,
          feels_like: temp - 1,
          temp_min: temp - 2,
          temp_max: temp + 2,
          pressure: 1013,
          humidity: 55 + Math.round(Math.random() * 30),
        },
        weather: [{
          id: 800,
          main: condition.split(' ').map(w => w[0].toUpperCase() + w.slice(1)).join(' '),
          description: condition,
          icon: iconCode,
        }],
        wind: { speed: 2 + Math.round(Math.random() * 6), deg: Math.round(Math.random() * 360) },
        dt_txt: date.toISOString().replace('T', ' ').slice(0, 19),
      })
    }
  }

  return {
    list,
    city: {
      name: city.split(' ').map(w => w[0].toUpperCase() + w.slice(1)).join(' '),
      country: info.country,
      coord: { lat: info.lat, lon: info.lon },
    },
  }
}

const aggregateDailyForecasts = (forecast: ForecastResponse): DailyForecast[] => {
  const dayMap = new Map<string, { temps: number[]; conditions: string[]; icons: string[] }>()
  const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat']

  for (const entry of forecast.list) {
    const date = new Date(entry.dt * 1000)
    const dateKey = date.toISOString().slice(0, 10)

    if (!dayMap.has(dateKey)) {
      dayMap.set(dateKey, { temps: [], conditions: [], icons: [] })
    }
    const bucket = dayMap.get(dateKey)!
    bucket.temps.push(entry.main.temp)
    bucket.conditions.push(entry.weather[0].description)
    bucket.icons.push(entry.weather[0].icon)
  }

  const dailies: DailyForecast[] = []
  for (const [dateKey, bucket] of dayMap) {
    const date = new Date(dateKey)
    dailies.push({
      date: dateKey,
      dayName: dayNames[date.getDay()],
      tempMin: Math.round(Math.min(...bucket.temps)),
      tempMax: Math.round(Math.max(...bucket.temps)),
      description: bucket.conditions[Math.floor(bucket.conditions.length / 2)],
      icon: bucket.icons[Math.floor(bucket.icons.length / 2)],
    })
  }

  return dailies.slice(0, 5)
}

export const getWeatherData = (city: string): WeatherDashboardData => {
  const current = generateCurrentWeather(city)
  const forecast = generateForecast(city)
  const daily = aggregateDailyForecasts(forecast)
  return { current, forecast, daily }
}

