type ChartPoint = { x: number; y: number; label: string; value: number }

const SVG_WIDTH = 500
const SVG_HEIGHT = 200
const PADDING = { top: 30, right: 30, bottom: 40, left: 50 }

const plotWidth = SVG_WIDTH - PADDING.left - PADDING.right
const plotHeight = SVG_HEIGHT - PADDING.top - PADDING.bottom

const mapPoints = (values: number[], labels: string[]): ChartPoint[] => {
  const min = Math.min(...values) - 2
  const max = Math.max(...values) + 2
  const range = max - min || 1

  return values.map((v, i) => ({
    x: PADDING.left + (i / (values.length - 1)) * plotWidth,
    y: PADDING.top + plotHeight - ((v - min) / range) * plotHeight,
    label: labels[i],
    value: v,
  }))
}

const polyline = (points: ChartPoint[]): string =>
  points.map(p => `${p.x},${p.y}`).join(' ')

export const renderTemperatureChart = (daily: DailyForecast[], unit: 'C' | 'F' = 'C'): string => {
  const temps = unit === 'C'
    ? daily.map(d => d.tempMax)
    : daily.map(d => Math.round(d.tempMax * 9 / 5 + 32))

  const labels = daily.map(d => d.dayName)
  const maxPoints = mapPoints(temps, labels)

  const tempsMin = unit === 'C'
    ? daily.map(d => d.tempMin)
    : daily.map(d => Math.round(d.tempMin * 9 / 5 + 32))

  const minPoints = mapPoints(tempsMin, labels)

  const allValues = [...temps, ...tempsMin]
  const globalMin = Math.min(...allValues) - 2
  const globalMax = Math.max(...allValues) + 2
  const range = globalMax - globalMin || 1

  const normalizeY = (v: number) =>
    PADDING.top + plotHeight - ((v - globalMin) / range) * plotHeight

  const normalizedMaxPoints = temps.map((v, i) => ({
    x: PADDING.left + (i / (temps.length - 1)) * plotWidth,
    y: normalizeY(v),
    label: labels[i],
    value: v,
  }))

  const normalizedMinPoints = tempsMin.map((v, i) => ({
    x: PADDING.left + (i / (tempsMin.length - 1)) * plotWidth,
    y: normalizeY(v),
    label: labels[i],
    value: v,
  }))

  const gridLines = 4
  const gridStep = range / gridLines
  const grids = Array.from({ length: gridLines + 1 }, (_, i) => {
    const val = Math.round(globalMin + i * gridStep)
    const y = normalizeY(val)
    return `<line x1="${PADDING.left}" y1="${y}" x2="${SVG_WIDTH - PADDING.right}" y2="${y}" stroke="#e0e0e0" stroke-width="1" stroke-dasharray="4,4"/>
    <text x="${PADDING.left - 8}" y="${y + 4}" text-anchor="end" font-size="11" fill="#888">${val}\u00B0</text>`
  }).join('\n')

  const xLabels = normalizedMaxPoints.map(p =>
    `<text x="${p.x}" y="${SVG_HEIGHT - 8}" text-anchor="middle" font-size="11" fill="#666">${p.label}</text>`
  ).join('\n')

  const maxDots = normalizedMaxPoints.map(p =>
    `<circle cx="${p.x}" cy="${p.y}" r="4" fill="#e74c3c"/>
    <text x="${p.x}" y="${p.y - 10}" text-anchor="middle" font-size="10" fill="#e74c3c">${p.value}\u00B0</text>`
  ).join('\n')

  const minDots = normalizedMinPoints.map(p =>
    `<circle cx="${p.x}" cy="${p.y}" r="4" fill="#3498db"/>
    <text x="${p.x}" y="${p.y + 16}" text-anchor="middle" font-size="10" fill="#3498db">${p.value}\u00B0</text>`
  ).join('\n')

  const unitLabel = unit === 'C' ? '\u00B0C' : '\u00B0F'

  return `<svg viewBox="0 0 ${SVG_WIDTH} ${SVG_HEIGHT}" xmlns="http://www.w3.org/2000/svg" style="width:100%;max-width:${SVG_WIDTH}px;height:auto;background:#fafafa;border-radius:8px;">
  ${grids}
  ${xLabels}
  <polyline points="${polyline(normalizedMaxPoints)}" fill="none" stroke="#e74c3c" stroke-width="2.5" stroke-linejoin="round"/>
  <polyline points="${polyline(normalizedMinPoints)}" fill="none" stroke="#3498db" stroke-width="2.5" stroke-linejoin="round"/>
  ${maxDots}
  ${minDots}
  <text x="${SVG_WIDTH / 2}" y="16" text-anchor="middle" font-size="13" font-weight="bold" fill="#333">Temperature Trend (${unitLabel})</text>
  <circle cx="${SVG_WIDTH - 110}" cy="14" r="4" fill="#e74c3c"/><text x="${SVG_WIDTH - 102}" y="18" font-size="10" fill="#666">High</text>
  <circle cx="${SVG_WIDTH - 60}" cy="14" r="4" fill="#3498db"/><text x="${SVG_WIDTH - 52}" y="18" font-size="10" fill="#666">Low</text>
</svg>`
}

