  const feelsLikeF = celsiusToFahrenheit(current.main.feels_like)
  const icon = getIconEmoji(current.weather[0].icon)
  const windDir = windDegToDirection(current.wind.deg)
  const chartSvg = renderTemperatureChart(daily, 'C')
  const now = new Date()
  const dateStr = now.toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric', year: 'numeric' })

  const template = h(Fragment, {},
    h('div', { style: styles.container },
      // Header
      h('div', { style: styles.header },
        h('p', { style: styles.title }, `${current.name}, ${current.sys.country}`),
        h('p', { style: styles.subtitle }, dateStr),
      ),

      // Search
      h('form', { style: styles.searchForm, 'p-trigger': 'submit:searchCity' },
        h('input', {
          type: 'text',
          name: 'city',
          placeholder: 'Enter city name...',
          style: styles.searchInput,
          'p-target': 'cityInput',
        }),
        h('button', { type: 'submit', style: styles.searchButton }, 'Search'),
      ),

      // Current conditions
      h('div', { style: styles.currentCard },
        h('div', { style: styles.currentTop },
          h('div', {},
            h('p', { style: styles.tempLarge },
              `${tempC}\u00B0C`,
              h('span', { style: styles.tempSecondary }, ` / ${tempF}\u00B0F`),
            ),
            h('p', { style: { fontSize: '13px', color: '#888', margin: '4px 0 0 0' } },
              `Feels like ${feelsLikeC}\u00B0C / ${feelsLikeF}\u00B0F`,
            ),
          ),
          h('div', { style: styles.weatherIcon }, icon),
        ),
        h('p', { style: styles.description }, current.weather[0].description),
        h('div', { style: styles.statsGrid },
          h('div', { style: styles.statBox },
            h('div', { style: styles.statLabel }, 'Humidity'),
            h('div', { style: styles.statValue }, `${current.main.humidity}%`),
          ),
          h('div', { style: styles.statBox },
            h('div', { style: styles.statLabel }, 'Wind'),
            h('div', { style: styles.statValue }, `${current.wind.speed} m/s`),
            h('div', { style: { fontSize: '11px', color: '#888' } }, windDir),
          ),
          h('div', { style: styles.statBox },
            h('div', { style: styles.statLabel }, 'Pressure'),
            h('div', { style: styles.statValue }, `${current.main.pressure}`),
            h('div', { style: { fontSize: '11px', color: '#888' } }, 'hPa'),
          ),
        ),
      ),

      // 5-day forecast
      h('div', { style: { marginBottom: '16px' } },
        h('p', { style: styles.sectionTitle }, '5-Day Forecast'),
        h('div', { style: styles.forecastStrip },
          ...daily.map(day =>
            h('div', { style: styles.forecastDay },
              h('div', { style: styles.forecastDayName }, day.dayName),
              h('div', { style: styles.forecastIcon }, getIconEmoji(day.icon)),
              h('div', { style: styles.forecastTemp },
                `${day.tempMax}\u00B0`,
                h('span', { style: styles.forecastTempLow }, ` ${day.tempMin}\u00B0`),
              ),
              h('div', { style: { fontSize: '11px', color: '#888', marginTop: '2px' } },
                `${celsiusToFahrenheit(day.tempMax)}\u00B0F`,
              ),
            ),
          ),
        ),
      ),

      // Chart
      h('div', { style: styles.chartContainer },
        h('p', { style: styles.sectionTitle }, 'Temperature Trend'),
        h('div', { innerHTML: chartSvg }),
      ),
    ),
  )

  const ssr = createSSR()
  return ssr(template)
}

import { getWeatherData } from './data'
import { renderDashboard } from './render'
import type { WeatherDashboardData } from './types'

const DATA_PATH = './data/last-search.json'

const saveLastSearch = async (data: WeatherDashboardData): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(data, null, 2))
}

const loadLastSearch = async (): Promise<WeatherDashboardData | null> => {
  const file = Bun.file(DATA_PATH)
  if (await file.exists()) {
    return file.json() as Promise<WeatherDashboardData>
  }
  return null
}

export const getWeather = (city: string): WeatherDashboardData => {
  return getWeatherData(city)
}

export const renderWeather = (city: string): string => {
  const data = getWeatherData(city)
  return renderDashboard(data)
}

export const handleSearch = async (city: string): Promise<string> => {
  const data = getWeatherData(city)
  await saveLastSearch(data)
  return renderDashboard(data)
}

export const serve = () => {
  const defaultCity = 'London'

  return Bun.serve({
    port: 3000,
    fetch: async (req) => {
      const url = new URL(req.url)

      if (url.pathname === '/api/weather') {
        const city = url.searchParams.get('city') ?? defaultCity
        const data = getWeatherData(city)
        await saveLastSearch(data)
        return new Response(JSON.stringify(data), {
          headers: { 'Content-Type': 'application/json' },
        })
      }

      if (url.pathname === '/api/render') {
        const city = url.searchParams.get('city') ?? defaultCity
        const html = await handleSearch(city)
        return new Response(html, {
          headers: { 'Content-Type': 'text/html' },
        })
      }

      const city = url.searchParams.get('city') ?? defaultCity
      const html = await handleSearch(city)

      return new Response(
        `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Weather Dashboard - ${city}</title>
  <style>
    * { box-sizing: border-box; margin: 0; padding: 0; }
    body { background: #e8eef5; min-height: 100vh; padding: 20px; }
  </style>
</head>
<body>
  ${html}
  <script>
    document.querySelector('form')?.addEventListener('submit', (e) => {
      e.preventDefault();
      const city = e.target.querySelector('input[name="city"]').value;
      if (city) window.location.search = '?city=' + encodeURIComponent(city);
    });
  </script>
</body>
</html>`,
        { headers: { 'Content-Type': 'text/html' } },
      )
    },
  })
}

// Run server if executed directly
if (import.meta.main) {
  const server = serve()
  console.log(`Weather Dashboard running at http://localhost:${server.port}`)
}

