const FORECAST_VARIATIONS = [
  { tempOffset: 0, description: 'clear sky', icon: '01d', id: 800 },
  { tempOffset: 2, description: 'few clouds', icon: '02d', id: 801 },
  { tempOffset: -1, description: 'scattered clouds', icon: '03d', id: 802 },
  { tempOffset: 3, description: 'light rain', icon: '10d', id: 500 },
  { tempOffset: -2, description: 'overcast clouds', icon: '04d', id: 804 },
]

const generateSeededRandom = (seed: string): (() => number) => {
  let hash = 0
  for (let i = 0; i < seed.length; i++) {
    const char = seed.charCodeAt(i)
    hash = ((hash << 5) - hash) + char
    hash |= 0
  }
  return () => {
    hash = (hash * 1103515245 + 12345) & 0x7fffffff
    return (hash % 100) / 100
  }
}

const buildCurrentWeather = (city: string): CurrentWeather => {
  const key = city.toLowerCase()
  const preset = WEATHER_PRESETS[key] ?? {
    temp: 18, humidity: 60, wind: 4.0, description: 'partly cloudy', icon: '02d', id: 802,
  }
  const coords = CITIES[key] ?? { lat: 0, lon: 0, country: 'XX' }
  const now = Math.floor(Date.now() / 1000)

  return {
    coord: { lon: coords.lon, lat: coords.lat },
    weather: [{ id: preset.id, main: preset.description.split(' ')[0], description: preset.description, icon: preset.icon }],
    main: {
      temp: preset.temp,
      feels_like: preset.temp - 2,
      temp_min: preset.temp - 3,
      temp_max: preset.temp + 3,
      pressure: 1013,
      humidity: preset.humidity,
    },
    wind: { speed: preset.wind, deg: 220 },
    clouds: { all: preset.humidity > 60 ? 75 : 30 },
    dt: now,
    sys: { country: coords.country, sunrise: now - 21600, sunset: now + 21600 },
    name: city.split(' ').map((w) => w.charAt(0).toUpperCase() + w.slice(1)).join(' '),
  }
}

const buildForecast = (city: string, baseTemp: number): ForecastResponse => {
  const key = city.toLowerCase()
  const coords = CITIES[key] ?? { lat: 0, lon: 0, country: 'XX' }
  const rng = generateSeededRandom(key)
  const now = new Date()
  const list: ForecastResponse['list'] = []

  for (let day = 0; day < 5; day++) {
    for (const hour of [6, 12, 18]) {
      const dt = new Date(now)
      dt.setDate(dt.getDate() + day + 1)
      dt.setHours(hour, 0, 0, 0)

      const variation = FORECAST_VARIATIONS[day % FORECAST_VARIATIONS.length]
      const tempJitter = Math.round((rng() - 0.5) * 6)
      const hourOffset = hour === 6 ? -3 : hour === 18 ? -1 : 2
      const temp = baseTemp + variation.tempOffset + tempJitter + hourOffset

      list.push({
        dt: Math.floor(dt.getTime() / 1000),
        main: {
          temp,
          feels_like: temp - 2,
          temp_min: temp - 2,
          temp_max: temp + 2,
          pressure: 1013,
          humidity: 55 + Math.round(rng() * 30),
        },
        weather: [{ id: variation.id, main: variation.description.split(' ')[0], description: variation.description, icon: variation.icon }],
        wind: { speed: 2 + Math.round(rng() * 8), deg: Math.round(rng() * 360) },
        dt_txt: dt.toISOString().replace('T', ' ').slice(0, 19),
      })
    }
  }

  return {
    city: {
      name: city.split(' ').map((w) => w.charAt(0).toUpperCase() + w.slice(1)).join(' '),
      country: coords.country,
    },
    list,
  }
}

const extractDailyForecasts = (forecast: ForecastResponse): DailyForecast[] => {
  const days = new Map<string, { temps: number[]; entry: ForecastResponse['list'][0] }>()

  for (const entry of forecast.list) {
    const date = entry.dt_txt.slice(0, 10)
    const existing = days.get(date)
    if (existing) {
      existing.temps.push(entry.main.temp)
    } else {
      days.set(date, { temps: [entry.main.temp], entry })
    }
  }

  const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat']

  return [...days.entries()].map(([date, { temps, entry }]) => {
    const d = new Date(date)
    return {
      date,
      dayName: dayNames[d.getDay()],
      tempHigh: Math.max(...temps),
      tempLow: Math.min(...temps),
      description: entry.weather[0].description,
      icon: entry.weather[0].icon,
    }
  })
}

export const getWeatherData = (city: string): WeatherData => {
  const current = buildCurrentWeather(city)
  const forecast = buildForecast(city, current.main.temp)
  const dailyForecasts = extractDailyForecasts(forecast)
  return { current, forecast, dailyForecasts }
}

