export type ChartPoint = { x: number; y: number; label: string; value: number }

const mapToPoints = (
  values: number[],
  labels: string[],
  width: number,
  height: number,
  padding: number,
  minVal: number,
  maxVal: number,
): ChartPoint[] => {
  const range = maxVal - minVal || 1
  const usableWidth = width - padding * 2
  const usableHeight = height - padding * 2

  return values.map((v, i) => ({
    x: padding + (i / Math.max(values.length - 1, 1)) * usableWidth,
    y: padding + usableHeight - ((v - minVal) / range) * usableHeight,
    label: labels[i],
    value: v,
  }))
}

const pointsToPolyline = (points: ChartPoint[]): string =>
  points.map((p) => `${p.x.toFixed(1)},${p.y.toFixed(1)}`).join(' ')

export const buildTrendChartSvg = (forecasts: DailyForecast[], width = 600, height = 260): string => {
  const padding = 45
  const labels = forecasts.map((f) => f.dayName)
  const highs = forecasts.map((f) => f.tempHigh)
  const lows = forecasts.map((f) => f.tempLow)

  const allTemps = [...highs, ...lows]
  const minTemp = Math.min(...allTemps) - 2
  const maxTemp = Math.max(...allTemps) + 2

  const highPoints = mapToPoints(highs, labels, width, height, padding, minTemp, maxTemp)
  const lowPoints = mapToPoints(lows, labels, width, height, padding, minTemp, maxTemp)

  const gridLines = () => {
    const steps = 5
    const range = maxTemp - minTemp
    const lines: string[] = []
    for (let i = 0; i <= steps; i++) {
      const val = minTemp + (range * i) / steps
      const y = padding + (height - padding * 2) - ((val - minTemp) / range) * (height - padding * 2)
      lines.push(`<line x1="${padding}" y1="${y.toFixed(1)}" x2="${width - padding}" y2="${y.toFixed(1)}" stroke="#e2e8f0" stroke-width="1" />`)
      lines.push(`<text x="${padding - 8}" y="${(y + 4).toFixed(1)}" text-anchor="end" font-size="11" fill="#94a3b8">${Math.round(val)}°</text>`)
    }
    return lines.join('\n    ')
  }

  const xLabels = () =>
    highPoints
      .map((p) => `<text x="${p.x.toFixed(1)}" y="${height - 10}" text-anchor="middle" font-size="12" fill="#64748b">${p.label}</text>`)
      .join('\n    ')

  const dots = (points: ChartPoint[], color: string) =>
    points
      .map(
        (p) =>
          `<circle cx="${p.x.toFixed(1)}" cy="${p.y.toFixed(1)}" r="4" fill="${color}" stroke="white" stroke-width="2" />` +
          `<text x="${p.x.toFixed(1)}" y="${(p.y - 10).toFixed(1)}" text-anchor="middle" font-size="10" fill="${color}">${Math.round(p.value)}°</text>`,
      )
      .join('\n    ')

  return `<svg viewBox="0 0 ${width} ${height}" xmlns="http://www.w3.org/2000/svg" style="width:100%;max-width:${width}px;height:auto;">
  <rect width="${width}" height="${height}" rx="12" fill="#f8fafc" />
  ${gridLines()}
  ${xLabels()}
  <polyline points="${pointsToPolyline(highPoints)}" fill="none" stroke="#ef4444" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round" />
  <polyline points="${pointsToPolyline(lowPoints)}" fill="none" stroke="#3b82f6" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round" />
  ${dots(highPoints, '#ef4444')}
  ${dots(lowPoints, '#3b82f6')}
  <circle cx="${width - 100}" cy="18" r="5" fill="#ef4444" />
  <text x="${width - 90}" y="22" font-size="11" fill="#475569">High</text>
  <circle cx="${width - 50}" cy="18" r="5" fill="#3b82f6" />
  <text x="${width - 40}" y="22" font-size="11" fill="#475569">Low</text>
</svg>`
}

