export { renderDashboard } from './render'
export { buildTrendChartSvg } from './chart'

const DEFAULT_CITY = 'new york'

const saveLastCity = async (city: string): Promise<void> => {
  const path = new URL('./data/last-city.json', import.meta.url).pathname
  await Bun.write(path, JSON.stringify({ city, timestamp: Date.now() }))
}

const loadLastCity = async (): Promise<string> => {
  const path = new URL('./data/last-city.json', import.meta.url).pathname
  const file = Bun.file(path)
  if (await file.exists()) {
    const data = await file.json() as { city: string }
    return data.city
  }
  return DEFAULT_CITY
}

export const handleCitySearch = async (city: string): Promise<string> => {
  const trimmed = city.trim()
  if (!trimmed) {
    return renderDashboard(getWeatherData(DEFAULT_CITY), '')
  }
  await saveLastCity(trimmed)
  const data = getWeatherData(trimmed)
  return renderDashboard(data, trimmed)
}

export const init = async (): Promise<string> => {
  const city = await loadLastCity()
  const data = getWeatherData(city)
  return renderDashboard(data, city)
}

export const serve = () => {
  return Bun.serve({
    port: 3000,
    fetch: async (req) => {
      const url = new URL(req.url)

      if (url.pathname === '/api/weather') {
        const city = url.searchParams.get('city') ?? DEFAULT_CITY
        const data = getWeatherData(city)
        return new Response(JSON.stringify(data), {
          headers: { 'Content-Type': 'application/json' },
        })
      }

      if (url.pathname === '/api/cities') {
        return new Response(JSON.stringify(getAvailableCities()), {
          headers: { 'Content-Type': 'application/json' },
        })
      }

      const city = url.searchParams.get('city') ?? await loadLastCity()
      const html = await handleCitySearch(city)

      return new Response(
        `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Weather Dashboard</title>
  <style>
    * { box-sizing: border-box; margin: 0; padding: 0; }
    body { background: #f1f5f9; min-height: 100vh; padding: 16px; }
  </style>
</head>
<body>
  ${html}
  <script>
    document.querySelector('button')?.addEventListener('click', () => {
      const input = document.querySelector('input');
      if (input?.value) {
        window.location.search = '?city=' + encodeURIComponent(input.value);
      }
    });
    document.querySelector('input')?.addEventListener('keydown', (e) => {
      if (e.key === 'Enter') document.querySelector('button')?.click();
    });
  </script>
</body>
</html>`,
        { headers: { 'Content-Type': 'text/html' } },
      )
    },
  })
}

