const CITY_DATA: Record<string, { lat: number; lon: number; country: string; timezone: number }> = {
  'new york': { lat: 40.7128, lon: -74.006, country: 'US', timezone: -18000 },
  london: { lat: 51.5074, lon: -0.1278, country: 'GB', timezone: 0 },
  tokyo: { lat: 35.6762, lon: 139.6503, country: 'JP', timezone: 32400 },
  paris: { lat: 48.8566, lon: 2.3522, country: 'FR', timezone: 3600 },
  sydney: { lat: -33.8688, lon: 151.2093, country: 'AU', timezone: 36000 },
}

const CONDITIONS = [
  { id: 800, main: 'Clear', description: 'clear sky', icon: '01d' },
  { id: 801, main: 'Clouds', description: 'few clouds', icon: '02d' },
  { id: 802, main: 'Clouds', description: 'scattered clouds', icon: '03d' },
  { id: 500, main: 'Rain', description: 'light rain', icon: '10d' },
  { id: 501, main: 'Rain', description: 'moderate rain', icon: '10d' },
  { id: 601, main: 'Snow', description: 'snow', icon: '13d' },
  { id: 701, main: 'Mist', description: 'mist', icon: '50d' },
]

const seededRandom = (seed: number): number => {
  const x = Math.sin(seed) * 10000
  return x - Math.floor(x)
}

const generateTemp = (baseTemp: number, seed: number, variance: number = 5): number =>
  Math.round((baseTemp + (seededRandom(seed) * variance * 2 - variance)) * 10) / 10

const BASE_TEMPS: Record<string, number> = {
  'new york': 8,
  london: 10,
  tokyo: 15,
  paris: 11,
  sydney: 22,
}

export const getPlaceholderCurrent = (city: string): CurrentWeather => {
  const key = city.toLowerCase()
  const cityInfo = CITY_DATA[key] ?? CITY_DATA['new york']
  const baseTemp = BASE_TEMPS[key] ?? 12
  const now = Math.floor(Date.now() / 1000)
  const condIndex = Math.floor(seededRandom(now / 86400) * CONDITIONS.length)
  const temp = generateTemp(baseTemp, now)

  return {
    coord: { lon: cityInfo.lon, lat: cityInfo.lat },
    weather: [CONDITIONS[condIndex]],
    main: {
      temp,
      feels_like: temp - 2,
      temp_min: temp - 3,
      temp_max: temp + 3,
      pressure: 1013 + Math.round(seededRandom(now + 1) * 20 - 10),
      humidity: 40 + Math.round(seededRandom(now + 2) * 40),
    },
    visibility: 10000,
    wind: {
      speed: Math.round(seededRandom(now + 3) * 10 * 10) / 10,
      deg: Math.round(seededRandom(now + 4) * 360),
      gust: Math.round(seededRandom(now + 5) * 15 * 10) / 10,
    },
    clouds: { all: Math.round(seededRandom(now + 6) * 100) },
    dt: now,
    sys: {
      country: cityInfo.country,
      sunrise: now - (now % 86400) + 6 * 3600,
      sunset: now - (now % 86400) + 18 * 3600,
    },
    timezone: cityInfo.timezone,
    name: city.charAt(0).toUpperCase() + city.slice(1),
  }
}

export const getPlaceholderForecast = (city: string): ForecastResponse => {
  const key = city.toLowerCase()
  const cityInfo = CITY_DATA[key] ?? CITY_DATA['new york']
  const baseTemp = BASE_TEMPS[key] ?? 12
  const now = Math.floor(Date.now() / 1000)
  const startOfDay = now - (now % 86400)

  const list: ForecastEntry[] = []

  for (let day = 0; day < 5; day++) {
    for (let hour = 0; hour < 24; hour += 3) {
      const dt = startOfDay + day * 86400 + hour * 3600
      const seed = dt + key.length
      const dayVariance = day * 0.5
      const hourVariance = hour < 12 ? hour * 0.3 : (24 - hour) * 0.3
      const temp = generateTemp(baseTemp + dayVariance, seed, 4 + hourVariance)
      const condIndex = Math.floor(seededRandom(seed + 100) * CONDITIONS.length)

      const date = new Date(dt * 1000)
      const dtTxt = `${date.getUTCFullYear()}-${String(date.getUTCMonth() + 1).padStart(2, '0')}-${String(date.getUTCDate()).padStart(2, '0')} ${String(date.getUTCHours()).padStart(2, '0')}:00:00`

      list.push({
        dt,
        main: {
          temp,
          feels_like: temp - 1.5,
          temp_min: temp - 1,
          temp_max: temp + 1,
          pressure: 1013 + Math.round(seededRandom(seed + 200) * 16 - 8),
          humidity: 45 + Math.round(seededRandom(seed + 300) * 35),
        },
        weather: [CONDITIONS[condIndex]],
        wind: {
          speed: Math.round(seededRandom(seed + 400) * 8 * 10) / 10,
          deg: Math.round(seededRandom(seed + 500) * 360),
        },
        clouds: { all: Math.round(seededRandom(seed + 600) * 100) },
        pop: Math.round(seededRandom(seed + 700) * 100) / 100,
        dt_txt: dtTxt,
      })
    }
  }

  return {
    list,
    city: {
      name: city.charAt(0).toUpperCase() + city.slice(1),
      country: cityInfo.country,
      coord: { lat: cityInfo.lat, lon: cityInfo.lon },
      timezone: cityInfo.timezone,
    },
  }
}

import type { DayForecast } from './types'

export type ChartPoint = {
  x: number
  y: number
  label: string
  value: number
}

export type ChartData = {
  points: ChartPoint[]
  minPoints: ChartPoint[]
  width: number
  height: number
  padding: { top: number; right: number; bottom: number; left: number }
}

export const buildChartData = (
  forecasts: DayForecast[],
  width: number = 600,
  height: number = 200,
): ChartData => {
  const padding = { top: 20, right: 30, bottom: 40, left: 45 }
  const plotW = width - padding.left - padding.right
  const plotH = height - padding.top - padding.bottom

  const allTemps = forecasts.flatMap((f) => [f.tempMax, f.tempMin])
  const minTemp = Math.min(...allTemps) - 2
  const maxTemp = Math.max(...allTemps) + 2
  const tempRange = maxTemp - minTemp || 1

  const mapX = (i: number): number => padding.left + (i / (forecasts.length - 1)) * plotW
  const mapY = (temp: number): number => padding.top + plotH - ((temp - minTemp) / tempRange) * plotH

  const points: ChartPoint[] = forecasts.map((f, i) => ({
    x: mapX(i),
    y: mapY(f.tempMax),
    label: f.dayName,
    value: f.tempMax,
  }))

  const minPoints: ChartPoint[] = forecasts.map((f, i) => ({
    x: mapX(i),
    y: mapY(f.tempMin),
    label: f.dayName,
    value: f.tempMin,
  }))

  return { points, minPoints, width, height, padding }
}

export const buildPolyline = (points: ChartPoint[]): string =>
  points.map((p) => `${p.x},${p.y}`).join(' ')

export const buildYAxisLabels = (
  forecasts: DayForecast[],
  height: number,
  padding: ChartData['padding'],
): { y: number; label: string }[] => {
  const allTemps = forecasts.flatMap((f) => [f.tempMax, f.tempMin])
  const minTemp = Math.min(...allTemps) - 2
  const maxTemp = Math.max(...allTemps) + 2
  const plotH = height - padding.top - padding.bottom
  const tempRange = maxTemp - minTemp || 1
  const step = Math.ceil(tempRange / 4)
  const labels: { y: number; label: string }[] = []

  for (let t = Math.floor(minTemp); t <= Math.ceil(maxTemp); t += step) {
    const y = padding.top + plotH - ((t - minTemp) / tempRange) * plotH
    labels.push({ y, label: `${t}°` })
  }

  return labels
}

