import { createSSR } from 'plaited'
import type { WeatherDashboardData, DayForecast, ForecastEntry } from './types'
import { getPlaceholderCurrent, getPlaceholderForecast } from './data'
import { renderDashboard } from './render'

const DAY_NAMES = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat']

const aggregateDailyForecasts = (entries: ForecastEntry[]): DayForecast[] => {
  const byDate = new Map<string, ForecastEntry[]>()

  for (const entry of entries) {
    const dateKey = entry.dt_txt.split(' ')[0]
    const existing = byDate.get(dateKey) ?? []
    existing.push(entry)
    byDate.set(dateKey, existing)
  }

  const dailyForecasts: DayForecast[] = []

  for (const [dateKey, dayEntries] of byDate) {
    if (dailyForecasts.length >= 5) break

    const temps = dayEntries.map((e) => e.main.temp)
    const date = new Date(dateKey)
    const midday = dayEntries[Math.floor(dayEntries.length / 2)]

    dailyForecasts.push({
      date: dateKey,
      dayName: DAY_NAMES[date.getUTCDay()],
      tempMin: Math.round(Math.min(...temps) * 10) / 10,
      tempMax: Math.round(Math.max(...temps) * 10) / 10,
      humidity: Math.round(dayEntries.reduce((sum, e) => sum + e.main.humidity, 0) / dayEntries.length),
      wind: Math.round(dayEntries.reduce((sum, e) => sum + e.wind.speed, 0) / dayEntries.length * 10) / 10,
      description: midday.weather[0].description,
      icon: midday.weather[0].icon,
    })
  }

  return dailyForecasts
}

export const getWeatherData = (city: string): WeatherDashboardData => {
  const current = getPlaceholderCurrent(city)
  const forecast = getPlaceholderForecast(city)
  const dailyForecasts = aggregateDailyForecasts(forecast.list)

  return { current, forecast, dailyForecasts, city }
}

export const saveLastCity = async (city: string): Promise<void> => {
  await Bun.write('data/last-city.json', JSON.stringify({ city, timestamp: Date.now() }))
}

export const loadLastCity = async (): Promise<string> => {
  try {
    const file = Bun.file('data/last-city.json')
    const content = await file.json()
    return content.city ?? 'London'
  } catch {
    return 'London'
  }
}

export const render = async (city?: string): Promise<string> => {
  const targetCity = city ?? (await loadLastCity())
  const data = getWeatherData(targetCity)
  await saveLastCity(targetCity)

  const ssr = createSSR()
  return ssr(renderDashboard(data))
}

export default { getWeatherData, render, saveLastCity, loadLastCity }

