import type { MapState, MapMarker, MapCircle, MarkerCategory } from './types'

const DATA_PATH = './data/markers.json'

const generateId = (): string =>
  crypto.randomUUID()

const readState = async (): Promise<MapState> => {
  const file = Bun.file(DATA_PATH)
  const text = await file.text()
  return JSON.parse(text) as MapState
}

const writeState = async (state: MapState): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(state, null, 2))
}

export const getState = async (): Promise<MapState> =>
  readState()

export const addMarker = async (marker: Omit<MapMarker, 'id' | 'createdAt'>): Promise<MapMarker> => {
  const state = await readState()
  const newMarker: MapMarker = {
    ...marker,
    id: generateId(),
    createdAt: new Date().toISOString(),
  }
  state.markers.push(newMarker)
  await writeState(state)
  return newMarker
}

export const removeMarker = async (id: string): Promise<boolean> => {
  const state = await readState()
  const idx = state.markers.findIndex(m => m.id === id)
  if (idx === -1) return false
  state.markers.splice(idx, 1)
  await writeState(state)
  return true
}

export const addCircle = async (circle: Omit<MapCircle, 'id' | 'createdAt'>): Promise<MapCircle> => {
  const state = await readState()
  const newCircle: MapCircle = {
    ...circle,
    id: generateId(),
    createdAt: new Date().toISOString(),
  }
  state.circles.push(newCircle)
  await writeState(state)
  return newCircle
}

export const removeCircle = async (id: string): Promise<boolean> => {
  const state = await readState()
  const idx = state.circles.findIndex(c => c.id === id)
  if (idx === -1) return false
  state.circles.splice(idx, 1)
  await writeState(state)
  return true
}

export const addCategory = async (category: Omit<MarkerCategory, 'id'>): Promise<MarkerCategory> => {
  const state = await readState()
  const newCategory: MarkerCategory = {
    ...category,
    id: generateId(),
  }
  state.categories.push(newCategory)
  await writeState(state)
  return newCategory
}

export const updateCenter = async (lat: number, lng: number, zoom: number): Promise<void> => {
  const state = await readState()
  state.center = { lat, lng }
  state.zoom = zoom
  await writeState(state)
}

import type { SearchResult } from './types'

const NOMINATIM_URL = 'https://nominatim.openstreetmap.org/search'

export const searchLocation = async (query: string): Promise<SearchResult[]> => {
  const params = new URLSearchParams({
    q: query,
    format: 'json',
    limit: '5',
    addressdetails: '1',
  })

  const response = await fetch(`${NOMINATIM_URL}?${params}`, {
    headers: {
      'User-Agent': 'interactive-map-module/1.0',
    },
  })

  if (!response.ok) {
    return []
  }

  const data = (await response.json()) as Array<{
    lat: string
    lon: string
    display_name: string
  }>

  return data.map(item => ({
    lat: parseFloat(item.lat),
    lng: parseFloat(item.lon),
    displayName: item.display_name,
  }))
}

