          allChip.style.cssText = 'padding:3px 10px;border-radius:12px;font-size:11px;cursor:pointer;border:1px solid ' + (activeFilter === null ? '#fff' : 'transparent') + ';font-weight:500;background:#333;color:#fff;';
          allChip.textContent = 'All';
          allChip.onclick = () => { activeFilter = null; renderFilterBar(); renderMarkerList(); };
          bar.appendChild(allChip);

          STATE.categories.forEach(cat => {
            const chip = document.createElement('span');
            const isActive = activeFilter === cat.id;
            chip.className = 'filter-chip' + (isActive ? ' active' : '');
            chip.style.cssText = 'padding:3px 10px;border-radius:12px;font-size:11px;cursor:pointer;border:1px solid ' + (isActive ? '#fff' : 'transparent') + ';font-weight:500;background:' + cat.color + '33;color:' + cat.color + ';';
            chip.textContent = cat.name;
            chip.onclick = () => { activeFilter = cat.id; renderFilterBar(); renderMarkerList(); };
            bar.appendChild(chip);
          });
        };

        const renderMarkerList = () => {
          const list = document.getElementById('marker-list');
          const filtered = STATE.markers.filter(m => !activeFilter || m.categoryId === activeFilter);
          if (filtered.length === 0) {
            list.innerHTML = '<div style="padding:20px;text-align:center;color:#666;font-size:13px;">No markers yet. Click the map to add one.</div>';
            return;
          }
          list.innerHTML = '';
          filtered.forEach(m => {
            const cat = categoryMap[m.categoryId] || categoryMap['default'];
            const item = document.createElement('div');
            item.className = 'marker-item';
            item.style.cssText = 'padding:10px 12px;border-radius:8px;margin-bottom:4px;cursor:pointer;background:#16213e;border-left:3px solid ' + cat.color + ';';
            item.innerHTML = '<button onclick="event.stopPropagation();deleteMarker(\\'' + m.id + '\\')" style="float:right;background:none;border:none;color:#e94560;cursor:pointer;font-size:14px;padding:0 4px;">✕</button>' +
              '<div style="font-size:14px;font-weight:600;margin-bottom:2px;">' + escHtml(m.title) + '</div>' +
              '<div style="font-size:12px;color:#a0a0a0;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">' + escHtml(m.description) + '</div>' +
              '<div style="font-size:10px;color:#666;margin-top:2px;">' + m.lat.toFixed(4) + ', ' + m.lng.toFixed(4) + '</div>';
            item.onclick = () => {
              map.setView([m.lat, m.lng], 16);
              markers[m.id]?.openPopup();
            };
            list.appendChild(item);
          });
        };

        const renderCircleInfo = () => {
          const info = document.getElementById('circle-info');
          const count = STATE.circles.length;
          info.textContent = count > 0 ? count + ' circle' + (count > 1 ? 's' : '') + ' on map' : '';
        };

        const showMarkerModal = () => {
          const overlay = document.getElementById('modal-overlay');
          const select = document.getElementById('modal-category');
          select.innerHTML = '';
          STATE.categories.forEach(cat => {
            const opt = document.createElement('option');
            opt.value = cat.id;
            opt.textContent = cat.name;
            select.appendChild(opt);
          });
          document.getElementById('modal-title').value = '';
          document.getElementById('modal-desc').value = '';
          overlay.classList.add('visible');
        };

        const hideMarkerModal = () => {
          document.getElementById('modal-overlay').classList.remove('visible');
          pendingLatLng = null;
        };

        const showCircleModal = (lat, lng) => {
          pendingLatLng = { lat, lng };
          const overlay = document.getElementById('circle-modal-overlay');
          document.getElementById('circle-label').value = '';
          document.getElementById('circle-radius').value = '500';
          overlay.style.display = 'flex';
        };

        const hideCircleModal = () => {
          document.getElementById('circle-modal-overlay').style.display = 'none';
          pendingLatLng = null;
        };

        document.getElementById('modal-cancel').onclick = hideMarkerModal;
        document.getElementById('modal-save').onclick = async () => {
          const title = document.getElementById('modal-title').value.trim();
          if (!title || !pendingLatLng) return;
          const body = {
            lat: pendingLatLng.lat,
            lng: pendingLatLng.lng,
            title,
            description: document.getElementById('modal-desc').value.trim(),
            categoryId: document.getElementById('modal-category').value,
          };
          const res = await fetch('/api/markers', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(body) });
          const marker = await res.json();
          STATE.markers.push(marker);
          addMarkerToMap(marker);
          renderMarkerList();
          hideMarkerModal();
        };

        document.getElementById('circle-cancel').onclick = hideCircleModal;
        document.getElementById('circle-save').onclick = async () => {
          const label = document.getElementById('circle-label').value.trim() || 'Area';
          if (!pendingLatLng) return;
          const body = {
            lat: pendingLatLng.lat,
            lng: pendingLatLng.lng,
            radius: parseInt(document.getElementById('circle-radius').value) || 500,
            color: document.getElementById('circle-color').value,
            label,
          };
          const res = await fetch('/api/circles', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(body) });
          const circle = await res.json();
          STATE.circles.push(circle);
          addCircleToMap(circle);
          renderCircleInfo();
          hideCircleModal();
        };

        const deleteMarker = async (id) => {
          await fetch('/api/markers/' + id, { method: 'DELETE' });
          if (markers[id]) { map.removeLayer(markers[id]); delete markers[id]; }
          STATE.markers = STATE.markers.filter(m => m.id !== id);
          renderMarkerList();
        };

        document.getElementById('btn-add-circle').onclick = () => {
          drawCircleMode = !drawCircleMode;
          document.getElementById('btn-add-circle').textContent = drawCircleMode ? 'Click map to place circle...' : 'Draw Circle on Map';
        };

        document.getElementById('btn-clear-markers').onclick = async () => {
          if (!confirm('Remove all markers?')) return;
          for (const m of [...STATE.markers]) { await deleteMarker(m.id); }
        };

        // Search
        const doSearch = async () => {
          const q = document.getElementById('search-input').value.trim();
          if (!q) return;
          const res = await fetch('/api/search?q=' + encodeURIComponent(q));
          const results = await res.json();
          const container = document.getElementById('search-results');
          if (results.length === 0) {
            container.style.display = 'block';
            container.innerHTML = '<div style="padding:8px;font-size:12px;color:#666;">No results found</div>';
            return;
          }
          container.style.display = 'block';
          container.innerHTML = '';
          results.forEach(r => {
            const div = document.createElement('div');
            div.style.cssText = 'padding:8px;font-size:12px;cursor:pointer;border-radius:4px;margin-bottom:2px;background:#1a1a2e;';
            div.textContent = r.displayName;
            div.onmouseenter = () => { div.style.background = '#0f3460'; };
            div.onmouseleave = () => { div.style.background = '#1a1a2e'; };
            div.onclick = () => {
              map.setView([r.lat, r.lng], 15);
              container.style.display = 'none';
              document.getElementById('search-input').value = '';
            };
            container.appendChild(div);
          });
        };

        document.getElementById('search-btn').onclick = doSearch;
        document.getElementById('search-input').onkeydown = (e) => { if (e.key === 'Enter') doSearch(); };

        document.addEventListener('click', (e) => {
          const sr = document.getElementById('search-results');
          if (!sr.contains(e.target) && e.target.id !== 'search-input' && e.target.id !== 'search-btn') {
            sr.style.display = 'none';
          }
        });

        initMap();
      `),
    ),
  )

  const ssr = createSSR()
  return '<!DOCTYPE html>' + ssr(tree)
}

import { getState, addMarker, removeMarker, addCircle, removeCircle, addCategory } from './store'
import { searchLocation } from './search'
import { renderPage } from './render'

const PORT = 3000

const jsonResponse = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const server = Bun.serve({
  port: PORT,
  fetch: async (req) => {
    const url = new URL(req.url)
    const path = url.pathname
    const method = req.method

    // Serve map UI
    if (path === '/' && method === 'GET') {
      const state = await getState()
      const html = renderPage(state)
      return new Response(html, {
        headers: { 'Content-Type': 'text/html' },
      })
    }

    // Get map state
    if (path === '/api/state' && method === 'GET') {
      const state = await getState()
      return jsonResponse(state)
    }

    // Add marker
    if (path === '/api/markers' && method === 'POST') {
      const body = await req.json()
      const marker = await addMarker({
        lat: body.lat,
        lng: body.lng,
        title: body.title || 'Untitled',
        description: body.description || '',
        categoryId: body.categoryId || 'default',
      })
      return jsonResponse(marker, 201)
    }

    // Delete marker
    if (path.startsWith('/api/markers/') && method === 'DELETE') {
      const id = path.slice('/api/markers/'.length)
      const removed = await removeMarker(id)
      return removed ? jsonResponse({ ok: true }) : jsonResponse({ error: 'Not found' }, 404)
    }

    // Add circle
    if (path === '/api/circles' && method === 'POST') {
      const body = await req.json()
      const circle = await addCircle({
        lat: body.lat,
        lng: body.lng,
        radius: body.radius || 500,
        color: body.color || '#e94560',
        label: body.label || 'Area',
      })
      return jsonResponse(circle, 201)
    }

    // Delete circle
    if (path.startsWith('/api/circles/') && method === 'DELETE') {
      const id = path.slice('/api/circles/'.length)
      const removed = await removeCircle(id)
      return removed ? jsonResponse({ ok: true }) : jsonResponse({ error: 'Not found' }, 404)
    }

    // Add category
    if (path === '/api/categories' && method === 'POST') {
      const body = await req.json()
      const category = await addCategory({
        name: body.name,
        color: body.color || '#2196F3',
      })
      return jsonResponse(category, 201)
    }

    // Search location
    if (path === '/api/search' && method === 'GET') {
      const query = url.searchParams.get('q') || ''
      if (!query) return jsonResponse([])
      const results = await searchLocation(query)
      return jsonResponse(results)
    }

    return jsonResponse({ error: 'Not found' }, 404)
  },
})

