import type { MapMarker, MapCircle, MarkerCategory, AddMarkerPayload, AddCirclePayload, AddCategoryPayload } from './types'

const MARKERS_PATH = './data/markers.json'
const CIRCLES_PATH = './data/circles.json'
const CATEGORIES_PATH = './data/categories.json'

const readJson = async <T>(path: string): Promise<T> => {
  const file = Bun.file(path)
  const text = await file.text()
  return JSON.parse(text) as T
}

const writeJson = async <T>(path: string, data: T): Promise<void> => {
  await Bun.write(path, JSON.stringify(data, null, 2))
}

const generateId = (): string =>
  crypto.randomUUID().slice(0, 8)

// --- Markers ---

export const getMarkers = async (): Promise<MapMarker[]> =>
  readJson<MapMarker[]>(MARKERS_PATH)

export const addMarker = async (payload: AddMarkerPayload): Promise<MapMarker> => {
  const markers = await getMarkers()
  const marker: MapMarker = {
    id: generateId(),
    title: payload.title,
    description: payload.description,
    position: payload.position,
    categoryId: payload.categoryId,
    createdAt: new Date().toISOString(),
  }
  markers.push(marker)
  await writeJson(MARKERS_PATH, markers)
  return marker
}

export const removeMarker = async (id: string): Promise<boolean> => {
  const markers = await getMarkers()
  const filtered = markers.filter((m) => m.id !== id)
  if (filtered.length === markers.length) return false
  await writeJson(MARKERS_PATH, filtered)
  return true
}

// --- Circles ---

export const getCircles = async (): Promise<MapCircle[]> =>
  readJson<MapCircle[]>(CIRCLES_PATH)

export const addCircle = async (payload: AddCirclePayload): Promise<MapCircle> => {
  const circles = await getCircles()
  const circle: MapCircle = {
    id: generateId(),
    center: payload.center,
    radius: payload.radius,
    color: payload.color,
    label: payload.label,
    createdAt: new Date().toISOString(),
  }
  circles.push(circle)
  await writeJson(CIRCLES_PATH, circles)
  return circle
}

export const removeCircle = async (id: string): Promise<boolean> => {
  const circles = await getCircles()
  const filtered = circles.filter((c) => c.id !== id)
  if (filtered.length === circles.length) return false
  await writeJson(CIRCLES_PATH, filtered)
  return true
}

// --- Categories ---

export const getCategories = async (): Promise<MarkerCategory[]> =>
  readJson<MarkerCategory[]>(CATEGORIES_PATH)

export const addCategory = async (payload: AddCategoryPayload): Promise<MarkerCategory> => {
  const categories = await getCategories()
  const category: MarkerCategory = {
    id: generateId(),
    name: payload.name,
    color: payload.color,
  }
  categories.push(category)
  await writeJson(CATEGORIES_PATH, categories)
  return category
}

export const removeCategory = async (id: string): Promise<boolean> => {
  if (id === 'default') return false
  const categories = await getCategories()
  const filtered = categories.filter((c) => c.id !== id)
  if (filtered.length === categories.length) return false
  await writeJson(CATEGORIES_PATH, filtered)
  return true
}

import type { SearchResult } from './types'

const NOMINATIM_BASE = 'https://nominatim.openstreetmap.org/search'

export const searchLocation = async (query: string): Promise<SearchResult[]> => {
  const url = new URL(NOMINATIM_BASE)
  url.searchParams.set('q', query)
  url.searchParams.set('format', 'json')
  url.searchParams.set('limit', '5')
  url.searchParams.set('addressdetails', '0')

  const response = await fetch(url.toString(), {
    headers: {
      'User-Agent': 'interactive-map-module/1.0',
    },
  })

  if (!response.ok) {
    throw new Error(`Nominatim search failed: ${response.status}`)
  }

  const data = (await response.json()) as Array<{
    display_name: string
    lat: string
    lon: string
    boundingbox?: [string, string, string, string]
  }>

  return data.map((item) => ({
    displayName: item.display_name,
    lat: parseFloat(item.lat),
    lng: parseFloat(item.lon),
    boundingBox: item.boundingbox
      ? [
          parseFloat(item.boundingbox[0]),
          parseFloat(item.boundingbox[1]),
          parseFloat(item.boundingbox[2]),
          parseFloat(item.boundingbox[3]),
        ]
      : undefined,
  }))
}

