const styleToStr = (s: Record<string, string | number>): string =>
  Object.entries(s)
    .map(([k, v]) => {
      const prop = k.replace(/[A-Z]/g, (m) => `-${m.toLowerCase()}`)
      return `${prop}:${typeof v === 'number' ? `${v}px` : v}`
    })
    .join(';')

const renderCategoryChips = (categories: MarkerCategory[]): string => {
  const chips = categories.map(
    (cat) =>
      `<button class="filter-chip" data-category-id="${cat.id}" style="${styleToStr(styles.filterChip(cat.color, false))}" onclick="filterByCategory('${cat.id}')">${cat.name}</button>`
  )
  return `<button class="filter-chip filter-chip-all" style="${styleToStr(styles.filterChip('#e94560', true))}" onclick="filterByCategory('all')">All</button>${chips.join('')}`
}

const renderMarkerList = (markers: MapMarker[], categories: MarkerCategory[]): string => {
  if (markers.length === 0) {
    return `<div style="padding:24px 16px;text-align:center;color:#707090;font-size:13px;">No markers yet. Click the map or use the form to add one.</div>`
  }

  const catMap = new Map(categories.map((c) => [c.id, c]))

  return markers
    .map((m) => {
      const cat = catMap.get(m.categoryId)
      const color = cat?.color ?? '#3b82f6'
      return `<div class="marker-item" data-marker-id="${m.id}" style="${styleToStr(styles.markerItem(color))}" onclick="centerOnMarker('${m.id}')" onmouseenter="this.style.background='#2a2a4a'" onmouseleave="this.style.background='transparent'">
  <div style="${styleToStr(styles.markerTitle)}">${escapeHtml(m.title)}</div>
  <div style="${styleToStr(styles.markerDesc)}">${escapeHtml(m.description)}</div>
  <div style="${styleToStr(styles.markerCoords)}">${m.position.lat.toFixed(5)}, ${m.position.lng.toFixed(5)}</div>
</div>`
    })
    .join('')
}

const escapeHtml = (s: string): string =>
  s.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;')

export const renderPage = (
  markers: MapMarker[],
  circles: MapCircle[],
  categories: MarkerCategory[],
  center: { lat: number; lng: number } = { lat: 40.7128, lng: -74.006 },
  zoom = 12
): string => {
  const markersJson = JSON.stringify(markers)
  const circlesJson = JSON.stringify(circles)
  const categoriesJson = JSON.stringify(categories)

  const categoryOptions = categories
