        <button id="toggleCircleForm" style="${styleToStr(styles.toggleButton)}" onclick="toggleForm('circleForm')">+ Circle</button>

        <div id="markerForm" style="${styleToStr(styles.formPanel)};display:none;">
          <h4 style="${styleToStr(styles.formTitle)}">Add Marker</h4>
          <div style="${styleToStr(styles.formGroup)}">
            <label style="${styleToStr(styles.formLabel)}">Title</label>
            <input id="mTitle" type="text" style="${styleToStr(styles.formInput)}" placeholder="Marker title" />
          </div>
          <div style="${styleToStr(styles.formGroup)}">
            <label style="${styleToStr(styles.formLabel)}">Description</label>
