          </div>
          <div style="${styleToStr(styles.formGroup)}">
            <label style="${styleToStr(styles.formLabel)}">Category</label>
            <select id="mCat" style="${styleToStr(styles.formSelect)}">${categoryOptions}</select>
          </div>
          <div style="${styleToStr(styles.formGroup)}">
            <label style="${styleToStr(styles.formLabel)}">Position (click map or enter lat,lng)</label>
            <input id="mPos" type="text" style="${styleToStr(styles.formInput)}" placeholder="${center.lat}, ${center.lng}" />
          </div>
          <button style="${styleToStr(styles.formButton)}" onclick="submitMarker()">Add Marker</button>
        </div>

        <div id="circleForm" style="${styleToStr(styles.formPanel)};display:none;">
          <h4 style="${styleToStr(styles.formTitle)}">Add Circle</h4>
          <div style="${styleToStr(styles.formGroup)}">
