            <input id="cLabel" type="text" style="${styleToStr(styles.formInput)}" placeholder="Circle label" />
          </div>
          <div style="${styleToStr(styles.formGroup)}">
            <label style="${styleToStr(styles.formLabel)}">Center (click map or enter lat,lng)</label>
            <input id="cCenter" type="text" style="${styleToStr(styles.formInput)}" placeholder="${center.lat}, ${center.lng}" />
          </div>
          <div style="${styleToStr(styles.formGroup)}">
            <label style="${styleToStr(styles.formLabel)}">Radius (meters)</label>
            <input id="cRadius" type="number" style="${styleToStr(styles.formInput)}" value="500" />
