  <script>
    // --- State ---
    const markersData = ${markersJson};
    const circlesData = ${circlesJson};
    const categoriesData = ${categoriesJson};
    const leafletMarkers = {};
    const leafletCircles = {};
    let activeFilter = 'all';

    // --- Category color map ---
    const catColorMap = {};
    categoriesData.forEach(c => { catColorMap[c.id] = c.color; });

    // --- Custom colored icon ---
    const makeIcon = (color) => {
      const svg = \`<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 36" width="24" height="36">
        <path d="M12 0C5.4 0 0 5.4 0 12c0 9 12 24 12 24s12-15 12-24C24 5.4 18.6 0 12 0z" fill="\${color}" stroke="#fff" stroke-width="1.5"/>
        <circle cx="12" cy="11" r="4.5" fill="#fff"/>
      </svg>\`;
      return L.divIcon({
        html: svg,
        iconSize: [24, 36],
        iconAnchor: [12, 36],
        popupAnchor: [0, -36],
        className: '',
      });
    };

    // --- Init map ---
    const map = L.map('map').setView([${center.lat}, ${center.lng}], ${zoom});
    L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
      attribution: '&copy; OpenStreetMap contributors',
      maxZoom: 19,
    }).addTo(map);

    // --- Load existing markers ---
    markersData.forEach(m => {
      const color = catColorMap[m.categoryId] || '#3b82f6';
      const lm = L.marker([m.position.lat, m.position.lng], { icon: makeIcon(color) })
        .addTo(map)
        .bindPopup(\`<h3>\${esc(m.title)}</h3><p>\${esc(m.description)}</p><button class="popup-delete" onclick="deleteMarker('\${m.id}')">Remove</button>\`);
      leafletMarkers[m.id] = lm;
    });

    // --- Load existing circles ---
    circlesData.forEach(c => {
      const lc = L.circle([c.center.lat, c.center.lng], {
        radius: c.radius,
        color: c.color,
        fillColor: c.color,
        fillOpacity: 0.15,
        weight: 2,
      })
        .addTo(map)
        .bindPopup(\`<h3>\${esc(c.label)}</h3><p>Radius: \${c.radius}m</p><button class="popup-delete" onclick="deleteCircle('\${c.id}')">Remove</button>\`);
      leafletCircles[c.id] = lc;
    });

    // --- Map click to populate position fields ---
    map.on('click', (e) => {
      const pos = e.latlng.lat.toFixed(6) + ', ' + e.latlng.lng.toFixed(6);
      document.getElementById('mPos').value = pos;
      document.getElementById('cCenter').value = pos;
    });

    // --- Toggle forms ---
    const toggleForm = (id) => {
      const el = document.getElementById(id);
      el.style.display = el.style.display === 'none' ? 'block' : 'none';
    };

    // --- Search ---
    const doSearch = async () => {
      const q = document.getElementById('searchInput').value.trim();
      if (!q) return;
      try {
        const res = await fetch('/api/search?q=' + encodeURIComponent(q));
        const results = await res.json();
        if (results.length > 0) {
          const r = results[0];
          map.flyTo([r.lat, r.lng], 14, { duration: 1.5 });
        }
      } catch (err) {
        console.error('Search failed:', err);
      }
    };

    // --- Submit marker ---
    const submitMarker = async () => {
      const title = document.getElementById('mTitle').value.trim();
      const description = document.getElementById('mDesc').value.trim();
      const categoryId = document.getElementById('mCat').value;
      const posStr = document.getElementById('mPos').value.trim();
      if (!title || !posStr) return alert('Title and position are required');
      const [lat, lng] = posStr.split(',').map(s => parseFloat(s.trim()));
      if (isNaN(lat) || isNaN(lng)) return alert('Invalid position format');

      const res = await fetch('/api/markers', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ title, description, categoryId, position: { lat, lng } }),
      });
      if (res.ok) location.reload();
    };

    // --- Submit circle ---
    const submitCircle = async () => {
      const label = document.getElementById('cLabel').value.trim();
      const centerStr = document.getElementById('cCenter').value.trim();
      const radius = parseFloat(document.getElementById('cRadius').value);
      const color = document.getElementById('cColor').value;
      if (!label || !centerStr) return alert('Label and center are required');
      const [lat, lng] = centerStr.split(',').map(s => parseFloat(s.trim()));
      if (isNaN(lat) || isNaN(lng)) return alert('Invalid center format');

      const res = await fetch('/api/circles', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ center: { lat, lng }, radius, color, label }),
      });
      if (res.ok) location.reload();
    };

    // --- Delete ---
    const deleteMarker = async (id) => {
      await fetch('/api/markers/' + id, { method: 'DELETE' });
      location.reload();
    };
    const deleteCircle = async (id) => {
      await fetch('/api/circles/' + id, { method: 'DELETE' });
      location.reload();
    };

    // --- Center on marker from sidebar ---
    const centerOnMarker = (id) => {
      const lm = leafletMarkers[id];
      if (lm) {
        map.flyTo(lm.getLatLng(), 16, { duration: 1 });
        lm.openPopup();
      }
    };

    // --- Filter by category ---
    const filterByCategory = (catId) => {
      activeFilter = catId;
      document.querySelectorAll('.filter-chip').forEach(el => {
        const elCat = el.dataset.categoryId || 'all';
        const isAll = el.classList.contains('filter-chip-all');
        if (isAll) {
          el.style.background = catId === 'all' ? '#e94560' : 'transparent';
          el.style.color = catId === 'all' ? '#ffffff' : '#e94560';
        } else {
          const color = catColorMap[elCat] || '#3b82f6';
          el.style.background = catId === elCat ? color : 'transparent';
          el.style.color = catId === elCat ? '#ffffff' : color;
        }
      });
      // Filter sidebar items
      document.querySelectorAll('.marker-item').forEach(el => {
        const mId = el.dataset.markerId;
        const marker = markersData.find(m => m.id === mId);
        if (!marker) return;
        const show = catId === 'all' || marker.categoryId === catId;
        el.style.display = show ? 'block' : 'none';
      });
      // Filter map markers
      Object.entries(leafletMarkers).forEach(([mId, lm]) => {
        const marker = markersData.find(m => m.id === mId);
        if (!marker) return;
        const show = catId === 'all' || marker.categoryId === catId;
        if (show) lm.addTo(map);
        else map.removeLayer(lm);
      });
    };

    // --- HTML escape ---
    const esc = (s) => {
      const d = document.createElement('div');
      d.textContent = s;
      return d.innerHTML;
    };
  <\/script>
</body>
</html>`
}

import { getMarkers, addMarker, removeMarker, getCircles, addCircle, removeCircle, getCategories, addCategory, removeCategory } from './store'
import { searchLocation } from './search'
import { renderPage } from './render'
import type { AddMarkerPayload, AddCirclePayload, AddCategoryPayload } from './types'

const PORT = parseInt(process.env.PORT || '3000', 10)

const jsonResponse = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const htmlResponse = (html: string): Response =>
  new Response(html, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const parseBody = async <T>(req: Request): Promise<T> => {
  const text = await req.text()
  return JSON.parse(text) as T
}

const extractId = (pathname: string, prefix: string): string | null => {
  const match = pathname.match(new RegExp(`^${prefix}/([^/]+)$`))
  return match ? match[1] : null
}

const server = Bun.serve({
  port: PORT,
  fetch: async (req: Request): Promise<Response> => {
    const url = new URL(req.url)
    const { pathname } = url
    const method = req.method

    // --- Page ---
    if (pathname === '/' && method === 'GET') {
      const [markers, circles, categories] = await Promise.all([
        getMarkers(),
        getCircles(),
        getCategories(),
      ])
      return htmlResponse(renderPage(markers, circles, categories))
    }

    // --- Search API ---
    if (pathname === '/api/search' && method === 'GET') {
      const query = url.searchParams.get('q') || ''
      if (!query) return jsonResponse({ error: 'Missing query parameter' }, 400)
      const results = await searchLocation(query)
      return jsonResponse(results)
    }

    // --- Markers API ---
    if (pathname === '/api/markers' && method === 'GET') {
      return jsonResponse(await getMarkers())
    }

    if (pathname === '/api/markers' && method === 'POST') {
      const body = await parseBody<AddMarkerPayload>(req)
      if (!body.title || !body.position) {
        return jsonResponse({ error: 'title and position are required' }, 400)
      }
      const marker = await addMarker({
        title: body.title,
        description: body.description || '',
        position: body.position,
        categoryId: body.categoryId || 'default',
      })
      return jsonResponse(marker, 201)
    }

    const markerId = extractId(pathname, '/api/markers')
    if (markerId && method === 'DELETE') {
      const removed = await removeMarker(markerId)
      return removed
        ? jsonResponse({ ok: true })
        : jsonResponse({ error: 'Marker not found' }, 404)
    }

    // --- Circles API ---
    if (pathname === '/api/circles' && method === 'GET') {
      return jsonResponse(await getCircles())
    }

    if (pathname === '/api/circles' && method === 'POST') {
      const body = await parseBody<AddCirclePayload>(req)
      if (!body.center || !body.radius) {
        return jsonResponse({ error: 'center and radius are required' }, 400)
      }
      const circle = await addCircle({
        center: body.center,
        radius: body.radius,
        color: body.color || '#e94560',
        label: body.label || '',
      })
      return jsonResponse(circle, 201)
    }

    const circleId = extractId(pathname, '/api/circles')
    if (circleId && method === 'DELETE') {
      const removed = await removeCircle(circleId)
      return removed
        ? jsonResponse({ ok: true })
        : jsonResponse({ error: 'Circle not found' }, 404)
    }

    // --- Categories API ---
    if (pathname === '/api/categories' && method === 'GET') {
      return jsonResponse(await getCategories())
    }

    if (pathname === '/api/categories' && method === 'POST') {
      const body = await parseBody<AddCategoryPayload>(req)
      if (!body.name || !body.color) {
        return jsonResponse({ error: 'name and color are required' }, 400)
      }
      const category = await addCategory(body)
      return jsonResponse(category, 201)
    }

    const categoryId = extractId(pathname, '/api/categories')
    if (categoryId && method === 'DELETE') {
      const removed = await removeCategory(categoryId)
      return removed
        ? jsonResponse({ ok: true })
        : jsonResponse({ error: 'Category not found or protected' }, 404)
    }

    // --- 404 ---
    return jsonResponse({ error: 'Not found' }, 404)
  },
})

