import type { MapMarker, MapCircle, MarkersData, CirclesData } from './types';

const DATA_DIR = new URL('./data/', import.meta.url).pathname;
const MARKERS_PATH = `${DATA_DIR}markers.json`;
const CIRCLES_PATH = `${DATA_DIR}circles.json`;

const readJson = async <T>(path: string, fallback: T): Promise<T> => {
  try {
    const file = Bun.file(path);
    const exists = await file.exists();
    if (!exists) return fallback;
    return (await file.json()) as T;
  } catch {
    return fallback;
  }
};

const writeJson = async <T>(path: string, data: T): Promise<void> => {
  await Bun.write(path, JSON.stringify(data, null, 2));
};

export const getMarkers = async (): Promise<MapMarker[]> => {
  const data = await readJson<MarkersData>(MARKERS_PATH, { markers: [] });
  return data.markers;
};

export const addMarker = async (marker: MapMarker): Promise<MapMarker> => {
  const data = await readJson<MarkersData>(MARKERS_PATH, { markers: [] });
  data.markers.push(marker);
  await writeJson(MARKERS_PATH, data);
  return marker;
};

export const deleteMarker = async (id: string): Promise<boolean> => {
  const data = await readJson<MarkersData>(MARKERS_PATH, { markers: [] });
  const idx = data.markers.findIndex((m) => m.id === id);
  if (idx === -1) return false;
  data.markers.splice(idx, 1);
  await writeJson(MARKERS_PATH, data);
  return true;
};

export const getCircles = async (): Promise<MapCircle[]> => {
  const data = await readJson<CirclesData>(CIRCLES_PATH, { circles: [] });
  return data.circles;
};

export const addCircle = async (circle: MapCircle): Promise<MapCircle> => {
  const data = await readJson<CirclesData>(CIRCLES_PATH, { circles: [] });
  data.circles.push(circle);
  await writeJson(CIRCLES_PATH, data);
  return circle;
};

export const deleteCircle = async (id: string): Promise<boolean> => {
  const data = await readJson<CirclesData>(CIRCLES_PATH, { circles: [] });
  const idx = data.circles.findIndex((c) => c.id === id);
  if (idx === -1) return false;
  data.circles.splice(idx, 1);
  await writeJson(CIRCLES_PATH, data);
  return true;
};

