const clientScript = (markers: MapMarker[], circles: MapCircle[]): string => `
(function() {
  var CATEGORY_COLORS = ${JSON.stringify(Object.fromEntries(CATEGORIES.map((c) => [c.name, c.color])))};

  var map = L.map('map').setView([40.7128, -74.006], 12);
  L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
    attribution: '&copy; OpenStreetMap contributors',
    maxZoom: 19,
  }).addTo(map);

  var markerLayer = L.layerGroup().addTo(map);
  var circleLayer = L.layerGroup().addTo(map);
  var leafletMarkers = {};
  var leafletCircles = {};
  var activeFilters = new Set(${JSON.stringify(CATEGORIES.map((c) => c.name))});

  function createColorIcon(color) {
    return L.divIcon({
      className: '',
      html: '<div style="width:24px;height:24px;border-radius:50% 50% 50% 0;background:' + color + ';transform:rotate(-45deg);border:2px solid #fff;box-shadow:0 1px 4px rgba(0,0,0,0.3);"></div>',
      iconSize: [24, 24],
      iconAnchor: [12, 24],
      popupAnchor: [0, -24],
    });
  }

  function addMarkerToMap(m) {
    var icon = createColorIcon(CATEGORY_COLORS[m.category] || '#2196F3');
    var lm = L.marker([m.lat, m.lng], { icon: icon })
      .bindPopup('<strong>' + escapeHtml(m.title) + '</strong>' + (m.description ? '<br>' + escapeHtml(m.description) : '') + '<br><em style="color:' + (CATEGORY_COLORS[m.category] || '#2196F3') + '">' + m.category + '</em>');
    markerLayer.addLayer(lm);
    leafletMarkers[m.id] = lm;
    if (!activeFilters.has(m.category)) lm.remove();
  }

  function addCircleToMap(c) {
    var lc = L.circle([c.lat, c.lng], {
      radius: c.radius,
      color: c.color || '#2196F3',
      fillOpacity: 0.15,
      weight: 2,
    });
    if (c.label) lc.bindPopup(escapeHtml(c.label));
    circleLayer.addLayer(lc);
    leafletCircles[c.id] = lc;
  }

  function escapeHtml(s) {
    var d = document.createElement('div');
    d.textContent = s;
    return d.innerHTML;
  }

  // Init existing data
  var initMarkers = ${JSON.stringify(markers)};
  var initCircles = ${JSON.stringify(circles)};
  initMarkers.forEach(addMarkerToMap);
  initCircles.forEach(addCircleToMap);

  // Click-to-center from sidebar
  document.getElementById('marker-list').addEventListener('click', function(e) {
    var item = e.target.closest('.marker-item');
    if (!item) return;
    if (e.target.closest('.delete-btn')) {
      var delId = e.target.closest('.delete-btn').dataset.deleteId;
      fetch('/api/markers/' + delId, { method: 'DELETE' }).then(function() { location.reload(); });
      return;
    }
    var lat = parseFloat(item.dataset.lat);
    var lng = parseFloat(item.dataset.lng);
    map.flyTo([lat, lng], 16);
    var lm = leafletMarkers[item.dataset.markerId];
    if (lm) lm.openPopup();
  });

  // Category filtering
  document.getElementById('filter-row').addEventListener('click', function(e) {
    var chip = e.target.closest('.filter-chip');
    if (!chip) return;
    var cat = chip.dataset.category;
    if (activeFilters.has(cat)) {
      activeFilters.delete(cat);
      chip.style.backgroundColor = '#fff';
      chip.style.color = CATEGORY_COLORS[cat];
    } else {
      activeFilters.add(cat);
      chip.style.backgroundColor = CATEGORY_COLORS[cat];
      chip.style.color = '#fff';
    }
    // Show/hide markers
    Object.keys(leafletMarkers).forEach(function(id) {
      var markerEl = document.querySelector('[data-marker-id="' + id + '"]');
      if (!markerEl) return;
      var mCat = markerEl.dataset.category;
      if (activeFilters.has(mCat)) {
        markerLayer.addLayer(leafletMarkers[id]);
        markerEl.style.display = '';
      } else {
        markerLayer.removeLayer(leafletMarkers[id]);
        markerEl.style.display = 'none';
      }
    });
    // Show/hide sections
    document.querySelectorAll('#marker-list > div').forEach(function(div) {
      if (div.style && div.style.textTransform === 'uppercase') {
        // section header - check if next siblings are visible
      }
    });
  });

  // Search location
  document.getElementById('search-btn').addEventListener('click', doSearch);
  document.getElementById('search-input').addEventListener('keydown', function(e) {
    if (e.key === 'Enter') doSearch();
  });
  function doSearch() {
    var q = document.getElementById('search-input').value.trim();
    if (!q) return;
    fetch('/api/search?q=' + encodeURIComponent(q))
      .then(function(r) { return r.json(); })
      .then(function(results) {
        if (results.length > 0) {
          map.flyTo([parseFloat(results[0].lat), parseFloat(results[0].lon)], 14);
        } else {
          alert('Location not found');
        }
      })
      .catch(function() { alert('Search failed'); });
  }

  // Add marker flow
  var pendingMarker = null;
  var pendingCircle = null;
  var overlay = document.getElementById('modal-overlay');
  var markerModal = document.getElementById('marker-modal');
  var circleModal = document.getElementById('circle-modal');

  document.getElementById('add-marker-btn').addEventListener('click', function() {
    markerModal.style.display = '';
    circleModal.style.display = 'none';
    overlay.classList.add('active');
  });

  document.getElementById('add-circle-btn').addEventListener('click', function() {
    markerModal.style.display = 'none';
    circleModal.style.display = '';
    overlay.classList.add('active');
  });

  function closeModal() {
    overlay.classList.remove('active');
    pendingMarker = null;
    pendingCircle = null;
  }

  document.getElementById('modal-cancel').addEventListener('click', closeModal);
  document.getElementById('circle-cancel').addEventListener('click', closeModal);
  overlay.addEventListener('click', function(e) { if (e.target === overlay) closeModal(); });

  document.getElementById('modal-submit').addEventListener('click', function() {
    var title = document.getElementById('marker-title').value.trim();
    if (!title) { alert('Title is required'); return; }
    pendingMarker = {
      title: title,
      description: document.getElementById('marker-desc').value.trim(),
      category: document.getElementById('marker-cat').value,
    };
    overlay.classList.remove('active');
    map.getContainer().style.cursor = 'crosshair';
  });

  document.getElementById('circle-submit').addEventListener('click', function() {
    var radius = parseInt(document.getElementById('circle-radius').value, 10);
    if (!radius || radius < 50) { alert('Radius must be at least 50m'); return; }
    pendingCircle = {
      label: document.getElementById('circle-label').value.trim(),
      radius: radius,
      color: document.getElementById('circle-color').value,
    };
    overlay.classList.remove('active');
    map.getContainer().style.cursor = 'crosshair';
  });

  map.on('click', function(e) {
    if (pendingMarker) {
      var body = Object.assign({}, pendingMarker, { lat: e.latlng.lat, lng: e.latlng.lng });
      fetch('/api/markers', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(body),
      })
        .then(function(r) { return r.json(); })
        .then(function(m) {
          addMarkerToMap(m);
          location.reload();
        });
      pendingMarker = null;
      map.getContainer().style.cursor = '';
    } else if (pendingCircle) {
      var cbody = Object.assign({}, pendingCircle, { lat: e.latlng.lat, lng: e.latlng.lng });
      fetch('/api/circles', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(cbody),
      })
        .then(function(r) { return r.json(); })
        .then(function(c) {
          addCircleToMap(c);
          location.reload();
        });
      pendingCircle = null;
      map.getContainer().style.cursor = '';
    }
  });
})();
`;

import { getMarkers, addMarker, deleteMarker, getCircles, addCircle, deleteCircle } from './store';
import { renderPage } from './render';
import type { MapMarker, MapCircle, MarkerCategory, NominatimResult } from './types';
import { CATEGORIES } from './categories';

const generateId = (): string => crypto.randomUUID();

const jsonResponse = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  });

const validCategories = new Set<string>(CATEGORIES.map((c) => c.name));

export const handleGetIndex = async (): Promise<Response> => {
  const [markers, circles] = await Promise.all([getMarkers(), getCircles()]);
  const html = renderPage(markers, circles);
  return new Response(html, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  });
};

export const handleGetMarkers = async (url: URL): Promise<Response> => {
  const markers = await getMarkers();
  const category = url.searchParams.get('category');
  const filtered = category
    ? markers.filter((m) => m.category === category)
    : markers;
  return jsonResponse(filtered);
};

export const handlePostMarker = async (req: Request): Promise<Response> => {
  const body = await req.json() as Record<string, unknown>;
  const { lat, lng, title, description, category } = body;

  if (typeof lat !== 'number' || typeof lng !== 'number' || typeof title !== 'string' || !title.trim()) {
    return jsonResponse({ error: 'lat (number), lng (number), and title (string) are required' }, 400);
  }

  const cat = (typeof category === 'string' && validCategories.has(category))
    ? category as MarkerCategory
    : 'general';

  const marker: MapMarker = {
    id: generateId(),
    lat,
    lng,
    title: title.trim(),
    description: typeof description === 'string' ? description.trim() : '',
    category: cat,
    createdAt: new Date().toISOString(),
  };

  const saved = await addMarker(marker);
  return jsonResponse(saved, 201);
};

export const handleDeleteMarker = async (id: string): Promise<Response> => {
  const deleted = await deleteMarker(id);
  if (!deleted) return jsonResponse({ error: 'Marker not found' }, 404);
  return jsonResponse({ ok: true });
};

export const handleGetCircles = async (): Promise<Response> => {
  const circles = await getCircles();
  return jsonResponse(circles);
};

export const handlePostCircle = async (req: Request): Promise<Response> => {
  const body = await req.json() as Record<string, unknown>;
  const { lat, lng, radius, color, label } = body;

  if (typeof lat !== 'number' || typeof lng !== 'number' || typeof radius !== 'number' || radius < 50) {
    return jsonResponse({ error: 'lat (number), lng (number), and radius (number >= 50) are required' }, 400);
  }

  const circle: MapCircle = {
    id: generateId(),
    lat,
    lng,
    radius,
    color: typeof color === 'string' ? color : '#2196F3',
    label: typeof label === 'string' ? label.trim() : '',
    createdAt: new Date().toISOString(),
  };

  const saved = await addCircle(circle);
  return jsonResponse(saved, 201);
};

export const handleDeleteCircle = async (id: string): Promise<Response> => {
  const deleted = await deleteCircle(id);
  if (!deleted) return jsonResponse({ error: 'Circle not found' }, 404);
  return jsonResponse({ ok: true });
};

export const handleSearch = async (url: URL): Promise<Response> => {
  const q = url.searchParams.get('q');
  if (!q) return jsonResponse({ error: 'q parameter required' }, 400);

  const nominatimUrl = `https://nominatim.openstreetmap.org/search?format=json&limit=5&q=${encodeURIComponent(q)}`;
  const res = await fetch(nominatimUrl, {
    headers: { 'User-Agent': 'interactive-map-module/1.0' },
  });
  const results = (await res.json()) as NominatimResult[];
  return jsonResponse(results.map((r) => ({
    lat: r.lat,
    lon: r.lon,
    display_name: r.display_name,
  })));
};

import {
  handleGetIndex,
  handleGetMarkers,
  handlePostMarker,
  handleDeleteMarker,
  handleGetCircles,
  handlePostCircle,
  handleDeleteCircle,
  handleSearch,
} from './handlers';

const PORT = Number(process.env.PORT) || 3000;

const router = async (req: Request): Promise<Response> => {
  const url = new URL(req.url);
  const { pathname } = url;
  const method = req.method;

  // Page
  if (pathname === '/' && method === 'GET') {
    return handleGetIndex();
  }

  // Markers API
  if (pathname === '/api/markers' && method === 'GET') {
    return handleGetMarkers(url);
  }
  if (pathname === '/api/markers' && method === 'POST') {
    return handlePostMarker(req);
  }
  const markerDeleteMatch = pathname.match(/^\/api\/markers\/([^/]+)$/);
  if (markerDeleteMatch && method === 'DELETE') {
    return handleDeleteMarker(markerDeleteMatch[1]);
  }

  // Circles API
  if (pathname === '/api/circles' && method === 'GET') {
    return handleGetCircles();
  }
  if (pathname === '/api/circles' && method === 'POST') {
    return handlePostCircle(req);
  }
  const circleDeleteMatch = pathname.match(/^\/api\/circles\/([^/]+)$/);
  if (circleDeleteMatch && method === 'DELETE') {
    return handleDeleteCircle(circleDeleteMatch[1]);
  }

  // Search
  if (pathname === '/api/search' && method === 'GET') {
    return handleSearch(url);
  }

  return new Response('Not Found', { status: 404 });
};

Bun.serve({
  port: PORT,
  fetch: router,
});

console.log(`Interactive Map running at http://localhost:${PORT}`);

