import type { CalendarEvent } from './types'

const DATA_PATH = `${import.meta.dir}/data/events.json`

export const loadEvents = async (): Promise<CalendarEvent[]> => {
  const file = Bun.file(DATA_PATH)
  if (await file.exists()) {
    return file.json()
  }
  return []
}

export const saveEvents = async (events: CalendarEvent[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(events, null, 2))
}

export const generateId = (): string => {
  return crypto.randomUUID()
}

export const addEvent = async (event: Omit<CalendarEvent, 'id'>): Promise<CalendarEvent> => {
  const events = await loadEvents()
  const newEvent: CalendarEvent = { id: generateId(), ...event }
  events.push(newEvent)
  await saveEvents(events)
  return newEvent
}

export const updateEvent = async (id: string, updates: Partial<Omit<CalendarEvent, 'id'>>): Promise<CalendarEvent | null> => {
  const events = await loadEvents()
  const idx = events.findIndex((e) => e.id === id)
  if (idx === -1) return null
  events[idx] = { ...events[idx], ...updates }
  await saveEvents(events)
  return events[idx]
}

export const deleteEvent = async (id: string): Promise<boolean> => {
  const events = await loadEvents()
  const filtered = events.filter((e) => e.id !== id)
  if (filtered.length === events.length) return false
  await saveEvents(filtered)
  return true
}

export const getEvent = async (id: string): Promise<CalendarEvent | null> => {
  const events = await loadEvents()
  return events.find((e) => e.id === id) ?? null
}

import type { CalendarEvent, DayCell, MonthGrid, Recurrence } from './types'

const MONTH_NAMES = [
  'January', 'February', 'March', 'April', 'May', 'June',
  'July', 'August', 'September', 'October', 'November', 'December',
]

const DAY_NAMES = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat']

const formatDate = (year: number, month: number, day: number): string => {
  const m = String(month + 1).padStart(2, '0')
  const d = String(day).padStart(2, '0')
  return `${year}-${m}-${d}`
}

const parseDate = (dateStr: string): { year: number; month: number; day: number } => {
  const [year, month, day] = dateStr.split('-').map(Number)
  return { year, month: month - 1, day }
}

const getTodayStr = (): string => {
  const now = new Date()
  return formatDate(now.getFullYear(), now.getMonth(), now.getDate())
}

const doesEventOccurOn = (event: CalendarEvent, targetDate: string): boolean => {
  if (event.date === targetDate) return true
  if (event.recurrence === 'none') return false

  const orig = parseDate(event.date)
  const target = parseDate(targetDate)
  const origD = new Date(orig.year, orig.month, orig.day)
  const targetD = new Date(target.year, target.month, target.day)

  if (targetD < origD) return false

  switch (event.recurrence) {
    case 'daily':
      return true
    case 'weekly': {
      const diffMs = targetD.getTime() - origD.getTime()
      const diffDays = Math.round(diffMs / (1000 * 60 * 60 * 24))
      return diffDays % 7 === 0
    }
    case 'monthly':
      return orig.day === target.day && (target.year > orig.year || target.month >= orig.month)
    default:
      return false
  }
}

export const getEventsForDate = (events: CalendarEvent[], date: string): CalendarEvent[] => {
  return events
    .filter((e) => doesEventOccurOn(e, date))
    .sort((a, b) => a.startTime.localeCompare(b.startTime))
}

export const buildMonthGrid = (year: number, month: number, events: CalendarEvent[]): MonthGrid => {
  const firstDay = new Date(year, month, 1).getDay()
  const daysInMonth = new Date(year, month + 1, 0).getDate()
  const daysInPrev = new Date(year, month, 0).getDate()
  const today = getTodayStr()

  const cells: DayCell[] = []

  // Previous month padding
  for (let i = firstDay - 1; i >= 0; i--) {
    const day = daysInPrev - i
    const prevMonth = month === 0 ? 11 : month - 1
    const prevYear = month === 0 ? year - 1 : year
    const date = formatDate(prevYear, prevMonth, day)
    cells.push({
      date,
      day,
      isCurrentMonth: false,
      isToday: date === today,
      events: getEventsForDate(events, date),
    })
  }

  // Current month
  for (let day = 1; day <= daysInMonth; day++) {
    const date = formatDate(year, month, day)
    cells.push({
      date,
      day,
      isCurrentMonth: true,
      isToday: date === today,
      events: getEventsForDate(events, date),
    })
  }

  // Next month padding
  const remaining = 7 - (cells.length % 7)
  if (remaining < 7) {
    for (let day = 1; day <= remaining; day++) {
      const nextMonth = month === 11 ? 0 : month + 1
      const nextYear = month === 11 ? year + 1 : year
      const date = formatDate(nextYear, nextMonth, day)
      cells.push({
        date,
        day,
        isCurrentMonth: false,
        isToday: date === today,
        events: getEventsForDate(events, date),
      })
    }
  }

  // Chunk into weeks
  const weeks: DayCell[][] = []
  for (let i = 0; i < cells.length; i += 7) {
    weeks.push(cells.slice(i, i + 7))
  }

  return {
    year,
    month,
    label: `${MONTH_NAMES[month]} ${year}`,
    weeks,
  }
}

