const styleToStr = (s: Record<string, string | number>): string =>
  Object.entries(s)
    .map(([k, v]) => `${k.replace(/[A-Z]/g, (c) => `-${c.toLowerCase()}`)}:${typeof v === 'number' ? `${v}px` : v}`)
    .join(';')

export const renderMonthView = (grid: MonthGrid): string => {
  const dayHeaders = DAY_NAMES.map((d) => h('div', { style: styleToStr(styles.dayHeader) }, d))

  const dayCells = grid.weeks.flatMap((week) =>
    week.map((cell) => {
      const cellStyle = {
        ...styles.dayCell,
        ...(cell.isCurrentMonth ? {} : styles.dayCellMuted),
        ...(cell.isToday ? styles.dayCellToday : {}),
      }

      const numberEl = cell.isToday
        ? h('div', { style: styleToStr(styles.todayNumber) }, String(cell.day))
        : h('div', { style: styleToStr(styles.dayNumber) }, String(cell.day))

      const uniqueCategories = [...new Set(cell.events.map((e) => e.category))]
      const dots = uniqueCategories.map((cat) =>
        h('span', {
          style: styleToStr({
            ...styles.eventDot,
            background: CATEGORY_COLORS[cat],
          }),
        })
      )

      const dotsRow = dots.length > 0 ? h('div', { style: styleToStr(styles.dotsRow) }, ...dots) : ''

      return h(
        'div',
        {
          style: styleToStr(cellStyle),
          'p-trigger': 'click:selectDay',
          'data-date': cell.date,
        },
        numberEl,
        dotsRow
