import type { CalendarEvent, EventCategory, Recurrence, ViewState } from './types'
import { loadEvents, addEvent, updateEvent, deleteEvent, getEvent } from './store'
import { buildMonthGrid, getEventsForDate } from './calendar'
import { renderMonthView, renderDayView, renderEventForm } from './views'

export type ActionResult = {
  html: string
  state: ViewState
}

export const showMonth = async (year: number, month: number): Promise<ActionResult> => {
  const events = await loadEvents()
  const grid = buildMonthGrid(year, month, events)
  return {
    html: renderMonthView(grid),
    state: { view: 'month', year, month, selectedDate: null },
  }
}

export const navigateMonth = async (state: ViewState, direction: -1 | 1): Promise<ActionResult> => {
  let { year, month } = state
  month += direction
  if (month < 0) {
    month = 11
    year -= 1
  } else if (month > 11) {
    month = 0
    year += 1
  }
  return showMonth(year, month)
}

export const showDay = async (date: string, state: ViewState): Promise<ActionResult> => {
  const events = await loadEvents()
  const dayEvents = getEventsForDate(events, date)
  return {
    html: renderDayView(date, dayEvents),
    state: { ...state, view: 'day', selectedDate: date },
  }
}

export const showAddForm = (date: string, state: ViewState): ActionResult => ({
  html: renderEventForm(date),
  state: { ...state, selectedDate: date },
})

export const showEditForm = async (eventId: string, state: ViewState): Promise<ActionResult> => {
  const event = await getEvent(eventId)
  if (!event) return showMonth(state.year, state.month)
  return {
    html: renderEventForm(event.date, event),
    state: { ...state, selectedDate: event.date },
  }
}

export type EventFormData = {
  title: string
  date: string
  startTime: string
  endTime: string
  description: string
  category: EventCategory
  recurrence: Recurrence
}

export const handleCreateEvent = async (data: EventFormData, state: ViewState): Promise<ActionResult> => {
  await addEvent(data)
  return showDay(data.date, state)
}

export const handleUpdateEvent = async (
  eventId: string,
  data: EventFormData,
  state: ViewState
): Promise<ActionResult> => {
  await updateEvent(eventId, data)
  return showDay(data.date, state)
}

export const handleDeleteEvent = async (eventId: string, state: ViewState): Promise<ActionResult> => {
  const event = await getEvent(eventId)
  await deleteEvent(eventId)
  const date = event?.date ?? state.selectedDate ?? ''
  if (date) return showDay(date, state)
  return showMonth(state.year, state.month)
}

export const handleBackToMonth = async (state: ViewState): Promise<ActionResult> => {
  return showMonth(state.year, state.month)
}

import type { ViewState } from './types'
import {
  showMonth,
  navigateMonth,
  showDay,
  showAddForm,
  showEditForm,
  handleCreateEvent,
  handleUpdateEvent,
  handleDeleteEvent,
  handleBackToMonth,
} from './handlers'
import type { EventFormData } from './handlers'

export type { CalendarEvent, EventCategory, Recurrence, ViewState } from './types'
export type { ActionResult, EventFormData } from './handlers'

const getInitialState = (): ViewState => {
  const now = new Date()
  return {
    view: 'month',
    year: now.getFullYear(),
    month: now.getMonth(),
    selectedDate: null,
  }
}

export const createCalendar = () => {
  let state: ViewState = getInitialState()

  const dispatch = async (action: string, payload?: Record<string, string>): Promise<string> => {
    let result

    switch (action) {
      case 'init':
        result = await showMonth(state.year, state.month)
        break

      case 'prevMonth':
        result = await navigateMonth(state, -1)
        break

      case 'nextMonth':
        result = await navigateMonth(state, 1)
        break

      case 'selectDay':
        if (!payload?.date) throw new Error('Missing date for selectDay')
        result = await showDay(payload.date, state)
        break

      case 'backToMonth':
        result = await handleBackToMonth(state)
        break

      case 'showAddForm':
        result = showAddForm(payload?.date ?? state.selectedDate ?? '', state)
        break

      case 'editEvent':
        if (!payload?.eventId) throw new Error('Missing eventId for editEvent')
        result = await showEditForm(payload.eventId, state)
        break

      case 'deleteEvent':
        if (!payload?.eventId) throw new Error('Missing eventId for deleteEvent')
        result = await handleDeleteEvent(payload.eventId, state)
        break

      case 'submitEvent': {
        if (!payload) throw new Error('Missing form data for submitEvent')
        const formData: EventFormData = {
          title: payload.title,
          date: payload.date,
          startTime: payload.startTime,
          endTime: payload.endTime,
          description: payload.description ?? '',
          category: payload.category as EventFormData['category'],
          recurrence: payload.recurrence as EventFormData['recurrence'],
        }
        if (payload.eventId) {
          result = await handleUpdateEvent(payload.eventId, formData, state)
        } else {
          result = await handleCreateEvent(formData, state)
        }
        break
      }

      case 'cancelForm':
        if (state.selectedDate) {
          result = await showDay(state.selectedDate, state)
        } else {
          result = await handleBackToMonth(state)
        }
        break

      default:
        throw new Error(`Unknown action: ${action}`)
    }

    state = result.state
    return result.html
  }

  return { dispatch, getState: () => ({ ...state }) }
}

