const DATA_PATH = `${import.meta.dir}/data/events.json`;

const generateId = (): string => crypto.randomUUID();

const now = (): string => new Date().toISOString();

export const loadEvents = async (): Promise<CalendarEvent[]> => {
  const file = Bun.file(DATA_PATH);
  const exists = await file.exists();
  if (!exists) {
    await Bun.write(DATA_PATH, '[]');
    return [];
  }
  const text = await file.text();
  return JSON.parse(text) as CalendarEvent[];
};

export const saveEvents = async (events: CalendarEvent[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(events, null, 2));
};

export const createEvent = async (input: CreateEventInput): Promise<CalendarEvent> => {
  const events = await loadEvents();
  const event: CalendarEvent = {
    id: generateId(),
    title: input.title,
    date: input.date,
    startTime: input.startTime,
    endTime: input.endTime,
    description: input.description ?? '',
    category: input.category ?? 'personal',
    recurrence: input.recurrence ?? 'none',
    createdAt: now(),
    updatedAt: now(),
  };
  events.push(event);
  await saveEvents(events);
  return event;
};

export const updateEvent = async (input: UpdateEventInput): Promise<CalendarEvent | null> => {
  const events = await loadEvents();
  const idx = events.findIndex((e) => e.id === input.id);
  if (idx === -1) return null;

  const existing = events[idx];
  const updated: CalendarEvent = {
    ...existing,
    title: input.title ?? existing.title,
    date: input.date ?? existing.date,
    startTime: input.startTime ?? existing.startTime,
    endTime: input.endTime ?? existing.endTime,
    description: input.description ?? existing.description,
    category: input.category ?? existing.category,
    recurrence: input.recurrence ?? existing.recurrence,
    updatedAt: now(),
  };
  events[idx] = updated;
  await saveEvents(events);
  return updated;
};

export const deleteEvent = async (id: string): Promise<boolean> => {
  const events = await loadEvents();
  const filtered = events.filter((e) => e.id !== id);
  if (filtered.length === events.length) return false;
  await saveEvents(filtered);
  return true;
};

export const getEventById = async (id: string): Promise<CalendarEvent | null> => {
  const events = await loadEvents();
  return events.find((e) => e.id === id) ?? null;
};

export const getEventsByDate = async (date: string): Promise<CalendarEvent[]> => {
  const events = await loadEvents();
  return events
    .filter((e) => e.date === date)
    .sort((a, b) => a.startTime.localeCompare(b.startTime));
};

import type { CalendarEvent } from './types';

const parseDate = (dateStr: string): Date => {
  const [year, month, day] = dateStr.split('-').map(Number);
  return new Date(year, month - 1, day);
};

const formatDate = (d: Date): string => {
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, '0');
  const day = String(d.getDate()).padStart(2, '0');
  return `${y}-${m}-${day}`;
};

const isSameOrBefore = (a: Date, b: Date): boolean =>
  a.getTime() <= b.getTime();

const addDays = (d: Date, n: number): Date => {
  const result = new Date(d);
  result.setDate(result.getDate() + n);
  return result;
};

const addWeeks = (d: Date, n: number): Date => addDays(d, n * 7);

const addMonths = (d: Date, n: number): Date => {
  const result = new Date(d);
  result.setMonth(result.getMonth() + n);
  return result;
};

export const expandRecurrences = (
  events: CalendarEvent[],
  rangeStart: string,
  rangeEnd: string,
): CalendarEvent[] => {
  const start = parseDate(rangeStart);
  const end = parseDate(rangeEnd);
  const expanded: CalendarEvent[] = [];

  for (const event of events) {
    if (event.recurrence === 'none') {
      const eventDate = parseDate(event.date);
      if (eventDate >= start && eventDate <= end) {
        expanded.push(event);
      }
      continue;
    }

    const originDate = parseDate(event.date);
    let current = new Date(originDate);
    let iterations = 0;
    const maxIterations = 366; // safety limit

    while (isSameOrBefore(current, end) && iterations < maxIterations) {
      if (current >= start) {
        expanded.push({
          ...event,
          date: formatDate(current),
        });
      }

      iterations++;
      switch (event.recurrence) {
        case 'daily':
          current = addDays(originDate, iterations);
          break;
        case 'weekly':
          current = addWeeks(originDate, iterations);
          break;
        case 'monthly':
          current = addMonths(originDate, iterations);
          break;
      }
    }
  }

  return expanded;
};

export const getEventsForDate = (
  events: CalendarEvent[],
  date: string,
): CalendarEvent[] => {
  const expanded = expandRecurrences(events, date, date);
  return expanded
    .filter((e) => e.date === date)
    .sort((a, b) => a.startTime.localeCompare(b.startTime));
};

import type { CalendarEvent, CalendarDay, MonthGrid } from './types';
import { expandRecurrences } from './recurrence';

const MONTH_NAMES = [
  'January', 'February', 'March', 'April', 'May', 'June',
  'July', 'August', 'September', 'October', 'November', 'December',
];

const formatDate = (d: Date): string => {
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, '0');
  const day = String(d.getDate()).padStart(2, '0');
  return `${y}-${m}-${day}`;
};

const todayStr = (): string => formatDate(new Date());

export const buildMonthGrid = (
  year: number,
  month: number,
  events: CalendarEvent[],
): MonthGrid => {
  const firstDay = new Date(year, month, 1);
  const lastDay = new Date(year, month + 1, 0);
  const startDow = firstDay.getDay(); // 0=Sunday

  // Expand range to include padding days
  const gridStart = new Date(firstDay);
  gridStart.setDate(gridStart.getDate() - startDow);

  const daysInGrid = Math.ceil((startDow + lastDay.getDate()) / 7) * 7;
  const gridEnd = new Date(gridStart);
  gridEnd.setDate(gridEnd.getDate() + daysInGrid - 1);

  const rangeStart = formatDate(gridStart);
  const rangeEnd = formatDate(gridEnd);
  const expanded = expandRecurrences(events, rangeStart, rangeEnd);

  const eventsByDate = new Map<string, CalendarEvent[]>();
  for (const evt of expanded) {
    const list = eventsByDate.get(evt.date) ?? [];
    list.push(evt);
    eventsByDate.set(evt.date, list);
  }

  const today = todayStr();
  const weeks: CalendarDay[][] = [];
  let currentDate = new Date(gridStart);

  for (let i = 0; i < daysInGrid; i++) {
    const weekIdx = Math.floor(i / 7);
    if (!weeks[weekIdx]) weeks[weekIdx] = [];

    const dateStr = formatDate(currentDate);
    const dayEvents = eventsByDate.get(dateStr) ?? [];
    dayEvents.sort((a, b) => a.startTime.localeCompare(b.startTime));

    weeks[weekIdx].push({
      date: dateStr,
      dayOfMonth: currentDate.getDate(),
      isCurrentMonth: currentDate.getMonth() === month,
      isToday: dateStr === today,
      events: dayEvents,
    });

    currentDate.setDate(currentDate.getDate() + 1);
  }

  return {
    year,
    month,
    label: `${MONTH_NAMES[month]} ${year}`,
    weeks,
  };
};

