const styleObj = (obj: Record<string, string | number>): string =>
  Object.entries(obj)
    .map(([k, v]) => {
      const prop = k.replace(/[A-Z]/g, (m) => `-${m.toLowerCase()}`);
      return `${prop}:${typeof v === 'number' ? `${v}px` : v}`;
    })
    .join(';');

const renderEventDots = (events: CalendarEvent[]) => {
  const categories = [...new Set(events.map((e) => e.category))];
  return h(
    'div',
    { style: styleObj(styles.dotsRow) },
    ...categories.map((cat) =>
      h('span', {
        style: styleObj({ ...styles.eventDot, backgroundColor: CATEGORY_COLORS[cat].dot }),
        title: CATEGORY_LABELS[cat],
      }),
    ),
  );
};

const renderEventChips = (events: CalendarEvent[]) => {
  const maxShow = 2;
  const shown = events.slice(0, maxShow);
  const overflow = events.length - maxShow;
  return h(
    Fragment,
    {},
    ...shown.map((evt) => {
      const colors = CATEGORY_COLORS[evt.category];
      return h(
        'div',
        {
          style: styleObj({
            ...styles.eventChip,
            backgroundColor: colors.bg,
            color: colors.text,
          }),
        },
        `${evt.startTime} ${evt.title}`,
      );
    }),
    ...(overflow > 0
      ? [h('div', { style: styleObj({ fontSize: '11px', color: '#6b7280' }) }, `+${overflow} more`)]
      : []),
  );
};

