const MONTH_NAMES = [
  'January', 'February', 'March', 'April', 'May', 'June',
  'July', 'August', 'September', 'October', 'November', 'December',
];

const DAY_NAMES = [
  'Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday',
];

const formatDayLabel = (dateStr: string): string => {
  const [y, m, d] = dateStr.split('-').map(Number);
  const date = new Date(y, m - 1, d);
  return `${DAY_NAMES[date.getDay()]}, ${MONTH_NAMES[date.getMonth()]} ${d}, ${y}`;
};

// --- Public API ---

export const viewMonth = async (year?: number, month?: number): Promise<string> => {
  const now = new Date();
  const y = year ?? now.getFullYear();
  const m = month ?? now.getMonth();
  const events = await loadEvents();
  const grid = buildMonthGrid(y, m, events);
  const ssr = createSSR();
  return ssr(renderMonthView(grid));
};

export const viewDay = async (date: string): Promise<string> => {
  const events = await loadEvents();
  const dayEvents = getEventsForDate(events, date);
  const dayView: DayView = {
    date,
    label: formatDayLabel(date),
    events: dayEvents,
  };
  const ssr = createSSR();
  return ssr(renderDayView(dayView));
};

export const showCreateForm = async (prefilledDate?: string): Promise<string> => {
  const ssr = createSSR();
  return ssr(renderEventForm(undefined, prefilledDate));
};

export const showEditForm = async (eventId: string): Promise<string> => {
  const event = await getEventById(eventId);
  if (!event) return '<div>Event not found.</div>';
  const ssr = createSSR();
  return ssr(renderEventForm(event));
};

export const addEvent = async (input: CreateEventInput): Promise<CalendarEvent> =>
  createEvent(input);

export const editEvent = async (input: UpdateEventInput): Promise<CalendarEvent | null> =>
  updateEvent(input);

export const removeEvent = async (id: string): Promise<boolean> =>
  deleteEvent(id);

export const listEventsForDate = async (date: string): Promise<CalendarEvent[]> => {
  const events = await loadEvents();
  return getEventsForDate(events, date);
};

export const listAllEvents = async (): Promise<CalendarEvent[]> =>
  loadEvents();

export const navigateMonth = async (year: number, month: number): Promise<string> =>
  viewMonth(year, month);

