import type { CalendarEvent } from './types';

const DATA_PATH = new URL('./data/events.json', import.meta.url).pathname;

export const loadEvents = async (): Promise<CalendarEvent[]> => {
  const file = Bun.file(DATA_PATH);
  if (!(await file.exists())) {
    await Bun.write(DATA_PATH, '[]');
    return [];
  }
  const text = await file.text();
  return JSON.parse(text) as CalendarEvent[];
};

export const saveEvents = async (events: CalendarEvent[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(events, null, 2));
};

export const generateId = (): string => {
  return `evt_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
};

export const addEvent = async (event: Omit<CalendarEvent, 'id'>): Promise<CalendarEvent> => {
  const events = await loadEvents();
  const newEvent: CalendarEvent = { id: generateId(), ...event };
  events.push(newEvent);
  await saveEvents(events);
  return newEvent;
};

export const updateEvent = async (
  id: string,
  updates: Partial<Omit<CalendarEvent, 'id'>>
): Promise<CalendarEvent | null> => {
  const events = await loadEvents();
  const idx = events.findIndex((e) => e.id === id);
  if (idx === -1) return null;
  events[idx] = { ...events[idx], ...updates };
  await saveEvents(events);
  return events[idx];
};

export const deleteEvent = async (id: string): Promise<boolean> => {
  const events = await loadEvents();
  const filtered = events.filter((e) => e.id !== id);
  if (filtered.length === events.length) return false;
  await saveEvents(filtered);
  return true;
};

export const getEventById = async (id: string): Promise<CalendarEvent | null> => {
  const events = await loadEvents();
  return events.find((e) => e.id === id) ?? null;
};

import type { CalendarEvent, DayCell, EventCategory, RecurrenceRule } from './types';

export const formatDate = (year: number, month: number, day: number): string => {
  const m = String(month + 1).padStart(2, '0');
  const d = String(day).padStart(2, '0');
  return `${year}-${m}-${d}`;
};

export const parseDate = (dateStr: string): { year: number; month: number; day: number } => {
  const [year, month, day] = dateStr.split('-').map(Number);
  return { year, month: month - 1, day };
};

export const getMonthName = (month: number): string => {
  const names = [
    'January', 'February', 'March', 'April', 'May', 'June',
    'July', 'August', 'September', 'October', 'November', 'December',
  ];
  return names[month];
};

export const getDaysInMonth = (year: number, month: number): number => {
  return new Date(year, month + 1, 0).getDate();
};

export const getFirstDayOfWeek = (year: number, month: number): number => {
  return new Date(year, month, 1).getDay();
};

export const getTodayString = (): string => {
  const now = new Date();
  return formatDate(now.getFullYear(), now.getMonth(), now.getDate());
};

const doesRecurrenceMatch = (
  eventDate: string,
  targetDate: string,
  recurrence: RecurrenceRule
): boolean => {
  const event = parseDate(eventDate);
  const target = parseDate(targetDate);
  const eventD = new Date(event.year, event.month, event.day);
  const targetD = new Date(target.year, target.month, target.day);

  if (targetD < eventD) return false;

  switch (recurrence) {
    case 'daily':
      return true;
    case 'weekly': {
      return eventD.getDay() === targetD.getDay();
    }
    case 'monthly': {
      return event.day === target.day;
    }
  }
};

export const getEventsForDate = (
  events: CalendarEvent[],
  dateStr: string,
  categoryFilter: EventCategory | null = null
): CalendarEvent[] => {
  const matching = events.filter((event) => {
    if (categoryFilter && event.category !== categoryFilter) return false;
    if (event.date === dateStr) return true;
    if (event.recurrence && doesRecurrenceMatch(event.date, dateStr, event.recurrence)) return true;
    return false;
  });

  return matching.sort((a, b) => a.startTime.localeCompare(b.startTime));
};

export const buildMonthGrid = (
  year: number,
  month: number,
  events: CalendarEvent[],
  categoryFilter: EventCategory | null = null
): DayCell[] => {
  const daysInMonth = getDaysInMonth(year, month);
  const firstDay = getFirstDayOfWeek(year, month);
  const today = getTodayString();
  const cells: DayCell[] = [];

  // Previous month padding
  const prevMonth = month === 0 ? 11 : month - 1;
  const prevYear = month === 0 ? year - 1 : year;
  const daysInPrev = getDaysInMonth(prevYear, prevMonth);

  for (let i = firstDay - 1; i >= 0; i--) {
    const day = daysInPrev - i;
    const date = formatDate(prevYear, prevMonth, day);
    const dayEvents = getEventsForDate(events, date, categoryFilter);
    cells.push({
      date,
      day,
      inMonth: false,
      isToday: date === today,
      hasEvents: dayEvents.length > 0,
      eventCategories: [...new Set(dayEvents.map((e) => e.category))],
    });
  }

  // Current month
  for (let day = 1; day <= daysInMonth; day++) {
    const date = formatDate(year, month, day);
    const dayEvents = getEventsForDate(events, date, categoryFilter);
    cells.push({
      date,
      day,
      inMonth: true,
      isToday: date === today,
      hasEvents: dayEvents.length > 0,
      eventCategories: [...new Set(dayEvents.map((e) => e.category))],
    });
  }

  // Next month padding
  const nextMonth = month === 11 ? 0 : month + 1;
  const nextYear = month === 11 ? year + 1 : year;
  const remaining = 42 - cells.length;

  for (let day = 1; day <= remaining; day++) {
    const date = formatDate(nextYear, nextMonth, day);
    const dayEvents = getEventsForDate(events, date, categoryFilter);
    cells.push({
      date,
      day,
      inMonth: false,
      isToday: date === today,
      hasEvents: dayEvents.length > 0,
      eventCategories: [...new Set(dayEvents.map((e) => e.category))],
    });
  }

  return cells;
};

export const navigateMonth = (
  year: number,
  month: number,
  direction: -1 | 1
): { year: number; month: number } => {
  let newMonth = month + direction;
  let newYear = year;
  if (newMonth < 0) {
    newMonth = 11;
    newYear--;
  } else if (newMonth > 11) {
    newMonth = 0;
    newYear++;
  }
  return { year: newYear, month: newMonth };
};

export const formatTimeDisplay = (time: string): string => {
  const [h, m] = time.split(':').map(Number);
  const period = h >= 12 ? 'PM' : 'AM';
  const hour12 = h === 0 ? 12 : h > 12 ? h - 12 : h;
  return `${hour12}:${String(m).padStart(2, '0')} ${period}`;
};

export const formatDateDisplay = (dateStr: string): string => {
  const { year, month, day } = parseDate(dateStr);
  const d = new Date(year, month, day);
  const dayName = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'][d.getDay()];
  return `${dayName}, ${getMonthName(month)} ${day}, ${year}`;
};

