import { createSSR } from 'plaited';
import type { CalendarEvent, CalendarState, EventCategory, RecurrenceRule } from './types';
import { loadEvents, addEvent, updateEvent, deleteEvent, getEventById } from './store';
import { navigateMonth, getTodayString, parseDate } from './calendar';
import { renderMonthView, renderDayView, renderEventForm } from './render';

const createInitialState = (): CalendarState => {
  const today = getTodayString();
  const { year, month } = parseDate(today);
  return {
    view: 'month',
    year,
    month,
    selectedDate: null,
    categoryFilter: null,
  };
};

let state: CalendarState = createInitialState();

const renderCurrentView = async (): Promise<string> => {
  const events = await loadEvents();
  const ssr = createSSR();

  if (state.view === 'day' && state.selectedDate) {
    return ssr(renderDayView(state, events));
  }
  return ssr(renderMonthView(state, events));
};

const renderForm = async (
  targetDate: string,
  eventId: string | null = null
): Promise<string> => {
  const existing = eventId ? await getEventById(eventId) : null;
  const ssr = createSSR();
  return ssr(renderEventForm(targetDate, existing));
};

export const handleAction = async (
  action: string,
  payload: string = '',
  formData: Record<string, string> = {}
): Promise<{ html: string; state: CalendarState }> => {
  switch (action) {
    case 'navigateMonth': {
      const direction = Number(payload) as -1 | 1;
      const nav = navigateMonth(state.year, state.month, direction);
      state = { ...state, year: nav.year, month: nav.month };
      break;
    }

    case 'selectDate': {
      state = { ...state, view: 'day', selectedDate: payload };
      break;
    }

    case 'backToMonth': {
      state = { ...state, view: 'month', selectedDate: null };
      break;
    }

    case 'filterCategory': {
      const filter = payload === 'all' ? null : (payload as EventCategory);
      state = { ...state, categoryFilter: filter };
      break;
    }

    case 'showEventForm': {
      const html = await renderForm(payload);
      return { html, state };
    }

    case 'editEvent': {
      const event = await getEventById(payload);
      if (event) {
        const html = await renderForm(event.date, event.id);
        return { html, state };
      }
      break;
    }

    case 'createEvent': {
      const recurrence =
        formData.recurrence === 'none' ? null : (formData.recurrence as RecurrenceRule);
      await addEvent({
        title: formData.title,
        date: formData.date,
        startTime: formData.startTime,
        endTime: formData.endTime,
        description: formData.description ?? '',
        category: (formData.category as EventCategory) ?? 'personal',
        recurrence,
      });
      break;
    }

    case 'updateEvent': {
      const eventId = formData.eventId;
      if (eventId) {
        const recurrence =
          formData.recurrence === 'none' ? null : (formData.recurrence as RecurrenceRule);
        await updateEvent(eventId, {
          title: formData.title,
          date: formData.date,
          startTime: formData.startTime,
          endTime: formData.endTime,
          description: formData.description ?? '',
          category: (formData.category as EventCategory) ?? 'personal',
          recurrence,
        });
      }
      break;
    }

    case 'deleteEvent': {
      await deleteEvent(payload);
      break;
    }

    case 'cancelForm': {
      // Just re-render current view
      break;
    }
  }

  const html = await renderCurrentView();
  return { html, state };
};

export const getCalendarHTML = async (): Promise<string> => {
  return renderCurrentView();
};

export const getState = (): CalendarState => state;

export const setState = (newState: Partial<CalendarState>): void => {
  state = { ...state, ...newState };
};

// Direct API for programmatic event creation
export const createEvent = async (eventData: {
  title: string;
  date: string;
  startTime: string;
  endTime: string;
  description?: string;
  category?: EventCategory;
  recurrence?: RecurrenceRule | null;
}): Promise<CalendarEvent> => {
  return addEvent({
    title: eventData.title,
    date: eventData.date,
    startTime: eventData.startTime,
    endTime: eventData.endTime,
    description: eventData.description ?? '',
    category: eventData.category ?? 'personal',
    recurrence: eventData.recurrence ?? null,
  });
};

