import type { DataRow, DetectedSchema, FieldInfo } from './types'

const isNumeric = (value: unknown): boolean => {
  if (typeof value === 'number') return true
  if (typeof value === 'string') {
    const trimmed = value.trim()
    return trimmed !== '' && !isNaN(Number(trimmed))
  }
  return false
}

export const detectSchema = (data: DataRow[]): DetectedSchema => {
  if (data.length === 0) {
    return { fields: [], numericFields: [], categoricalFields: [] }
  }

  const allKeys = new Set<string>()
  for (const row of data) {
    for (const key of Object.keys(row)) {
      allKeys.add(key)
    }
  }

  const fields: FieldInfo[] = []
  const numericFields: string[] = []
  const categoricalFields: string[] = []

  for (const key of allKeys) {
    const values = data.map((row) => row[key]).filter((v) => v !== undefined && v !== null)
    const allNumeric = values.length > 0 && values.every(isNumeric)

    if (allNumeric) {
      fields.push({ name: key, kind: 'numeric' })
      numericFields.push(key)
    } else {
      fields.push({ name: key, kind: 'categorical' })
      categoricalFields.push(key)
    }
  }

  return { fields, numericFields, categoricalFields }
}

export const parseData = (jsonStr: string): { data: DataRow[] | null; error: string | null } => {
  try {
    const parsed = JSON.parse(jsonStr)
    if (!Array.isArray(parsed)) {
      return { data: null, error: 'Input must be a JSON array' }
    }
    if (parsed.length === 0) {
      return { data: null, error: 'Array must contain at least one object' }
    }
    if (typeof parsed[0] !== 'object' || parsed[0] === null) {
      return { data: null, error: 'Array elements must be objects' }
    }
    return { data: parsed as DataRow[], error: null }
  } catch (e) {
    const msg = e instanceof Error ? e.message : 'Invalid JSON'
    return { data: null, error: msg }
  }
}

import { h } from 'plaited'
import type { DataRow, ChartConfig } from '../types'

export type Padding = {
  top: number
  right: number
  bottom: number
  left: number
}

export const DEFAULT_PADDING: Padding = {
  top: 50,
  right: 30,
  bottom: 60,
  left: 70,
}

export const extractNumericValues = (data: DataRow[], field: string): number[] =>
  data.map((row) => {
    const v = row[field]
    return typeof v === 'number' ? v : Number(v)
  })

export const extractLabels = (data: DataRow[], field: string): string[] =>
  data.map((row) => String(row[field] ?? ''))

export const niceMax = (values: number[]): number => {
  const max = Math.max(...values)
  if (max === 0) return 10
  const magnitude = Math.pow(10, Math.floor(Math.log10(max)))
  return Math.ceil(max / magnitude) * magnitude
}

export const generateTicks = (max: number, count: number = 5): number[] => {
  const step = max / count
  return Array.from({ length: count + 1 }, (_, i) => Math.round(i * step))
}

export const renderTitle = (config: ChartConfig) => {
  if (!config.title) return null
  return h('text', {
    x: String(config.width / 2),
    y: '28',
    'text-anchor': 'middle',
    'font-size': '16',
    'font-weight': 'bold',
    'font-family': 'system-ui, sans-serif',
    fill: '#1a1a1a',
  }, config.title)
}

export const renderAxisLabels = (config: ChartConfig, padding: Padding) => {
  const elements: ReturnType<typeof h>[] = []

  if (config.xLabel) {
    elements.push(
      h('text', {
        x: String((config.width - padding.left - padding.right) / 2 + padding.left),
        y: String(config.height - 8),
        'text-anchor': 'middle',
        'font-size': '12',
        'font-family': 'system-ui, sans-serif',
        fill: '#555',
      }, config.xLabel)
    )
  }

  if (config.yLabel) {
    elements.push(
      h('text', {
        x: '14',
        y: String((config.height - padding.top - padding.bottom) / 2 + padding.top),
        'text-anchor': 'middle',
        'font-size': '12',
        'font-family': 'system-ui, sans-serif',
        fill: '#555',
        transform: `rotate(-90, 14, ${(config.height - padding.top - padding.bottom) / 2 + padding.top})`,
      }, config.yLabel)
    )
  }

  return elements
}

export const wrapSvg = (config: ChartConfig, ...children: unknown[]) =>
  h('svg', {
    xmlns: 'http://www.w3.org/2000/svg',
    viewBox: `0 0 ${config.width} ${config.height}`,
    width: String(config.width),
    height: String(config.height),
    style: 'background: #ffffff; border-radius: 4px;',
  }, ...children)

import { h } from 'plaited'
import type { DataRow, ChartConfig } from '../types'
import {
  DEFAULT_PADDING,
  extractNumericValues,
  extractLabels,
  niceMax,
  generateTicks,
  renderTitle,
  renderAxisLabels,
  wrapSvg,
} from './common'

export const renderBarChart = (data: DataRow[], config: ChartConfig): string => {
  const padding = { ...DEFAULT_PADDING }
  const labels = extractLabels(data, config.categoryField)
  const valueFields = config.valueFields.length > 0 ? config.valueFields : []
  if (valueFields.length === 0) return ''

  const allValues: number[] = []
  for (const field of valueFields) {
    allValues.push(...extractNumericValues(data, field))
  }

  const maxVal = niceMax(allValues)
  const ticks = generateTicks(maxVal)

  const chartW = config.width - padding.left - padding.right
  const chartH = config.height - padding.top - padding.bottom
  const groupWidth = chartW / labels.length
  const barCount = valueFields.length
  const barGap = 4
  const barWidth = Math.max(2, (groupWidth - barGap * (barCount + 1)) / barCount)

  const bars: ReturnType<typeof h>[] = []
  const labelElements: ReturnType<typeof h>[] = []

  labels.forEach((label, i) => {
    const groupX = padding.left + i * groupWidth

    valueFields.forEach((field, fi) => {
      const values = extractNumericValues(data, field)
      const val = values[i] ?? 0
      const barH = (val / maxVal) * chartH
      const barX = groupX + barGap + fi * (barWidth + barGap)
      const barY = padding.top + chartH - barH

      bars.push(
        h('rect', {
          x: String(barX),
          y: String(barY),
          width: String(barWidth),
          height: String(barH),
          fill: config.colors[fi % config.colors.length],
          rx: '2',
        }),
        h('title', {}, `${field}: ${val}`)
      )
    })

    labelElements.push(
      h('text', {
        x: String(groupX + groupWidth / 2),
        y: String(padding.top + chartH + 18),
        'text-anchor': 'middle',
        'font-size': '11',
        'font-family': 'system-ui, sans-serif',
        fill: '#555',
      }, label.length > 12 ? label.slice(0, 11) + '\u2026' : label)
    )
  })

  const gridLines = ticks.map((tick) => {
    const y = padding.top + chartH - (tick / maxVal) * chartH
    return [
      h('line', {
        x1: String(padding.left),
        y1: String(y),
        x2: String(padding.left + chartW),
        y2: String(y),
        stroke: '#e5e5e5',
        'stroke-width': '1',
      }),
      h('text', {
        x: String(padding.left - 8),
        y: String(y + 4),
        'text-anchor': 'end',
        'font-size': '11',
        'font-family': 'system-ui, sans-serif',
        fill: '#555',
      }, String(tick)),
    ]
  })

  const axes = [
    h('line', {
      x1: String(padding.left),
      y1: String(padding.top),
      x2: String(padding.left),
      y2: String(padding.top + chartH),
      stroke: '#ccc',
      'stroke-width': '1',
    }),
    h('line', {
      x1: String(padding.left),
      y1: String(padding.top + chartH),
      x2: String(padding.left + chartW),
      y2: String(padding.top + chartH),
      stroke: '#ccc',
      'stroke-width': '1',
    }),
  ]

  const legend = valueFields.length > 1
    ? renderLegend(valueFields, config)
    : []

  return wrapSvg(
    config,
    renderTitle(config),
    ...renderAxisLabels(config, padding),
    ...gridLines.flat(),
    ...axes,
    ...bars,
    ...labelElements,
    ...legend,
  ).toString()
}

const renderLegend = (fields: string[], config: ChartConfig): ReturnType<typeof h>[] => {
  const startX = config.width - 20
  return fields.map((field, i) => {
    const y = 14 + i * 18
    return h('g', {},
      h('rect', {
        x: String(startX - 80),
        y: String(y - 8),
        width: '10',
        height: '10',
        fill: config.colors[i % config.colors.length],
        rx: '2',
      }),
      h('text', {
        x: String(startX - 65),
        y: String(y + 1),
        'font-size': '11',
        'font-family': 'system-ui, sans-serif',
        fill: '#555',
      }, field),
    )
  })
}

import { h } from 'plaited'
import type { DataRow, ChartConfig } from '../types'
import {
  DEFAULT_PADDING,
  extractNumericValues,
  extractLabels,
  niceMax,
  generateTicks,
  renderTitle,
  renderAxisLabels,
  wrapSvg,
} from './common'

export const renderLineChart = (data: DataRow[], config: ChartConfig): string => {
  const padding = { ...DEFAULT_PADDING }
  const labels = extractLabels(data, config.categoryField)
  const valueFields = config.valueFields.length > 0 ? config.valueFields : []
  if (valueFields.length === 0) return ''

  const allValues: number[] = []
  for (const field of valueFields) {
    allValues.push(...extractNumericValues(data, field))
  }

  const maxVal = niceMax(allValues)
  const ticks = generateTicks(maxVal)

  const chartW = config.width - padding.left - padding.right
  const chartH = config.height - padding.top - padding.bottom
  const stepX = labels.length > 1 ? chartW / (labels.length - 1) : chartW

  const lines: ReturnType<typeof h>[] = []
  const dots: ReturnType<typeof h>[] = []

  valueFields.forEach((field, fi) => {
    const values = extractNumericValues(data, field)
    const color = config.colors[fi % config.colors.length]

    const points = values.map((val, i) => {
      const x = padding.left + (labels.length > 1 ? i * stepX : chartW / 2)
      const y = padding.top + chartH - (val / maxVal) * chartH
      return { x, y, val }
    })

    const pathD = points
      .map((p, i) => `${i === 0 ? 'M' : 'L'}${p.x},${p.y}`)
      .join(' ')

    lines.push(
      h('path', {
        d: pathD,
        fill: 'none',
        stroke: color,
        'stroke-width': '2.5',
        'stroke-linejoin': 'round',
        'stroke-linecap': 'round',
      })
    )

    points.forEach((p) => {
      dots.push(
        h('circle', {
          cx: String(p.x),
          cy: String(p.y),
          r: '4',
          fill: color,
          stroke: '#fff',
          'stroke-width': '2',
        }),
        h('title', {}, `${field}: ${p.val}`)
      )
    })
  })

  const labelElements = labels.map((label, i) => {
    const x = padding.left + (labels.length > 1 ? i * stepX : chartW / 2)
    return h('text', {
      x: String(x),
      y: String(padding.top + chartH + 18),
      'text-anchor': 'middle',
      'font-size': '11',
      'font-family': 'system-ui, sans-serif',
      fill: '#555',
    }, label.length > 12 ? label.slice(0, 11) + '\u2026' : label)
  })

  const gridLines = ticks.map((tick) => {
    const y = padding.top + chartH - (tick / maxVal) * chartH
    return [
      h('line', {
        x1: String(padding.left),
        y1: String(y),
        x2: String(padding.left + chartW),
        y2: String(y),
        stroke: '#e5e5e5',
        'stroke-width': '1',
      }),
      h('text', {
        x: String(padding.left - 8),
        y: String(y + 4),
        'text-anchor': 'end',
        'font-size': '11',
        'font-family': 'system-ui, sans-serif',
        fill: '#555',
      }, String(tick)),
    ]
  })

  const axes = [
    h('line', {
      x1: String(padding.left),
      y1: String(padding.top),
      x2: String(padding.left),
      y2: String(padding.top + chartH),
      stroke: '#ccc',
      'stroke-width': '1',
    }),
    h('line', {
      x1: String(padding.left),
      y1: String(padding.top + chartH),
      x2: String(padding.left + chartW),
      y2: String(padding.top + chartH),
      stroke: '#ccc',
      'stroke-width': '1',
    }),
  ]

  const legend = valueFields.length > 1
    ? renderLineLegend(valueFields, config)
    : []

  return wrapSvg(
    config,
    renderTitle(config),
    ...renderAxisLabels(config, padding),
    ...gridLines.flat(),
    ...axes,
    ...lines,
    ...dots,
    ...labelElements,
    ...legend,
  ).toString()
}

const renderLineLegend = (fields: string[], config: ChartConfig): ReturnType<typeof h>[] => {
  const startX = config.width - 20
  return fields.map((field, i) => {
    const y = 14 + i * 18
    const color = config.colors[i % config.colors.length]
    return h('g', {},
      h('line', {
        x1: String(startX - 80),
        y1: String(y - 2),
        x2: String(startX - 65),
        y2: String(y - 2),
        stroke: color,
        'stroke-width': '2.5',
      }),
      h('circle', {
        cx: String(startX - 72),
        cy: String(y - 2),
        r: '3',
        fill: color,
      }),
      h('text', {
        x: String(startX - 60),
        y: String(y + 1),
        'font-size': '11',
        'font-family': 'system-ui, sans-serif',
        fill: '#555',
      }, field),
    )
  })
}

import { h } from 'plaited'
import type { DataRow, ChartConfig } from '../types'
import { extractNumericValues, extractLabels, renderTitle, wrapSvg } from './common'

export const renderPieChart = (data: DataRow[], config: ChartConfig): string => {
  const labels = extractLabels(data, config.categoryField)
  const valueField = config.valueFields[0]
  if (!valueField) return ''

  const values = extractNumericValues(data, valueField)
  const total = values.reduce((sum, v) => sum + v, 0)
  if (total === 0) return ''

  const cx = config.width / 2 - 60
  const cy = config.height / 2 + 10
  const radius = Math.min(cx - 40, cy - 50)

  const slices: ReturnType<typeof h>[] = []
  const legendItems: ReturnType<typeof h>[] = []

  let currentAngle = -Math.PI / 2

  values.forEach((val, i) => {
    const sliceAngle = (val / total) * Math.PI * 2
    const startAngle = currentAngle
    const endAngle = currentAngle + sliceAngle
    currentAngle = endAngle

    const x1 = cx + radius * Math.cos(startAngle)
    const y1 = cy + radius * Math.sin(startAngle)
    const x2 = cx + radius * Math.cos(endAngle)
    const y2 = cy + radius * Math.sin(endAngle)
    const largeArc = sliceAngle > Math.PI ? 1 : 0
    const color = config.colors[i % config.colors.length]
    const percentage = ((val / total) * 100).toFixed(1)

    const pathD = [
      `M ${cx} ${cy}`,
      `L ${x1} ${y1}`,
      `A ${radius} ${radius} 0 ${largeArc} 1 ${x2} ${y2}`,
      'Z',
    ].join(' ')

    slices.push(
      h('path', {
        d: pathD,
        fill: color,
        stroke: '#fff',
        'stroke-width': '2',
      }),
      h('title', {}, `${labels[i]}: ${val} (${percentage}%)`)
    )

    // Label on slice if large enough
    if (sliceAngle > 0.3) {
      const midAngle = startAngle + sliceAngle / 2
      const labelRadius = radius * 0.65
      const lx = cx + labelRadius * Math.cos(midAngle)
      const ly = cy + labelRadius * Math.sin(midAngle)
      slices.push(
        h('text', {
          x: String(lx),
          y: String(ly + 4),
          'text-anchor': 'middle',
          'font-size': '11',
          'font-weight': 'bold',
          'font-family': 'system-ui, sans-serif',
          fill: '#fff',
        }, `${percentage}%`)
      )
    }

    // Legend item
    const legendX = config.width - 140
    const legendY = 60 + i * 22
    legendItems.push(
      h('g', {},
        h('rect', {
          x: String(legendX),
          y: String(legendY - 9),
          width: '12',
          height: '12',
          fill: color,
          rx: '2',
        }),
        h('text', {
          x: String(legendX + 18),
          y: String(legendY + 2),
          'font-size': '11',
          'font-family': 'system-ui, sans-serif',
          fill: '#555',
        }, `${labels[i]} (${val})`)
      )
    )
  })

  return wrapSvg(
    config,
    renderTitle(config),
    ...slices,
    ...legendItems,
  ).toString()
}

import { h } from 'plaited'

type TokenType = 'key' | 'string' | 'number' | 'boolean' | 'null' | 'brace' | 'comma'

type Token = {
  type: TokenType
  value: string
}

const TOKEN_COLORS: Record<TokenType, string> = {
  key: '#9d174d',
  string: '#065f46',
  number: '#1e40af',
  boolean: '#7c3aed',
  null: '#7c3aed',
  brace: '#6b7280',
  comma: '#6b7280',
}

const tokenize = (json: string): Token[] => {
  const tokens: Token[] = []
  const regex =
    /("(?:\\.|[^"\\])*")\s*:|("(?:\\.|[^"\\])*")|(-?\d+(?:\.\d+)?(?:[eE][+-]?\d+)?)|(\btrue\b|\bfalse\b)|(\bnull\b)|([[\]{}])|([,:])/g

  let match: RegExpExecArray | null
  let lastIndex = 0

  while ((match = regex.exec(json)) !== null) {
    if (match.index > lastIndex) {
      tokens.push({ type: 'brace', value: json.slice(lastIndex, match.index) })
    }

    if (match[1]) {
      tokens.push({ type: 'key', value: match[1] })
      tokens.push({ type: 'comma', value: ':' })
    } else if (match[2]) {
      tokens.push({ type: 'string', value: match[2] })
    } else if (match[3]) {
      tokens.push({ type: 'number', value: match[3] })
    } else if (match[4]) {
      tokens.push({ type: 'boolean', value: match[4] })
    } else if (match[5]) {
      tokens.push({ type: 'null', value: match[5] })
    } else if (match[6]) {
      tokens.push({ type: 'brace', value: match[6] })
    } else if (match[7]) {
      tokens.push({ type: 'comma', value: match[7] })
    }

    lastIndex = match.index + match[0].length
  }

  if (lastIndex < json.length) {
    tokens.push({ type: 'brace', value: json.slice(lastIndex) })
  }

  return tokens
}

export const highlightJson = (json: string): string => {
  const tokens = tokenize(json)

  const spans = tokens.map((token) =>
    h('span', {
      style: `color: ${TOKEN_COLORS[token.type]}`,
    }, token.value)
  )

  return h('code', {
    style: 'font-family: "SF Mono", "Fira Code", monospace; font-size: 13px; line-height: 1.5; white-space: pre-wrap; word-break: break-word;',
  }, ...spans).toString()
}

