export const createSvgDownloadUrl = (svgContent: string): string => {
  const blob = new Blob([svgContent], { type: 'image/svg+xml;charset=utf-8' })
  return URL.createObjectURL(blob)
}

export const triggerSvgDownload = (svgContent: string, filename: string = 'chart.svg'): void => {
  const url = createSvgDownloadUrl(svgContent)
  const anchor = document.createElement('a')
  anchor.href = url
  anchor.download = filename
  anchor.style.display = 'none'
  document.body.appendChild(anchor)
  anchor.click()
  document.body.removeChild(anchor)
  URL.revokeObjectURL(url)
}

export const svgToDataUri = (svgContent: string): string => {
  const encoded = encodeURIComponent(svgContent)
  return `data:image/svg+xml;charset=utf-8,${encoded}`
}

export const renderDownloadButton = (svgContent: string): string => {
  const dataUri = svgToDataUri(svgContent)
  return `<a href="${dataUri}" download="chart.svg" style="display: inline-flex; align-items: center; gap: 6px; padding: 8px 16px; background: #4e79a7; color: #fff; border-radius: 6px; text-decoration: none; font-size: 13px; font-weight: 500; font-family: system-ui, sans-serif; cursor: pointer; transition: background 0.15s;">` +
    `<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg>` +
    `Download SVG</a>`
}

import { h } from 'plaited'
import type { ChartConfig, ChartType, DataRow, DetectedSchema } from './types'
import { DEFAULT_COLORS, DEFAULT_CONFIG } from './types'
import { detectSchema, parseData } from './detect'
import { renderBarChart } from './charts/bar'
import { renderLineChart } from './charts/line'
import { renderPieChart } from './charts/pie'
import { renderEditor } from './editor'
import { renderDownloadButton } from './download'

const CHART_RENDERERS: Record<ChartType, (data: DataRow[], config: ChartConfig) => string> = {
  bar: renderBarChart,
  line: renderLineChart,
  pie: renderPieChart,
}

const renderChartTypeSelector = (selected: ChartType): string => {
  const types: ChartType[] = ['bar', 'line', 'pie']
  const labels: Record<ChartType, string> = {
    bar: 'Bar Chart',
    line: 'Line Chart',
    pie: 'Pie Chart',
  }
  const icons: Record<ChartType, string> = {
    bar: '\u2593',
    line: '\u2571',
    pie: '\u25D4',
  }

  const buttons = types.map((t) =>
    h('button', {
      'p-trigger': `click:selectChartType`,
      'data-type': t,
      style: `padding: 8px 16px; border: 1px solid ${t === selected ? '#4e79a7' : '#d1d5db'}; background: ${t === selected ? '#4e79a7' : '#fff'}; color: ${t === selected ? '#fff' : '#374151'}; border-radius: 6px; cursor: pointer; font-size: 13px; font-weight: 500; font-family: system-ui, sans-serif; transition: all 0.15s;`,
    }, `${icons[t]} ${labels[t]}`)
  )

  return h('div', {
    style: 'display: flex; gap: 8px;',
  }, ...buttons).toString()
}

const renderFieldSelector = (
  label: string,
  triggerName: string,
  options: string[],
  selected: string | string[],
  multi: boolean = false,
): string => {
  const selectedSet = new Set(Array.isArray(selected) ? selected : [selected])

  const optionElements = options.map((opt) =>
    h('option', {
      value: opt,
      ...(selectedSet.has(opt) ? { selected: '' } : {}),
    }, opt)
  )

  return h('div', { style: 'display: flex; flex-direction: column; gap: 4px;' },
    h('label', {
      style: 'font-size: 12px; font-weight: 600; color: #6b7280; text-transform: uppercase; letter-spacing: 0.05em; font-family: system-ui, sans-serif;',
    }, label),
    h('select', {
      'p-trigger': `change:${triggerName}`,
      ...(multi ? { multiple: '' } : {}),
      style: 'padding: 8px 12px; border: 1px solid #d1d5db; border-radius: 6px; font-size: 13px; font-family: system-ui, sans-serif; background: #fff; outline: none;',
    }, ...optionElements),
  ).toString()
}

const renderTextInput = (label: string, triggerName: string, value: string, placeholder: string): string =>
  h('div', { style: 'display: flex; flex-direction: column; gap: 4px;' },
    h('label', {
      style: 'font-size: 12px; font-weight: 600; color: #6b7280; text-transform: uppercase; letter-spacing: 0.05em; font-family: system-ui, sans-serif;',
    }, label),
