const renderColorInput = (colors: string[]): string => {
  const swatches = colors.slice(0, 10).map((color, i) =>
    h('input', {
      type: 'color',
      value: color,
      'data-index': String(i),
      'p-trigger': 'input:updateColor',
      style: 'width: 28px; height: 28px; border: 1px solid #d1d5db; border-radius: 4px; cursor: pointer; padding: 0;',
    })
