      style: 'font-size: 12px; font-weight: 600; color: #6b7280; text-transform: uppercase; letter-spacing: 0.05em; font-family: system-ui, sans-serif;',
    }, 'Colors'),
    h('div', { style: 'display: flex; gap: 4px; flex-wrap: wrap;' }, ...swatches),
  ).toString()
}

export const renderFullPage = (
  jsonStr: string,
  config: ChartConfig,
): string => {
  const { data, error: parseError } = parseData(jsonStr)
  let schema: DetectedSchema = { fields: [], numericFields: [], categoricalFields: [] }
  let chartSvg = ''
  let chartError: string | null = parseError

  if (data) {
    schema = detectSchema(data)

    const effectiveConfig = { ...config }
    if (!effectiveConfig.categoryField && schema.categoricalFields.length > 0) {
      effectiveConfig.categoryField = schema.categoricalFields[0]
    }
    if (effectiveConfig.valueFields.length === 0 && schema.numericFields.length > 0) {
      effectiveConfig.valueFields = [schema.numericFields[0]]
    }

    if (effectiveConfig.categoryField && effectiveConfig.valueFields.length > 0) {
      const renderer = CHART_RENDERERS[effectiveConfig.type]
      chartSvg = renderer(data, effectiveConfig)
    } else {
      chartError = 'Need at least one categorical and one numeric field'
    }
  }

  const container = h('div', {
    style: 'max-width: 960px; margin: 0 auto; padding: 24px; font-family: system-ui, sans-serif;',
  },
    // Header
    h('div', { style: 'margin-bottom: 24px;' },
      h('h1', {
        style: 'font-size: 22px; font-weight: 700; color: #1a1a1a; margin: 0 0 4px 0;',
      }, 'Chart Generator'),
      h('p', {
        style: 'font-size: 14px; color: #6b7280; margin: 0;',
      }, 'Paste JSON data, pick a chart type, and customize.'),
    ),

    // Main layout: two columns
    h('div', { style: 'display: grid; grid-template-columns: 1fr 1fr; gap: 24px; align-items: start;' },

      // Left: editor + controls
      h('div', { style: 'display: flex; flex-direction: column; gap: 16px;' },
        // JSON editor
        renderEditor(jsonStr, chartError),

        // Chart type selector
        h('div', { style: 'display: flex; flex-direction: column; gap: 8px;' },
          h('label', {
            style: 'font-size: 13px; font-weight: 600; color: #374151;',
          }, 'Chart Type'),
          renderChartTypeSelector(config.type),
        ),

        // Field selectors
        ...(schema.categoricalFields.length > 0
          ? [renderFieldSelector('Category Field', 'selectCategory', schema.categoricalFields, config.categoryField || schema.categoricalFields[0])]
          : []),
        ...(schema.numericFields.length > 0
          ? [renderFieldSelector('Value Field(s)', 'selectValue', schema.numericFields, config.valueFields.length > 0 ? config.valueFields : [schema.numericFields[0]], config.type !== 'pie')]
          : []),

        // Labels
        h('div', { style: 'display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 8px;' },
          renderTextInput('Title', 'updateTitle', config.title, 'Chart title'),
          renderTextInput('X Label', 'updateXLabel', config.xLabel, 'X axis'),
          renderTextInput('Y Label', 'updateYLabel', config.yLabel, 'Y axis'),
        ),

        // Colors
        renderColorInput(config.colors),
      ),

      // Right: chart output
      h('div', { style: 'display: flex; flex-direction: column; gap: 12px; position: sticky; top: 24px;' },
        h('div', {
          'p-target': 'chart-output',
          style: 'border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden; background: #fff; min-height: 300px; display: flex; align-items: center; justify-content: center;',
        },
          chartSvg
            ? chartSvg
            : h('div', { style: 'color: #9ca3af; font-size: 14px; padding: 24px; text-align: center;' }, 'Enter valid JSON data to generate a chart').toString(),
        ),
        ...(chartSvg
          ? [h('div', { style: 'display: flex; justify-content: flex-end;' }, renderDownloadButton(chartSvg)).toString()]
          : []),
      ),
    ),

    // Schema info
    ...(schema.fields.length > 0
      ? [h('div', { style: 'margin-top: 16px; padding: 12px; background: #f3f4f6; border-radius: 8px; font-size: 12px; color: #6b7280; font-family: system-ui, sans-serif;' },
          h('strong', {}, 'Detected fields: '),
          schema.fields.map((f) => `${f.name} (${f.kind})`).join(', '),
        ).toString()]
      : []),
  )

  return container.toString()
}

