/**
 * Generate a chart SVG string from raw JSON data and config.
 */
export const generateChart = (
  jsonStr: string,
  config: Partial<ChartConfig> = {},
): { svg: string; error: string | null } => {
  const { data, error } = parseData(jsonStr)
  if (!data) return { svg: '', error }

  const schema = detectSchema(data)
  const merged: ChartConfig = {
    ...DEFAULT_CONFIG,
    ...config,
    colors: config.colors ?? DEFAULT_COLORS,
  }

  if (!merged.categoryField && schema.categoricalFields.length > 0) {
    merged.categoryField = schema.categoricalFields[0]
  }
  if (merged.valueFields.length === 0 && schema.numericFields.length > 0) {
    merged.valueFields = merged.type === 'pie'
      ? [schema.numericFields[0]]
      : schema.numericFields
  }

  if (!merged.categoryField || merged.valueFields.length === 0) {
    return { svg: '', error: 'Need at least one categorical and one numeric field' }
  }

  const renderers: Record<ChartType, (d: DataRow[], c: ChartConfig) => string> = {
    bar: renderBarChart,
    line: renderLineChart,
    pie: renderPieChart,
  }

  const svg = renderers[merged.type](data, merged)
  return { svg, error: null }
}

/**
 * Render the full interactive page HTML.
 */
export const renderPage = (
  jsonStr: string = '[]',
  config: Partial<ChartConfig> = {},
): string => {
  const ssr = createSSR()
  const merged: ChartConfig = {
    ...DEFAULT_CONFIG,
    ...config,
    colors: config.colors ?? DEFAULT_COLORS,
  }
  const html = renderFullPage(jsonStr, merged)
  return ssr.render(html)
}

/**
 * Load a sample dataset from data/samples.json
 */
export const loadSample = async (name: string): Promise<string> => {
  const file = Bun.file(new URL('../data/samples.json', import.meta.url).pathname)
  const samples = await file.json()
  const sample = samples[name]
  if (!sample) {
    const available = Object.keys(samples).join(', ')
    throw new Error(`Sample "${name}" not found. Available: ${available}`)
  }
  return JSON.stringify(sample, null, 2)
}

/**
 * Save chart SVG to disk.
 */
export const saveChart = async (
  svgContent: string,
  path: string = './data/chart.svg',
): Promise<void> => {
  await Bun.write(path, svgContent)
}

