export const PALETTE_NAMES = Object.keys(PALETTES)

export const getColors = (palette: string, count: number): string[] => {
  const colors = PALETTES[palette] ?? PALETTES.default
  const result: string[] = []
  for (let i = 0; i < count; i++) {
    result.push(colors[i % colors.length])
  }
  return result
}

import type { DataRow, DetectedSchema, FieldInfo, FieldType } from './types'

const detectFieldType = (values: (string | number)[]): FieldType => {
  const validValues = values.filter((v) => v !== null && v !== undefined && v !== '')
  if (validValues.length === 0) return 'categorical'

  const numericCount = validValues.filter((v) => {
    if (typeof v === 'number') return true
    if (typeof v === 'string') {
      const parsed = Number(v)
      return !Number.isNaN(parsed) && v.trim() !== ''
    }
    return false
  }).length

  return numericCount / validValues.length >= 0.8 ? 'numeric' : 'categorical'
}

export const detectSchema = (data: DataRow[]): DetectedSchema => {
  if (data.length === 0) {
    return { fields: [], numericFields: [], categoricalFields: [] }
  }

  const keys = Object.keys(data[0])
  const fields: FieldInfo[] = keys.map((key) => {
    const values = data.map((row) => row[key])
    const type = detectFieldType(values)
    return {
      name: key,
      type,
      sample: values[0],
    }
  })

  return {
    fields,
    numericFields: fields.filter((f) => f.type === 'numeric').map((f) => f.name),
    categoricalFields: fields.filter((f) => f.type === 'categorical').map((f) => f.name),
  }
}

export const coerceNumeric = (value: string | number): number => {
  if (typeof value === 'number') return value
  const parsed = Number(value)
  return Number.isNaN(parsed) ? 0 : parsed
}

import { h } from '@plaited/template'
import type { ChartConfig, ChartDimensions, DataRow, PieSlice } from './types'
import { coerceNumeric } from './field-detector'
import { getColors } from './colors'

const PADDING = { top: 60, right: 30, bottom: 70, left: 80 }

const computeDimensions = (config: ChartConfig): ChartDimensions => ({
  svgWidth: config.width,
  svgHeight: config.height,
  plotLeft: PADDING.left,
  plotTop: PADDING.top,
  plotWidth: config.width - PADDING.left - PADDING.right,
  plotHeight: config.height - PADDING.top - PADDING.bottom,
})

const niceMax = (value: number): number => {
  if (value <= 0) return 10
  const magnitude = Math.pow(10, Math.floor(Math.log10(value)))
  const normalized = value / magnitude
  if (normalized <= 1) return magnitude
  if (normalized <= 2) return 2 * magnitude
  if (normalized <= 5) return 5 * magnitude
  return 10 * magnitude
}

const generateTicks = (maxValue: number, count: number = 5): number[] => {
  const step = maxValue / count
  const ticks: number[] = []
  for (let i = 0; i <= count; i++) {
    ticks.push(Math.round(step * i * 100) / 100)
  }
  return ticks
}

const formatTickLabel = (value: number): string => {
  if (Math.abs(value) >= 1_000_000) return `${(value / 1_000_000).toFixed(1)}M`
  if (Math.abs(value) >= 1_000) return `${(value / 1_000).toFixed(1)}K`
  return String(value)
}

const renderTitle = (title: string, width: number) =>
  title
    ? h('text', {
        x: String(width / 2),
        y: '30',
        'text-anchor': 'middle',
        'font-size': '18',
        'font-weight': 'bold',
        'font-family': 'system-ui, sans-serif',
        fill: '#1a1a2e',
      }, title)
    : null

const renderYAxis = (
  dim: ChartDimensions,
  maxValue: number,
  label: string,
) => {
  const ticks = generateTicks(maxValue)
  return h('g', { class: 'y-axis' },
    h('line', {
      x1: String(dim.plotLeft),
      y1: String(dim.plotTop),
      x2: String(dim.plotLeft),
      y2: String(dim.plotTop + dim.plotHeight),
      stroke: '#ccc',
      'stroke-width': '1',
    }),
    ...ticks.map((tick) => {
      const y = dim.plotTop + dim.plotHeight - (tick / maxValue) * dim.plotHeight
      return h('g', {},
        h('line', {
          x1: String(dim.plotLeft - 5),
          y1: String(y),
          x2: String(dim.plotLeft),
          y2: String(y),
          stroke: '#ccc',
          'stroke-width': '1',
        }),
        h('line', {
          x1: String(dim.plotLeft),
          y1: String(y),
          x2: String(dim.plotLeft + dim.plotWidth),
          y2: String(y),
          stroke: '#eee',
          'stroke-width': '1',
          'stroke-dasharray': '4,4',
        }),
        h('text', {
          x: String(dim.plotLeft - 10),
          y: String(y + 4),
          'text-anchor': 'end',
          'font-size': '12',
          'font-family': 'system-ui, sans-serif',
          fill: '#666',
        }, formatTickLabel(tick)),
      )
    }),
    label
      ? h('text', {
          x: String(-(dim.plotTop + dim.plotHeight / 2)),
          y: '20',
          transform: 'rotate(-90)',
          'text-anchor': 'middle',
          'font-size': '13',
          'font-family': 'system-ui, sans-serif',
          fill: '#444',
        }, label)
      : null,
  )
}

const renderXAxis = (
  dim: ChartDimensions,
  labels: string[],
  label: string,
  barMode: boolean = false,
) => {
  const step = barMode
    ? dim.plotWidth / labels.length
    : labels.length > 1
      ? dim.plotWidth / (labels.length - 1)
      : dim.plotWidth
  return h('g', { class: 'x-axis' },
    h('line', {
      x1: String(dim.plotLeft),
      y1: String(dim.plotTop + dim.plotHeight),
      x2: String(dim.plotLeft + dim.plotWidth),
      y2: String(dim.plotTop + dim.plotHeight),
      stroke: '#ccc',
      'stroke-width': '1',
    }),
    ...labels.map((lbl, i) => {
      const x = barMode
        ? dim.plotLeft + i * step + step / 2
        : dim.plotLeft + i * step
      return h('text', {
        x: String(x),
        y: String(dim.plotTop + dim.plotHeight + 20),
        'text-anchor': 'middle',
        'font-size': '11',
        'font-family': 'system-ui, sans-serif',
        fill: '#666',
        transform: labels.length > 8
          ? `rotate(-35, ${x}, ${dim.plotTop + dim.plotHeight + 20})`
          : undefined,
      }, lbl.length > 12 ? `${lbl.slice(0, 11)}…` : lbl)
    }),
    label
      ? h('text', {
          x: String(dim.plotLeft + dim.plotWidth / 2),
          y: String(dim.svgHeight - 10),
          'text-anchor': 'middle',
          'font-size': '13',
          'font-family': 'system-ui, sans-serif',
          fill: '#444',
        }, label)
      : null,
  )
}

const renderLegend = (
  dim: ChartDimensions,
  valueFields: string[],
  colors: string[],
) => {
  if (valueFields.length <= 1) return null
  return h('g', { class: 'legend' },
    ...valueFields.map((field, i) =>
      h('g', { transform: `translate(${dim.plotLeft + i * 120}, ${dim.plotTop - 25})` },
        h('rect', {
          width: '12',
          height: '12',
          rx: '2',
          fill: colors[i],
        }),
        h('text', {
          x: '18',
          y: '11',
          'font-size': '12',
          'font-family': 'system-ui, sans-serif',
          fill: '#444',
        }, field),
      ),
    ),
  )
}

export const renderBarChart = (data: DataRow[], config: ChartConfig): string => {
  const dim = computeDimensions(config)
  const colors = config.colors.length > 0
    ? config.colors
    : getColors('default', config.valueFields.length)
  const labels = data.map((row) => String(row[config.categoryField] ?? ''))

  const allValues = data.flatMap((row) =>
    config.valueFields.map((f) => coerceNumeric(row[f]))
  )
  const maxValue = niceMax(Math.max(...allValues, 0))
  const groupCount = config.valueFields.length
  const groupWidth = dim.plotWidth / data.length
  const barGap = 4
  const barWidth = (groupWidth - barGap * (groupCount + 1)) / groupCount

  const bars = data.flatMap((row, i) =>
    config.valueFields.map((field, j) => {
      const value = coerceNumeric(row[field])
      const barHeight = (value / maxValue) * dim.plotHeight
      const x = dim.plotLeft + i * groupWidth + barGap * (j + 1) + j * barWidth
      const y = dim.plotTop + dim.plotHeight - barHeight
      return h('rect', {
        x: String(x),
        y: String(y),
        width: String(Math.max(barWidth, 1)),
        height: String(barHeight),
        fill: colors[j % colors.length],
        rx: '2',
      },
        h('title', {}, `${field}: ${value}`),
      )
    }),
  )

  const svg = h('svg', {
    xmlns: 'http://www.w3.org/2000/svg',
    viewBox: `0 0 ${dim.svgWidth} ${dim.svgHeight}`,
    width: String(dim.svgWidth),
    height: String(dim.svgHeight),
    style: 'background: #fff; border-radius: 8px;',
  },
    renderTitle(config.title, dim.svgWidth),
    renderYAxis(dim, maxValue, config.yLabel),
    renderXAxis(dim, labels, config.xLabel, true),
    renderLegend(dim, config.valueFields, colors),
    h('g', { class: 'bars' }, ...bars),
  )
  return svg.strings.join('')
}

export const renderLineChart = (data: DataRow[], config: ChartConfig): string => {
  const dim = computeDimensions(config)
  const colors = config.colors.length > 0
    ? config.colors
    : getColors('default', config.valueFields.length)
  const labels = data.map((row) => String(row[config.categoryField] ?? ''))

  const allValues = data.flatMap((row) =>
    config.valueFields.map((f) => coerceNumeric(row[f]))
  )
  const maxValue = niceMax(Math.max(...allValues, 0))
  const step = data.length > 1 ? dim.plotWidth / (data.length - 1) : 0

  const lines = config.valueFields.map((field, j) => {
    const points = data.map((row, i) => {
      const x = dim.plotLeft + i * step
      const y = dim.plotTop + dim.plotHeight - (coerceNumeric(row[field]) / maxValue) * dim.plotHeight
      return { x, y, value: coerceNumeric(row[field]) }
    })
    const pathData = points.map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`).join(' ')
    const color = colors[j % colors.length]

    return h('g', {},
      h('path', {
        d: pathData,
        fill: 'none',
        stroke: color,
        'stroke-width': '2.5',
        'stroke-linejoin': 'round',
        'stroke-linecap': 'round',
      }),
      ...points.map((p) =>
        h('circle', {
          cx: String(p.x),
          cy: String(p.y),
          r: '4',
          fill: '#fff',
          stroke: color,
          'stroke-width': '2',
        },
          h('title', {}, `${field}: ${p.value}`),
        ),
      ),
    )
  })

  const svg = h('svg', {
    xmlns: 'http://www.w3.org/2000/svg',
    viewBox: `0 0 ${dim.svgWidth} ${dim.svgHeight}`,
    width: String(dim.svgWidth),
    height: String(dim.svgHeight),
    style: 'background: #fff; border-radius: 8px;',
  },
    renderTitle(config.title, dim.svgWidth),
    renderYAxis(dim, maxValue, config.yLabel),
    renderXAxis(dim, labels, config.xLabel),
    renderLegend(dim, config.valueFields, colors),
    h('g', { class: 'lines' }, ...lines),
  )
  return svg.strings.join('')
}

export const renderPieChart = (data: DataRow[], config: ChartConfig): string => {
  const dim = computeDimensions(config)
  const valueField = config.valueFields[0]
  const colors = config.colors.length > 0
    ? config.colors
    : getColors('default', data.length)

  const total = data.reduce((sum, row) => sum + coerceNumeric(row[valueField]), 0)
  if (total === 0) {
    return h('svg', {
      xmlns: 'http://www.w3.org/2000/svg',
      viewBox: `0 0 ${dim.svgWidth} ${dim.svgHeight}`,
      width: String(dim.svgWidth),
      height: String(dim.svgHeight),
    },
      h('text', {
        x: String(dim.svgWidth / 2),
        y: String(dim.svgHeight / 2),
        'text-anchor': 'middle',
        'font-size': '16',
        fill: '#999',
      }, 'No data to display'),
    ).strings.join('')
  }

  const cx = dim.plotLeft + dim.plotWidth / 2 - 60
  const cy = dim.plotTop + dim.plotHeight / 2
  const radius = Math.min(dim.plotWidth - 120, dim.plotHeight) / 2 - 10

  const slices: PieSlice[] = []
  let currentAngle = -Math.PI / 2
  data.forEach((row, i) => {
    const value = coerceNumeric(row[valueField])
    const percentage = (value / total) * 100
    const angle = (value / total) * 2 * Math.PI
    slices.push({
      label: String(row[config.categoryField] ?? `Item ${i + 1}`),
      value,
      percentage,
      startAngle: currentAngle,
      endAngle: currentAngle + angle,
      color: colors[i % colors.length],
    })
    currentAngle += angle
  })

  const arcPath = (startAngle: number, endAngle: number): string => {
    const x1 = cx + radius * Math.cos(startAngle)
    const y1 = cy + radius * Math.sin(startAngle)
    const x2 = cx + radius * Math.cos(endAngle)
    const y2 = cy + radius * Math.sin(endAngle)
    const largeArc = endAngle - startAngle > Math.PI ? 1 : 0
    return `M ${cx} ${cy} L ${x1} ${y1} A ${radius} ${radius} 0 ${largeArc} 1 ${x2} ${y2} Z`
  }

  const sliceElements = slices.map((slice) =>
    h('path', {
      d: arcPath(slice.startAngle, slice.endAngle),
      fill: slice.color,
      stroke: '#fff',
      'stroke-width': '2',
    },
      h('title', {}, `${slice.label}: ${slice.value} (${slice.percentage.toFixed(1)}%)`),
    ),
  )

  const legendX = cx + radius + 40
  const legendStartY = dim.plotTop + 20
  const legendItems = slices.map((slice, i) =>
    h('g', { transform: `translate(${legendX}, ${legendStartY + i * 24})` },
      h('rect', {
        width: '14',
        height: '14',
        rx: '3',
        fill: slice.color,
      }),
      h('text', {
        x: '22',
        y: '12',
        'font-size': '12',
        'font-family': 'system-ui, sans-serif',
        fill: '#444',
      }, `${slice.label} (${slice.percentage.toFixed(1)}%)`),
    ),
  )

  const svg = h('svg', {
    xmlns: 'http://www.w3.org/2000/svg',
    viewBox: `0 0 ${dim.svgWidth} ${dim.svgHeight}`,
    width: String(dim.svgWidth),
    height: String(dim.svgHeight),
    style: 'background: #fff; border-radius: 8px;',
  },
    renderTitle(config.title, dim.svgWidth),
    h('g', { class: 'pie-slices' }, ...sliceElements),
    h('g', { class: 'pie-legend' }, ...legendItems),
  )
  return svg.strings.join('')
}

export const renderChart = (data: DataRow[], config: ChartConfig): string => {
  switch (config.type) {
    case 'bar':
      return renderBarChart(data, config)
    case 'line':
      return renderLineChart(data, config)
    case 'pie':
      return renderPieChart(data, config)
    default:
      return renderBarChart(data, config)
  }
}

import { h } from '@plaited/template'

type TokenType = 'key' | 'string' | 'number' | 'boolean' | 'null' | 'punctuation'

type Token = {
  type: TokenType
  value: string
}

const TOKEN_COLORS: Record<TokenType, string> = {
  key: '#0550ae',
  string: '#0a3069',
  number: '#0550ae',
  boolean: '#cf222e',
  null: '#cf222e',
  punctuation: '#57606a',
}

const escapeHtml = (str: string): string =>
  str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')

const tokenizeJson = (json: string): Token[] => {
  const tokens: Token[] = []
  let i = 0

  while (i < json.length) {
    const ch = json[i]

    if (/\s/.test(ch)) {
      let ws = ''
      while (i < json.length && /\s/.test(json[i])) {
        ws += json[i]
        i++
      }
      tokens.push({ type: 'punctuation', value: ws })
      continue
    }

    if (ch === '"') {
      let str = '"'
      i++
      while (i < json.length && json[i] !== '"') {
        if (json[i] === '\\') {
          str += json[i]
          i++
        }
        if (i < json.length) {
          str += json[i]
          i++
        }
      }
      if (i < json.length) {
        str += '"'
        i++
      }

      const isKey = /^\s*:/.test(json.slice(i))
      tokens.push({ type: isKey ? 'key' : 'string', value: str })
      continue
    }

    if (ch === '-' || (ch >= '0' && ch <= '9')) {
      let num = ''
      while (i < json.length && /[0-9.eE+\-]/.test(json[i])) {
        num += json[i]
        i++
      }
      tokens.push({ type: 'number', value: num })
      continue
    }

    if (json.slice(i, i + 4) === 'true') {
      tokens.push({ type: 'boolean', value: 'true' })
      i += 4
      continue
    }
    if (json.slice(i, i + 5) === 'false') {
      tokens.push({ type: 'boolean', value: 'false' })
      i += 5
      continue
    }
    if (json.slice(i, i + 4) === 'null') {
      tokens.push({ type: 'null', value: 'null' })
      i += 4
      continue
    }

    tokens.push({ type: 'punctuation', value: ch })
    i++
  }

  return tokens
}

export const highlightJson = (json: string): string => {
  const tokens = tokenizeJson(json)
  return tokens
    .map((token) => {
      const escaped = escapeHtml(token.value)
      if (token.type === 'punctuation') return escaped
      return `<span style="color: ${TOKEN_COLORS[token.type]}">${escaped}</span>`
    })
    .join('')
}

