        }, 'Load Sample'),
      ),
    ),
    h('textarea', {
      'p-target': 'json-input',
      'p-trigger': 'json-change',
      spellcheck: 'false',
      autocomplete: 'off',
      autocorrect: 'off',
      autocapitalize: 'off',
