          max: '2000',
          style: inputStyle + ' width: 100%;',
        }),
      ),
      h('div', { style: 'display: flex; flex-direction: column; gap: 4px;' },
        h('label', { style: labelStyle }, 'Height (px)'),
        h('input', {
          type: 'number',
          'p-target': 'input-height',
          'p-trigger': 'change-height',
          value: String(config.height),
          min: '150',
          max: '1500',
          style: inputStyle + ' width: 100%;',
        }),
      ),
    ),

    h('div', { style: 'margin-top: 16px; display: flex; flex-direction: column; gap: 4px;' },
      h('label', { style: labelStyle }, 'Custom Colors (comma-separated hex)'),
