    "structure": "form",
    "mechanics": ["chart"],
    "boundary": "all",
    "scale": 2
  },
  "dependencies": {
    "plaited": "latest"
  }
}

export type ChartType = 'bar' | 'line' | 'pie'

export type FieldKind = 'numeric' | 'categorical'

export type FieldInfo = {
  name: string
  kind: FieldKind
}

export type ChartConfig = {
  type: ChartType
  title: string
  xAxisLabel: string
  yAxisLabel: string
  categoryField: string
  valueFields: string[]
  colors: string[]
  width: number
  height: number
}

export type DetectedFields = {
  numeric: string[]
  categorical: string[]
}

export type ChartData = Record<string, string | number>[]

export type TokenType = 'key' | 'string' | 'number' | 'boolean' | 'null' | 'bracket' | 'punctuation'

export type Token = {
  type: TokenType
  value: string
}

export type ParsedInput = {
  valid: boolean
  data: ChartData | null
  error: string | null
}

import type { ChartData, DetectedFields, FieldInfo, FieldKind } from './types'

const classifyField = (values: (string | number | undefined)[]): FieldKind => {
  const defined = values.filter((v) => v !== undefined && v !== null)
  if (defined.length === 0) return 'categorical'

  const numericCount = defined.filter((v) => {
    if (typeof v === 'number') return true
    if (typeof v === 'string') {
      const parsed = Number(v)
      return !Number.isNaN(parsed) && v.trim() !== ''
    }
    return false
  }).length

  return numericCount / defined.length > 0.8 ? 'numeric' : 'categorical'
}

export const detectFields = (data: ChartData): DetectedFields => {
  if (data.length === 0) return { numeric: [], categorical: [] }

  const allKeys = new Set<string>()
  for (const row of data) {
    for (const key of Object.keys(row)) {
      allKeys.add(key)
    }
  }

  const fields: FieldInfo[] = [...allKeys].map((name) => ({
    name,
    kind: classifyField(data.map((row) => row[name])),
  }))

  return {
    numeric: fields.filter((f) => f.kind === 'numeric').map((f) => f.name),
    categorical: fields.filter((f) => f.kind === 'categorical').map((f) => f.name),
  }
}

export const pickDefaults = (detected: DetectedFields): { category: string; values: string[] } => {
  const category = detected.categorical[0] ?? detected.numeric[0] ?? ''
  const values = detected.numeric.length > 0
    ? detected.numeric
    : detected.categorical.slice(1)
  return { category, values }
}

import { h } from 'plaited'
import type { Token, TokenType, ParsedInput, ChartData } from './types'

const TOKEN_COLORS: Record<TokenType, string> = {
  key: '#9cdcfe',
  string: '#ce9178',
  number: '#b5cea8',
  boolean: '#569cd6',
  null: '#569cd6',
  bracket: '#ffd700',
  punctuation: '#d4d4d4',
}

const tokenize = (json: string): Token[] => {
  const tokens: Token[] = []
  const regex = /("(?:\\.|[^"\\])*")\s*:|("(?:\\.|[^"\\])*")|(-?\d+(?:\.\d+)?(?:[eE][+-]?\d+)?)|(\btrue\b|\bfalse\b)|(\bnull\b)|([\[\]{}])|([,:])|([ \t\n\r]+)|([^\s])/g

  let match: RegExpExecArray | null
  while ((match = regex.exec(json)) !== null) {
    if (match[1] !== undefined) {
      tokens.push({ type: 'key', value: match[1] })
      const colonIdx = match[0].indexOf(':', match[1].length)
      if (colonIdx !== -1) {
        const between = match[0].slice(match[1].length, colonIdx)
        if (between) tokens.push({ type: 'punctuation', value: between })
        tokens.push({ type: 'punctuation', value: ':' })
      }
    } else if (match[2] !== undefined) {
      tokens.push({ type: 'string', value: match[2] })
    } else if (match[3] !== undefined) {
      tokens.push({ type: 'number', value: match[3] })
    } else if (match[4] !== undefined) {
      tokens.push({ type: 'boolean', value: match[4] })
    } else if (match[5] !== undefined) {
      tokens.push({ type: 'null', value: match[5] })
    } else if (match[6] !== undefined) {
      tokens.push({ type: 'bracket', value: match[6] })
    } else if (match[7] !== undefined) {
      tokens.push({ type: 'punctuation', value: match[7] })
    } else if (match[8] !== undefined) {
      tokens.push({ type: 'punctuation', value: match[8] })
    } else if (match[9] !== undefined) {
      tokens.push({ type: 'punctuation', value: match[9] })
    }
  }
  return tokens
}

export const highlightJson = (json: string) => {
  const tokens = tokenize(json)
  return tokens.map((token) =>
    h('span', { style: { color: TOKEN_COLORS[token.type] } }, token.value)
  )
}

export const parseJsonInput = (input: string): ParsedInput => {
  try {
    const parsed = JSON.parse(input)
    if (!Array.isArray(parsed)) {
      return { valid: false, data: null, error: 'Input must be a JSON array of objects' }
    }
    if (parsed.length === 0) {
      return { valid: false, data: null, error: 'Array must contain at least one object' }
    }
    if (!parsed.every((item: unknown) => typeof item === 'object' && item !== null && !Array.isArray(item))) {
      return { valid: false, data: null, error: 'All array items must be objects' }
    }
    return { valid: true, data: parsed as ChartData, error: null }
  } catch (e) {
    const message = e instanceof Error ? e.message : 'Invalid JSON'
    return { valid: false, data: null, error: message }
  }
}

