import { h } from 'plaited'
import type { ChartConfig, ChartData } from './types'
import { getColor } from './colors'

export const renderBarChart = (data: ChartData, config: ChartConfig) => {
  const { width, height, title, xAxisLabel, yAxisLabel, categoryField, valueFields, colors } = config

  const margin = { top: 50, right: 30, bottom: 80, left: 70 }
  const chartWidth = width - margin.left - margin.right
  const chartHeight = height - margin.top - margin.bottom

  const categories = data.map((d) => String(d[categoryField] ?? ''))
  const seriesCount = valueFields.length
  const groupWidth = chartWidth / categories.length
  const barWidth = Math.min((groupWidth * 0.8) / seriesCount, 60)
  const groupPadding = (groupWidth - barWidth * seriesCount) / 2

  let maxVal = 0
  for (const field of valueFields) {
    for (const row of data) {
      const v = Number(row[field]) || 0
      if (v > maxVal) maxVal = v
    }
  }
  maxVal = maxVal * 1.1 || 1

  const scaleY = (v: number) => chartHeight - (v / maxVal) * chartHeight

  const tickCount = 5
  const yTicks = Array.from({ length: tickCount + 1 }, (_, i) =>
    Math.round((maxVal / tickCount) * i * 100) / 100
  )

  const bars = valueFields.flatMap((field, seriesIdx) =>
    data.map((row, i) => {
      const val = Number(row[field]) || 0
      const x = margin.left + i * groupWidth + groupPadding + seriesIdx * barWidth
      const barHeight = (val / maxVal) * chartHeight
      const y = margin.top + chartHeight - barHeight
      const color = getColor(seriesIdx, colors.length > 0 ? colors : undefined)

      return h('g', {},
        h('rect', {
          x: String(x),
          y: String(y),
          width: String(barWidth),
          height: String(barHeight),
          fill: color,
          rx: '3',
          ry: '3',
        }),
        h('title', {}, `${field}: ${val}`),
      )
    })
  )

  const xLabels = categories.map((cat, i) => {
    const x = margin.left + i * groupWidth + groupWidth / 2
    return h('text', {
      x: String(x),
      y: String(margin.top + chartHeight + 20),
      'text-anchor': 'middle',
      fill: '#666',
      'font-size': '12',
      transform: categories.length > 8
        ? `rotate(-45, ${x}, ${margin.top + chartHeight + 20})`
        : undefined,
    }, cat)
  })

  const yTickElements = yTicks.map((tick) => {
    const y = margin.top + scaleY(tick)
    return h('g', {},
      h('line', {
        x1: String(margin.left),
        y1: String(y),
        x2: String(margin.left + chartWidth),
        y2: String(y),
        stroke: '#e0e0e0',
        'stroke-dasharray': '3,3',
      }),
      h('text', {
        x: String(margin.left - 10),
        y: String(y + 4),
        'text-anchor': 'end',
        fill: '#666',
        'font-size': '12',
      }, String(tick)),
    )
  })

  const legend = seriesCount > 1
    ? valueFields.map((field, i) => {
        const color = getColor(i, colors.length > 0 ? colors : undefined)
        return h('g', { transform: `translate(${margin.left + i * 120}, ${height - 15})` },
          h('rect', { x: '0', y: '-10', width: '14', height: '14', fill: color, rx: '2' }),
          h('text', { x: '20', y: '2', fill: '#666', 'font-size': '12' }, field),
        )
      })
    : []

  return h('svg', {
      xmlns: 'http://www.w3.org/2000/svg',
      viewBox: `0 0 ${width} ${height}`,
      width: String(width),
      height: String(height),
      style: { backgroundColor: '#fff', borderRadius: '8px' },
    },
    h('text', {
      x: String(width / 2),
      y: '30',
      'text-anchor': 'middle',
      'font-size': '18',
      'font-weight': 'bold',
      fill: '#333',
    }, title),
    ...yTickElements,
    h('line', {
      x1: String(margin.left),
      y1: String(margin.top),
      x2: String(margin.left),
      y2: String(margin.top + chartHeight),
      stroke: '#333',
      'stroke-width': '1',
    }),
    h('line', {
      x1: String(margin.left),
      y1: String(margin.top + chartHeight),
      x2: String(margin.left + chartWidth),
      y2: String(margin.top + chartHeight),
      stroke: '#333',
      'stroke-width': '1',
    }),
    ...bars,
    ...xLabels,
    ...(xAxisLabel ? [h('text', {
      x: String(margin.left + chartWidth / 2),
      y: String(height - 45),
      'text-anchor': 'middle',
      fill: '#666',
      'font-size': '14',
    }, xAxisLabel)] : []),
    ...(yAxisLabel ? [h('text', {
      x: '15',
      y: String(margin.top + chartHeight / 2),
      'text-anchor': 'middle',
      fill: '#666',
      'font-size': '14',
      transform: `rotate(-90, 15, ${margin.top + chartHeight / 2})`,
    }, yAxisLabel)] : []),
    ...legend,
  )
}

import { h } from 'plaited'
import type { ChartConfig, ChartData } from './types'
import { getColor } from './colors'

export const renderLineChart = (data: ChartData, config: ChartConfig) => {
  const { width, height, title, xAxisLabel, yAxisLabel, categoryField, valueFields, colors } = config

  const margin = { top: 50, right: 30, bottom: 80, left: 70 }
  const chartWidth = width - margin.left - margin.right
  const chartHeight = height - margin.top - margin.bottom

  const categories = data.map((d) => String(d[categoryField] ?? ''))
  const pointCount = categories.length

  let maxVal = 0
  let minVal = Infinity
  for (const field of valueFields) {
    for (const row of data) {
      const v = Number(row[field]) || 0
      if (v > maxVal) maxVal = v
      if (v < minVal) minVal = v
    }
  }
  minVal = Math.min(0, minVal)
  const range = (maxVal - minVal) * 1.1 || 1
  maxVal = minVal + range

  const scaleX = (i: number) => margin.left + (i / Math.max(pointCount - 1, 1)) * chartWidth
  const scaleY = (v: number) => margin.top + chartHeight - ((v - minVal) / range) * chartHeight

  const tickCount = 5
  const yTicks = Array.from({ length: tickCount + 1 }, (_, i) =>
    Math.round((minVal + (range / tickCount) * i) * 100) / 100
  )

  const lines = valueFields.map((field, seriesIdx) => {
    const color = getColor(seriesIdx, colors.length > 0 ? colors : undefined)
    const points = data.map((row, i) => {
      const val = Number(row[field]) || 0
      return `${scaleX(i)},${scaleY(val)}`
    })

    const dots = data.map((row, i) => {
      const val = Number(row[field]) || 0
      return h('circle', {
        cx: String(scaleX(i)),
        cy: String(scaleY(val)),
        r: '4',
        fill: color,
        stroke: '#fff',
        'stroke-width': '2',
      },
        h('title', {}, `${field}: ${val}`),
      )
    })

    return h('g', {},
      h('polyline', {
        points: points.join(' '),
        fill: 'none',
        stroke: color,
        'stroke-width': '2.5',
        'stroke-linejoin': 'round',
        'stroke-linecap': 'round',
      }),
      ...dots,
    )
  })

  const xLabels = categories.map((cat, i) => {
    const x = scaleX(i)
    return h('text', {
      x: String(x),
      y: String(margin.top + chartHeight + 20),
      'text-anchor': 'middle',
      fill: '#666',
      'font-size': '12',
      transform: categories.length > 8
        ? `rotate(-45, ${x}, ${margin.top + chartHeight + 20})`
        : undefined,
    }, cat)
  })

  const yTickElements = yTicks.map((tick) => {
    const y = scaleY(tick)
    return h('g', {},
      h('line', {
        x1: String(margin.left),
        y1: String(y),
        x2: String(margin.left + chartWidth),
        y2: String(y),
        stroke: '#e0e0e0',
        'stroke-dasharray': '3,3',
      }),
      h('text', {
        x: String(margin.left - 10),
        y: String(y + 4),
        'text-anchor': 'end',
        fill: '#666',
        'font-size': '12',
      }, String(tick)),
    )
  })

  const legend = valueFields.length > 1
    ? valueFields.map((field, i) => {
        const color = getColor(i, colors.length > 0 ? colors : undefined)
        return h('g', { transform: `translate(${margin.left + i * 120}, ${height - 15})` },
          h('line', { x1: '0', y1: '-3', x2: '14', y2: '-3', stroke: color, 'stroke-width': '3' }),
          h('circle', { cx: '7', cy: '-3', r: '3', fill: color }),
          h('text', { x: '20', y: '2', fill: '#666', 'font-size': '12' }, field),
        )
      })
    : []

  return h('svg', {
      xmlns: 'http://www.w3.org/2000/svg',
      viewBox: `0 0 ${width} ${height}`,
      width: String(width),
      height: String(height),
      style: { backgroundColor: '#fff', borderRadius: '8px' },
    },
    h('text', {
      x: String(width / 2),
      y: '30',
      'text-anchor': 'middle',
      'font-size': '18',
      'font-weight': 'bold',
      fill: '#333',
    }, title),
    ...yTickElements,
    h('line', {
      x1: String(margin.left),
      y1: String(margin.top),
      x2: String(margin.left),
      y2: String(margin.top + chartHeight),
      stroke: '#333',
      'stroke-width': '1',
    }),
    h('line', {
      x1: String(margin.left),
      y1: String(margin.top + chartHeight),
      x2: String(margin.left + chartWidth),
      y2: String(margin.top + chartHeight),
      stroke: '#333',
      'stroke-width': '1',
    }),
    ...lines,
    ...xLabels,
    ...(xAxisLabel ? [h('text', {
      x: String(margin.left + chartWidth / 2),
      y: String(height - 45),
      'text-anchor': 'middle',
      fill: '#666',
      'font-size': '14',
    }, xAxisLabel)] : []),
    ...(yAxisLabel ? [h('text', {
      x: '15',
      y: String(margin.top + chartHeight / 2),
      'text-anchor': 'middle',
      fill: '#666',
      'font-size': '14',
      transform: `rotate(-90, 15, ${margin.top + chartHeight / 2})`,
    }, yAxisLabel)] : []),
    ...legend,
  )
}

import { h } from 'plaited'
import type { ChartConfig, ChartData } from './types'
import { getColor } from './colors'

const polarToCartesian = (cx: number, cy: number, r: number, angleDeg: number) => {
  const rad = ((angleDeg - 90) * Math.PI) / 180
  return { x: cx + r * Math.cos(rad), y: cy + r * Math.sin(rad) }
}

const describeArc = (cx: number, cy: number, r: number, startAngle: number, endAngle: number): string => {
  const span = endAngle - startAngle
  if (span >= 359.99) {
    const mid = startAngle + span / 2
    const s1 = polarToCartesian(cx, cy, r, startAngle)
    const m = polarToCartesian(cx, cy, r, mid)
    const e1 = polarToCartesian(cx, cy, r, endAngle - 0.01)
    return `M ${s1.x} ${s1.y} A ${r} ${r} 0 0 1 ${m.x} ${m.y} A ${r} ${r} 0 0 1 ${e1.x} ${e1.y} Z`
  }

  const start = polarToCartesian(cx, cy, r, startAngle)
  const end = polarToCartesian(cx, cy, r, endAngle)
  const largeArc = span > 180 ? 1 : 0
  return `M ${cx} ${cy} L ${start.x} ${start.y} A ${r} ${r} 0 ${largeArc} 1 ${end.x} ${end.y} Z`
}

export const renderPieChart = (data: ChartData, config: ChartConfig) => {
  const { width, height, title, categoryField, valueFields, colors } = config

  const valueField = valueFields[0]
  if (!valueField) {
    return h('svg', { xmlns: 'http://www.w3.org/2000/svg', width: String(width), height: String(height) },
      h('text', { x: String(width / 2), y: String(height / 2), 'text-anchor': 'middle', fill: '#999' },
        'No numeric field selected'),
    )
  }

  const slices = data.map((row) => ({
    label: String(row[categoryField] ?? ''),
    value: Math.max(0, Number(row[valueField]) || 0),
  }))

  const total = slices.reduce((sum, s) => sum + s.value, 0)
  if (total === 0) {
    return h('svg', { xmlns: 'http://www.w3.org/2000/svg', width: String(width), height: String(height) },
      h('text', { x: String(width / 2), y: String(height / 2), 'text-anchor': 'middle', fill: '#999' },
        'All values are zero'),
    )
  }

  const cx = width / 2
  const cy = height / 2 + 10
  const radius = Math.min(width, height) / 2 - 60

  let currentAngle = 0
  const paths = slices.map((slice, i) => {
    const sliceAngle = (slice.value / total) * 360
    const startAngle = currentAngle
    const endAngle = currentAngle + sliceAngle
    currentAngle = endAngle

    const color = getColor(i, colors.length > 0 ? colors : undefined)
    const midAngle = startAngle + sliceAngle / 2
    const percentage = ((slice.value / total) * 100).toFixed(1)

    const labelPos = polarToCartesian(cx, cy, radius * 0.65, midAngle)

    return h('g', {},
      h('path', {
        d: describeArc(cx, cy, radius, startAngle, endAngle),
        fill: color,
        stroke: '#fff',
        'stroke-width': '2',
      },
        h('title', {}, `${slice.label}: ${slice.value} (${percentage}%)`),
      ),
      sliceAngle > 15 ? h('text', {
        x: String(labelPos.x),
        y: String(labelPos.y),
        'text-anchor': 'middle',
        'dominant-baseline': 'middle',
        fill: '#fff',
        'font-size': '12',
        'font-weight': 'bold',
      }, `${percentage}%`) : null,
    )
  })

  const legendY = height - 30
  const legendItems = slices.map((slice, i) => {
    const color = getColor(i, colors.length > 0 ? colors : undefined)
    const xPos = (i % 4) * (width / 4) + 20
    const yPos = legendY + Math.floor(i / 4) * 20
    return h('g', { transform: `translate(${xPos}, ${yPos})` },
      h('rect', { x: '0', y: '-10', width: '12', height: '12', fill: color, rx: '2' }),
      h('text', { x: '18', y: '0', fill: '#666', 'font-size': '11' }, slice.label),
    )
  })

  return h('svg', {
      xmlns: 'http://www.w3.org/2000/svg',
      viewBox: `0 0 ${width} ${height}`,
      width: String(width),
      height: String(height),
      style: { backgroundColor: '#fff', borderRadius: '8px' },
    },
    h('text', {
      x: String(width / 2),
      y: '30',
      'text-anchor': 'middle',
      'font-size': '18',
      'font-weight': 'bold',
      fill: '#333',
    }, title),
    ...paths,
    ...legendItems,
  )
}

import { h } from 'plaited'
import type { ChartConfig, ChartData, ChartType } from './types'
import { renderBarChart } from './bar-chart'
import { renderLineChart } from './line-chart'
import { renderPieChart } from './pie-chart'
import { detectFields, pickDefaults } from './detect-fields'
import { DEFAULT_PALETTE, PALETTES } from './colors'

const CHART_RENDERERS: Record<ChartType, (data: ChartData, config: ChartConfig) => ReturnType<typeof h>> = {
  bar: renderBarChart,
  line: renderLineChart,
  pie: renderPieChart,
}

export const buildConfig = (
  data: ChartData,
  overrides: Partial<ChartConfig> = {},
): ChartConfig => {
  const detected = detectFields(data)
  const defaults = pickDefaults(detected)

  return {
    type: overrides.type ?? 'bar',
    title: overrides.title ?? 'Chart',
    xAxisLabel: overrides.xAxisLabel ?? defaults.category,
    yAxisLabel: overrides.yAxisLabel ?? '',
    categoryField: overrides.categoryField ?? defaults.category,
    valueFields: overrides.valueFields ?? defaults.values,
    colors: overrides.colors ?? DEFAULT_PALETTE,
    width: overrides.width ?? 700,
    height: overrides.height ?? 450,
  }
}

export const renderChart = (data: ChartData, config: ChartConfig) => {
  const renderer = CHART_RENDERERS[config.type]
  return renderer(data, config)
}

export const renderChartControls = (config: ChartConfig, detected: ReturnType<typeof detectFields>) => {
  const controlGroupStyles = {
