import { buildConfig, renderChart, renderChartControls } from './chart-renderer'
import { PALETTES, DEFAULT_PALETTE } from './colors'

const SAMPLE_DATA: ChartData = [
  { month: 'Jan', sales: 120, expenses: 80, profit: 40 },
  { month: 'Feb', sales: 150, expenses: 95, profit: 55 },
  { month: 'Mar', sales: 180, expenses: 110, profit: 70 },
  { month: 'Apr', sales: 140, expenses: 85, profit: 55 },
  { month: 'May', sales: 200, expenses: 130, profit: 70 },
  { month: 'Jun', sales: 170, expenses: 100, profit: 70 },
]

type AppState = {
  jsonInput: string
  data: ChartData
  config: ChartConfig
  error: string | null
}

const createInitialState = (): AppState => {
  const json = JSON.stringify(SAMPLE_DATA, null, 2)
  const data = SAMPLE_DATA
  const config = buildConfig(data, { title: 'Monthly Performance' })
  return { jsonInput: json, data, config, error: null }
}

const updateData = (state: AppState, json: string): AppState => {
  const parsed = parseJsonInput(json)
  if (!parsed.valid || !parsed.data) {
    return { ...state, jsonInput: json, error: parsed.error }
  }

  const detected = detectFields(parsed.data)
  const defaults = pickDefaults(detected)

  const categoryField = detected.categorical.includes(state.config.categoryField)
    ? state.config.categoryField
    : defaults.category

  const valueFields = state.config.valueFields.filter((f) => detected.numeric.includes(f))
  const finalValueFields = valueFields.length > 0 ? valueFields : defaults.values

  return {
    jsonInput: json,
    data: parsed.data,
    config: {
      ...state.config,
      categoryField,
      valueFields: finalValueFields,
    },
    error: null,
  }
}

