export const handleAction = (state: AppState, action: string, payload?: string): AppState => {
  switch (action) {
    case 'updateJson':
      return updateData(state, payload ?? '')
    case 'setChartType':
      return { ...state, config: { ...state.config, type: (payload ?? 'bar') as ChartType } }
    case 'setTitle':
      return { ...state, config: { ...state.config, title: payload ?? '' } }
    case 'setXLabel':
      return { ...state, config: { ...state.config, xAxisLabel: payload ?? '' } }
    case 'setYLabel':
      return { ...state, config: { ...state.config, yAxisLabel: payload ?? '' } }
    case 'setCategoryField':
      return { ...state, config: { ...state.config, categoryField: payload ?? '' } }
    case 'toggleValueField': {
      const field = payload ?? ''
      const current = state.config.valueFields
      const next = current.includes(field)
        ? current.filter((f) => f !== field)
        : [...current, field]
      return { ...state, config: { ...state.config, valueFields: next.length > 0 ? next : current } }
    }
    case 'setPalette': {
      const palette = PALETTES[payload ?? 'default'] ?? DEFAULT_PALETTE
      return { ...state, config: { ...state.config, colors: palette } }
    }
    case 'setCustomColors': {
      const colors = (payload ?? '')
        .split(',')
        .map((c) => c.trim())
        .filter((c) => /^#[0-9a-fA-F]{3,8}$/.test(c))
      if (colors.length > 0) {
        return { ...state, config: { ...state.config, colors } }
      }
      return state
    }
    default:
      return state
  }
}

export const saveSvgToFile = async (data: ChartData, config: ChartConfig, filename = 'chart.svg'): Promise<string> => {
  const svg = generateSvgString(data, config)
  const path = `data/${filename}`
  await Bun.write(path, svg)
  return path
}

export const loadDataFromFile = async (path: string): Promise<ChartData> => {
  const file = Bun.file(path)
  const text = await file.text()
  const parsed = parseJsonInput(text)
  if (!parsed.valid || !parsed.data) {
    throw new Error(parsed.error ?? 'Invalid JSON data')
  }
  return parsed.data
}

