export type RGB = { r: number; g: number; b: number }
export type HSL = { h: number; s: number; l: number }

export type Color = {
  hex: string
  rgb: RGB
  hsl: HSL
}

const clamp = (v: number, min: number, max: number): number =>
  Math.max(min, Math.min(max, v))

const round = (v: number, decimals = 1): number =>
  Math.round(v * 10 ** decimals) / 10 ** decimals

export const hexToRgb = (hex: string): RGB => {
  const cleaned = hex.replace(/^#/, '')
  const expanded =
    cleaned.length === 3
      ? cleaned
          .split('')
          .map((c) => c + c)
          .join('')
      : cleaned
  const num = parseInt(expanded, 16)
  return {
    r: (num >> 16) & 255,
    g: (num >> 8) & 255,
    b: num & 255,
  }
}

export const rgbToHex = ({ r, g, b }: RGB): string => {
  const toHex = (n: number) =>
    clamp(Math.round(n), 0, 255).toString(16).padStart(2, '0')
  return `#${toHex(r)}${toHex(g)}${toHex(b)}`
}

export const rgbToHsl = ({ r, g, b }: RGB): HSL => {
  const rn = r / 255
  const gn = g / 255
  const bn = b / 255
  const max = Math.max(rn, gn, bn)
  const min = Math.min(rn, gn, bn)
  const delta = max - min
  const l = (max + min) / 2

  if (delta === 0) {
    return { h: 0, s: 0, l: round(l * 100) }
  }

  const s = l > 0.5 ? delta / (2 - max - min) : delta / (max + min)

  let h = 0
  if (max === rn) {
    h = ((gn - bn) / delta + (gn < bn ? 6 : 0)) / 6
  } else if (max === gn) {
    h = ((bn - rn) / delta + 2) / 6
  } else {
    h = ((rn - gn) / delta + 4) / 6
  }

  return {
    h: round(h * 360),
    s: round(s * 100),
    l: round(l * 100),
  }
}

export const hslToRgb = ({ h, s, l }: HSL): RGB => {
  const sn = s / 100
  const ln = l / 100
  const c = (1 - Math.abs(2 * ln - 1)) * sn
  const x = c * (1 - Math.abs(((h / 60) % 2) - 1))
  const m = ln - c / 2

  let rn = 0,
    gn = 0,
    bn = 0
  if (h < 60) {
    ;[rn, gn, bn] = [c, x, 0]
  } else if (h < 120) {
    ;[rn, gn, bn] = [x, c, 0]
  } else if (h < 180) {
    ;[rn, gn, bn] = [0, c, x]
  } else if (h < 240) {
    ;[rn, gn, bn] = [0, x, c]
  } else if (h < 300) {
    ;[rn, gn, bn] = [x, 0, c]
  } else {
    ;[rn, gn, bn] = [c, 0, x]
  }

  return {
    r: Math.round((rn + m) * 255),
    g: Math.round((gn + m) * 255),
    b: Math.round((bn + m) * 255),
  }
}

export const createColor = (hex: string): Color => {
  const rgb = hexToRgb(hex)
  const hsl = rgbToHsl(rgb)
  return { hex: rgbToHex(rgb), rgb, hsl }
}

export const colorFromHsl = (hsl: HSL): Color => {
  const normalizedH = ((hsl.h % 360) + 360) % 360
  const normalizedHsl = {
    h: round(normalizedH),
    s: round(clamp(hsl.s, 0, 100)),
    l: round(clamp(hsl.l, 0, 100)),
  }
  const rgb = hslToRgb(normalizedHsl)
  return { hex: rgbToHex(rgb), rgb, hsl: normalizedHsl }
}

export const isValidHex = (hex: string): boolean =>
  /^#?([0-9a-fA-F]{3}|[0-9a-fA-F]{6})$/.test(hex)

export const formatRgb = ({ r, g, b }: RGB): string => `rgb(${r}, ${g}, ${b})`

export const formatHsl = ({ h, s, l }: HSL): string =>
  `hsl(${h}, ${s}%, ${l}%)`

import type { Color, RGB } from './color'

export type WCAGLevel = 'AAA' | 'AA' | 'Fail'

export type ContrastResult = {
  ratio: number
  ratioDisplay: string
  normalText: { aa: boolean; aaa: boolean; level: WCAGLevel }
  largeText: { aa: boolean; aaa: boolean; level: WCAGLevel }
}

const srgbToLinear = (channel: number): number => {
  const c = channel / 255
  return c <= 0.04045 ? c / 12.92 : ((c + 0.055) / 1.055) ** 2.4
}

export const relativeLuminance = ({ r, g, b }: RGB): number =>
  0.2126 * srgbToLinear(r) + 0.7152 * srgbToLinear(g) + 0.0722 * srgbToLinear(b)

export const contrastRatio = (color1: RGB, color2: RGB): number => {
  const l1 = relativeLuminance(color1)
  const l2 = relativeLuminance(color2)
  const lighter = Math.max(l1, l2)
  const darker = Math.min(l1, l2)
  return (lighter + 0.05) / (darker + 0.05)
}

const getLevel = (aa: boolean, aaa: boolean): WCAGLevel => {
  if (aaa) return 'AAA'
  if (aa) return 'AA'
  return 'Fail'
}

export const checkContrast = (foreground: Color, background: Color): ContrastResult => {
  const ratio = contrastRatio(foreground.rgb, background.rgb)
  const rounded = Math.round(ratio * 100) / 100

  const normalAA = ratio >= 4.5
  const normalAAA = ratio >= 7
  const largeAA = ratio >= 3
  const largeAAA = ratio >= 4.5

  return {
    ratio: rounded,
    ratioDisplay: `${rounded.toFixed(2)}:1`,
    normalText: {
      aa: normalAA,
      aaa: normalAAA,
      level: getLevel(normalAA, normalAAA),
    },
    largeText: {
      aa: largeAA,
      aaa: largeAAA,
      level: getLevel(largeAA, largeAAA),
    },
  }
}

