import { createColor, isValidHex, type Color } from './color'
import { generatePalette, harmonyModes, type HarmonyMode, type Palette } from './harmony'
import { checkContrast, type ContrastResult } from './contrast'
import { renderPaletteView } from './render'

const DATA_PATH = './data/palettes.json'

type AppState = {
  baseHex: string
  mode: HarmonyMode
  palette: Palette
  fgIndex: number
  bgIndex: number
}

const createInitialState = (hex = '#3a86ff'): AppState => {
  const base = createColor(hex)
  const mode: HarmonyMode = 'complementary'
  const palette = generatePalette(base, mode)
  return {
    baseHex: base.hex,
    mode,
    palette,
    fgIndex: 0,
    bgIndex: palette.colors.length - 1,
  }
}

const updateBaseColor = (state: AppState, hex: string): AppState => {
  if (!isValidHex(hex)) return state
  const normalized = hex.startsWith('#') ? hex : `#${hex}`
  const base = createColor(normalized)
  const palette = generatePalette(base, state.mode)
  return {
    ...state,
    baseHex: base.hex,
    palette,
    fgIndex: 0,
    bgIndex: palette.colors.length - 1,
  }
}

const updateMode = (state: AppState, mode: HarmonyMode): AppState => {
  if (!harmonyModes.includes(mode)) return state
  const palette = generatePalette(state.palette.base, mode)
  return {
    ...state,
    mode,
    palette,
    fgIndex: 0,
    bgIndex: palette.colors.length - 1,
  }
}

const updateContrastSelection = (
  state: AppState,
  target: 'fg' | 'bg',
  index: number,
): AppState => {
  const clamped = Math.max(0, Math.min(index, state.palette.colors.length - 1))
  return target === 'fg'
    ? { ...state, fgIndex: clamped }
    : { ...state, bgIndex: clamped }
}

const getContrastResult = (state: AppState): ContrastResult => {
  const fg = state.palette.colors[state.fgIndex] ?? state.palette.colors[0]
  const bg = state.palette.colors[state.bgIndex] ?? state.palette.colors[state.palette.colors.length - 1]
  return checkContrast(fg, bg)
}

const renderView = (state: AppState): string =>
  renderPaletteView(state.palette, state.baseHex, state.fgIndex, state.bgIndex)

const savePalette = async (palette: Palette): Promise<void> => {
  const file = Bun.file(DATA_PATH)
  const existing: Palette[] = (await file.exists())
    ? await file.json()
    : []
  const entry = {
    mode: palette.mode,
    base: palette.base.hex,
    colors: palette.colors.map((c) => c.hex),
    savedAt: new Date().toISOString(),
  }
  existing.push(entry as unknown as Palette)
  await Bun.write(DATA_PATH, JSON.stringify(existing, null, 2))
}

const copyToClipboard = async (value: string): Promise<boolean> => {
  try {
    const proc = Bun.spawn(['pbcopy'], { stdin: 'pipe' })
    proc.stdin.write(value)
    proc.stdin.end()
    await proc.exited
    return true
  } catch {
    return false
  }
}

export {
  createColor,
  isValidHex,
  generatePalette,
  checkContrast,
  harmonyModes,
  createInitialState,
  updateBaseColor,
  updateMode,
  updateContrastSelection,
  getContrastResult,
  renderView,
  savePalette,
  copyToClipboard,
}

export type { Color, HarmonyMode, Palette, ContrastResult, AppState }

// Entry point: render default palette
const main = () => {
  const state = createInitialState()
  const html = renderView(state)
  console.log(html)

  const contrast = getContrastResult(state)
  console.log(`\nContrast ratio: ${contrast.ratioDisplay}`)
  console.log(`Normal text — AA: ${contrast.normalText.aa ? 'Pass' : 'Fail'}, AAA: ${contrast.normalText.aaa ? 'Pass' : 'Fail'}`)
  console.log(`Large text  — AA: ${contrast.largeText.aa ? 'Pass' : 'Fail'}, AAA: ${contrast.largeText.aaa ? 'Pass' : 'Fail'}`)
}

