export type RGB = { r: number; g: number; b: number }
export type HSL = { h: number; s: number; l: number }
export type ColorValue = { hex: string; rgb: RGB; hsl: HSL }

export const hexToRgb = (hex: string): RGB => {
  const clean = hex.replace(/^#/, '')
  const full =
    clean.length === 3
      ? clean
          .split('')
          .map((c) => c + c)
          .join('')
      : clean
  const n = parseInt(full, 16)
  return { r: (n >> 16) & 255, g: (n >> 8) & 255, b: n & 255 }
}

export const rgbToHex = (rgb: RGB): string => {
  const toHex = (v: number) =>
    Math.round(Math.max(0, Math.min(255, v)))
      .toString(16)
      .padStart(2, '0')
  return `#${toHex(rgb.r)}${toHex(rgb.g)}${toHex(rgb.b)}`
}

export const rgbToHsl = (rgb: RGB): HSL => {
  const r = rgb.r / 255
  const g = rgb.g / 255
  const b = rgb.b / 255
  const max = Math.max(r, g, b)
  const min = Math.min(r, g, b)
  const l = (max + min) / 2
  if (max === min) return { h: 0, s: 0, l: Math.round(l * 100) }
  const d = max - min
  const s = l > 0.5 ? d / (2 - max - min) : d / (max + min)
  let h = 0
  if (max === r) h = ((g - b) / d + (g < b ? 6 : 0)) / 6
  else if (max === g) h = ((b - r) / d + 2) / 6
  else h = ((r - g) / d + 4) / 6
  return {
    h: Math.round(h * 360),
    s: Math.round(s * 100),
    l: Math.round(l * 100),
  }
}

export const hslToRgb = (hsl: HSL): RGB => {
  const h = hsl.h / 360
  const s = hsl.s / 100
  const l = hsl.l / 100
  if (s === 0) {
    const v = Math.round(l * 255)
    return { r: v, g: v, b: v }
  }
  const hue2rgb = (p: number, q: number, t: number): number => {
    const tt = t < 0 ? t + 1 : t > 1 ? t - 1 : t
    if (tt < 1 / 6) return p + (q - p) * 6 * tt
    if (tt < 1 / 2) return q
    if (tt < 2 / 3) return p + (q - p) * (2 / 3 - tt) * 6
    return p
  }
  const q = l < 0.5 ? l * (1 + s) : l + s - l * s
  const p = 2 * l - q
  return {
    r: Math.round(hue2rgb(p, q, h + 1 / 3) * 255),
    g: Math.round(hue2rgb(p, q, h) * 255),
    b: Math.round(hue2rgb(p, q, h - 1 / 3) * 255),
  }
}

export const normalizeHue = (h: number): number => ((h % 360) + 360) % 360

export const toColorValue = (hsl: HSL): ColorValue => {
  const normalized = { ...hsl, h: normalizeHue(hsl.h) }
  const rgb = hslToRgb(normalized)
  return { hex: rgbToHex(rgb), rgb, hsl: normalized }
}

export const parseHexInput = (input: string): string | null => {
  const clean = input.trim().replace(/^#/, '')
  if (/^[0-9a-fA-F]{3}$/.test(clean) || /^[0-9a-fA-F]{6}$/.test(clean)) {
    return `#${clean.length === 3 ? clean.split('').map((c) => c + c).join('') : clean}`
  }
  return null
}

export const formatRgb = (rgb: RGB): string => `rgb(${rgb.r}, ${rgb.g}, ${rgb.b})`

export const formatHsl = (hsl: HSL): string => `hsl(${hsl.h}, ${hsl.s}%, ${hsl.l}%)`

import type { RGB } from './colors'

export type WCAGLevel = 'AAA' | 'AA' | 'Fail'

export type ContrastResult = {
  ratio: number
  ratioText: string
  normalText: { aa: boolean; aaa: boolean; level: WCAGLevel }
  largeText: { aa: boolean; aaa: boolean; level: WCAGLevel }
}

const srgbToLinear = (c: number): number => {
  const s = c / 255
  return s <= 0.04045 ? s / 12.92 : Math.pow((s + 0.055) / 1.055, 2.4)
}

export const relativeLuminance = (rgb: RGB): number =>
  0.2126 * srgbToLinear(rgb.r) + 0.7152 * srgbToLinear(rgb.g) + 0.0722 * srgbToLinear(rgb.b)

export const contrastRatio = (rgb1: RGB, rgb2: RGB): number => {
  const l1 = relativeLuminance(rgb1)
  const l2 = relativeLuminance(rgb2)
  const lighter = Math.max(l1, l2)
  const darker = Math.min(l1, l2)
  return (lighter + 0.05) / (darker + 0.05)
}

const getLevel = (ratio: number, aaThreshold: number, aaaThreshold: number): WCAGLevel => {
  if (ratio >= aaaThreshold) return 'AAA'
  if (ratio >= aaThreshold) return 'AA'
  return 'Fail'
}

export const checkContrast = (rgb1: RGB, rgb2: RGB): ContrastResult => {
  const ratio = contrastRatio(rgb1, rgb2)
  return {
    ratio,
    ratioText: `${ratio.toFixed(2)}:1`,
    normalText: {
      aa: ratio >= 4.5,
      aaa: ratio >= 7,
      level: getLevel(ratio, 4.5, 7),
    },
    largeText: {
      aa: ratio >= 3,
      aaa: ratio >= 4.5,
      level: getLevel(ratio, 3, 4.5),
    },
  }
}

import type { HSL, ColorValue } from './colors'
import { toColorValue, normalizeHue } from './colors'

export type HarmonyMode =
  | 'complementary'
  | 'analogous'
  | 'triadic'
  | 'split-complementary'
  | 'tetradic'

export type Palette = {
  mode: HarmonyMode
  base: ColorValue
  colors: ColorValue[]
}

const shiftHue = (hsl: HSL, degrees: number): HSL => ({
  h: normalizeHue(hsl.h + degrees),
  s: hsl.s,
  l: hsl.l,
})

const harmonyOffsets: Record<HarmonyMode, number[]> = {
  complementary: [0, 180],
  analogous: [-30, 0, 30],
  triadic: [0, 120, 240],
  'split-complementary': [0, 150, 210],
  tetradic: [0, 60, 180, 240],
}

export const generatePalette = (baseHsl: HSL, mode: HarmonyMode): Palette => {
  const base = toColorValue(baseHsl)
  const offsets = harmonyOffsets[mode]
  const colors = offsets.map((offset) => toColorValue(shiftHue(baseHsl, offset)))
  return { mode, base, colors }
}

export const allModes: HarmonyMode[] = [
  'complementary',
  'analogous',
  'triadic',
  'split-complementary',
  'tetradic',
]

export const modeLabels: Record<HarmonyMode, string> = {
  complementary: 'Complementary',
