export const renderPalette = (
  palette: Palette,
  activeMode: HarmonyMode,
  selectedIndices: [number, number] | [number] | [],
  contrastResult: ContrastResult | null,
): string => {
  const selectedColor1 =
    selectedIndices.length >= 1 ? palette.colors[selectedIndices[0]] ?? null : null
  const selectedColor2 =
    selectedIndices.length >= 2 ? palette.colors[selectedIndices[1]] ?? null : null

  const tree = h(
    'div',
    { style: styles.container },
    h(
      'div',
      { style: styles.header },
      h('h1', { style: styles.title }, 'Color Palette Generator'),
      h('p', { style: styles.subtitle }, 'Create harmonious color palettes using color theory'),
    ),
    h(
      'div',
      { style: styles.inputSection },
      h('input', {
        type: 'color',
        value: palette.base.hex,
        style: styles.colorPicker,
        'p-trigger': 'color-pick',
        'p-target': 'color-picker',
      }),
      h('input', {
        type: 'text',
        value: palette.base.hex.toUpperCase(),
        placeholder: '#3B82F6',
        style: styles.hexInput,
        'p-trigger': 'hex-input',
        'p-target': 'hex-input',
        maxlength: '7',
        spellcheck: 'false',
      }),
    ),
    h(
      'div',
      { style: styles.modeSelector },
      ...allModes.map((mode) =>
        h(
          'button',
          {
            style: mode === activeMode ? styles.modeButtonActive : styles.modeButton,
            'p-trigger': `set-mode:${mode}`,
          },
          modeLabels[mode],
        ),
      ),
    ),
    h('p', { style: styles.modeDescription }, modeDescriptions[activeMode]),
    h(
      'div',
      { style: styles.paletteGrid },
      ...palette.colors.map((color, i) =>
        renderSwatch(color, i, selectedIndices.includes(i)),
      ),
    ),
    renderContrastChecker(selectedColor1, selectedColor2, contrastResult),
  )

  const { render } = createSSR()
  return render(tree)
}

import { hexToRgb, rgbToHsl, parseHexInput } from './colors'
import type { HSL, ColorValue } from './colors'
import { generatePalette, allModes } from './palette'
import type { HarmonyMode, Palette } from './palette'
import { checkContrast } from './contrast'
import type { ContrastResult } from './contrast'
import { renderPalette } from './render'

export type AppState = {
  baseHsl: HSL
  mode: HarmonyMode
  palette: Palette
  selectedIndices: [number, number] | [number] | []
  contrastResult: ContrastResult | null
}

const DEFAULT_HEX = '#3B82F6'

const createInitialState = (hex: string = DEFAULT_HEX): AppState => {
  const rgb = hexToRgb(hex)
  const hsl = rgbToHsl(rgb)
  const mode: HarmonyMode = 'complementary'
  const palette = generatePalette(hsl, mode)
  return { baseHsl: hsl, mode, palette, selectedIndices: [], contrastResult: null }
}

const updateBaseColor = (state: AppState, hex: string): AppState => {
  const parsed = parseHexInput(hex)
  if (!parsed) return state
  const rgb = hexToRgb(parsed)
  const hsl = rgbToHsl(rgb)
  const palette = generatePalette(hsl, state.mode)
  return { ...state, baseHsl: hsl, palette, selectedIndices: [], contrastResult: null }
}

const updateMode = (state: AppState, mode: HarmonyMode): AppState => {
  if (!allModes.includes(mode)) return state
  const palette = generatePalette(state.baseHsl, mode)
  return { ...state, mode, palette, selectedIndices: [], contrastResult: null }
}

const selectColor = (state: AppState, index: number): AppState => {
  if (index < 0 || index >= state.palette.colors.length) return state

  const { selectedIndices } = state

  if (selectedIndices.length === 0) {
    return { ...state, selectedIndices: [index], contrastResult: null }
  }

  if (selectedIndices.length === 1) {
    if (selectedIndices[0] === index) {
      return { ...state, selectedIndices: [], contrastResult: null }
    }
    const color1 = state.palette.colors[selectedIndices[0]]
    const color2 = state.palette.colors[index]
    const contrastResult = checkContrast(color1.rgb, color2.rgb)
    return { ...state, selectedIndices: [selectedIndices[0], index], contrastResult }
  }

  return { ...state, selectedIndices: [index], contrastResult: null }
}

const render = (state: AppState): string =>
  renderPalette(state.palette, state.mode, state.selectedIndices, state.contrastResult)

// -- Persistence --

const DATA_PATH = './data/palettes.json'

type SavedPalette = {
  baseHex: string
  mode: HarmonyMode
  createdAt: string
}

const savePalette = async (state: AppState): Promise<void> => {
  const entry: SavedPalette = {
    baseHex: state.palette.base.hex,
    mode: state.mode,
    createdAt: new Date().toISOString(),
  }
  const file = Bun.file(DATA_PATH)
  let existing: SavedPalette[] = []
  if (await file.exists()) {
    existing = await file.json()
  }
  existing.push(entry)
  await Bun.write(DATA_PATH, JSON.stringify(existing, null, 2))
}

const loadPalettes = async (): Promise<SavedPalette[]> => {
  const file = Bun.file(DATA_PATH)
  if (await file.exists()) {
    return file.json()
  }
  return []
}

// -- Clipboard --

const copyToClipboard = async (text: string): Promise<boolean> => {
  const proc = Bun.spawn(['pbcopy'], { stdin: 'pipe' })
  proc.stdin.write(text)
  proc.stdin.end()
  const exitCode = await proc.exited
  return exitCode === 0
}

// -- Event handling --

type EventAction =
  | { type: 'color-pick'; value: string }
  | { type: 'hex-input'; value: string }
  | { type: 'set-mode'; value: HarmonyMode }
  | { type: 'select-color'; value: number }
  | { type: 'copy-value'; value: string }
  | { type: 'save-palette' }

const handleAction = async (state: AppState, action: EventAction): Promise<AppState> => {
  switch (action.type) {
    case 'color-pick':
    case 'hex-input':
      return updateBaseColor(state, action.value)
    case 'set-mode':
      return updateMode(state, action.value)
    case 'select-color':
      return selectColor(state, action.value)
    case 'copy-value':
      await copyToClipboard(action.value)
      return state
    case 'save-palette':
      await savePalette(state)
      return state
  }
}

// -- Exports --

export {
  createInitialState,
  updateBaseColor,
  updateMode,
  selectColor,
  render,
  handleAction,
  savePalette,
  loadPalettes,
  copyToClipboard,
}

