export type RGB = { r: number; g: number; b: number }
export type HSL = { h: number; s: number; l: number }
export type ColorValue = {
  hex: string
  rgb: RGB
  hsl: HSL
}

export const hexToRgb = (hex: string): RGB => {
  const cleaned = hex.replace(/^#/, '')
  const full =
    cleaned.length === 3
      ? cleaned
          .split('')
          .map((c) => c + c)
          .join('')
      : cleaned
  const num = parseInt(full, 16)
  return {
    r: (num >> 16) & 255,
    g: (num >> 8) & 255,
    b: num & 255,
  }
}

export const rgbToHex = (rgb: RGB): string => {
  const toHex = (n: number) =>
    Math.round(Math.max(0, Math.min(255, n)))
      .toString(16)
      .padStart(2, '0')
  return `#${toHex(rgb.r)}${toHex(rgb.g)}${toHex(rgb.b)}`
}

export const rgbToHsl = (rgb: RGB): HSL => {
  const r = rgb.r / 255
  const g = rgb.g / 255
  const b = rgb.b / 255
  const max = Math.max(r, g, b)
  const min = Math.min(r, g, b)
  const l = (max + min) / 2
  if (max === min) return { h: 0, s: 0, l: Math.round(l * 100) }
  const d = max - min
  const s = l > 0.5 ? d / (2 - max - min) : d / (max + min)
  let h = 0
  if (max === r) h = ((g - b) / d + (g < b ? 6 : 0)) / 6
  else if (max === g) h = ((b - r) / d + 2) / 6
  else h = ((r - g) / d + 4) / 6
  return {
    h: Math.round(h * 360),
    s: Math.round(s * 100),
    l: Math.round(l * 100),
  }
}

export const hslToRgb = (hsl: HSL): RGB => {
  const h = hsl.h / 360
  const s = hsl.s / 100
  const l = hsl.l / 100
  if (s === 0) {
    const v = Math.round(l * 255)
    return { r: v, g: v, b: v }
  }
  const hue2rgb = (p: number, q: number, t: number): number => {
    const tt = t < 0 ? t + 1 : t > 1 ? t - 1 : t
    if (tt < 1 / 6) return p + (q - p) * 6 * tt
    if (tt < 1 / 2) return q
    if (tt < 2 / 3) return p + (q - p) * (2 / 3 - tt) * 6
    return p
  }
  const q = l < 0.5 ? l * (1 + s) : l + s - l * s
  const p = 2 * l - q
  return {
    r: Math.round(hue2rgb(p, q, h + 1 / 3) * 255),
    g: Math.round(hue2rgb(p, q, h) * 255),
    b: Math.round(hue2rgb(p, q, h - 1 / 3) * 255),
  }
}

export const toColorValue = (hex: string): ColorValue => {
  const rgb = hexToRgb(hex)
  const hsl = rgbToHsl(rgb)
  return { hex: hex.startsWith('#') ? hex.toLowerCase() : `#${hex.toLowerCase()}`, rgb, hsl }
}

export const fromHsl = (hsl: HSL): ColorValue => {
  const rgb = hslToRgb(hsl)
  const hex = rgbToHex(rgb)
  return { hex, rgb, hsl }
}

export const isValidHex = (value: string): boolean => /^#?([0-9a-fA-F]{3}|[0-9a-fA-F]{6})$/.test(value)

export const formatRgb = (rgb: RGB): string => `rgb(${rgb.r}, ${rgb.g}, ${rgb.b})`

export const formatHsl = (hsl: HSL): string => `hsl(${hsl.h}, ${hsl.s}%, ${hsl.l}%)`

import { type ColorValue, type HSL, fromHsl, rgbToHsl, hexToRgb } from './colors'

export type HarmonyMode = 'complementary' | 'analogous' | 'triadic' | 'split-complementary' | 'tetradic'

const rotateHue = (hsl: HSL, degrees: number): HSL => ({
  h: (hsl.h + degrees + 360) % 360,
  s: hsl.s,
  l: hsl.l,
})

const generateFromOffsets = (baseHsl: HSL, offsets: number[]): ColorValue[] =>
  offsets.map((offset) => fromHsl(rotateHue(baseHsl, offset)))

const harmonyOffsets: Record<HarmonyMode, number[]> = {
  complementary: [0, 180],
  analogous: [-30, 0, 30],
  triadic: [0, 120, 240],
  'split-complementary': [0, 150, 210],
  tetradic: [0, 90, 180, 270],
}

export const generatePalette = (baseHex: string, mode: HarmonyMode): ColorValue[] => {
  const rgb = hexToRgb(baseHex)
  const hsl = rgbToHsl(rgb)
  return generateFromOffsets(hsl, harmonyOffsets[mode])
}

export const allHarmonyModes: HarmonyMode[] = [
  'complementary',
  'analogous',
  'triadic',
  'split-complementary',
  'tetradic',
]

export const harmonyDescriptions: Record<HarmonyMode, string> = {
  complementary: 'Opposite colors on the wheel',
  analogous: 'Adjacent colors on the wheel',
  triadic: 'Three equally spaced colors',
  'split-complementary': 'Base + neighbors of its complement',
  tetradic: 'Four colors forming a rectangle',
}

import type { RGB } from './colors'

export type WcagLevel = 'AAA' | 'AA' | 'Fail'

export type ContrastResult = {
  ratio: number
  normalText: { aa: boolean; aaa: boolean; level: WcagLevel }
  largeText: { aa: boolean; aaa: boolean; level: WcagLevel }
}

const linearize = (channel: number): number => {
  const c = channel / 255
  return c <= 0.04045 ? c / 12.92 : Math.pow((c + 0.055) / 1.055, 2.4)
}

export const relativeLuminance = (rgb: RGB): number =>
  0.2126 * linearize(rgb.r) + 0.7152 * linearize(rgb.g) + 0.0722 * linearize(rgb.b)

export const contrastRatio = (rgb1: RGB, rgb2: RGB): number => {
  const l1 = relativeLuminance(rgb1)
  const l2 = relativeLuminance(rgb2)
  const lighter = Math.max(l1, l2)
  const darker = Math.min(l1, l2)
  return (lighter + 0.05) / (darker + 0.05)
}

const getLevel = (ratio: number, aaThreshold: number, aaaThreshold: number): { aa: boolean; aaa: boolean; level: WcagLevel } => {
  const aaa = ratio >= aaaThreshold
  const aa = ratio >= aaThreshold
  return { aa, aaa, level: aaa ? 'AAA' : aa ? 'AA' : 'Fail' }
}

export const checkContrast = (rgb1: RGB, rgb2: RGB): ContrastResult => {
  const ratio = contrastRatio(rgb1, rgb2)
  return {
    ratio: Math.round(ratio * 100) / 100,
    normalText: getLevel(ratio, 4.5, 7),
    largeText: getLevel(ratio, 3, 4.5),
  }
}

