export const renderPage = (
  baseHex: string,
  mode: HarmonyMode,
  palette: ColorValue[],
  contrastPair: [ColorValue, ColorValue] | null,
  contrastResult: ContrastResult | null,
) => {
  const { html } = createSSR()
  return html(
    h(
      'html',
      { lang: 'en' },
      h(
        'head',
        {},
        h('meta', { charset: 'UTF-8' }),
        h('meta', { name: 'viewport', content: 'width=device-width, initial-scale=1.0' }),
        h('title', {}, 'Color Palette Generator'),
        h('style', {}, `
          * { margin: 0; padding: 0; box-sizing: border-box; }
          body { background: #fafafa; min-height: 100vh; }
          [p-trigger="copyValue"]:hover { background-color: #f0f0f0 !important; }
          [p-trigger="selectColor"]:hover::after {
            content: 'Select';
            position: absolute;
            font-size: 12px;
            font-weight: 600;
            padding: 4px 10px;
            background: rgba(0,0,0,0.6);
            color: #fff;
            border-radius: 4px;
          }
        `),
      ),
      h(
        'body',
        {},
        h(
          'div',
          { style: styles.container, 'p-target': 'palette' },
          h('h1', { style: styles.title }, 'Color Palette Generator'),
          h(
            'div',
            { style: styles.inputSection },
            h('input', {
              type: 'color',
              value: baseHex,
              style: styles.colorPicker,
              'p-trigger': 'colorPick',
            }),
            h('input', {
              type: 'text',
              value: baseHex,
              placeholder: '#3a86ff',
              style: styles.hexInput,
              maxlength: '7',
              'p-trigger': 'hexInput',
            }),
          ),
          renderModeSelector(mode),
          h(
            'div',
            { style: styles.palette },
            ...palette.map((color, i) => renderSwatch(color, i)),
          ),
          contrastPair && contrastResult
            ? renderContrastResult(contrastPair[0], contrastPair[1], contrastResult)
            : renderContrastPlaceholder(),
        ),
        h('script', {}, `
          document.addEventListener('click', (e) => {
            const copyEl = e.target.closest('[p-trigger="copyValue"]');
            if (copyEl) {
              const value = copyEl.dataset.value || copyEl.textContent;
              navigator.clipboard.writeText(value).then(() => {
                const orig = copyEl.textContent;
                copyEl.textContent = 'Copied!';
                setTimeout(() => { copyEl.textContent = orig; }, 1200);
              });
              return;
            }
          });

          const selected = [];
          document.addEventListener('click', (e) => {
            const swatchColor = e.target.closest('[p-trigger="selectColor"]');
            if (swatchColor) {
              const swatch = swatchColor.closest('[data-index]');
              const idx = parseInt(swatch.dataset.index, 10);
              selected.push(idx);
              swatchColor.style.outline = '3px solid #111';
              swatchColor.style.outlineOffset = '-3px';
              if (selected.length === 2) {
                const params = new URLSearchParams(window.location.search);
                params.set('c1', String(selected[0]));
                params.set('c2', String(selected[1]));
                window.location.search = params.toString();
              }
            }
          });

          document.querySelector('[p-trigger="colorPick"]')?.addEventListener('input', (e) => {
            const params = new URLSearchParams(window.location.search);
            params.set('base', e.target.value);
            params.delete('c1');
            params.delete('c2');
            window.location.search = params.toString();
          });

          document.querySelector('[p-trigger="hexInput"]')?.addEventListener('change', (e) => {
            let val = e.target.value.trim();
            if (!val.startsWith('#')) val = '#' + val;
            if (/^#([0-9a-fA-F]{3}|[0-9a-fA-F]{6})$/.test(val)) {
              const params = new URLSearchParams(window.location.search);
              params.set('base', val);
              params.delete('c1');
              params.delete('c2');
              window.location.search = params.toString();
            }
          });

          document.querySelectorAll('[p-trigger="changeMode"]').forEach((btn) => {
            btn.addEventListener('click', () => {
              const params = new URLSearchParams(window.location.search);
              params.set('mode', btn.dataset.mode);
              params.delete('c1');
              params.delete('c2');
              window.location.search = params.toString();
            });
          });
        `),
      ),
    ),
  )
}

import { isValidHex, toColorValue } from './colors'
import { generatePalette, type HarmonyMode, allHarmonyModes } from './harmony'
import { checkContrast } from './contrast'
import { renderPage } from './render'

const DEFAULT_BASE = '#3a86ff'
const DEFAULT_MODE: HarmonyMode = 'complementary'

const server = Bun.serve({
  port: 3000,
  fetch: (req) => {
    const url = new URL(req.url)

    if (url.pathname !== '/' && url.pathname !== '/index.html') {
      return new Response('Not Found', { status: 404 })
    }

    const baseParam = url.searchParams.get('base') ?? DEFAULT_BASE
    const modeParam = (url.searchParams.get('mode') ?? DEFAULT_MODE) as HarmonyMode
    const c1Param = url.searchParams.get('c1')
    const c2Param = url.searchParams.get('c2')

    const baseHex = isValidHex(baseParam) ? (baseParam.startsWith('#') ? baseParam : `#${baseParam}`) : DEFAULT_BASE
    const mode = allHarmonyModes.includes(modeParam) ? modeParam : DEFAULT_MODE

    const palette = generatePalette(baseHex, mode)

    let contrastPair: [typeof palette[0], typeof palette[0]] | null = null
    let contrastResult = null

    if (c1Param !== null && c2Param !== null) {
      const i1 = parseInt(c1Param, 10)
      const i2 = parseInt(c2Param, 10)
      if (
        !isNaN(i1) &&
        !isNaN(i2) &&
        i1 >= 0 &&
        i1 < palette.length &&
        i2 >= 0 &&
        i2 < palette.length &&
        i1 !== i2
      ) {
        contrastPair = [palette[i1], palette[i2]]
        contrastResult = checkContrast(palette[i1].rgb, palette[i2].rgb)
      }
    }

    const html = renderPage(baseHex, mode, palette, contrastPair, contrastResult)

    return new Response(html, {
      headers: { 'Content-Type': 'text/html; charset=utf-8' },
    })
  },
})

console.log(`Color Palette Generator running at http://localhost:${server.port}`)

