import type { Document, DocumentListItem } from './types'

const DATA_PATH = './data/documents.json'

const readDocuments = async (): Promise<Document[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) {
    await Bun.write(DATA_PATH, '[]')
    return []
  }
  const text = await file.text()
  return JSON.parse(text) as Document[]
}

const writeDocuments = async (docs: Document[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(docs, null, 2))
}

const generateId = (): string => {
  return `doc_${Date.now()}_${Math.random().toString(36).slice(2, 9)}`
}

export const listDocuments = async (): Promise<DocumentListItem[]> => {
  const docs = await readDocuments()
  return docs
    .map(({ id, title, updatedAt }) => ({ id, title, updatedAt }))
    .sort((a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime())
}

export const getDocument = async (id: string): Promise<Document | null> => {
  const docs = await readDocuments()
  return docs.find((d) => d.id === id) ?? null
}

export const saveDocument = async (
  title: string,
  content: string,
  id?: string
): Promise<Document> => {
  const docs = await readDocuments()
  const now = new Date().toISOString()

  if (id) {
    const idx = docs.findIndex((d) => d.id === id)
    if (idx !== -1) {
      docs[idx] = { ...docs[idx], title, content, updatedAt: now }
      await writeDocuments(docs)
      return docs[idx]
    }
  }

  const doc: Document = {
    id: generateId(),
    title,
    content,
    createdAt: now,
    updatedAt: now,
  }
  docs.push(doc)
  await writeDocuments(docs)
  return doc
}

export const deleteDocument = async (id: string): Promise<boolean> => {
  const docs = await readDocuments()
  const filtered = docs.filter((d) => d.id !== id)
  if (filtered.length === docs.length) return false
  await writeDocuments(filtered)
  return true
}

const escapeHtml = (text: string): string =>
  text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')

const parseInline = (text: string): string => {
  let result = text
  // images (before links to avoid conflict)
  result = result.replace(/!\[([^\]]*)\]\(([^)]+)\)/g, '<img src="$2" alt="$1" />')
  // links
  result = result.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2">$1</a>')
  // bold+italic
  result = result.replace(/\*\*\*(.+?)\*\*\*/g, '<strong><em>$1</em></strong>')
  // bold
  result = result.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
  // italic
  result = result.replace(/\*(.+?)\*/g, '<em>$1</em>')
  // strikethrough
  result = result.replace(/~~(.+?)~~/g, '<del>$1</del>')
  // inline code
  result = result.replace(/`([^`]+)`/g, '<code>$1</code>')
  return result
}

const parseTable = (lines: string[]): string => {
  if (lines.length < 2) return ''
  const parseRow = (line: string): string[] =>
    line
      .split('|')
      .map((c) => c.trim())
      .filter((c) => c.length > 0)

  const headers = parseRow(lines[0])
  // lines[1] is the separator row, skip it
  const bodyRows = lines.slice(2).map(parseRow)

  const headerHtml = headers.map((h) => `<th>${parseInline(h)}</th>`).join('')
  const bodyHtml = bodyRows
    .map((row) => {
      const cells = row.map((c) => `<td>${parseInline(c)}</td>`).join('')
      return `<tr>${cells}</tr>`
    })
    .join('\n')

  return `<table>\n<thead><tr>${headerHtml}</tr></thead>\n<tbody>\n${bodyHtml}\n</tbody>\n</table>`
}

export const renderMarkdown = (source: string): string => {
  const lines = source.split('\n')
  const html: string[] = []
  let i = 0

  while (i < lines.length) {
    const line = lines[i]

    // fenced code block
    if (line.startsWith('```')) {
      const lang = line.slice(3).trim()
      const codeLines: string[] = []
      i++
      while (i < lines.length && !lines[i].startsWith('```')) {
        codeLines.push(escapeHtml(lines[i]))
        i++
      }
      i++ // skip closing ```
      const langAttr = lang ? ` class="language-${escapeHtml(lang)}"` : ''
      html.push(`<pre><code${langAttr}>${codeLines.join('\n')}</code></pre>`)
      continue
    }

    // table (line with pipes followed by separator row)
    if (line.includes('|') && i + 1 < lines.length && /^\|?[\s-:|]+\|/.test(lines[i + 1])) {
      const tableLines: string[] = [line]
      i++
      while (i < lines.length && lines[i].includes('|')) {
        tableLines.push(lines[i])
        i++
      }
      html.push(parseTable(tableLines))
      continue
    }

    // horizontal rule
    if (/^(-{3,}|\*{3,}|_{3,})\s*$/.test(line)) {
      html.push('<hr />')
      i++
      continue
    }

    // headings
    const headingMatch = line.match(/^(#{1,6})\s+(.+)$/)
    if (headingMatch) {
      const level = headingMatch[1].length
      html.push(`<h${level}>${parseInline(headingMatch[2])}</h${level}>`)
      i++
      continue
    }

    // blockquote
    if (line.startsWith('>')) {
      const quoteLines: string[] = []
      while (i < lines.length && lines[i].startsWith('>')) {
        quoteLines.push(lines[i].replace(/^>\s?/, ''))
        i++
      }
      html.push(`<blockquote>${parseInline(quoteLines.join('\n'))}</blockquote>`)
      continue
    }

    // unordered list
    if (/^[\s]*[-*+]\s/.test(line)) {
      const items: string[] = []
      while (i < lines.length && /^[\s]*[-*+]\s/.test(lines[i])) {
        items.push(lines[i].replace(/^[\s]*[-*+]\s/, ''))
        i++
      }
      const listItems = items.map((item) => `<li>${parseInline(item)}</li>`).join('\n')
      html.push(`<ul>\n${listItems}\n</ul>`)
      continue
    }

    // ordered list
    if (/^[\s]*\d+\.\s/.test(line)) {
      const items: string[] = []
      while (i < lines.length && /^[\s]*\d+\.\s/.test(lines[i])) {
        items.push(lines[i].replace(/^[\s]*\d+\.\s/, ''))
        i++
      }
      const listItems = items.map((item) => `<li>${parseInline(item)}</li>`).join('\n')
      html.push(`<ol>\n${listItems}\n</ol>`)
      continue
    }

    // empty line
    if (line.trim() === '') {
      i++
      continue
    }

    // paragraph
    const paraLines: string[] = []
    while (i < lines.length && lines[i].trim() !== '' && !/^#{1,6}\s/.test(lines[i]) && !lines[i].startsWith('```') && !lines[i].startsWith('>') && !/^[-*+]\s/.test(lines[i]) && !/^\d+\.\s/.test(lines[i]) && !/^(-{3,}|\*{3,}|_{3,})\s*$/.test(lines[i])) {
      paraLines.push(lines[i])
      i++
    }
    if (paraLines.length > 0) {
      html.push(`<p>${parseInline(paraLines.join('\n'))}</p>`)
    }
  }

  return html.join('\n')
}

