const styleToString = (style: Record<string, string>): string =>
  Object.entries(style)
    .map(([k, v]) => {
      const prop = k.replace(/[A-Z]/g, (m) => `-${m.toLowerCase()}`)
      return `${prop}: ${v}`
    })
    .join('; ')

const s = (style: Record<string, string>) => styleToString(style)

export const renderToolbar = (): string => {
  const dividerIndices = [3, 6, 8, 10, 12]
  const buttons = toolbarActions.map((item, idx) => {
    const divider = dividerIndices.includes(idx)
      ? `<div style="${s(layoutStyles.toolbarDivider)}"></div>`
      : ''
    return `${divider}<button
      style="${s(layoutStyles.toolbarBtn)}"
      p-trigger="click:toolbar-action"
      data-action="${item.action}"
      title="${item.title}"
    >${item.label}</button>`
  })
  return `<div style="${s(layoutStyles.toolbar)}">${buttons.join('')}</div>`
}

export const renderDocList = (docs: DocumentListItem[]): string => {
  if (docs.length === 0) {
    return '<div style="padding: 16px; color: #666; text-align: center; font-size: 13px;">No saved documents</div>'
  }
  return docs
    .map(
      (doc) => `
    <div style="${s(layoutStyles.docItem)}" p-trigger="click:load-doc" data-id="${doc.id}">
      <div style="${s(layoutStyles.docItemTitle)}">${doc.title}</div>
      <div style="${s(layoutStyles.docItemDate)}">${new Date(doc.updatedAt).toLocaleDateString()} ${new Date(doc.updatedAt).toLocaleTimeString()}</div>
    </div>`
    )
    .join('')
}

