        >New</button>
        ${currentId ? `<button
          style="${s({ ...layoutStyles.btn, ...layoutStyles.btnDanger })}"
          p-trigger="click:delete-doc"
        >Delete</button>` : ''}
        <button
          style="${s({ ...layoutStyles.btn, ...layoutStyles.btnSecondary })}"
          p-trigger="click:toggle-sidebar"
        >${sidebarOpen ? 'Hide Docs' : 'Show Docs'}</button>
      </div>
    </div>
    ${renderToolbar()}
    <div style="${s(layoutStyles.splitPane)}">
      <div style="${s(layoutStyles.editorPane)}">
        <div style="${s(layoutStyles.editorLabel)}">Editor</div>
        <textarea
