        >${markdown.replace(/</g, '&lt;').replace(/>/g, '&gt;')}</textarea>
      </div>
      <div style="${s(layoutStyles.previewPane)}">
        <div style="${s(layoutStyles.previewLabel)}">Preview</div>
        <div class="preview" style="${s(layoutStyles.previewContent)}" p-target="preview">
          ${previewHtml}
        </div>
      </div>
      ${sidebarHtml}
    </div>
  </div>
  <script>
    const editor = document.querySelector('[p-target="editor"]');
    const preview = document.querySelector('[p-target="preview"]');
    const titleInput = document.querySelector('[p-target="title-input"]');
    const docIdInput = document.querySelector('[p-target="doc-id"]');

    // Live preview via server rendering
    let debounceTimer;
    editor.addEventListener('input', () => {
      clearTimeout(debounceTimer);
      debounceTimer = setTimeout(async () => {
        const resp = await fetch('/api/render', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ markdown: editor.value })
        });
        const data = await resp.json();
        preview.innerHTML = data.html;
      }, 150);
    });

    // Toolbar actions
    document.querySelectorAll('[p-trigger="click:toolbar-action"]').forEach(btn => {
      btn.addEventListener('click', async () => {
        const action = btn.dataset.action;
        const resp = await fetch('/api/toolbar', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            action,
            selectionStart: editor.selectionStart,
            selectionEnd: editor.selectionEnd,
            text: editor.value
          })
        });
        const data = await resp.json();
        editor.value = data.text;
        editor.selectionStart = data.cursorStart;
        editor.selectionEnd = data.cursorEnd;
        editor.focus();
        editor.dispatchEvent(new Event('input'));
      });
    });

    // Save document
    document.querySelector('[p-trigger="click:save-doc"]').addEventListener('click', async () => {
      const title = titleInput.value.trim() || 'Untitled';
      const id = docIdInput.value;
      const resp = await fetch('/api/documents', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ title, content: editor.value, id: id || undefined })
      });
      const doc = await resp.json();
      docIdInput.value = doc.id;
      titleInput.value = doc.title;
      refreshDocList();
    });

    // New document
    document.querySelector('[p-trigger="click:new-doc"]')?.addEventListener('click', () => {
      editor.value = '';
      titleInput.value = '';
      docIdInput.value = '';
      preview.innerHTML = '';
    });

    // Delete document
    document.querySelector('[p-trigger="click:delete-doc"]')?.addEventListener('click', async () => {
      const id = docIdInput.value;
      if (!id) return;
      if (!confirm('Delete this document?')) return;
      await fetch('/api/documents/' + id, { method: 'DELETE' });
      editor.value = '';
      titleInput.value = '';
      docIdInput.value = '';
      preview.innerHTML = '';
      refreshDocList();
      location.reload();
    });

    // Toggle sidebar
    document.querySelectorAll('[p-trigger="click:toggle-sidebar"]').forEach(btn => {
      btn.addEventListener('click', () => location.href = '/?sidebar=' + (${sidebarOpen} ? '0' : '1'));
    });

    // Load document from list
    const refreshDocList = async () => {
      const listEl = document.querySelector('[p-target="doc-list"]');
      if (!listEl) return;
      const resp = await fetch('/api/documents');
      const docs = await resp.json();
      listEl.innerHTML = docs.length === 0
        ? '<div style="padding: 16px; color: #666; text-align: center; font-size: 13px;">No saved documents</div>'
        : docs.map(d =>
          '<div class="doc-item" style="padding: 10px 12px; border-radius: 6px; cursor: pointer; margin-bottom: 4px; background-color: #1a1a3e; border: 1px solid transparent;" data-id="' + d.id + '">' +
          '<div style="font-size: 14px; font-weight: 500; color: #e0e0e0; margin-bottom: 2px;">' + d.title + '</div>' +
          '<div style="font-size: 11px; color: #666;">' + new Date(d.updatedAt).toLocaleDateString() + '</div></div>'
        ).join('');
      attachDocListeners();
    };

    const attachDocListeners = () => {
      document.querySelectorAll('[data-id]').forEach(el => {
        el.addEventListener('click', async () => {
          const id = el.dataset.id;
          const resp = await fetch('/api/documents/' + id);
          const doc = await resp.json();
          editor.value = doc.content;
          titleInput.value = doc.title;
          docIdInput.value = doc.id;
          editor.dispatchEvent(new Event('input'));
        });
      });
    };
    attachDocListeners();
  </script>
</body>
</html>`
}

