const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url)
    const path = url.pathname

    // API: Render markdown
    if (path === '/api/render' && req.method === 'POST') {
      const body = (await req.json()) as { markdown: string }
      const html = renderMarkdown(body.markdown)
      return Response.json({ html })
    }

    // API: Toolbar action
    if (path === '/api/toolbar' && req.method === 'POST') {
      const body = (await req.json()) as {
        action: ToolbarAction
        selectionStart: number
        selectionEnd: number
        text: string
      }
      const insert = getInsertText(body.action)
      const selected = body.text.slice(body.selectionStart, body.selectionEnd)
      const content = selected || insert.placeholder

      let newText: string
      let cursorStart: number
      let cursorEnd: number

      if (insert.blockLevel && body.selectionStart > 0 && body.text[body.selectionStart - 1] !== '\n') {
        const prefix = '\n' + insert.before
        newText =
          body.text.slice(0, body.selectionStart) +
          prefix +
          content +
          insert.after +
          body.text.slice(body.selectionEnd)
        cursorStart = body.selectionStart + prefix.length
        cursorEnd = cursorStart + content.length
      } else {
        newText =
          body.text.slice(0, body.selectionStart) +
          insert.before +
          content +
          insert.after +
          body.text.slice(body.selectionEnd)
        cursorStart = body.selectionStart + insert.before.length
        cursorEnd = cursorStart + content.length
      }

      return Response.json({ text: newText, cursorStart, cursorEnd })
    }

    // API: List documents
    if (path === '/api/documents' && req.method === 'GET') {
      const docs = await listDocuments()
      return Response.json(docs)
    }

    // API: Save document
    if (path === '/api/documents' && req.method === 'POST') {
      const body = (await req.json()) as { title: string; content: string; id?: string }
      const doc = await saveDocument(body.title, body.content, body.id)
      return Response.json(doc)
    }

    // API: Get single document
    if (path.startsWith('/api/documents/') && req.method === 'GET') {
      const id = path.split('/').pop()!
      const doc = await getDocument(id)
      if (!doc) return Response.json({ error: 'Not found' }, { status: 404 })
      return Response.json(doc)
    }

    // API: Delete document
    if (path.startsWith('/api/documents/') && req.method === 'DELETE') {
      const id = path.split('/').pop()!
      const deleted = await deleteDocument(id)
      if (!deleted) return Response.json({ error: 'Not found' }, { status: 404 })
      return Response.json({ ok: true })
    }

    // Main page
    if (path === '/' || path === '/index.html') {
      const sidebarOpen = url.searchParams.get('sidebar') !== '0'
      const docs = await listDocuments()
      const previewHtml = renderMarkdown(DEFAULT_MARKDOWN)
      const html = renderPage(previewHtml, docs, '', '', sidebarOpen, DEFAULT_MARKDOWN)
      return new Response(html, {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      })
    }

    return new Response('Not found', { status: 404 })
  },
})

