import type { Document, DocumentStore } from './types'

const DATA_PATH = new URL('./data/documents.json', import.meta.url).pathname

const readStore = async (): Promise<DocumentStore> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return []
  const text = await file.text()
  return JSON.parse(text) as DocumentStore
}

const writeStore = async (store: DocumentStore): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(store, null, 2))
}

const generateId = (): string => {
  return `doc_${Date.now()}_${Math.random().toString(36).slice(2, 9)}`
}

export const saveDocument = async (title: string, content: string, id?: string): Promise<Document> => {
  const store = await readStore()
  const now = new Date().toISOString()

  if (id) {
    const index = store.findIndex((doc) => doc.id === id)
    if (index !== -1) {
      store[index] = {
        ...store[index],
        title,
        content,
        updatedAt: now,
      }
      await writeStore(store)
      return store[index]
    }
  }

  const doc: Document = {
    id: generateId(),
    title,
    content,
    createdAt: now,
    updatedAt: now,
  }
  store.push(doc)
  await writeStore(store)
  return doc
}

export const loadDocument = async (id: string): Promise<Document | null> => {
  const store = await readStore()
  return store.find((doc) => doc.id === id) ?? null
}

export const listDocuments = async (): Promise<Document[]> => {
  const store = await readStore()
  return store.sort((a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime())
}

export const deleteDocument = async (id: string): Promise<boolean> => {
  const store = await readStore()
  const index = store.findIndex((doc) => doc.id === id)
  if (index === -1) return false
  store.splice(index, 1)
  await writeStore(store)
  return true
}

const escapeHtml = (text: string): string =>
  text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')

const parseInline = (text: string): string => {
  let result = text

  // Images (before links so ![...](...) isn't matched as link)
  result = result.replace(/!\[([^\]]*)\]\(([^)]+)\)/g, '<img src="$2" alt="$1" style="max-width:100%;" />')

  // Links
  result = result.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2">$1</a>')

  // Bold + italic
  result = result.replace(/\*\*\*(.+?)\*\*\*/g, '<strong><em>$1</em></strong>')

  // Bold
  result = result.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')

  // Italic
  result = result.replace(/\*(.+?)\*/g, '<em>$1</em>')

  // Inline code
  result = result.replace(/`([^`]+)`/g, '<code style="background:#f0f0f0;padding:2px 6px;border-radius:3px;font-size:0.9em;">$1</code>')

  return result
}

const parseTable = (lines: string[]): string => {
  if (lines.length < 2) return ''

  const parseRow = (line: string): string[] =>
    line
      .split('|')
      .map((cell) => cell.trim())
      .filter((cell) => cell.length > 0)

  const headerCells = parseRow(lines[0])
  const alignmentRow = parseRow(lines[1])

  const alignments = alignmentRow.map((cell) => {
    const left = cell.startsWith(':')
    const right = cell.endsWith(':')
    if (left && right) return 'center'
    if (right) return 'right'
    return 'left'
  })

  let html = '<table style="border-collapse:collapse;width:100%;margin:12px 0;">'
  html += '<thead><tr>'
  headerCells.forEach((cell, i) => {
    const align = alignments[i] ?? 'left'
    html += `<th style="border:1px solid #ddd;padding:8px 12px;text-align:${align};background:#f6f6f6;">${parseInline(cell)}</th>`
  })
  html += '</tr></thead><tbody>'

  for (let i = 2; i < lines.length; i++) {
    const cells = parseRow(lines[i])
    html += '<tr>'
    cells.forEach((cell, j) => {
      const align = alignments[j] ?? 'left'
      html += `<td style="border:1px solid #ddd;padding:8px 12px;text-align:${align};">${parseInline(cell)}</td>`
    })
    html += '</tr>'
  }

  html += '</tbody></table>'
  return html
}

export const renderMarkdown = (source: string): string => {
  const lines = source.split('\n')
  const htmlParts: string[] = []
  let i = 0

  while (i < lines.length) {
    const line = lines[i]

    // Fenced code blocks
    if (line.startsWith('```')) {
      const lang = line.slice(3).trim()
      const codeLines: string[] = []
      i++
      while (i < lines.length && !lines[i].startsWith('```')) {
        codeLines.push(lines[i])
        i++
      }
      i++ // skip closing ```
      const code = escapeHtml(codeLines.join('\n'))
      htmlParts.push(
        `<pre style="background:#1e1e1e;color:#d4d4d4;padding:16px;border-radius:6px;overflow-x:auto;font-size:0.9em;">${lang ? `<code data-lang="${escapeHtml(lang)}">` : '<code>'}${code}</code></pre>`
      )
      continue
    }

    // Table detection
    if (line.includes('|') && i + 1 < lines.length && /^\s*\|?[\s:-]+\|[\s:-]+\|?\s*$/.test(lines[i + 1])) {
      const tableLines: string[] = [line]
      i++
      while (i < lines.length && lines[i].includes('|')) {
        tableLines.push(lines[i])
        i++
      }
      htmlParts.push(parseTable(tableLines))
      continue
    }

    // Horizontal rule
    if (/^(\*{3,}|-{3,}|_{3,})\s*$/.test(line)) {
      htmlParts.push('<hr style="border:none;border-top:2px solid #ddd;margin:24px 0;" />')
      i++
      continue
    }

    // Headings
    const headingMatch = line.match(/^(#{1,6})\s+(.+)$/)
    if (headingMatch) {
      const level = headingMatch[1].length
      const text = parseInline(headingMatch[2])
      const sizes: Record<number, string> = { 1: '2em', 2: '1.5em', 3: '1.25em', 4: '1.1em', 5: '1em', 6: '0.9em' }
      htmlParts.push(
        `<h${level} style="font-size:${sizes[level]};margin:16px 0 8px;line-height:1.3;">${text}</h${level}>`
      )
      i++
      continue
    }

    // Blockquote
    if (line.startsWith('>')) {
      const quoteLines: string[] = []
      while (i < lines.length && lines[i].startsWith('>')) {
        quoteLines.push(lines[i].replace(/^>\s?/, ''))
        i++
      }
      const content = quoteLines.map((l) => parseInline(l)).join('<br />')
      htmlParts.push(
        `<blockquote style="border-left:4px solid #0969da;margin:12px 0;padding:8px 16px;color:#555;background:#f8f9fa;">${content}</blockquote>`
      )
      continue
    }

    // Unordered list
    if (/^[\s]*[-*+]\s/.test(line)) {
      const listItems: string[] = []
      while (i < lines.length && /^[\s]*[-*+]\s/.test(lines[i])) {
        listItems.push(parseInline(lines[i].replace(/^[\s]*[-*+]\s/, '')))
        i++
      }
      const items = listItems.map((item) => `<li style="margin:4px 0;">${item}</li>`).join('')
      htmlParts.push(`<ul style="margin:12px 0;padding-left:24px;">${items}</ul>`)
      continue
    }

    // Ordered list
    if (/^\d+\.\s/.test(line)) {
      const listItems: string[] = []
      while (i < lines.length && /^\d+\.\s/.test(lines[i])) {
        listItems.push(parseInline(lines[i].replace(/^\d+\.\s/, '')))
        i++
      }
      const items = listItems.map((item) => `<li style="margin:4px 0;">${item}</li>`).join('')
      htmlParts.push(`<ol style="margin:12px 0;padding-left:24px;">${items}</ol>`)
      continue
    }

    // Empty line
    if (line.trim() === '') {
      i++
      continue
    }

    // Paragraph
    const paraLines: string[] = []
    while (i < lines.length && lines[i].trim() !== '' && !/^(#{1,6}\s|```|>|[-*+]\s|\d+\.\s|(\*{3,}|-{3,}|_{3,})\s*$)/.test(lines[i]) && !lines[i].includes('|')) {
      paraLines.push(lines[i])
      i++
    }
    if (paraLines.length > 0) {
      htmlParts.push(`<p style="margin:12px 0;line-height:1.6;">${parseInline(paraLines.join(' '))}</p>`)
    }
  }

  return htmlParts.join('\n')
}

