    body { overflow: hidden; }
    textarea:focus { outline: none; }
    button:hover { opacity: 0.85; }
    .doc-item:hover { background: #f6f8fa; }
  </style>
</head>
<body>
  ${editorHtml}
  <script>
    const editor = document.querySelector('[p-target="editor"]');
    const preview = document.querySelector('[p-target="preview"]');
    const titleInput = document.querySelector('[p-target="title-input"]');
    let currentDocId = document.querySelector('[p-target="doc-id"]')?.value || null;

    // Live preview update
    editor.addEventListener('input', () => {
      fetch('/api/render', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ content: editor.value }),
      })
        .then(r => r.json())
        .then(data => { preview.innerHTML = data.html; });
    });

    // Toolbar formatting
    document.querySelectorAll('[p-trigger="format:click"]').forEach(btn => {
      btn.addEventListener('click', () => {
        const action = btn.dataset.action;
        fetch('/api/format', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            content: editor.value,
            selectionStart: editor.selectionStart,
            selectionEnd: editor.selectionEnd,
            action,
          }),
        })
          .then(r => r.json())
          .then(data => {
            editor.value = data.newContent;
            editor.setSelectionRange(data.cursorStart, data.cursorEnd);
            editor.focus();
            editor.dispatchEvent(new Event('input'));
          });
      });
    });

    // Save
    document.querySelector('[p-trigger="save-doc:click"]').addEventListener('click', () => {
      fetch('/api/save', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          title: titleInput.value || 'Untitled',
          content: editor.value,
          id: currentDocId,
        }),
      })
        .then(r => r.json())
        .then(data => {
          currentDocId = data.id;
          if (!document.querySelector('[p-target="doc-id"]')) {
            const hidden = document.createElement('input');
            hidden.type = 'hidden';
            hidden.setAttribute('p-target', 'doc-id');
            titleInput.parentNode.insertBefore(hidden, titleInput.nextSibling);
          }
          document.querySelector('[p-target="doc-id"]').value = data.id;
          alert('Document saved!');
        });
    });

    // New document
    document.querySelector('[p-trigger="new-doc:click"]').addEventListener('click', () => {
      editor.value = '';
      titleInput.value = '';
      currentDocId = null;
      const hidden = document.querySelector('[p-target="doc-id"]');
      if (hidden) hidden.remove();
      editor.dispatchEvent(new Event('input'));
    });

    // Load modal
    document.querySelector('[p-trigger="open-load:click"]').addEventListener('click', () => {
      fetch('/api/documents')
        .then(r => r.json())
        .then(docs => {
          const modal = document.createElement('div');
          modal.id = 'load-modal';
          modal.style.cssText = 'position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,0.5);display:flex;align-items:center;justify-content:center;z-index:1000;';

          let itemsHtml = '';
          if (docs.length === 0) {
            itemsHtml = '<p style="color:#656d76;font-size:14px;">No saved documents yet.</p>';
          } else {
            docs.forEach(doc => {
              const date = new Date(doc.updatedAt);
              itemsHtml += '<div style="display:flex;justify-content:space-between;align-items:center;padding:10px 12px;border-radius:6px;cursor:pointer;border:1px solid #d0d7de;margin-bottom:8px;" data-doc-id="' + doc.id + '">' +
                '<div>' +
                  '<div style="font-weight:600;font-size:14px;">' + (doc.title || 'Untitled') + '</div>' +
                  '<div style="font-size:12px;color:#656d76;">Updated: ' + date.toLocaleDateString() + ' ' + date.toLocaleTimeString() + '</div>' +
                '</div>' +
                '<button onclick="event.stopPropagation();deleteDoc(\\'' + doc.id + '\\')" style="padding:4px 8px;font-size:12px;border:1px solid #cf222e;border-radius:4px;background:#fff;color:#cf222e;cursor:pointer;">Delete</button>' +
              '</div>';
            });
          }

          modal.innerHTML = '<div style="background:#fff;border-radius:12px;padding:24px;width:480px;max-height:60vh;overflow:auto;box-shadow:0 8px 32px rgba(0,0,0,0.2);">' +
            '<div style="font-size:18px;font-weight:600;margin-bottom:16px;">Saved Documents</div>' +
            itemsHtml +
            '<button id="close-modal-btn" style="padding:6px 14px;font-size:13px;border:1px solid #d0d7de;border-radius:6px;background:#fff;cursor:pointer;margin-top:12px;">Close</button>' +
          '</div>';

          document.body.appendChild(modal);

          modal.querySelector('#close-modal-btn').addEventListener('click', () => modal.remove());
          modal.addEventListener('click', (e) => { if (e.target === modal) modal.remove(); });

          modal.querySelectorAll('[data-doc-id]').forEach(item => {
            item.addEventListener('click', () => {
              const id = item.dataset.docId;
              fetch('/api/documents/' + id)
                .then(r => r.json())
                .then(doc => {
                  editor.value = doc.content;
                  titleInput.value = doc.title;
                  currentDocId = doc.id;
                  if (!document.querySelector('[p-target="doc-id"]')) {
                    const hidden = document.createElement('input');
                    hidden.type = 'hidden';
                    hidden.setAttribute('p-target', 'doc-id');
                    titleInput.parentNode.insertBefore(hidden, titleInput.nextSibling);
                  }
                  document.querySelector('[p-target="doc-id"]').value = doc.id;
                  editor.dispatchEvent(new Event('input'));
                  modal.remove();
                });
            });
          });
        });
    });

    // Global delete function
    window.deleteDoc = (id) => {
      if (!confirm('Delete this document?')) return;
      fetch('/api/documents/' + id, { method: 'DELETE' })
        .then(() => {
          const modal = document.getElementById('load-modal');
          if (modal) modal.remove();
          document.querySelector('[p-trigger="open-load:click"]').click();
          if (currentDocId === id) {
            editor.value = '';
            titleInput.value = '';
            currentDocId = null;
            const hidden = document.querySelector('[p-target="doc-id"]');
            if (hidden) hidden.remove();
            editor.dispatchEvent(new Event('input'));
          }
        });
    };
  </script>
</body>
</html>`
}

const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url)

    // API: render markdown
    if (url.pathname === '/api/render' && req.method === 'POST') {
      const { content } = (await req.json()) as { content: string }
      const html = renderMarkdown(content)
      return Response.json({ html })
    }

    // API: apply format
    if (url.pathname === '/api/format' && req.method === 'POST') {
      const body = (await req.json()) as {
        content: string
        selectionStart: number
        selectionEnd: number
        action: ToolbarAction
      }
      const result = applyFormat(body.content, body.selectionStart, body.selectionEnd, body.action)
      return Response.json(result)
    }

    // API: save document
    if (url.pathname === '/api/save' && req.method === 'POST') {
      const { title, content, id } = (await req.json()) as {
        title: string
        content: string
        id?: string
      }
      const doc = await saveDocument(title, content, id)
      return Response.json(doc)
    }

    // API: list documents
    if (url.pathname === '/api/documents' && req.method === 'GET') {
      const docs = await listDocuments()
      return Response.json(docs)
    }

    // API: get/delete document
    const docMatch = url.pathname.match(/^\/api\/documents\/(.+)$/)
    if (docMatch) {
      const id = docMatch[1]
      if (req.method === 'GET') {
        const doc = await loadDocument(id)
        if (!doc) return Response.json({ error: 'Not found' }, { status: 404 })
        return Response.json(doc)
      }
      if (req.method === 'DELETE') {
        const deleted = await deleteDocument(id)
        return Response.json({ deleted })
      }
    }

    // Main page
    if (url.pathname === '/') {
      const html = renderPage(DEFAULT_CONTENT, '')
      return new Response(html, {
        headers: { 'Content-Type': 'text/html' },
      })
    }

    return new Response('Not Found', { status: 404 })
  },
})

