const escapeHtml = (text: string): string =>
  text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')

const parseInline = (text: string): string => {
  let result = text
  // Images (must come before links)
  result = result.replace(/!\[([^\]]*)\]\(([^)]+)\)/g, '<img src="$2" alt="$1" style="max-width:100%">')
  // Links
  result = result.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2">$1</a>')
  // Bold + italic
  result = result.replace(/\*\*\*(.+?)\*\*\*/g, '<strong><em>$1</em></strong>')
  // Bold
  result = result.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
  // Italic
  result = result.replace(/\*(.+?)\*/g, '<em>$1</em>')
  // Inline code
  result = result.replace(/`([^`]+)`/g, '<code>$1</code>')
  return result
}

const parseTable = (lines: string[]): { html: string; consumed: number } => {
  if (lines.length < 2) return { html: '', consumed: 0 }

  const parseRow = (line: string): string[] =>
    line.replace(/^\|/, '').replace(/\|$/, '').split('|').map(c => c.trim())

  const headerCells = parseRow(lines[0])
  const separatorLine = lines[1]

  if (!/^\|?[\s-:|]+\|?$/.test(separatorLine)) return { html: '', consumed: 0 }

  const alignments = parseRow(separatorLine).map(cell => {
    const left = cell.startsWith(':')
    const right = cell.endsWith(':')
    if (left && right) return 'center'
    if (right) return 'right'
    if (left) return 'left'
    return ''
  })

  const styleFor = (i: number): string => {
    const a = alignments[i]
    return a ? ` style="text-align:${a}"` : ''
  }

  let html = '<table><thead><tr>'
  headerCells.forEach((cell, i) => {
    html += `<th${styleFor(i)}>${parseInline(cell)}</th>`
  })
  html += '</tr></thead><tbody>'

  let consumed = 2
  for (let i = 2; i < lines.length; i++) {
    const line = lines[i]
    if (!line.includes('|')) break
    const cells = parseRow(line)
    html += '<tr>'
    cells.forEach((cell, j) => {
      html += `<td${styleFor(j)}>${parseInline(cell)}</td>`
    })
    html += '</tr>'
    consumed++
  }
  html += '</tbody></table>'
  return { html, consumed }
}

export const renderMarkdown = (source: string): string => {
  const lines = source.split('\n')
  const output: string[] = []
  let i = 0
  let inCodeBlock = false
  let codeBlockContent: string[] = []
  let codeBlockLang = ''

  const flushCodeBlock = () => {
    const escaped = escapeHtml(codeBlockContent.join('\n'))
    const langAttr = codeBlockLang ? ` class="language-${codeBlockLang}"` : ''
    output.push(`<pre><code${langAttr}>${escaped}</code></pre>`)
    codeBlockContent = []
    codeBlockLang = ''
    inCodeBlock = false
  }

  while (i < lines.length) {
    const line = lines[i]

    // Fenced code blocks
    if (/^```/.test(line)) {
      if (inCodeBlock) {
        flushCodeBlock()
        i++
        continue
      }
      inCodeBlock = true
      codeBlockLang = line.slice(3).trim()
      i++
      continue
    }
    if (inCodeBlock) {
      codeBlockContent.push(line)
      i++
      continue
    }

    // Blank line
    if (line.trim() === '') {
      i++
      continue
    }

    // Horizontal rule
    if (/^(\*{3,}|-{3,}|_{3,})\s*$/.test(line.trim())) {
      output.push('<hr>')
      i++
      continue
    }

    // Headings
    const headingMatch = line.match(/^(#{1,6})\s+(.+)$/)
    if (headingMatch) {
      const level = headingMatch[1].length
      output.push(`<h${level}>${parseInline(headingMatch[2])}</h${level}>`)
      i++
      continue
    }

    // Table
    if (line.includes('|') && i + 1 < lines.length && /^\|?[\s-:|]+\|?$/.test(lines[i + 1])) {
      const tableLines = lines.slice(i)
      const { html, consumed } = parseTable(tableLines)
      if (consumed > 0) {
        output.push(html)
        i += consumed
        continue
      }
    }

    // Blockquote
    if (line.startsWith('>')) {
      const quoteLines: string[] = []
      while (i < lines.length && (lines[i].startsWith('>') || (lines[i].trim() !== '' && quoteLines.length > 0 && !lines[i].startsWith('#')))) {
        if (!lines[i].startsWith('>')) break
        quoteLines.push(lines[i].replace(/^>\s?/, ''))
        i++
      }
      output.push(`<blockquote>${renderMarkdown(quoteLines.join('\n'))}</blockquote>`)
      continue
    }

    // Unordered list
    if (/^[\s]*[-*+]\s/.test(line)) {
      const listItems: string[] = []
      while (i < lines.length && /^[\s]*[-*+]\s/.test(lines[i])) {
        listItems.push(lines[i].replace(/^[\s]*[-*+]\s/, ''))
        i++
      }
      output.push('<ul>' + listItems.map(item => `<li>${parseInline(item)}</li>`).join('') + '</ul>')
      continue
    }

    // Ordered list
    if (/^\s*\d+\.\s/.test(line)) {
      const listItems: string[] = []
      while (i < lines.length && /^\s*\d+\.\s/.test(lines[i])) {
        listItems.push(lines[i].replace(/^\s*\d+\.\s/, ''))
        i++
      }
      output.push('<ol>' + listItems.map(item => `<li>${parseInline(item)}</li>`).join('') + '</ol>')
      continue
    }

    // Paragraph
    const paraLines: string[] = []
    while (i < lines.length && lines[i].trim() !== '' && !/^#{1,6}\s/.test(lines[i]) && !/^```/.test(lines[i]) && !/^>/.test(lines[i]) && !/^[-*+]\s/.test(lines[i]) && !/^\d+\.\s/.test(lines[i]) && !/^(\*{3,}|-{3,}|_{3,})\s*$/.test(lines[i].trim())) {
      paraLines.push(lines[i])
      i++
    }
    if (paraLines.length > 0) {
      output.push(`<p>${parseInline(paraLines.join('\n'))}</p>`)
    }
  }

  // Close unclosed code block
  if (inCodeBlock) {
    flushCodeBlock()
  }

  return output.join('\n')
}

import type { Document } from './types'

const DATA_PATH = new URL('./data/documents.json', import.meta.url).pathname

const readDocuments = async (): Promise<Document[]> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return []
  const text = await file.text()
  return JSON.parse(text) as Document[]
}

const writeDocuments = async (docs: Document[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(docs, null, 2))
}

export const getAllDocuments = async (): Promise<Document[]> => {
  const docs = await readDocuments()
  return docs.sort((a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime())
}

export const getDocument = async (id: string): Promise<Document | undefined> => {
  const docs = await readDocuments()
  return docs.find(d => d.id === id)
}

export const saveDocument = async (
  title: string,
  content: string,
  id?: string
): Promise<Document> => {
  const docs = await readDocuments()
  const now = new Date().toISOString()

  if (id) {
    const idx = docs.findIndex(d => d.id === id)
    if (idx !== -1) {
      docs[idx] = { ...docs[idx], title, content, updatedAt: now }
      await writeDocuments(docs)
      return docs[idx]
    }
  }

  const doc: Document = {
    id: crypto.randomUUID(),
    title,
    content,
    createdAt: now,
    updatedAt: now,
  }
  docs.push(doc)
  await writeDocuments(docs)
  return doc
}

export const deleteDocument = async (id: string): Promise<boolean> => {
  const docs = await readDocuments()
  const filtered = docs.filter(d => d.id !== id)
  if (filtered.length === docs.length) return false
  await writeDocuments(filtered)
  return true
}

export const filterDocuments = async (query: string): Promise<Document[]> => {
  const docs = await getAllDocuments()
  const q = query.toLowerCase()
  return docs.filter(d =>
    d.title.toLowerCase().includes(q) || d.content.toLowerCase().includes(q)
  )
}

