const styleToStr = (obj: Record<string, string | number>): string =>
  Object.entries(obj)
    .map(([k, v]) => {
      const prop = k.replace(/[A-Z]/g, m => `-${m.toLowerCase()}`)
      return `${prop}:${v}`
    })
    .join(';')

const renderToolbar = () =>
  h('div', { style: styleToStr(styles.toolbar as Record<string, string>), 'p-target': 'toolbar' },
    ...toolbarButtons.map((btn, i) => {
      const group = i === 3 || i === 5 || i === 7 || i === 9 || i === 11 || i === 13
      const items = []
      if (group) items.push(h('div', { style: styleToStr(styles.toolbarDivider as Record<string, string>) }))
      items.push(
        h('button', {
          style: styleToStr(styles.toolbarButton as Record<string, string>),
          title: btn.label,
          'p-trigger': `click:toolbar-${btn.action}`,
        }, btn.icon)
      )
      return h(Fragment, {}, ...items)
    })
  )

const renderHeader = (title: string, hasDocId: boolean) =>
  h('div', { style: styleToStr(styles.header as Record<string, string>) },
    h('input', {
      type: 'text',
      placeholder: 'Document title...',
      value: title,
      style: styleToStr(styles.titleInput as Record<string, string>),
      'p-target': 'title-input',
      'p-trigger': 'input:title-change',
    }),
    h('button', {
      style: styleToStr(styles.headerButton as Record<string, string>),
      'p-trigger': 'click:new-doc',
    }, 'New'),
    h('button', {
      style: styleToStr(styles.headerButton as Record<string, string>),
      'p-trigger': 'click:show-docs',
    }, 'Documents'),
    h('button', {
      style: styleToStr(styles.saveButton as Record<string, string>),
      'p-trigger': 'click:save-doc',
    }, hasDocId ? 'Update' : 'Save'),
  )

const renderEditor = (content: string) =>
  h('div', { style: styleToStr(styles.splitPane as Record<string, string>) },
    h('div', { style: styleToStr(styles.editorPane as Record<string, string>) },
      h('textarea', {
        style: styleToStr(styles.textarea as Record<string, string>),
        placeholder: 'Write your markdown here...',
        'p-target': 'editor',
        'p-trigger': 'input:editor-input',
      }, content),
    ),
    h('div', { style: styleToStr(styles.previewPane as Record<string, string>), 'p-target': 'preview-pane' },
