import { renderEditorView, renderDocumentList, renderPreviewHtml } from './view'
import { getAllDocuments, getDocument, saveDocument, deleteDocument, filterDocuments } from './storage'
import { getInsertionText } from './toolbar'
import type { EditorState, ToolbarAction } from './types'

const state: EditorState = {
  currentDocId: null,
  title: '',
  content: '',
}

const handleEditorView = (): Response => {
  const html = renderEditorView(state.title, state.content, state.currentDocId)
  return new Response(html, { headers: { 'Content-Type': 'text/html' } })
}

const handleDocumentList = async (): Promise<Response> => {
  const docs = await getAllDocuments()
  const html = renderDocumentList(docs)
  return new Response(html, { headers: { 'Content-Type': 'text/html' } })
}

const handleSave = async (req: Request): Promise<Response> => {
  const body = await req.json() as { title: string; content: string; id?: string }
  const doc = await saveDocument(body.title, body.content, body.id)
  state.currentDocId = doc.id
  state.title = doc.title
  state.content = doc.content
  return Response.json(doc)
}

const handleLoad = async (id: string): Promise<Response> => {
  const doc = await getDocument(id)
  if (!doc) return new Response('Not found', { status: 404 })
  state.currentDocId = doc.id
  state.title = doc.title
  state.content = doc.content
  return Response.json(doc)
}

const handleDelete = async (id: string): Promise<Response> => {
  const success = await deleteDocument(id)
  if (!success) return new Response('Not found', { status: 404 })
  if (state.currentDocId === id) {
    state.currentDocId = null
    state.title = ''
    state.content = ''
  }
  return Response.json({ success: true })
}

const handlePreview = async (req: Request): Promise<Response> => {
  const body = await req.json() as { content: string }
  const html = renderPreviewHtml(body.content)
  return new Response(html, { headers: { 'Content-Type': 'text/html' } })
}

const handleSearch = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const query = url.searchParams.get('q') ?? ''
  const docs = await filterDocuments(query)
  return Response.json(docs)
}

const handleToolbarAction = (action: ToolbarAction): Response => {
  const insertion = getInsertionText(action)
  return Response.json(insertion)
}

const handleNewDoc = (): Response => {
  state.currentDocId = null
  state.title = ''
  state.content = ''
  return Response.json({ success: true })
}

export default {
  fetch: async (req: Request): Promise<Response> => {
    const url = new URL(req.url)
    const path = url.pathname

    // GET routes
    if (req.method === 'GET') {
      if (path === '/' || path === '/editor') return handleEditorView()
      if (path === '/documents') return handleDocumentList()
      if (path === '/search') return handleSearch(req)
      if (path === '/new') return handleNewDoc()

      const loadMatch = path.match(/^\/documents\/([^/]+)$/)
      if (loadMatch) return handleLoad(loadMatch[1])

      const toolbarMatch = path.match(/^\/toolbar\/(.+)$/)
      if (toolbarMatch) return handleToolbarAction(toolbarMatch[1] as ToolbarAction)
    }

    // POST routes
    if (req.method === 'POST') {
      if (path === '/save') return handleSave(req)
      if (path === '/preview') return handlePreview(req)
    }

    // DELETE routes
    if (req.method === 'DELETE') {
      const deleteMatch = path.match(/^\/documents\/([^/]+)$/)
      if (deleteMatch) return handleDelete(deleteMatch[1])
    }

    return new Response('Not found', { status: 404 })
  },
}

import type { ToolbarAction } from './types'

type ClientState = {
  currentDocId: string | null
  title: string
  content: string
}

const state: ClientState = {
  currentDocId: null,
  title: '',
  content: '',
}

const getEditor = (): HTMLTextAreaElement | null =>
  document.querySelector('[p-target="editor"]')

const getPreview = (): HTMLElement | null =>
  document.querySelector('[p-target="preview"]')

const getTitleInput = (): HTMLInputElement | null =>
  document.querySelector('[p-target="title-input"]')

const updatePreview = async () => {
  const preview = getPreview()
  if (!preview) return
  const res = await fetch('/preview', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ content: state.content }),
  })
  preview.innerHTML = await res.text()
}

const insertAtCursor = (before: string, after: string, placeholder: string) => {
  const editor = getEditor()
  if (!editor) return
  const start = editor.selectionStart
  const end = editor.selectionEnd
  const selected = editor.value.substring(start, end)
  const text = selected || placeholder
  const insertion = `${before}${text}${after}`
  editor.setRangeText(insertion, start, end, 'select')
  state.content = editor.value
  editor.focus()
  if (!selected) {
    editor.selectionStart = start + before.length
    editor.selectionEnd = start + before.length + text.length
  }
  updatePreview()
}

const handleToolbarClick = async (action: ToolbarAction) => {
  const res = await fetch(`/toolbar/${action}`)
  const { before, after, placeholder } = await res.json()
  insertAtCursor(before, after, placeholder)
}

const handleSave = async () => {
  const title = state.title || 'Untitled'
  const res = await fetch('/save', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      title,
      content: state.content,
      id: state.currentDocId,
    }),
  })
  const doc = await res.json()
  state.currentDocId = doc.id
  state.title = doc.title
}

const handleNewDoc = () => {
  state.currentDocId = null
  state.title = ''
  state.content = ''
  const editor = getEditor()
  const titleInput = getTitleInput()
  const preview = getPreview()
  if (editor) editor.value = ''
  if (titleInput) titleInput.value = ''
  if (preview) preview.innerHTML = ''
}

const handleShowDocs = () => {
  window.location.href = '/documents'
}

const handleLoadDoc = async (id: string) => {
  const res = await fetch(`/documents/${id}`)
  if (!res.ok) return
  const doc = await res.json()
  state.currentDocId = doc.id
  state.title = doc.title
  state.content = doc.content
  window.location.href = '/editor'
}

const handleDeleteDoc = async (id: string) => {
  await fetch(`/documents/${id}`, { method: 'DELETE' })
  window.location.reload()
}

export const initClient = () => {
  document.addEventListener('click', (e) => {
    const target = e.target as HTMLElement
    const trigger = target.getAttribute('p-trigger')
    if (!trigger) return

    const [, action] = trigger.split(':')
    if (!action) return

    if (action.startsWith('toolbar-')) {
      handleToolbarClick(action.replace('toolbar-', '') as ToolbarAction)
    } else if (action === 'save-doc') {
      handleSave()
    } else if (action === 'new-doc') {
      handleNewDoc()
    } else if (action === 'show-docs') {
      handleShowDocs()
    } else if (action.startsWith('load-doc-')) {
      handleLoadDoc(action.replace('load-doc-', ''))
    } else if (action.startsWith('delete-doc-')) {
      e.stopPropagation()
      handleDeleteDoc(action.replace('delete-doc-', ''))
    }
  })

  document.addEventListener('input', (e) => {
    const target = e.target as HTMLElement
    const trigger = target.getAttribute('p-trigger')
    if (!trigger) return

    const [, action] = trigger.split(':')
    if (action === 'editor-input') {
      state.content = (target as HTMLTextAreaElement).value
      updatePreview()
    } else if (action === 'title-change') {
      state.title = (target as HTMLInputElement).value
    }
  })

  // Initial preview render
  const editor = getEditor()
  if (editor && editor.value) {
    state.content = editor.value
    updatePreview()
  }
}

