import type { Project, GalleryFilters } from './types'

const DATA_PATH = './data/projects.json'

export const loadProjects = async (): Promise<Project[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  return file.json()
}

export const saveProjects = async (projects: Project[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(projects, null, 2))
}

export const getProject = async (id: string): Promise<Project | undefined> => {
  const projects = await loadProjects()
  return projects.find((p) => p.id === id)
}

export const addProject = async (project: Project): Promise<void> => {
  const projects = await loadProjects()
  projects.push(project)
  await saveProjects(projects)
}

export const removeProject = async (id: string): Promise<void> => {
  const projects = await loadProjects()
  await saveProjects(projects.filter((p) => p.id !== id))
}

export const getAllTags = async (): Promise<string[]> => {
  const projects = await loadProjects()
  const tagSet = new Set<string>()
  for (const p of projects) {
    for (const t of p.tags) tagSet.add(t)
  }
  return [...tagSet].sort()
}

export const filterAndSort = (projects: Project[], filters: GalleryFilters): Project[] => {
  let result = [...projects]

  if (filters.search) {
    const q = filters.search.toLowerCase()
    result = result.filter(
      (p) =>
        p.title.toLowerCase().includes(q) ||
        p.description.toLowerCase().includes(q)
    )
  }

  if (filters.tag) {
    result = result.filter((p) =>
      p.tags.some((t) => t.toLowerCase() === filters.tag.toLowerCase())
    )
  }

  result.sort((a, b) => {
    let cmp: number
    if (filters.sortBy === 'title') {
      cmp = a.title.localeCompare(b.title)
    } else {
      cmp = new Date(a.dateAdded).getTime() - new Date(b.dateAdded).getTime()
    }
    return filters.sortOrder === 'desc' ? -cmp : cmp
  })

  return result
}

