import { createSSR } from 'plaited'
import type { GalleryFilters, SortField, SortOrder } from './types'
import { loadProjects, getAllTags, getProject, addProject, removeProject, filterAndSort } from './data'
import { renderGallery, renderDetail, renderLightbox } from './render'

export const handleGalleryView = async (params: Partial<GalleryFilters> = {}) => {
  const filters: GalleryFilters = {
    search: params.search ?? '',
    tag: params.tag ?? '',
    sortBy: params.sortBy ?? 'dateAdded',
    sortOrder: params.sortOrder ?? 'desc',
  }

  const allProjects = await loadProjects()
  const allTags = await getAllTags()
  const filtered = filterAndSort(allProjects, filters)

  const template = renderGallery(filtered, allTags, filters, allProjects.length)
  const ssr = createSSR()
  return ssr(template)
}

export const handleDetailView = async (projectId: string, activeImage = 0) => {
  const project = await getProject(projectId)
  if (!project) return '<div>Project not found</div>'

  const template = renderDetail(project, activeImage)
  const ssr = createSSR()
  return ssr(template)
}

export const handleLightboxView = async (projectId: string, activeIndex = 0) => {
  const project = await getProject(projectId)
  if (!project) return ''

  const images = project.images.length > 0 ? project.images : [project.thumbnail]
  const template = renderLightbox(images, activeIndex)
  const ssr = createSSR()
  return ssr(template)
}

export const handleSortChange = (value: string): { sortBy: SortField; sortOrder: SortOrder } => {
  const [field, order] = value.split('-') as [SortField, SortOrder]
  return { sortBy: field, sortOrder: order }
}

