import type { Project, ProjectInput, SortOption, GalleryQuery } from './types'

const DATA_PATH = `${import.meta.dir}/data/projects.json`

const readProjects = async (): Promise<Project[]> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return []
  return file.json()
}

const writeProjects = async (projects: Project[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(projects, null, 2))
}

const generateId = (title: string): string =>
  title
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-|-$/g, '')

const sortProjects = (projects: Project[], sort: SortOption): Project[] => {
  const sorted = [...projects]
  switch (sort) {
    case 'date-desc':
      return sorted.sort((a, b) => new Date(b.dateAdded).getTime() - new Date(a.dateAdded).getTime())
    case 'date-asc':
      return sorted.sort((a, b) => new Date(a.dateAdded).getTime() - new Date(b.dateAdded).getTime())
    case 'alpha-asc':
      return sorted.sort((a, b) => a.title.localeCompare(b.title))
    case 'alpha-desc':
      return sorted.sort((a, b) => b.title.localeCompare(a.title))
    default:
      return sorted
  }
}

export const getProjects = async (query: GalleryQuery = {}): Promise<Project[]> => {
  let projects = await readProjects()

  if (query.tag) {
    const tag = query.tag.toLowerCase()
    projects = projects.filter((p) => p.tags.some((t) => t.toLowerCase() === tag))
  }

  if (query.search) {
    const term = query.search.toLowerCase()
    projects = projects.filter((p) => p.title.toLowerCase().includes(term))
  }

  const sort = query.sort ?? 'date-desc'
  return sortProjects(projects, sort)
}

export const getProject = async (id: string): Promise<Project | null> => {
  const projects = await readProjects()
  return projects.find((p) => p.id === id) ?? null
}

export const getAllTags = async (): Promise<string[]> => {
  const projects = await readProjects()
  const tagSet = new Set<string>()
  for (const p of projects) {
    for (const t of p.tags) {
      tagSet.add(t)
    }
  }
  return [...tagSet].sort()
}

export const addProject = async (input: ProjectInput): Promise<Project> => {
  const projects = await readProjects()
  const project: Project = {
    ...input,
    id: generateId(input.title),
    dateAdded: new Date().toISOString().split('T')[0],
  }
  projects.push(project)
  await writeProjects(projects)
  return project
}

export const updateProject = async (id: string, updates: Partial<ProjectInput>): Promise<Project | null> => {
  const projects = await readProjects()
  const idx = projects.findIndex((p) => p.id === id)
  if (idx === -1) return null
  projects[idx] = { ...projects[idx], ...updates }
  await writeProjects(projects)
  return projects[idx]
}

export const deleteProject = async (id: string): Promise<boolean> => {
  const projects = await readProjects()
  const idx = projects.findIndex((p) => p.id === id)
  if (idx === -1) return false
  projects.splice(idx, 1)
  await writeProjects(projects)
  return true
}

import { h, Fragment } from 'plaited'
