const styleAttr = (obj: Record<string, string | number | undefined>): string =>
  Object.entries(obj)
    .filter(([, v]) => v !== undefined)
    .map(([k, v]) => {
      const prop = k.replace(/[A-Z]/g, (m) => `-${m.toLowerCase()}`)
      return `${prop}:${typeof v === 'number' ? `${v}px` : v}`
    })
    .join(';')

const TagPill = (tag: string, activeTag: string | undefined) => {
  const isActive = activeTag?.toLowerCase() === tag.toLowerCase()
  const st = isActive ? styles.tagActive : styles.tag
  const href = isActive ? '/' : `/?tag=${encodeURIComponent(tag)}`
  return h('a', { href, style: styleAttr(st) }, tag)
}

const ProjectCard = (project: Project) =>
  h('a', { href: `/project/${project.id}`, style: styleAttr(styles.card) },
    h('img', {
      src: project.thumbnail,
      alt: project.title,
      style: styleAttr(styles.cardThumb),
      loading: 'lazy',
    }),
    h('div', { style: styleAttr(styles.cardBody) },
      h('h3', { style: styleAttr(styles.cardTitle) }, project.title),
      h('p', { style: styleAttr(styles.cardDesc) }, project.description),
      h('div', { style: styleAttr(styles.cardTags) },
        ...project.tags.map((tag) =>
          h('span', { style: styleAttr(styles.cardTag) }, tag)
        ),
      ),
      h('div', { style: styleAttr(styles.cardLinks) },
        ...(project.demoUrl
          ? [h('span', { style: styleAttr(styles.cardLink) }, 'Live Demo')]
          : []),
        ...(project.sourceUrl
          ? [h('span', { style: styleAttr(styles.cardLink) }, 'Source')]
          : []),
      ),
    ),
  )

