          document.getElementById('lightbox-img').src = images[currentIdx];
          lb.style.display = 'flex';
          updateLightboxCounter();
          document.body.style.overflow = 'hidden';
        };

        document.querySelector('.carousel-img')?.addEventListener('click', openLightbox);

        const closeLightbox = () => {
          document.getElementById('lightbox').style.display = 'none';
          document.body.style.overflow = '';
        };

        const updateLightboxCounter = () => {
          const counter = document.getElementById('lightbox-counter');
          if (counter) counter.textContent = (currentIdx + 1) + ' / ' + images.length;
        };

        const lightboxNav = (dir) => {
          currentIdx = (currentIdx + dir + images.length) % images.length;
          document.getElementById('lightbox-img').src = images[currentIdx];
          setImage(currentIdx);
          updateLightboxCounter();
        };

        document.getElementById('lightbox')?.addEventListener('click', (e) => {
          if (e.target.id === 'lightbox') closeLightbox();
        });

        document.addEventListener('keydown', (e) => {
          const lb = document.getElementById('lightbox');
          if (lb.style.display === 'flex') {
            if (e.key === 'Escape') closeLightbox();
            if (e.key === 'ArrowLeft') lightboxNav(-1);
            if (e.key === 'ArrowRight') lightboxNav(1);
          }
        });
      `),
    ),
  )
}

const formatDate = (iso: string): string => {
  const d = new Date(iso)
  return d.toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' })
}

import type { SortOption, GalleryQuery, ProjectInput } from './types'
import { getProjects, getProject, getAllTags, addProject, updateProject, deleteProject } from './data'
import { renderGallery, renderDetail } from './render'
import { createSSR } from 'plaited'

const ssr = createSSR()

const htmlResponse = (template: ReturnType<typeof renderGallery>): Response => {
  const html = ssr(template)
  return new Response(html, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })
}

const jsonResponse = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const parseQuery = (url: URL): GalleryQuery => ({
  tag: url.searchParams.get('tag') ?? undefined,
  search: url.searchParams.get('search') ?? undefined,
  sort: (url.searchParams.get('sort') as SortOption) ?? undefined,
})

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const { pathname } = url
  const method = req.method

  // Gallery page
  if (pathname === '/' && method === 'GET') {
    const query = parseQuery(url)
    const [projects, allTags] = await Promise.all([getProjects(query), getAllTags()])
    const template = renderGallery(projects, allTags, query.tag, query.search, query.sort)
    return htmlResponse(template)
  }

  // Project detail page
  const detailMatch = pathname.match(/^\/project\/([a-z0-9-]+)$/)
  if (detailMatch && method === 'GET') {
    const project = await getProject(detailMatch[1])
    if (!project) {
      return new Response('Project not found', { status: 404 })
    }
    const imageIdx = parseInt(url.searchParams.get('img') ?? '0', 10)
    const template = renderDetail(project, imageIdx)
    return htmlResponse(template)
  }

  // API: list projects
  if (pathname === '/api/projects' && method === 'GET') {
    const query = parseQuery(url)
    const projects = await getProjects(query)
    return jsonResponse(projects)
  }

  // API: create project
  if (pathname === '/api/projects' && method === 'POST') {
    const body = (await req.json()) as ProjectInput
    if (!body.title || !body.description) {
      return jsonResponse({ error: 'title and description are required' }, 400)
    }
    const project = await addProject(body)
    return jsonResponse(project, 201)
  }

  // API: update project
  const apiUpdateMatch = pathname.match(/^\/api\/projects\/([a-z0-9-]+)$/)
  if (apiUpdateMatch && method === 'PUT') {
    const body = (await req.json()) as Partial<ProjectInput>
    const project = await updateProject(apiUpdateMatch[1], body)
    if (!project) return jsonResponse({ error: 'Project not found' }, 404)
    return jsonResponse(project)
  }

  // API: delete project
  if (apiUpdateMatch && method === 'DELETE') {
    const deleted = await deleteProject(apiUpdateMatch[1])
    if (!deleted) return jsonResponse({ error: 'Project not found' }, 404)
    return jsonResponse({ ok: true })
  }

  return new Response('Not Found', { status: 404 })
}

import { handleRequest } from './routes'

const PORT = parseInt(process.env.PORT ?? '3000', 10)

const server = Bun.serve({
  port: PORT,
  fetch: handleRequest,
})

console.log(`Portfolio Gallery running at http://localhost:${server.port}`)

