import type { Project, GalleryFilters } from './types'

const DATA_PATH = `${import.meta.dir}/data/projects.json`

export const getProjects = async (): Promise<Project[]> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return []
  const text = await file.text()
  return JSON.parse(text) as Project[]
}

export const saveProjects = async (projects: Project[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(projects, null, 2))
}

export const getProjectById = async (id: string): Promise<Project | undefined> => {
  const projects = await getProjects()
  return projects.find((p) => p.id === id)
}

export const addProject = async (project: Project): Promise<void> => {
  const projects = await getProjects()
  projects.push(project)
  await saveProjects(projects)
}

export const updateProject = async (id: string, updates: Partial<Project>): Promise<Project | undefined> => {
  const projects = await getProjects()
  const index = projects.findIndex((p) => p.id === id)
  if (index === -1) return undefined
  projects[index] = { ...projects[index], ...updates }
  await saveProjects(projects)
  return projects[index]
}

export const deleteProject = async (id: string): Promise<boolean> => {
  const projects = await getProjects()
  const filtered = projects.filter((p) => p.id !== id)
  if (filtered.length === projects.length) return false
  await saveProjects(filtered)
  return true
}

export const getAllTags = async (): Promise<string[]> => {
  const projects = await getProjects()
  const tagSet = new Set<string>()
  for (const project of projects) {
    for (const tag of project.tags) {
      tagSet.add(tag)
    }
  }
  return [...tagSet].sort()
}

export const filterAndSortProjects = (projects: Project[], filters: GalleryFilters): Project[] => {
  let result = [...projects]

  if (filters.search) {
    const query = filters.search.toLowerCase()
    result = result.filter((p) => p.title.toLowerCase().includes(query))
  }

  if (filters.tag) {
    result = result.filter((p) => p.tags.includes(filters.tag))
  }

  result.sort((a, b) => {
    let cmp: number
    if (filters.sortField === 'dateAdded') {
      cmp = new Date(a.dateAdded).getTime() - new Date(b.dateAdded).getTime()
    } else {
      cmp = a.title.localeCompare(b.title)
    }
    return filters.sortOrder === 'desc' ? -cmp : cmp
  })

  return result
}

