import { h, Fragment } from 'plaited'
import type { Project, GalleryFilters } from './types'
import { styles } from './styles'

const inlineStyle = (obj: Record<string, string | number>): string =>
  Object.entries(obj)
    .map(([k, v]) => {
      const prop = k.replace(/[A-Z]/g, (m) => `-${m.toLowerCase()}`)
      return `${prop}:${typeof v === 'number' ? `${v}px` : v}`
    })
    .join(';')

const mergeStyles = (...objs: Record<string, string | number>[]): string =>
  inlineStyle(Object.assign({}, ...objs))

export const renderTagFilters = (allTags: string[], activeTag: string): string => {
  const allButton = h(
    'button',
    {
      style: inlineStyle(activeTag === '' ? styles.tagButtonActive : styles.tagButton),
      'p-trigger': 'click:filterTag',
      'data-tag': '',
    },
    'All',
  )

  const tagButtons = allTags.map((tag) =>
    h(
      'button',
      {
        style: inlineStyle(tag === activeTag ? styles.tagButtonActive : styles.tagButton),
        'p-trigger': 'click:filterTag',
        'data-tag': tag,
      },
      tag,
    ),
  )

  return h('div', { style: inlineStyle(styles.tagFilters) }, allButton, ...tagButtons)
}

