const parseFilters = (url: URL): GalleryFilters => ({
  search: url.searchParams.get('search') ?? '',
  tag: url.searchParams.get('tag') ?? '',
  sortField: (url.searchParams.get('sort') as SortField) ?? 'dateAdded',
  sortOrder: (url.searchParams.get('order') as SortOrder) ?? 'desc',
})

const htmlPage = (title: string, body: string): string => {
  const ssr = createSSR()
  return ssr(
    `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>${title}</title>
  <style>
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    body { -webkit-font-smoothing: antialiased; }
    img { max-width: 100%; }
    a { color: inherit; }
  </style>
</head>
<body>${body}</body>
</html>`,
  )
}

const jsonResponse = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

export default {
  fetch: async (req: Request): Promise<Response> => {
    const url = new URL(req.url)
    const { pathname } = url
    const method = req.method

    // API: CRUD for projects
    if (pathname === '/projects' && method === 'POST') {
      const body = (await req.json()) as Project
      await addProject(body)
      return jsonResponse(body, 201)
    }

    if (pathname.startsWith('/projects/') && method === 'PUT') {
      const id = pathname.split('/')[2]
      const body = (await req.json()) as Partial<Project>
      const updated = await updateProject(id, body)
      if (!updated) return jsonResponse({ error: 'Not found' }, 404)
      return jsonResponse(updated)
    }

    if (pathname.startsWith('/projects/') && method === 'DELETE') {
      const id = pathname.split('/')[2]
      const deleted = await deleteProject(id)
      if (!deleted) return jsonResponse({ error: 'Not found' }, 404)
      return jsonResponse({ success: true })
    }

    // API: Get all projects as JSON
    if (pathname === '/api/projects' && method === 'GET') {
      const projects = await getProjects()
      const filters = parseFilters(url)
      const filtered = filterAndSortProjects(projects, filters)
      return jsonResponse(filtered)
    }

    // API: Get single project as JSON
    if (pathname.startsWith('/api/projects/') && method === 'GET') {
      const id = pathname.split('/')[3]
      const project = await getProjectById(id)
      if (!project) return jsonResponse({ error: 'Not found' }, 404)
      return jsonResponse(project)
    }

    // Detail view
    if (pathname.startsWith('/project/') && method === 'GET') {
      const id = pathname.split('/')[2]
      const project = await getProjectById(id)
      if (!project) {
        return new Response('Project not found', { status: 404 })
      }
      const imageIndex = Number(url.searchParams.get('img') ?? '0')
      const body = renderDetail(project, imageIndex)
      const html = htmlPage(`${project.title} | Portfolio`, body)
      return new Response(html, { headers: { 'Content-Type': 'text/html' } })
    }

    // Gallery view (index)
    if (pathname === '/' && method === 'GET') {
      const projects = await getProjects()
      const allTags = await getAllTags()
      const filters = parseFilters(url)
      const filtered = filterAndSortProjects(projects, filters)
      const body = renderGallery(filtered, allTags, filters)
      const html = htmlPage('Portfolio Gallery', body)
      return new Response(html, { headers: { 'Content-Type': 'text/html' } })
    }

    return new Response('Not Found', { status: 404 })
  },
}

{
  "name": "@node/drawing-canvas",
  "version": "1.0.0",
  "description": "A freehand drawing canvas with shapes, layers, and PNG export",
  "main": "index.ts",
  "modnet": {
    "contentType": "art",
    "structure": "form",
    "mechanics": ["track"],
    "boundary": "none",
    "scale": 2
  },
  "dependencies": {
    "plaited": "latest"
  }
}

export type Tool = 'pen' | 'rectangle' | 'circle' | 'line' | 'eraser';

export type Point = {
  x: number;
  y: number;
};

export type StrokeSegment = {
  type: 'pen' | 'eraser';
  points: Point[];
  color: string;
  size: number;
};

export type ShapeAction = {
  type: 'rectangle' | 'circle' | 'line';
  start: Point;
  end: Point;
  color: string;
  size: number;
};

export type DrawAction = StrokeSegment | ShapeAction;

export type Layer = {
  id: string;
  name: string;
  visible: boolean;
  actions: DrawAction[];
};

export type CanvasState = {
  layers: Layer[];
  activeLayerId: string;
  width: number;
  height: number;
};

export type HistoryEntry = {
  layerId: string;
  action: DrawAction;
};

export type DrawingMetadata = {
  id: string;
  name: string;
  createdAt: string;
  updatedAt: string;
  width: number;
  height: number;
  layerCount: number;
};

export type ToolbarState = {
  activeTool: Tool;
  color: string;
  brushSize: number;
};

import type { CanvasState, DrawAction, HistoryEntry, Layer, Point, Tool } from './types';

const generateId = (): string => crypto.randomUUID();

const createLayer = (name: string): Layer => ({
  id: generateId(),
  name,
  visible: true,
  actions: [],
});

const createInitialState = (width = 800, height = 600): CanvasState => {
  const baseLayer = createLayer('Layer 1');
  return {
    layers: [baseLayer],
    activeLayerId: baseLayer.id,
    width,
    height,
  };
};

const getActiveLayer = (state: CanvasState): Layer | undefined =>
  state.layers.find((l) => l.id === state.activeLayerId);

const addLayer = (state: CanvasState, name?: string): CanvasState => {
  const layer = createLayer(name ?? `Layer ${state.layers.length + 1}`);
  return {
    ...state,
    layers: [...state.layers, layer],
    activeLayerId: layer.id,
  };
};

const removeLayer = (state: CanvasState, layerId: string): CanvasState => {
  if (state.layers.length <= 1) return state;
  const filtered = state.layers.filter((l) => l.id !== layerId);
  const activeLayerId =
    state.activeLayerId === layerId ? filtered[filtered.length - 1].id : state.activeLayerId;
  return { ...state, layers: filtered, activeLayerId };
};

const toggleLayerVisibility = (state: CanvasState, layerId: string): CanvasState => ({
  ...state,
  layers: state.layers.map((l) => (l.id === layerId ? { ...l, visible: !l.visible } : l)),
});

const reorderLayers = (state: CanvasState, fromIndex: number, toIndex: number): CanvasState => {
  const layers = [...state.layers];
  const [moved] = layers.splice(fromIndex, 1);
  layers.splice(toIndex, 0, moved);
  return { ...state, layers };
};

const addActionToLayer = (state: CanvasState, layerId: string, action: DrawAction): CanvasState => ({
  ...state,
  layers: state.layers.map((l) =>
    l.id === layerId ? { ...l, actions: [...l.actions, action] } : l
  ),
});

const removeLastActionFromLayer = (state: CanvasState, layerId: string): { state: CanvasState; removed: DrawAction | undefined } => {
  const layer = state.layers.find((l) => l.id === layerId);
  if (!layer || layer.actions.length === 0) return { state, removed: undefined };
  const removed = layer.actions[layer.actions.length - 1];
  return {
    state: {
      ...state,
      layers: state.layers.map((l) =>
        l.id === layerId ? { ...l, actions: l.actions.slice(0, -1) } : l
      ),
    },
    removed,
  };
};

const clearLayer = (state: CanvasState, layerId: string): CanvasState => ({
  ...state,
  layers: state.layers.map((l) => (l.id === layerId ? { ...l, actions: [] } : l)),
});

const clearAllLayers = (state: CanvasState): CanvasState => ({
  ...state,
  layers: state.layers.map((l) => ({ ...l, actions: [] })),
});

export type CanvasEngine = {
  getState: () => CanvasState;
  getActiveLayer: () => Layer | undefined;
  setActiveTool: (tool: Tool) => void;
  getActiveTool: () => Tool;
  setColor: (color: string) => void;
  getColor: () => string;
  setBrushSize: (size: number) => void;
  getBrushSize: () => number;
  addLayer: (name?: string) => void;
  removeLayer: (layerId: string) => void;
  setActiveLayer: (layerId: string) => void;
  toggleLayerVisibility: (layerId: string) => void;
  reorderLayers: (fromIndex: number, toIndex: number) => void;
  startStroke: (point: Point) => void;
  continueStroke: (point: Point) => void;
  endStroke: (point: Point) => void;
  undo: () => void;
  redo: () => void;
  canUndo: () => boolean;
  canRedo: () => boolean;
  clearActiveLayer: () => void;
  clearAll: () => void;
  toJSON: () => string;
  fromJSON: (json: string) => void;
};

const createCanvasEngine = (width = 800, height = 600): CanvasEngine => {
  let state = createInitialState(width, height);
  let activeTool: Tool = 'pen';
  let color = '#000000';
  let brushSize = 4;
  let currentStrokePoints: Point[] = [];
  let undoStack: HistoryEntry[] = [];
  let redoStack: HistoryEntry[] = [];

  const engine: CanvasEngine = {
    getState: () => state,
    getActiveLayer: () => getActiveLayer(state),

    setActiveTool: (tool) => {
      activeTool = tool;
    },
    getActiveTool: () => activeTool,

    setColor: (c) => {
      color = c;
    },
    getColor: () => color,

    setBrushSize: (size) => {
      brushSize = Math.max(1, Math.min(100, size));
    },
    getBrushSize: () => brushSize,

    addLayer: (name) => {
      state = addLayer(state, name);
    },
    removeLayer: (layerId) => {
      state = removeLayer(state, layerId);
    },
    setActiveLayer: (layerId) => {
      state = { ...state, activeLayerId: layerId };
    },
    toggleLayerVisibility: (layerId) => {
      state = toggleLayerVisibility(state, layerId);
    },
    reorderLayers: (fromIndex, toIndex) => {
      state = reorderLayers(state, fromIndex, toIndex);
    },

    startStroke: (point) => {
      currentStrokePoints = [point];
    },
    continueStroke: (point) => {
      currentStrokePoints.push(point);
    },
    endStroke: (point) => {
      const active = getActiveLayer(state);
      if (!active) return;

      let action: DrawAction;
      if (activeTool === 'pen' || activeTool === 'eraser') {
        currentStrokePoints.push(point);
        action = {
          type: activeTool,
          points: [...currentStrokePoints],
          color: activeTool === 'eraser' ? '#ffffff' : color,
          size: brushSize,
        };
      } else {
        const start = currentStrokePoints[0] ?? point;
        action = {
          type: activeTool,
          start,
          end: point,
          color,
          size: brushSize,
        };
      }

      state = addActionToLayer(state, active.id, action);
      undoStack.push({ layerId: active.id, action });
      redoStack = [];
      currentStrokePoints = [];
    },

    undo: () => {
      const entry = undoStack.pop();
      if (!entry) return;
      const result = removeLastActionFromLayer(state, entry.layerId);
      state = result.state;
      if (result.removed) {
        redoStack.push(entry);
      }
    },
    redo: () => {
      const entry = redoStack.pop();
      if (!entry) return;
      state = addActionToLayer(state, entry.layerId, entry.action);
      undoStack.push(entry);
    },
    canUndo: () => undoStack.length > 0,
    canRedo: () => redoStack.length > 0,

    clearActiveLayer: () => {
      const active = getActiveLayer(state);
      if (!active) return;
      state = clearLayer(state, active.id);
      undoStack = undoStack.filter((e) => e.layerId !== active.id);
      redoStack = redoStack.filter((e) => e.layerId !== active.id);
    },
    clearAll: () => {
      state = clearAllLayers(state);
      undoStack = [];
      redoStack = [];
    },

    toJSON: () => JSON.stringify(state, null, 2),
    fromJSON: (json) => {
      const parsed = JSON.parse(json) as CanvasState;
      state = parsed;
      undoStack = [];
      redoStack = [];
    },
  };

  return engine;
};

export { createCanvasEngine, createLayer, createInitialState };

import type { CanvasState, DrawAction, Layer, StrokeSegment, ShapeAction } from './types';

const isStroke = (action: DrawAction): action is StrokeSegment =>
  action.type === 'pen' || action.type === 'eraser';

const isShape = (action: DrawAction): action is ShapeAction =>
  action.type === 'rectangle' || action.type === 'circle' || action.type === 'line';

const renderStroke = (ctx: CanvasRenderingContext2D, stroke: StrokeSegment): void => {
  if (stroke.points.length < 2) return;

  ctx.save();
  ctx.strokeStyle = stroke.color;
  ctx.lineWidth = stroke.size;
  ctx.lineCap = 'round';
  ctx.lineJoin = 'round';

  if (stroke.type === 'eraser') {
    ctx.globalCompositeOperation = 'destination-out';
  }

  ctx.beginPath();
  ctx.moveTo(stroke.points[0].x, stroke.points[0].y);
  for (let i = 1; i < stroke.points.length; i++) {
    ctx.lineTo(stroke.points[i].x, stroke.points[i].y);
  }
  ctx.stroke();
  ctx.restore();
};

const renderShape = (ctx: CanvasRenderingContext2D, shape: ShapeAction): void => {
  ctx.save();
  ctx.strokeStyle = shape.color;
  ctx.lineWidth = shape.size;
  ctx.lineCap = 'round';

  switch (shape.type) {
    case 'rectangle': {
      const x = Math.min(shape.start.x, shape.end.x);
      const y = Math.min(shape.start.y, shape.end.y);
      const w = Math.abs(shape.end.x - shape.start.x);
      const h = Math.abs(shape.end.y - shape.start.y);
      ctx.strokeRect(x, y, w, h);
      break;
    }
    case 'circle': {
      const cx = (shape.start.x + shape.end.x) / 2;
      const cy = (shape.start.y + shape.end.y) / 2;
      const rx = Math.abs(shape.end.x - shape.start.x) / 2;
      const ry = Math.abs(shape.end.y - shape.start.y) / 2;
      ctx.beginPath();
      ctx.ellipse(cx, cy, rx, ry, 0, 0, Math.PI * 2);
      ctx.stroke();
      break;
    }
    case 'line': {
      ctx.beginPath();
      ctx.moveTo(shape.start.x, shape.start.y);
      ctx.lineTo(shape.end.x, shape.end.y);
      ctx.stroke();
      break;
    }
  }

  ctx.restore();
};

const renderAction = (ctx: CanvasRenderingContext2D, action: DrawAction): void => {
  if (isStroke(action)) {
    renderStroke(ctx, action);
  } else if (isShape(action)) {
    renderShape(ctx, action);
  }
};

const renderLayer = (ctx: CanvasRenderingContext2D, layer: Layer): void => {
  if (!layer.visible) return;
  for (const action of layer.actions) {
    renderAction(ctx, action);
  }
};

const renderCanvas = (ctx: CanvasRenderingContext2D, state: CanvasState): void => {
  ctx.clearRect(0, 0, state.width, state.height);

  // White background
  ctx.fillStyle = '#ffffff';
  ctx.fillRect(0, 0, state.width, state.height);

  for (const layer of state.layers) {
    renderLayer(ctx, layer);
  }
};

const renderLayerThumbnail = (
  ctx: CanvasRenderingContext2D,
  layer: Layer,
  thumbWidth: number,
  thumbHeight: number,
  canvasWidth: number,
  canvasHeight: number
): void => {
  ctx.clearRect(0, 0, thumbWidth, thumbHeight);

  // Checkerboard background to indicate transparency
  const checkSize = 4;
  for (let y = 0; y < thumbHeight; y += checkSize) {
    for (let x = 0; x < thumbWidth; x += checkSize) {
      const isLight = ((x / checkSize) + (y / checkSize)) % 2 === 0;
      ctx.fillStyle = isLight ? '#e0e0e0' : '#c0c0c0';
      ctx.fillRect(x, y, checkSize, checkSize);
    }
  }

  // Scale to fit
  const scaleX = thumbWidth / canvasWidth;
  const scaleY = thumbHeight / canvasHeight;
  ctx.save();
  ctx.scale(scaleX, scaleY);

  for (const action of layer.actions) {
    renderAction(ctx, action);
  }

  ctx.restore();

  // Dim if not visible
  if (!layer.visible) {
    ctx.fillStyle = 'rgba(255, 255, 255, 0.6)';
    ctx.fillRect(0, 0, thumbWidth, thumbHeight);
  }
};

export { renderCanvas, renderLayer, renderLayerThumbnail, renderAction };

import type { CanvasState, DrawingMetadata } from './types';

const DATA_DIR = './data';
const DRAWINGS_INDEX = `${DATA_DIR}/drawings.json`;

const ensureDataDir = async (): Promise<void> => {
  const dir = Bun.file(DATA_DIR);
  try {
    await Bun.write(`${DATA_DIR}/.keep`, '');
  } catch {
    // directory already exists
  }
};

const loadIndex = async (): Promise<DrawingMetadata[]> => {
  const file = Bun.file(DRAWINGS_INDEX);
  if (await file.exists()) {
    const text = await file.text();
    return JSON.parse(text) as DrawingMetadata[];
  }
  return [];
};

const saveIndex = async (entries: DrawingMetadata[]): Promise<void> => {
  await Bun.write(DRAWINGS_INDEX, JSON.stringify(entries, null, 2));
};

const saveDrawing = async (
  state: CanvasState,
  name: string,
  id?: string
): Promise<DrawingMetadata> => {
  await ensureDataDir();

  const drawingId = id ?? crypto.randomUUID();
  const now = new Date().toISOString();
  const filePath = `${DATA_DIR}/${drawingId}.json`;

  await Bun.write(filePath, JSON.stringify(state, null, 2));

  const index = await loadIndex();
  const existingIdx = index.findIndex((e) => e.id === drawingId);

  const meta: DrawingMetadata = {
    id: drawingId,
    name,
    createdAt: existingIdx >= 0 ? index[existingIdx].createdAt : now,
    updatedAt: now,
    width: state.width,
    height: state.height,
    layerCount: state.layers.length,
  };

  if (existingIdx >= 0) {
    index[existingIdx] = meta;
  } else {
    index.push(meta);
  }

  await saveIndex(index);
  return meta;
};

const loadDrawing = async (id: string): Promise<CanvasState | null> => {
  const file = Bun.file(`${DATA_DIR}/${id}.json`);
  if (await file.exists()) {
    const text = await file.text();
    return JSON.parse(text) as CanvasState;
  }
  return null;
};

const deleteDrawing = async (id: string): Promise<boolean> => {
  const index = await loadIndex();
  const filtered = index.filter((e) => e.id !== id);
  if (filtered.length === index.length) return false;

  await saveIndex(filtered);

  const file = Bun.file(`${DATA_DIR}/${id}.json`);
  if (await file.exists()) {
    await Bun.write(`${DATA_DIR}/${id}.json`, '');
  }

  return true;
};

const listDrawings = async (): Promise<DrawingMetadata[]> => {
  return loadIndex();
};

const savePNG = async (
  pngDataUrl: string,
  filename: string
): Promise<string> => {
  await ensureDataDir();
  const base64 = pngDataUrl.replace(/^data:image\/png;base64,/, '');
  const buffer = Buffer.from(base64, 'base64');
  const filePath = `${DATA_DIR}/${filename}`;
  await Bun.write(filePath, buffer);
  return filePath;
};

const loadPNG = async (filename: string): Promise<string | null> => {
  const filePath = `${DATA_DIR}/${filename}`;
  const file = Bun.file(filePath);
  if (await file.exists()) {
    const buffer = await file.arrayBuffer();
    const base64 = Buffer.from(buffer).toString('base64');
    return `data:image/png;base64,${base64}`;
  }
  return null;
};

export { saveDrawing, loadDrawing, deleteDrawing, listDrawings, savePNG, loadPNG };

