export type DrawingCanvasApp = {
  engine: CanvasEngine;
  render: () => string;
  handleToolSelect: (tool: Tool) => void;
  handleColorSelect: (color: string) => void;
  handleBrushSize: (size: number) => void;
  handlePointerDown: (point: Point) => void;
  handlePointerMove: (point: Point) => void;
  handlePointerUp: (point: Point) => void;
  handleUndo: () => void;
  handleRedo: () => void;
  handleClearLayer: () => void;
  handleClearAll: () => void;
  handleAddLayer: () => void;
  handleRemoveLayer: () => void;
  handleLayerSelect: (layerId: string) => void;
  handleToggleVisibility: (layerId: string) => void;
  handleSaveProject: (name: string) => Promise<string>;
  handleLoadProject: (id: string) => Promise<boolean>;
  handleSavePNG: (canvasDataUrl: string, filename: string) => Promise<string>;
  handleLoadPNG: (filename: string) => Promise<string | null>;
  renderToCanvas: (ctx: CanvasRenderingContext2D) => void;
  renderThumbnail: (
    ctx: CanvasRenderingContext2D,
    layerId: string,
    thumbWidth: number,
    thumbHeight: number
  ) => void;
  listSavedDrawings: () => Promise<Array<{ id: string; name: string; updatedAt: string }>>;
};

const createDrawingCanvasApp = (width = 800, height = 600): DrawingCanvasApp => {
  const engine = createCanvasEngine(width, height);
  let isDrawing = false;

  const app: DrawingCanvasApp = {
    engine,

    render: () => {
      const state = engine.getState();
      const layers = state.layers.map((l) => ({
        id: l.id,
        name: l.name,
        visible: l.visible,
      }));

      const html = renderApp(
        engine.getActiveTool(),
        engine.getColor(),
        engine.getBrushSize(),
        layers,
        state.activeLayerId,
        engine.canUndo(),
        engine.canRedo(),
        state.width,
        state.height
      );

      const ssr = createSSR();
      return ssr(html);
    },

    handleToolSelect: (tool) => {
      engine.setActiveTool(tool);
    },

    handleColorSelect: (color) => {
      engine.setColor(color);
    },

    handleBrushSize: (size) => {
      engine.setBrushSize(size);
    },

    handlePointerDown: (point) => {
      isDrawing = true;
      engine.startStroke(point);
    },

    handlePointerMove: (point) => {
      if (!isDrawing) return;
      engine.continueStroke(point);
    },

    handlePointerUp: (point) => {
      if (!isDrawing) return;
      isDrawing = false;
      engine.endStroke(point);
    },

    handleUndo: () => {
      engine.undo();
    },

    handleRedo: () => {
      engine.redo();
    },

    handleClearLayer: () => {
      engine.clearActiveLayer();
    },

    handleClearAll: () => {
      engine.clearAll();
    },

    handleAddLayer: () => {
      engine.addLayer();
    },

    handleRemoveLayer: () => {
      const active = engine.getActiveLayer();
      if (active) {
        engine.removeLayer(active.id);
      }
    },

    handleLayerSelect: (layerId) => {
      engine.setActiveLayer(layerId);
    },

    handleToggleVisibility: (layerId) => {
      engine.toggleLayerVisibility(layerId);
    },

    handleSaveProject: async (name) => {
      const state = engine.getState();
      const meta = await saveDrawing(state, name);
      return meta.id;
    },

    handleLoadProject: async (id) => {
      const state = await loadDrawing(id);
      if (!state) return false;
      engine.fromJSON(JSON.stringify(state));
      return true;
    },

    handleSavePNG: async (canvasDataUrl, filename) => {
      return savePNG(canvasDataUrl, filename);
    },

    handleLoadPNG: async (filename) => {
      return loadPNG(filename);
    },

    renderToCanvas: (ctx) => {
      renderCanvas(ctx, engine.getState());
    },

    renderThumbnail: (ctx, layerId, thumbWidth, thumbHeight) => {
      const state = engine.getState();
      const layer = state.layers.find((l) => l.id === layerId);
      if (!layer) return;
      renderLayerThumbnail(ctx, layer, thumbWidth, thumbHeight, state.width, state.height);
    },

    listSavedDrawings: async () => {
      const drawings = await listDrawings();
      return drawings.map((d) => ({ id: d.id, name: d.name, updatedAt: d.updatedAt }));
    },
  };

  return app;
};

