import { createCanvasEngine } from './canvas';
import { renderCanvas, renderLayerThumbnail } from './renderer';
import type { Tool, Point } from './types';

/**
 * Client-side controller that wires DOM events to the canvas engine
 * and manages the render loop. Intended to run in the browser.
 */
const initDrawingCanvas = (rootEl: HTMLElement, canvasWidth = 800, canvasHeight = 600) => {
  const engine = createCanvasEngine(canvasWidth, canvasHeight);
  let isDrawing = false;
  let rafId = 0;

  // --- DOM refs ---
  const mainCanvas = rootEl.querySelector<HTMLCanvasElement>('[p-target="main-canvas"]');
  if (!mainCanvas) throw new Error('main-canvas not found');
  const ctx = mainCanvas.getContext('2d')!;

  // --- helpers ---
  const canvasPoint = (e: PointerEvent): Point => {
    const rect = mainCanvas.getBoundingClientRect();
    return { x: e.clientX - rect.left, y: e.clientY - rect.top };
  };

  const scheduleRender = () => {
    cancelAnimationFrame(rafId);
    rafId = requestAnimationFrame(() => {
      renderCanvas(ctx, engine.getState());
      updateThumbnails();
      updateUI();
    });
  };

  const updateThumbnails = () => {
    const state = engine.getState();
    for (const layer of state.layers) {
      const thumbCanvas = rootEl.querySelector<HTMLCanvasElement>(
        `[p-target="layer-thumb-${layer.id}"]`
      );
      if (!thumbCanvas) continue;
      const thumbCtx = thumbCanvas.getContext('2d');
      if (!thumbCtx) continue;
      renderLayerThumbnail(thumbCtx, layer, 40, 30, state.width, state.height);
    }
  };

  const updateUI = () => {
    // Update tool buttons
    rootEl.querySelectorAll<HTMLButtonElement>('[p-trigger^="tool-select:"]').forEach((btn) => {
      const tool = btn.getAttribute('p-trigger')?.split(':')[1];
      const isActive = tool === engine.getActiveTool();
      btn.style.backgroundColor = isActive ? '#094771' : '#3c3c3c';
      btn.style.borderColor = isActive ? '#1177bb' : '#555';
    });

    // Update undo/redo
    const undoBtn = rootEl.querySelector<HTMLButtonElement>('[p-trigger="undo"]');
    const redoBtn = rootEl.querySelector<HTMLButtonElement>('[p-trigger="redo"]');
    if (undoBtn) undoBtn.style.opacity = engine.canUndo() ? '1' : '0.4';
    if (redoBtn) redoBtn.style.opacity = engine.canRedo() ? '1' : '0.4';

    // Update color swatches
    rootEl.querySelectorAll<HTMLElement>('[p-trigger^="color-select:"]').forEach((swatch) => {
      const color = swatch.getAttribute('p-trigger')?.split(':')[1];
      swatch.style.borderColor = color === engine.getColor() ? '#1177bb' : 'transparent';
    });

    // Update layer highlights
    const state = engine.getState();
    rootEl.querySelectorAll<HTMLElement>('[p-trigger^="layer-select:"]').forEach((item) => {
      const layerId = item.getAttribute('p-trigger')?.split(':')[1];
      item.style.backgroundColor = layerId === state.activeLayerId ? '#094771' : 'transparent';
    });
  };

  // --- pointer events on canvas ---
  mainCanvas.addEventListener('pointerdown', (e) => {
    isDrawing = true;
    mainCanvas.setPointerCapture(e.pointerId);
    engine.startStroke(canvasPoint(e));
  });

  mainCanvas.addEventListener('pointermove', (e) => {
    if (!isDrawing) return;
    engine.continueStroke(canvasPoint(e));
    // Live preview for pen/eraser
    const tool = engine.getActiveTool();
    if (tool === 'pen' || tool === 'eraser') {
      renderCanvas(ctx, engine.getState());
      // Draw current stroke in progress
      const state = engine.getState();
      // handled by next frame
    }
    scheduleRender();
  });

  mainCanvas.addEventListener('pointerup', (e) => {
    if (!isDrawing) return;
    isDrawing = false;
    engine.endStroke(canvasPoint(e));
    scheduleRender();
  });

  // --- delegated click handler for toolbar/sidebar ---
  rootEl.addEventListener('click', (e) => {
    const target = (e.target as HTMLElement).closest<HTMLElement>('[p-trigger]');
    if (!target) return;
    const trigger = target.getAttribute('p-trigger') ?? '';
    const [action, value] = trigger.split(':');

    switch (action) {
      case 'tool-select':
        engine.setActiveTool(value as Tool);
        break;
      case 'color-select':
        engine.setColor(value);
        break;
      case 'undo':
        engine.undo();
        break;
      case 'redo':
        engine.redo();
        break;
      case 'clear-layer':
        engine.clearActiveLayer();
        break;
      case 'clear-all':
        engine.clearAll();
        break;
      case 'add-layer':
        engine.addLayer();
        break;
      case 'remove-layer': {
        const active = engine.getActiveLayer();
        if (active) engine.removeLayer(active.id);
        break;
      }
      case 'layer-select':
        engine.setActiveLayer(value);
        break;
      case 'toggle-visibility':
        engine.toggleLayerVisibility(value);
        break;
      case 'save-png': {
        const dataUrl = mainCanvas.toDataURL('image/png');
        const link = document.createElement('a');
        link.download = 'drawing.png';
        link.href = dataUrl;
        link.click();
        return; // no re-render needed
      }
      case 'load-png': {
        const input = document.createElement('input');
        input.type = 'file';
        input.accept = 'image/png';
        input.onchange = () => {
          const file = input.files?.[0];
          if (!file) return;
          const img = new Image();
          img.onload = () => {
            const activeLayer = engine.getActiveLayer();
            if (!activeLayer) return;
            ctx.drawImage(img, 0, 0);
          };
          img.src = URL.createObjectURL(file);
        };
        input.click();
        return;
      }
      case 'save-project': {
        const json = engine.toJSON();
        const blob = new Blob([json], { type: 'application/json' });
        const link = document.createElement('a');
        link.download = 'drawing.json';
        link.href = URL.createObjectURL(blob);
        link.click();
        return;
      }
      case 'load-project': {
        const input = document.createElement('input');
        input.type = 'file';
        input.accept = 'application/json';
        input.onchange = async () => {
          const file = input.files?.[0];
          if (!file) return;
          const text = await file.text();
          engine.fromJSON(text);
          scheduleRender();
        };
        input.click();
        return;
      }
      default:
        return;
    }

    scheduleRender();
  });

  // --- input events for range/color ---
  rootEl.addEventListener('input', (e) => {
    const target = e.target as HTMLInputElement;
    const trigger = target.getAttribute('p-trigger');
    if (trigger === 'brush-size') {
      engine.setBrushSize(Number(target.value));
      const preview = rootEl.querySelector<HTMLElement>('[p-trigger="brush-size"]')
        ?.parentElement?.querySelector<HTMLElement>('div > div');
      if (preview) {
        const s = Math.min(Number(target.value), 50);
        preview.style.width = `${s}px`;
        preview.style.height = `${s}px`;
      }
    } else if (trigger === 'color-input') {
      engine.setColor(target.value);
      scheduleRender();
    }
  });

  // --- keyboard shortcuts ---
  document.addEventListener('keydown', (e) => {
    if ((e.metaKey || e.ctrlKey) && e.key === 'z') {
      e.preventDefault();
      if (e.shiftKey) {
        engine.redo();
      } else {
        engine.undo();
      }
      scheduleRender();
    }
  });

  // Initial render
  scheduleRender();

  return { engine, scheduleRender };
};

