import type { Layer, CanvasState } from './types'

let layerCounter = 0

export const createLayer = (name?: string): Layer => {
  layerCounter++
  return {
    id: `layer-${layerCounter}-${Date.now()}`,
    name: name ?? `Layer ${layerCounter}`,
    visible: true,
    opacity: 1,
    actions: [],
  }
}

export const createInitialState = (width = 800, height = 600): CanvasState => {
  const baseLayer = createLayer('Background')
  return {
    width,
    height,
    layers: [baseLayer],
    activeLayerId: baseLayer.id,
  }
}

export const addLayer = (state: CanvasState, name?: string): CanvasState => {
  const layer = createLayer(name)
  return {
    ...state,
    layers: [...state.layers, layer],
    activeLayerId: layer.id,
  }
}

export const removeLayer = (state: CanvasState, layerId: string): CanvasState => {
  if (state.layers.length <= 1) return state
  const filtered = state.layers.filter((l) => l.id !== layerId)
  const activeLayerId =
    state.activeLayerId === layerId ? filtered[filtered.length - 1].id : state.activeLayerId
  return { ...state, layers: filtered, activeLayerId }
}

export const toggleLayerVisibility = (state: CanvasState, layerId: string): CanvasState => ({
  ...state,
  layers: state.layers.map((l) => (l.id === layerId ? { ...l, visible: !l.visible } : l)),
})

export const setActiveLayer = (state: CanvasState, layerId: string): CanvasState => ({
  ...state,
  activeLayerId: layerId,
})

export const reorderLayers = (state: CanvasState, fromIndex: number, toIndex: number): CanvasState => {
  const layers = [...state.layers]
  const [moved] = layers.splice(fromIndex, 1)
  layers.splice(toIndex, 0, moved)
  return { ...state, layers }
}

export const renameLayer = (state: CanvasState, layerId: string, name: string): CanvasState => ({
  ...state,
  layers: state.layers.map((l) => (l.id === layerId ? { ...l, name } : l)),
})

import type { CanvasState, HistoryEntry } from './types'

const MAX_HISTORY = 50

export type HistoryManager = {
  push: (state: CanvasState) => void
  undo: () => CanvasState | null
  redo: () => CanvasState | null
  canUndo: () => boolean
  canRedo: () => boolean
  clear: () => void
}

export const createHistoryManager = (): HistoryManager => {
  const undoStack: HistoryEntry[] = []
  const redoStack: HistoryEntry[] = []

  const toEntry = (state: CanvasState): HistoryEntry => ({
    layers: structuredClone(state.layers),
    activeLayerId: state.activeLayerId,
  })

  const fromEntry = (entry: HistoryEntry, state: CanvasState): CanvasState => ({
    ...state,
    layers: structuredClone(entry.layers),
    activeLayerId: entry.activeLayerId,
  })

  const push = (state: CanvasState): void => {
    undoStack.push(toEntry(state))
    if (undoStack.length > MAX_HISTORY) undoStack.shift()
    redoStack.length = 0
  }

  const undo = (): CanvasState | null => {
    const entry = undoStack.pop()
    if (!entry) return null
    return fromEntry(entry, { width: 0, height: 0, layers: [], activeLayerId: '' })
  }

  const redo = (): CanvasState | null => {
    const entry = redoStack.pop()
    if (!entry) return null
    return fromEntry(entry, { width: 0, height: 0, layers: [], activeLayerId: '' })
  }

  const canUndo = (): boolean => undoStack.length > 0
  const canRedo = (): boolean => redoStack.length > 0

  const clear = (): void => {
    undoStack.length = 0
    redoStack.length = 0
  }

  return { push, undo, redo, canUndo, canRedo, clear }
}

import type { CanvasState, DrawingProject } from './types'

const DATA_DIR = './data'

export const saveProject = async (state: CanvasState, filename: string): Promise<string> => {
  const project: DrawingProject = {
    version: '1.0.0',
    state,
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  }
  const path = `${DATA_DIR}/${filename}.json`
  await Bun.write(path, JSON.stringify(project, null, 2))
  return path
}

export const loadProject = async (filename: string): Promise<CanvasState | null> => {
  const path = `${DATA_DIR}/${filename}.json`
  const file = Bun.file(path)
  if (!(await file.exists())) return null
  const project = (await file.json()) as DrawingProject
  return project.state
}

export const listProjects = async (): Promise<string[]> => {
  const glob = new Bun.Glob('*.json')
  const files: string[] = []
  for await (const file of glob.scan({ cwd: DATA_DIR })) {
    files.push(file.replace('.json', ''))
  }
  return files
}

export const deleteProject = async (filename: string): Promise<boolean> => {
  const path = `${DATA_DIR}/${filename}.json`
  const file = Bun.file(path)
  if (!(await file.exists())) return false
  await Bun.$`rm ${path}`
  return true
}

export const exportPng = async (
  canvas: HTMLCanvasElement,
  filename: string,
): Promise<string> => {
  const dataUrl = canvas.toDataURL('image/png')
  const base64 = dataUrl.split(',')[1]
  const buffer = Buffer.from(base64, 'base64')
  const path = `${DATA_DIR}/${filename}.png`
  await Bun.write(path, buffer)
  return path
}

export const importPng = async (filename: string): Promise<string | null> => {
  const path = `${DATA_DIR}/${filename}.png`
  const file = Bun.file(path)
  if (!(await file.exists())) return null
  const buffer = await file.arrayBuffer()
  const base64 = Buffer.from(buffer).toString('base64')
  return `data:image/png;base64,${base64}`
}

import type { ToolType, Point, DrawAction, CanvasState } from './types'
import { createHistoryManager } from './history'
import type { HistoryManager } from './history'
import { createInitialState, addLayer, removeLayer, toggleLayerVisibility, setActiveLayer } from './layers'
import { saveProject, loadProject, exportPng, importPng } from './storage'

export type DrawingCanvas = {
  getState: () => CanvasState
  setTool: (tool: ToolType) => void
  getTool: () => ToolType
  setColor: (color: string) => void
  getColor: () => string
  setBrushSize: (size: number) => void
  getBrushSize: () => number
  startStroke: (point: Point) => void
  continueStroke: (point: Point) => void
  endStroke: () => void
  undo: () => CanvasState | null
  redo: () => CanvasState | null
  canUndo: () => boolean
  canRedo: () => boolean
  clearActiveLayer: () => void
  addLayer: (name?: string) => void
  removeLayer: (layerId: string) => void
  toggleLayerVisibility: (layerId: string) => void
  setActiveLayer: (layerId: string) => void
  save: (filename: string) => Promise<string>
  load: (filename: string) => Promise<boolean>
  exportPng: (canvas: HTMLCanvasElement, filename: string) => Promise<string>
  importPng: (filename: string) => Promise<string | null>
  renderToCanvas: (ctx: CanvasRenderingContext2D) => void
  renderLayerThumbnail: (layerId: string, ctx: CanvasRenderingContext2D, width: number, height: number) => void
}

export const createDrawingCanvas = (width = 800, height = 600): DrawingCanvas => {
  let state = createInitialState(width, height)
  let activeTool: ToolType = 'pen'
  let activeColor = '#000000'
  let brushSize = 3
  let currentAction: DrawAction | null = null
  const history: HistoryManager = createHistoryManager()

  // Save initial state to history
  history.push(state)

  const getActiveLayer = () => state.layers.find((l) => l.id === state.activeLayerId)

  const renderAction = (ctx: CanvasRenderingContext2D, action: DrawAction): void => {
    if (action.points.length === 0) return

    ctx.save()
    ctx.lineWidth = action.size
    ctx.lineCap = 'round'
    ctx.lineJoin = 'round'

    if (action.tool === 'eraser') {
      ctx.globalCompositeOperation = 'destination-out'
      ctx.strokeStyle = 'rgba(0,0,0,1)'
    } else {
      ctx.globalCompositeOperation = 'source-over'
      ctx.strokeStyle = action.color
      ctx.fillStyle = action.color
    }

    const { points, tool } = action

    if (tool === 'pen' || tool === 'eraser') {
      ctx.beginPath()
      ctx.moveTo(points[0].x, points[0].y)
      for (let i = 1; i < points.length; i++) {
        ctx.lineTo(points[i].x, points[i].y)
      }
      if (points.length === 1) {
        ctx.arc(points[0].x, points[0].y, action.size / 2, 0, Math.PI * 2)
        ctx.fill()
      } else {
        ctx.stroke()
      }
    } else if (tool === 'line' && points.length >= 2) {
      const start = points[0]
      const end = points[points.length - 1]
      ctx.beginPath()
      ctx.moveTo(start.x, start.y)
      ctx.lineTo(end.x, end.y)
      ctx.stroke()
    } else if (tool === 'rectangle' && points.length >= 2) {
      const start = points[0]
      const end = points[points.length - 1]
      const x = Math.min(start.x, end.x)
      const y = Math.min(start.y, end.y)
      const w = Math.abs(end.x - start.x)
      const h = Math.abs(end.y - start.y)
      ctx.strokeRect(x, y, w, h)
    } else if (tool === 'circle' && points.length >= 2) {
      const start = points[0]
      const end = points[points.length - 1]
      const cx = (start.x + end.x) / 2
      const cy = (start.y + end.y) / 2
      const rx = Math.abs(end.x - start.x) / 2
      const ry = Math.abs(end.y - start.y) / 2
      ctx.beginPath()
      ctx.ellipse(cx, cy, rx, ry, 0, 0, Math.PI * 2)
      ctx.stroke()
    }

    ctx.restore()
  }

  const renderLayer = (
    ctx: CanvasRenderingContext2D,
    layerId: string,
    targetWidth?: number,
    targetHeight?: number,
  ): void => {
    const layer = state.layers.find((l) => l.id === layerId)
    if (!layer) return

    const scaleX = targetWidth ? targetWidth / state.width : 1
    const scaleY = targetHeight ? targetHeight / state.height : 1

    ctx.save()
    ctx.globalAlpha = layer.opacity

    if (scaleX !== 1 || scaleY !== 1) {
      ctx.scale(scaleX, scaleY)
    }

    for (const action of layer.actions) {
      renderAction(ctx, action)
    }

    ctx.restore()
  }

  const renderToCanvas = (ctx: CanvasRenderingContext2D): void => {
    ctx.clearRect(0, 0, state.width, state.height)

    // White background
    ctx.fillStyle = '#ffffff'
    ctx.fillRect(0, 0, state.width, state.height)

    for (const layer of state.layers) {
      if (!layer.visible) continue
      renderLayer(ctx, layer.id)
    }

    // Render in-progress action
    if (currentAction) {
      renderAction(ctx, currentAction)
    }
  }

  const renderLayerThumbnail = (
    layerId: string,
    ctx: CanvasRenderingContext2D,
    width: number,
    height: number,
  ): void => {
    ctx.clearRect(0, 0, width, height)
    ctx.fillStyle = '#ffffff'
    ctx.fillRect(0, 0, width, height)
    renderLayer(ctx, layerId, width, height)
  }

  return {
    getState: () => state,

    setTool: (tool) => {
      activeTool = tool
    },
    getTool: () => activeTool,

    setColor: (color) => {
      activeColor = color
    },
    getColor: () => activeColor,

    setBrushSize: (size) => {
      brushSize = Math.max(1, Math.min(100, size))
    },
    getBrushSize: () => brushSize,

    startStroke: (point) => {
      const layer = getActiveLayer()
      if (!layer || !layer.visible) return

      currentAction = {
        tool: activeTool,
        color: activeColor,
        size: brushSize,
        points: [point],
        layerId: state.activeLayerId,
      }
    },

    continueStroke: (point) => {
      if (!currentAction) return
      currentAction.points.push(point)
    },

    endStroke: () => {
      if (!currentAction) return

      history.push(state)

      state = {
        ...state,
        layers: state.layers.map((l) =>
          l.id === currentAction!.layerId
            ? { ...l, actions: [...l.actions, currentAction!] }
            : l,
        ),
      }

      currentAction = null
    },

    undo: () => {
      const restored = history.undo()
      if (restored) {
        state = { ...state, ...restored }
        return state
      }
      return null
    },

    redo: () => {
      const restored = history.redo()
      if (restored) {
        state = { ...state, ...restored }
        return state
      }
      return null
    },

    canUndo: () => history.canUndo(),
    canRedo: () => history.canRedo(),

    clearActiveLayer: () => {
      history.push(state)
      state = {
        ...state,
        layers: state.layers.map((l) =>
          l.id === state.activeLayerId ? { ...l, actions: [] } : l,
        ),
      }
    },

    addLayer: (name?) => {
      history.push(state)
      state = addLayer(state, name)
    },

    removeLayer: (layerId) => {
      if (state.layers.length <= 1) return
      history.push(state)
      state = removeLayer(state, layerId)
    },

    toggleLayerVisibility: (layerId) => {
      state = toggleLayerVisibility(state, layerId)
    },

    setActiveLayer: (layerId) => {
      state = setActiveLayer(state, layerId)
    },

    save: (filename) => saveProject(state, filename),
    load: async (filename) => {
      const loaded = await loadProject(filename)
      if (!loaded) return false
      history.push(state)
      state = loaded
      history.clear()
      history.push(state)
      return true
    },

    exportPng: (canvas, filename) => exportPng(canvas, filename),
    importPng: (filename) => importPng(filename),

    renderToCanvas,
    renderLayerThumbnail,
  }
}

