import { createDrawingCanvas } from './canvas'
import type { ToolType, Point } from './types'

const drawingCanvas = createDrawingCanvas(800, 600)

let mainCanvas: HTMLCanvasElement | null = null
let mainCtx: CanvasRenderingContext2D | null = null
let isDrawing = false
let animFrameId: number | null = null

const getCanvasPoint = (e: MouseEvent): Point => {
  if (!mainCanvas) return { x: 0, y: 0 }
  const rect = mainCanvas.getBoundingClientRect()
  const scaleX = mainCanvas.width / rect.width
  const scaleY = mainCanvas.height / rect.height
  return {
    x: (e.clientX - rect.left) * scaleX,
    y: (e.clientY - rect.top) * scaleY,
  }
}

const scheduleRender = (): void => {
  if (animFrameId !== null) return
  animFrameId = requestAnimationFrame(() => {
    animFrameId = null
    if (mainCtx) {
      drawingCanvas.renderToCanvas(mainCtx)
    }
    updateLayerThumbnails()
  })
}

const updateLayerThumbnails = (): void => {
  const state = drawingCanvas.getState()
  for (const layer of state.layers) {
    const thumbCanvas = document.querySelector(`[p-target="thumb-${layer.id}"]`) as HTMLCanvasElement | null
    if (!thumbCanvas) continue
    const thumbCtx = thumbCanvas.getContext('2d')
    if (!thumbCtx) continue
    drawingCanvas.renderLayerThumbnail(layer.id, thumbCtx, 40, 30)
  }
}

const updateToolbarState = (): void => {
  const activeTool = drawingCanvas.getTool()
  const toolButtons = document.querySelectorAll<HTMLButtonElement>('[p-trigger^="tool-select:"]')
  toolButtons.forEach((btn) => {
    const toolId = btn.getAttribute('p-trigger')?.split(':')[1]
    if (toolId === activeTool) {
      btn.style.backgroundColor = '#007acc'
      btn.style.borderColor = '#007acc'
      btn.style.color = '#ffffff'
    } else {
      btn.style.backgroundColor = '#3c3c3c'
      btn.style.borderColor = '#555'
      btn.style.color = '#e0e0e0'
    }
  })
}

const updateLayersPanel = (): void => {
  const state = drawingCanvas.getState()
  const layerList = document.querySelector('[p-target="layer-list"]')
  if (!layerList) return

  const items = document.querySelectorAll('[p-trigger^="layer-select:"]')
  items.forEach((item) => {
    const layerId = item.getAttribute('p-trigger')?.split(':')[1]
    const el = item as HTMLElement
    if (layerId === state.activeLayerId) {
      el.style.backgroundColor = '#37373d'
      el.style.border = '1px solid #007acc'
    } else {
      el.style.backgroundColor = 'transparent'
      el.style.border = '1px solid transparent'
    }
  })
}

const rebuildUI = (): void => {
  const state = drawingCanvas.getState()
  const app = document.getElementById('app')
  if (!app) return

  app.innerHTML = ''

  // Build container
  const container = document.createElement('div')
  container.style.cssText = 'display:flex;font-family:system-ui,-apple-system,sans-serif;height:100vh;background:#1e1e1e;color:#e0e0e0;'

  // Canvas area
  const canvasArea = document.createElement('div')
  canvasArea.style.cssText = 'flex:1;display:flex;flex-direction:column;overflow:hidden;'

  // Toolbar
  const toolbar = buildToolbar()
  canvasArea.appendChild(toolbar)

  // Canvas wrapper
  const canvasWrapper = document.createElement('div')
  canvasWrapper.style.cssText = 'flex:1;display:flex;align-items:center;justify-content:center;overflow:auto;padding:20px;background:#1e1e1e;'

  mainCanvas = document.createElement('canvas')
  mainCanvas.width = state.width
  mainCanvas.height = state.height
  mainCanvas.style.cssText = 'border:1px solid #3c3c3c;cursor:crosshair;box-shadow:0 2px 12px rgba(0,0,0,0.4);'
  mainCtx = mainCanvas.getContext('2d')

  mainCanvas.addEventListener('mousedown', onMouseDown)
  mainCanvas.addEventListener('mousemove', onMouseMove)
  mainCanvas.addEventListener('mouseup', onMouseUp)
  mainCanvas.addEventListener('mouseleave', onMouseUp)

  canvasWrapper.appendChild(mainCanvas)
  canvasArea.appendChild(canvasWrapper)
  container.appendChild(canvasArea)

  // Layers sidebar
  const sidebar = buildLayersSidebar()
  container.appendChild(sidebar)

  app.appendChild(container)
  scheduleRender()
}

const buildToolbar = (): HTMLElement => {
