  toolbar.style.cssText = 'display:flex;align-items:center;gap:4px;padding:6px 12px;background:#333;border-bottom:1px solid #3c3c3c;flex-wrap:wrap;'

  const toolDefs: Array<{ id: ToolType; label: string }> = [
    { id: 'pen', label: 'Pen' },
    { id: 'line', label: 'Line' },
    { id: 'rectangle', label: 'Rect' },
    { id: 'circle', label: 'Circle' },
