      drawingCanvas.setTool(tool.id)
      rebuildUI()
    })
    toolbar.appendChild(btn)
  }

  toolbar.appendChild(createSeparator())

  // Color picker
  const colorLabel = document.createElement('span')
  colorLabel.textContent = 'Color:'
  colorLabel.style.cssText = 'font-size:12px;color:#aaa;margin-right:4px;'
  toolbar.appendChild(colorLabel)

  const colorInput = document.createElement('input')
  colorInput.type = 'color'
  colorInput.value = drawingCanvas.getColor()
  colorInput.style.cssText = 'width:32px;height:32px;border:none;border-radius:4px;cursor:pointer;padding:0;background:transparent;'
  colorInput.addEventListener('input', (e) => {
    drawingCanvas.setColor((e.target as HTMLInputElement).value)
  })
  toolbar.appendChild(colorInput)

  toolbar.appendChild(createSeparator())

  // Brush size
  const sizeLabel = document.createElement('span')
  sizeLabel.textContent = 'Size:'
  sizeLabel.style.cssText = 'font-size:12px;color:#aaa;margin-right:4px;'
  toolbar.appendChild(sizeLabel)

  const sizeDisplay = document.createElement('span')
  sizeDisplay.textContent = String(drawingCanvas.getBrushSize())
  sizeDisplay.style.cssText = 'font-size:12px;color:#aaa;min-width:24px;'

  const sizeInput = document.createElement('input')
  sizeInput.type = 'range'
  sizeInput.min = '1'
  sizeInput.max = '50'
  sizeInput.value = String(drawingCanvas.getBrushSize())
  sizeInput.style.cssText = 'width:80px;accent-color:#007acc;'
  sizeInput.addEventListener('input', (e) => {
    const val = Number((e.target as HTMLInputElement).value)
    drawingCanvas.setBrushSize(val)
    sizeDisplay.textContent = String(val)
  })
  toolbar.appendChild(sizeInput)
  toolbar.appendChild(sizeDisplay)

  toolbar.appendChild(createSeparator())

  // Undo/Redo
  toolbar.appendChild(
    createActionButton('Undo', drawingCanvas.canUndo(), () => {
      drawingCanvas.undo()
      rebuildUI()
    }),
  )
  toolbar.appendChild(
    createActionButton('Redo', drawingCanvas.canRedo(), () => {
      drawingCanvas.redo()
      rebuildUI()
    }),
  )

  toolbar.appendChild(createSeparator())

  // Clear
  toolbar.appendChild(
    createActionButton('Clear', true, () => {
      drawingCanvas.clearActiveLayer()
      rebuildUI()
    }),
  )

  // Save PNG
  toolbar.appendChild(
    createActionButton('Save PNG', true, async () => {
      if (!mainCanvas) return
      const name = prompt('Filename:', 'drawing')
      if (!name) return
      await drawingCanvas.exportPng(mainCanvas, name)
      alert(`Saved as ${name}.png`)
    }),
  )

  // Save project
  toolbar.appendChild(
    createActionButton('Save', true, async () => {
      const name = prompt('Project name:', 'my-drawing')
