const buildLayersSidebar = (): HTMLElement => {
  const state = drawingCanvas.getState()

  const sidebar = document.createElement('div')
  sidebar.style.cssText = 'width:220px;background:#252526;border-left:1px solid #3c3c3c;display:flex;flex-direction:column;overflow:hidden;'

  // Title
  const titleSection = document.createElement('div')
  titleSection.style.cssText = 'padding:12px;border-bottom:1px solid #3c3c3c;'
  const title = document.createElement('div')
  title.textContent = 'LAYERS'
  title.style.cssText = 'font-size:11px;font-weight:600;text-transform:uppercase;letter-spacing:0.5px;color:#888;'
  titleSection.appendChild(title)
  sidebar.appendChild(titleSection)

  // Layer list (reversed so top layer appears first)
  const layerList = document.createElement('div')
  layerList.style.cssText = 'flex:1;overflow-y:auto;padding:8px;'

  const reversedLayers = [...state.layers].reverse()
  for (const layer of reversedLayers) {
    const isActive = layer.id === state.activeLayerId
    const item = document.createElement('div')
    item.style.cssText = `display:flex;align-items:center;gap:8px;padding:6px 8px;border-radius:4px;cursor:pointer;font-size:13px;margin-bottom:4px;${isActive ? 'background:#37373d;border:1px solid #007acc;' : 'border:1px solid transparent;'}`

    item.addEventListener('click', () => {
      drawingCanvas.setActiveLayer(layer.id)
      rebuildUI()
    })

    // Thumbnail
    const thumb = document.createElement('canvas')
    thumb.width = 40
    thumb.height = 30
    thumb.style.cssText = 'width:40px;height:30px;border:1px solid #555;border-radius:2px;background:#fff;flex-shrink:0;'
    thumb.setAttribute('data-layer-id', layer.id)
    item.appendChild(thumb)

    // Name
    const nameSpan = document.createElement('span')
    nameSpan.textContent = layer.name
    nameSpan.style.cssText = 'flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;'
    item.appendChild(nameSpan)

    // Visibility toggle
    const visBtn = document.createElement('button')
    visBtn.textContent = layer.visible ? '\u{1F441}' : '\u2014'
    visBtn.title = layer.visible ? 'Hide layer' : 'Show layer'
    visBtn.style.cssText = 'cursor:pointer;font-size:14px;border:none;background:none;color:#e0e0e0;padding:2px;'
    visBtn.addEventListener('click', (e) => {
      e.stopPropagation()
      drawingCanvas.toggleLayerVisibility(layer.id)
      rebuildUI()
    })
    item.appendChild(visBtn)

    layerList.appendChild(item)
  }

  sidebar.appendChild(layerList)

  // Layer actions
  const actions = document.createElement('div')
  actions.style.cssText = 'display:flex;gap:4px;padding:8px 12px;border-top:1px solid #3c3c3c;'

  const addBtn = document.createElement('button')
  addBtn.textContent = '+ Add'
  addBtn.style.cssText = 'padding:4px 8px;border:1px solid #555;border-radius:3px;background:#3c3c3c;color:#e0e0e0;cursor:pointer;font-size:12px;flex:1;text-align:center;'
  addBtn.addEventListener('click', () => {
    drawingCanvas.addLayer()
    rebuildUI()
  })
  actions.appendChild(addBtn)

  const removeBtn = document.createElement('button')
  removeBtn.textContent = '- Remove'
  removeBtn.style.cssText = 'padding:4px 8px;border:1px solid #555;border-radius:3px;background:#3c3c3c;color:#e0e0e0;cursor:pointer;font-size:12px;flex:1;text-align:center;'
  removeBtn.addEventListener('click', () => {
    drawingCanvas.removeLayer(state.activeLayerId)
    rebuildUI()
  })
  actions.appendChild(removeBtn)

  sidebar.appendChild(actions)

  // Schedule thumbnail rendering after DOM is ready
  requestAnimationFrame(() => {
    for (const layer of state.layers) {
      const thumbCanvas = document.querySelector(`[data-layer-id="${layer.id}"]`) as HTMLCanvasElement | null
      if (!thumbCanvas) continue
      const thumbCtx = thumbCanvas.getContext('2d')
      if (!thumbCtx) continue
      drawingCanvas.renderLayerThumbnail(layer.id, thumbCtx, 40, 30)
    }
  })

  return sidebar
}

