const onMouseDown = (e: MouseEvent): void => {
  isDrawing = true
  drawingCanvas.startStroke(getCanvasPoint(e))
  scheduleRender()
}

const onMouseMove = (e: MouseEvent): void => {
  if (!isDrawing) return
  drawingCanvas.continueStroke(getCanvasPoint(e))
  scheduleRender()
}

const onMouseUp = (): void => {
  if (!isDrawing) return
  isDrawing = false
  drawingCanvas.endStroke()
  rebuildUI()
}

