import type { DrawAction, CanvasState } from './types'

export const pushToHistory = (state: CanvasState, actions: DrawAction[]): CanvasState => ({
  ...state,
  history: [...state.history, actions],
  redoStack: [],
})

export const undo = (state: CanvasState): CanvasState => {
  if (state.history.length === 0) return state

  const lastActions = state.history[state.history.length - 1]
  const newHistory = state.history.slice(0, -1)

  const newLayers = state.layers.map((layer) => {
    const actionsToRemove = lastActions.filter((a) => a.kind !== 'clear' ? a.layerId === layer.id : a.layerId === layer.id)
    if (actionsToRemove.length === 0) return layer

    return {
      ...layer,
      actions: layer.actions.slice(0, layer.actions.length - actionsToRemove.length),
    }
  })

  return {
    ...state,
    layers: newLayers,
    history: newHistory,
    redoStack: [...state.redoStack, lastActions],
  }
}

export const redo = (state: CanvasState): CanvasState => {
  if (state.redoStack.length === 0) return state

  const nextActions = state.redoStack[state.redoStack.length - 1]
  const newRedoStack = state.redoStack.slice(0, -1)

  const newLayers = state.layers.map((layer) => {
    const actionsToAdd = nextActions.filter((a) => a.kind !== 'clear' ? a.layerId === layer.id : a.layerId === layer.id)
    if (actionsToAdd.length === 0) return layer

    return {
      ...layer,
      actions: [...layer.actions, ...actionsToAdd],
    }
  })

  return {
    ...state,
    layers: newLayers,
    history: [...state.history, nextActions],
    redoStack: newRedoStack,
  }
}

import type { Layer, CanvasState } from './types'

let layerCounter = 0

export const createLayer = (name?: string): Layer => {
  layerCounter += 1
  return {
    id: `layer-${layerCounter}-${Date.now()}`,
    name: name ?? `Layer ${layerCounter}`,
    visible: true,
    opacity: 1,
    actions: [],
  }
}

export const addLayer = (state: CanvasState, name?: string): CanvasState => {
  const layer = createLayer(name)
  return {
    ...state,
    layers: [...state.layers, layer],
    activeLayerId: layer.id,
  }
}

export const removeLayer = (state: CanvasState, layerId: string): CanvasState => {
  if (state.layers.length <= 1) return state

  const filtered = state.layers.filter((l) => l.id !== layerId)
  const activeLayerId = state.activeLayerId === layerId
    ? filtered[filtered.length - 1].id
    : state.activeLayerId

  return { ...state, layers: filtered, activeLayerId }
}

export const toggleLayerVisibility = (state: CanvasState, layerId: string): CanvasState => ({
  ...state,
  layers: state.layers.map((l) =>
    l.id === layerId ? { ...l, visible: !l.visible } : l
  ),
})

export const setActiveLayer = (state: CanvasState, layerId: string): CanvasState => ({
  ...state,
  activeLayerId: layerId,
})

export const reorderLayers = (state: CanvasState, fromIndex: number, toIndex: number): CanvasState => {
  const layers = [...state.layers]
  const [moved] = layers.splice(fromIndex, 1)
  layers.splice(toIndex, 0, moved)
  return { ...state, layers }
}

import type { Point, ToolKind, DrawAction, CanvasState, StrokeAction, ShapeAction } from './types'

export const createStrokeAction = (
  points: Point[],
  color: string,
  size: number,
  tool: 'pen' | 'eraser',
  layerId: string,
): StrokeAction => ({
  kind: 'stroke',
  points,
  color,
  size,
  tool,
  layerId,
})

export const createShapeAction = (
  tool: 'rectangle' | 'circle' | 'line',
  start: Point,
  end: Point,
  color: string,
  fillColor: string | null,
  size: number,
  layerId: string,
): ShapeAction => ({
  kind: 'shape',
  tool,
  start,
  end,
  color,
  fillColor,
