})

export const addActionToLayer = (state: CanvasState, action: DrawAction): CanvasState => ({
  ...state,
  layers: state.layers.map((layer) =>
    layer.id === state.activeLayerId
      ? { ...layer, actions: [...layer.actions, action] }
      : layer
  ),
})

export const setTool = (state: CanvasState, tool: ToolKind): CanvasState => ({
  ...state,
  activeTool: tool,
})

export const setStrokeColor = (state: CanvasState, color: string): CanvasState => ({
  ...state,
  strokeColor: color,
})

export const setFillColor = (state: CanvasState, color: string | null): CanvasState => ({
  ...state,
  fillColor: color,
})

export const setBrushSize = (state: CanvasState, size: number): CanvasState => ({
