export const clearActiveLayer = (state: CanvasState): CanvasState => ({
  ...state,
  layers: state.layers.map((layer) =>
    layer.id === state.activeLayerId
      ? { ...layer, actions: [] }
      : layer
  ),
})

import type { DrawAction, Point, Layer } from './types'

export const renderActionToSVGPath = (action: DrawAction): string => {
  if (action.kind === 'clear') return ''

  if (action.kind === 'stroke') {
    if (action.points.length === 0) return ''

    const isEraser = action.tool === 'eraser'
    const strokeColor = isEraser ? '#ffffff' : action.color
    const pathData = pointsToPathData(action.points)

    return `<path d="${pathData}" stroke="${strokeColor}" stroke-width="${action.size}" fill="none" stroke-linecap="round" stroke-linejoin="round" />`
  }

  if (action.kind === 'shape') {
    const fill = action.fillColor ?? 'none'

    switch (action.tool) {
      case 'rectangle': {
        const x = Math.min(action.start.x, action.end.x)
        const y = Math.min(action.start.y, action.end.y)
        const w = Math.abs(action.end.x - action.start.x)
        const ht = Math.abs(action.end.y - action.start.y)
        return `<rect x="${x}" y="${y}" width="${w}" height="${ht}" stroke="${action.color}" stroke-width="${action.size}" fill="${fill}" />`
      }
      case 'circle': {
        const cx = (action.start.x + action.end.x) / 2
        const cy = (action.start.y + action.end.y) / 2
        const rx = Math.abs(action.end.x - action.start.x) / 2
        const ry = Math.abs(action.end.y - action.start.y) / 2
        return `<ellipse cx="${cx}" cy="${cy}" rx="${rx}" ry="${ry}" stroke="${action.color}" stroke-width="${action.size}" fill="${fill}" />`
      }
      case 'line':
        return `<line x1="${action.start.x}" y1="${action.start.y}" x2="${action.end.x}" y2="${action.end.y}" stroke="${action.color}" stroke-width="${action.size}" stroke-linecap="round" />`
    }
  }

  return ''
}

const pointsToPathData = (points: Point[]): string => {
  if (points.length === 0) return ''
  if (points.length === 1) {
    return `M ${points[0].x} ${points[0].y} L ${points[0].x} ${points[0].y}`
  }

  let d = `M ${points[0].x} ${points[0].y}`

  for (let i = 1; i < points.length - 1; i++) {
    const midX = (points[i].x + points[i + 1].x) / 2
    const midY = (points[i].y + points[i + 1].y) / 2
    d += ` Q ${points[i].x} ${points[i].y} ${midX} ${midY}`
  }

  const last = points[points.length - 1]
  d += ` L ${last.x} ${last.y}`

  return d
}

export const renderLayerToSVG = (layer: Layer, width: number, height: number): string => {
  if (!layer.visible) return ''

  const elements = layer.actions.map(renderActionToSVGPath).join('\n    ')
  return `<g opacity="${layer.opacity}">\n    ${elements}\n  </g>`
}

export const renderCanvasToSVG = (layers: Layer[], width: number, height: number): string => {
  const layerContent = layers.map((l) => renderLayerToSVG(l, width, height)).join('\n  ')

  return `<svg xmlns="http://www.w3.org/2000/svg" width="${width}" height="${height}" viewBox="0 0 ${width} ${height}">
  <rect width="${width}" height="${height}" fill="white" />
  ${layerContent}
</svg>`
}

export const renderLayerThumbnail = (layer: Layer, width: number, height: number, thumbSize: number = 48): string => {
  const scale = thumbSize / Math.max(width, height)
  const thumbW = Math.round(width * scale)
  const thumbH = Math.round(height * scale)

  const elements = layer.actions.map(renderActionToSVGPath).join('\n    ')

  return `<svg xmlns="http://www.w3.org/2000/svg" width="${thumbW}" height="${thumbH}" viewBox="0 0 ${width} ${height}">
  <rect width="${width}" height="${height}" fill="white" stroke="#ccc" stroke-width="2" />
  <g opacity="${layer.opacity}">
    ${elements}
  </g>
</svg>`
}

import type { CanvasState, DrawingMetadata, Layer } from './types'
import { renderCanvasToSVG } from './renderer'

const DATA_DIR = './data'
const DRAWINGS_INDEX = `${DATA_DIR}/drawings.json`

const ensureDataDir = async () => {
  const dir = Bun.file(DATA_DIR)
  try {
    await Bun.write(`${DATA_DIR}/.gitkeep`, '')
  } catch {
    // directory exists
  }
}

export const loadDrawingsIndex = async (): Promise<DrawingMetadata[]> => {
  const file = Bun.file(DRAWINGS_INDEX)
  if (!(await file.exists())) return []

  const text = await file.text()
  return JSON.parse(text) as DrawingMetadata[]
}

const saveDrawingsIndex = async (drawings: DrawingMetadata[]) => {
  await Bun.write(DRAWINGS_INDEX, JSON.stringify(drawings, null, 2))
}

export const saveDrawing = async (
  state: CanvasState,
  name: string,
  existingId?: string,
): Promise<DrawingMetadata> => {
  await ensureDataDir()

  const id = existingId ?? `drawing-${Date.now()}`
  const now = new Date().toISOString()

  const dataPath = `${DATA_DIR}/${id}.json`
  const svgPath = `${DATA_DIR}/${id}.svg`
  const thumbnailPath = `${DATA_DIR}/${id}-thumb.svg`

  const saveData = {
    width: state.width,
    height: state.height,
    layers: state.layers,
  }

  await Bun.write(dataPath, JSON.stringify(saveData, null, 2))

  const svg = renderCanvasToSVG(state.layers, state.width, state.height)
  await Bun.write(svgPath, svg)

  const thumbSvg = renderCanvasToSVG(state.layers, state.width, state.height)
  await Bun.write(thumbnailPath, thumbSvg)

  const metadata: DrawingMetadata = {
    id,
    name,
    createdAt: existingId ? (await getDrawingMetadata(id))?.createdAt ?? now : now,
    updatedAt: now,
    width: state.width,
    height: state.height,
    thumbnailPath,
    dataPath,
  }

  const drawings = await loadDrawingsIndex()
  const existingIndex = drawings.findIndex((d) => d.id === id)
  if (existingIndex >= 0) {
    drawings[existingIndex] = metadata
  } else {
    drawings.push(metadata)
  }

  await saveDrawingsIndex(drawings)
  return metadata
}

const getDrawingMetadata = async (id: string): Promise<DrawingMetadata | undefined> => {
  const drawings = await loadDrawingsIndex()
  return drawings.find((d) => d.id === id)
}

export const loadDrawing = async (id: string): Promise<{ layers: Layer[]; width: number; height: number } | null> => {
  const metadata = await getDrawingMetadata(id)
  if (!metadata) return null

  const file = Bun.file(metadata.dataPath)
  if (!(await file.exists())) return null

  const text = await file.text()
  return JSON.parse(text)
}

export const deleteDrawing = async (id: string): Promise<boolean> => {
  const drawings = await loadDrawingsIndex()
  const drawing = drawings.find((d) => d.id === id)
  if (!drawing) return false

  const filesToDelete = [drawing.dataPath, drawing.thumbnailPath, `${DATA_DIR}/${id}.svg`]

  for (const filePath of filesToDelete) {
    try {
      const file = Bun.file(filePath)
      if (await file.exists()) {
        await Bun.write(filePath, '')
      }
    } catch {
      // file doesn't exist
    }
  }

  const remaining = drawings.filter((d) => d.id !== id)
  await saveDrawingsIndex(remaining)
  return true
}

export const exportAsPNG = async (state: CanvasState): Promise<string> => {
  const svg = renderCanvasToSVG(state.layers, state.width, state.height)
  const pngPath = `${DATA_DIR}/export-${Date.now()}.svg`
  await Bun.write(pngPath, svg)
  return pngPath
}

import type { CanvasState, ToolKind, Point } from './types'
import { createLayer } from './layers'
import { createStrokeAction, createShapeAction, addActionToLayer } from './tools'
import { pushToHistory } from './history'

export const createCanvasState = (width = 800, height = 600): CanvasState => {
  const baseLayer = createLayer('Background')
  return {
    width,
    height,
    layers: [baseLayer],
    activeLayerId: baseLayer.id,
    activeTool: 'pen',
    strokeColor: '#000000',
    fillColor: null,
    brushSize: 3,
    history: [],
    redoStack: [],
  }
}

export const beginStroke = (
  state: CanvasState,
  point: Point,
): { state: CanvasState; currentPoints: Point[] } => {
  return { state, currentPoints: [point] }
}

export const continueStroke = (
  currentPoints: Point[],
  point: Point,
): Point[] => {
  return [...currentPoints, point]
}

export const finishStroke = (
  state: CanvasState,
  points: Point[],
): CanvasState => {
  if (points.length === 0) return state

  const tool = state.activeTool === 'eraser' ? 'eraser' as const : 'pen' as const
  const action = createStrokeAction(
    points,
    state.strokeColor,
    state.brushSize,
    tool,
    state.activeLayerId,
  )

  const newState = addActionToLayer(state, action)
  return pushToHistory(newState, [action])
}

export const finishShape = (
  state: CanvasState,
  start: Point,
  end: Point,
): CanvasState => {
  const tool = state.activeTool as 'rectangle' | 'circle' | 'line'
  const action = createShapeAction(
    tool,
    start,
    end,
    state.strokeColor,
    state.fillColor,
    state.brushSize,
    state.activeLayerId,
  )

  const newState = addActionToLayer(state, action)
  return pushToHistory(newState, [action])
}

export const isShapeTool = (tool: ToolKind): tool is 'rectangle' | 'circle' | 'line' =>
  tool === 'rectangle' || tool === 'circle' || tool === 'line'

export const isStrokeTool = (tool: ToolKind): tool is 'pen' | 'eraser' =>
  tool === 'pen' || tool === 'eraser'

import type { CanvasState, ToolKind, Point } from './types'
import { createCanvasState, beginStroke, continueStroke, finishStroke, finishShape, isShapeTool, isStrokeTool } from './canvas'
import { setTool, setStrokeColor, setFillColor, setBrushSize, clearActiveLayer } from './tools'
import { addLayer, removeLayer, toggleLayerVisibility, setActiveLayer, reorderLayers } from './layers'
import { undo, redo } from './history'
import { saveDrawing, loadDrawing, loadDrawingsIndex, deleteDrawing, exportAsPNG } from './storage'
import { renderCanvasView } from './view'

export type DrawingCanvas = {
  getState: () => CanvasState
  render: () => ReturnType<typeof renderCanvasView>

  // Tool selection
  selectTool: (tool: ToolKind) => void
  setStrokeColor: (color: string) => void
  setFillColor: (color: string | null) => void
  setBrushSize: (size: number) => void

  // Drawing
  startDrawing: (point: Point) => void
  draw: (point: Point) => void
  stopDrawing: () => void

  // History
  undo: () => void
  redo: () => void

  // Canvas operations
  clearLayer: () => void
  clearAll: () => void

  // Layer management
  addLayer: (name?: string) => void
  removeLayer: (layerId: string) => void
  toggleLayerVisibility: (layerId: string) => void
  selectLayer: (layerId: string) => void
  reorderLayers: (fromIndex: number, toIndex: number) => void

  // Persistence
  save: (name: string, existingId?: string) => Promise<ReturnType<typeof saveDrawing>>
  load: (id: string) => Promise<boolean>
  listDrawings: () => Promise<ReturnType<typeof loadDrawingsIndex>>
  deleteDrawing: (id: string) => Promise<boolean>
  exportSVG: () => Promise<string>
}

export const createDrawingCanvas = (width = 800, height = 600): DrawingCanvas => {
  let state = createCanvasState(width, height)
  let currentPoints: Point[] = []
  let shapeStart: Point | null = null
  let isDrawing = false

  const canvas: DrawingCanvas = {
    getState: () => state,
    render: () => renderCanvasView(state),

    selectTool: (tool) => {
      state = setTool(state, tool)
    },

    setStrokeColor: (color) => {
      state = setStrokeColor(state, color)
    },

    setFillColor: (color) => {
      state = setFillColor(state, color)
    },

    setBrushSize: (size) => {
      state = setBrushSize(state, size)
    },

    startDrawing: (point) => {
      isDrawing = true
      if (isStrokeTool(state.activeTool)) {
        const result = beginStroke(state, point)
        state = result.state
        currentPoints = result.currentPoints
      } else if (isShapeTool(state.activeTool)) {
        shapeStart = point
      }
    },

    draw: (point) => {
      if (!isDrawing) return
      if (isStrokeTool(state.activeTool)) {
        currentPoints = continueStroke(currentPoints, point)
      }
    },

    stopDrawing: () => {
      if (!isDrawing) return
      isDrawing = false

      if (isStrokeTool(state.activeTool) && currentPoints.length > 0) {
        state = finishStroke(state, currentPoints)
        currentPoints = []
      } else if (isShapeTool(state.activeTool) && shapeStart) {
        // If no end point, use shapeStart as both
        state = finishShape(state, shapeStart, shapeStart)
        shapeStart = null
      }
    },

    undo: () => {
      state = undo(state)
    },

    redo: () => {
      state = redo(state)
    },

    clearLayer: () => {
      state = clearActiveLayer(state)
    },

    clearAll: () => {
      for (const layer of state.layers) {
        state = setActiveLayer(state, layer.id)
        state = clearActiveLayer(state)
      }
      state = setActiveLayer(state, state.layers[0].id)
    },

    addLayer: (name) => {
      state = addLayer(state, name)
    },

    removeLayer: (layerId) => {
      state = removeLayer(state, layerId)
    },

    toggleLayerVisibility: (layerId) => {
      state = toggleLayerVisibility(state, layerId)
    },

    selectLayer: (layerId) => {
      state = setActiveLayer(state, layerId)
    },

    reorderLayers: (fromIndex, toIndex) => {
      state = reorderLayers(state, fromIndex, toIndex)
    },

    save: async (name, existingId) => {
      return saveDrawing(state, name, existingId)
    },

    load: async (id) => {
      const data = await loadDrawing(id)
      if (!data) return false

      state = {
        ...state,
        width: data.width,
        height: data.height,
        layers: data.layers,
        activeLayerId: data.layers[0]?.id ?? state.activeLayerId,
        history: [],
        redoStack: [],
      }
      return true
    },

    listDrawings: () => loadDrawingsIndex(),

    deleteDrawing: (id) => deleteDrawing(id),

    exportSVG: () => exportAsPNG(state),
  }

  return canvas
}

