import type { StatResult, HistogramBin } from './types'

const sortAsc = (arr: number[]): number[] => [...arr].sort((a, b) => a - b)

const sum = (arr: number[]): number => arr.reduce((acc, v) => acc + v, 0)

const mean = (arr: number[]): number => sum(arr) / arr.length

const median = (sorted: number[]): number => {
  const mid = Math.floor(sorted.length / 2)
  return sorted.length % 2 === 0
    ? (sorted[mid - 1] + sorted[mid]) / 2
    : sorted[mid]
}

const quartile = (sorted: number[], q: 0.25 | 0.75): number => {
  const pos = (sorted.length - 1) * q
  const lo = Math.floor(pos)
  const hi = Math.ceil(pos)
  if (lo === hi) return sorted[lo]
  return sorted[lo] + (sorted[hi] - sorted[lo]) * (pos - lo)
}

const mode = (arr: number[]): number[] => {
  const freq = new Map<number, number>()
  for (const v of arr) {
    freq.set(v, (freq.get(v) ?? 0) + 1)
  }
  const maxFreq = Math.max(...freq.values())
  if (maxFreq === 1) return [] // no mode when all values appear once
  const modes: number[] = []
  for (const [val, count] of freq) {
    if (count === maxFreq) modes.push(val)
  }
  return modes.sort((a, b) => a - b)
}

const variance = (arr: number[], m: number): number =>
  sum(arr.map((v) => (v - m) ** 2)) / arr.length

export const computeStats = (values: number[]): StatResult => {
  const sorted = sortAsc(values)
  const m = mean(sorted)
  const v = variance(sorted, m)
  const q1 = quartile(sorted, 0.25)
  const q3 = quartile(sorted, 0.75)
  return {
    mean: m,
    median: median(sorted),
    mode: mode(values),
    stdDev: Math.sqrt(v),
    variance: v,
    min: sorted[0],
    max: sorted[sorted.length - 1],
    range: sorted[sorted.length - 1] - sorted[0],
    q1,
    q3,
    iqr: q3 - q1,
    count: values.length,
  }
}

export const buildHistogramBins = (values: number[], binCount = 10): HistogramBin[] => {
  const sorted = sortAsc(values)
  const min = sorted[0]
  const max = sorted[sorted.length - 1]
  const binWidth = (max - min) / binCount || 1
  const bins: HistogramBin[] = Array.from({ length: binCount }, (_, i) => ({
    low: min + i * binWidth,
    high: min + (i + 1) * binWidth,
    count: 0,
  }))
  for (const v of values) {
    let idx = Math.floor((v - min) / binWidth)
    if (idx >= binCount) idx = binCount - 1
    bins[idx].count++
  }
  return bins
}

export const parseInput = (raw: string): number[] => {
  const trimmed = raw.trim()
  // Try JSON array first
  if (trimmed.startsWith('[')) {
    const parsed = JSON.parse(trimmed) as unknown[]
    return parsed.map(Number).filter((n) => !Number.isNaN(n))
  }
  // Comma-separated
  return trimmed
    .split(',')
    .map((s) => s.trim())
    .filter((s) => s.length > 0)
    .map(Number)
    .filter((n) => !Number.isNaN(n))
}

export const round = (n: number, decimals = 4): number =>
  Math.round(n * 10 ** decimals) / 10 ** decimals

