// --- SVG Box Plot ---
const BOX_PLOT_HEIGHT = 80
const BOX_PLOT_PADDING = 40
const SVG_WIDTH = 700
const SVG_PADDING_LEFT = 60
const SVG_PADDING_RIGHT = 20

export const renderBoxPlots = (datasets: Dataset[]) => {
  if (datasets.length === 0) return h(Fragment, {})

  const globalMin = Math.min(...datasets.map((d) => d.stats.min))
  const globalMax = Math.max(...datasets.map((d) => d.stats.max))
  const dataRange = globalMax - globalMin || 1
  const plotWidth = SVG_WIDTH - SVG_PADDING_LEFT - SVG_PADDING_RIGHT
  const totalHeight = datasets.length * (BOX_PLOT_HEIGHT + BOX_PLOT_PADDING) + 40

  const scaleX = (v: number): number =>
    SVG_PADDING_LEFT + ((v - globalMin) / dataRange) * plotWidth

  const ticks = generateTicks(globalMin, globalMax, 8)

  const plotElements = datasets.flatMap((ds, i) => {
    const y = i * (BOX_PLOT_HEIGHT + BOX_PLOT_PADDING) + 30
    const midY = y + BOX_PLOT_HEIGHT / 2
    const boxTop = y + 10
    const boxBottom = y + BOX_PLOT_HEIGHT - 10
    const boxHeight = boxBottom - boxTop
    const color = colorFor(i)

    const { min, max, q1, q3, median: med } = ds.stats
    const whiskerLo = Math.max(min, q1 - 1.5 * ds.stats.iqr)
    const whiskerHi = Math.min(max, q3 + 1.5 * ds.stats.iqr)

    const outliers = ds.values.filter((v) => v < whiskerLo || v > whiskerHi)

    return [
      // dataset label
      h('text', { x: String(SVG_PADDING_LEFT - 8), y: String(midY + 4), 'text-anchor': 'end', 'font-size': '12', fill: color, 'font-weight': '600' }, ds.name),
      // whisker line
      h('line', { x1: String(scaleX(whiskerLo)), x2: String(scaleX(whiskerHi)), y1: String(midY), y2: String(midY), stroke: color, 'stroke-width': '1.5' }),
      // whisker caps
      h('line', { x1: String(scaleX(whiskerLo)), x2: String(scaleX(whiskerLo)), y1: String(boxTop + 5), y2: String(boxBottom - 5), stroke: color, 'stroke-width': '1.5' }),
      h('line', { x1: String(scaleX(whiskerHi)), x2: String(scaleX(whiskerHi)), y1: String(boxTop + 5), y2: String(boxBottom - 5), stroke: color, 'stroke-width': '1.5' }),
      // box
      h('rect', { x: String(scaleX(q1)), y: String(boxTop), width: String(scaleX(q3) - scaleX(q1)), height: String(boxHeight), fill: color, 'fill-opacity': '0.25', stroke: color, 'stroke-width': '1.5', rx: '2' }),
      // median line
      h('line', { x1: String(scaleX(med)), x2: String(scaleX(med)), y1: String(boxTop), y2: String(boxBottom), stroke: color, 'stroke-width': '2.5' }),
      // outliers
      ...outliers.map((v) =>
        h('circle', { cx: String(scaleX(v)), cy: String(midY), r: '3', fill: 'none', stroke: color, 'stroke-width': '1.5' })
      ),
    ]
  })

  const tickElements = ticks.flatMap((t) => [
    h('line', { x1: String(scaleX(t)), x2: String(scaleX(t)), y1: String(totalHeight - 25), y2: String(totalHeight - 20), stroke: '#999', 'stroke-width': '1' }),
    h('text', { x: String(scaleX(t)), y: String(totalHeight - 6), 'text-anchor': 'middle', 'font-size': '11', fill: '#666' }, String(round(t, 2))),
  ])

  // axis line
  const axisLine = h('line', { x1: String(SVG_PADDING_LEFT), x2: String(SVG_WIDTH - SVG_PADDING_RIGHT), y1: String(totalHeight - 25), y2: String(totalHeight - 25), stroke: '#ccc', 'stroke-width': '1' })

  return h('svg', { width: String(SVG_WIDTH), height: String(totalHeight), viewBox: `0 0 ${SVG_WIDTH} ${totalHeight}`, style: { display: 'block', margin: '0 auto' } },
    axisLine,
    ...tickElements,
    ...plotElements,
  )
}

// --- SVG Histogram ---
const HIST_WIDTH = 700
const HIST_HEIGHT = 250
const HIST_PAD_TOP = 20
const HIST_PAD_BOTTOM = 40
const HIST_PAD_LEFT = 50
const HIST_PAD_RIGHT = 20

export const renderHistograms = (datasets: Dataset[]) => {
  if (datasets.length === 0) return h(Fragment, {})

  const binCount = 10
  const allBins: Array<{ bins: HistogramBin[]; datasetIndex: number }> = datasets.map((ds, i) => ({
    bins: buildHistogramBins(ds.values, binCount),
    datasetIndex: i,
  }))

  const svgs = allBins.map(({ bins, datasetIndex }) => {
    const ds = datasets[datasetIndex]
    const color = colorFor(datasetIndex)
    const maxCount = Math.max(...bins.map((b) => b.count), 1)
    const plotW = HIST_WIDTH - HIST_PAD_LEFT - HIST_PAD_RIGHT
    const plotH = HIST_HEIGHT - HIST_PAD_TOP - HIST_PAD_BOTTOM
    const barW = plotW / bins.length

    const bars = bins.map((bin, j) => {
      const barH = (bin.count / maxCount) * plotH
      const x = HIST_PAD_LEFT + j * barW
      const y = HIST_PAD_TOP + plotH - barH
      return h(Fragment, {},
        h('rect', { x: String(x + 1), y: String(y), width: String(barW - 2), height: String(barH), fill: color, 'fill-opacity': '0.6', stroke: color, 'stroke-width': '1' }),
        bin.count > 0
          ? h('text', { x: String(x + barW / 2), y: String(y - 4), 'text-anchor': 'middle', 'font-size': '10', fill: '#333' }, String(bin.count))
          : h(Fragment, {}),
      )
    })

    // x-axis labels
    const xLabels = bins.map((bin, j) => {
      const x = HIST_PAD_LEFT + j * barW + barW / 2
      return h('text', { x: String(x), y: String(HIST_HEIGHT - 6), 'text-anchor': 'middle', 'font-size': '10', fill: '#666' }, String(round(bin.low, 1)))
    })

    // y-axis ticks
    const yTickCount = 5
    const yTicks = Array.from({ length: yTickCount + 1 }, (_, i) => {
      const val = Math.round((maxCount / yTickCount) * i)
      const y = HIST_PAD_TOP + plotH - (val / maxCount) * plotH
      return h(Fragment, {},
        h('line', { x1: String(HIST_PAD_LEFT - 4), x2: String(HIST_PAD_LEFT), y1: String(y), y2: String(y), stroke: '#999', 'stroke-width': '1' }),
        h('text', { x: String(HIST_PAD_LEFT - 8), y: String(y + 4), 'text-anchor': 'end', 'font-size': '10', fill: '#666' }, String(val)),
      )
    })

    return h('div', { style: { marginBottom: '24px' } },
      h('div', { style: { fontSize: '14px', fontWeight: '600', color, marginBottom: '4px' } }, `${ds.name} — Histogram`),
      h('svg', { width: String(HIST_WIDTH), height: String(HIST_HEIGHT), viewBox: `0 0 ${HIST_WIDTH} ${HIST_HEIGHT}`, style: { display: 'block' } },
        // axes
        h('line', { x1: String(HIST_PAD_LEFT), x2: String(HIST_WIDTH - HIST_PAD_RIGHT), y1: String(HIST_PAD_TOP + plotH), y2: String(HIST_PAD_TOP + plotH), stroke: '#ccc', 'stroke-width': '1' }),
