const generateTicks = (min: number, max: number, count: number): number[] => {
  const range = max - min || 1
  const step = range / (count - 1)
  return Array.from({ length: count }, (_, i) => min + i * step)
}

import { createSSR } from 'plaited'
import type { Dataset, StoredDatasets } from './types'
import { computeStats, parseInput } from './stats'
import { renderPage } from './render'

const DATA_PATH = './data/datasets.json'

const loadDatasets = async (): Promise<Dataset[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const stored: StoredDatasets = await file.json()
  return stored.datasets.map((d) => ({
    name: d.name,
    values: d.values,
    stats: computeStats(d.values),
  }))
}

const saveDatasets = async (datasets: Dataset[]): Promise<void> => {
  const stored: StoredDatasets = {
    datasets: datasets.map((d) => ({ name: d.name, values: d.values })),
  }
  await Bun.write(DATA_PATH, JSON.stringify(stored, null, 2))
}

const addDataset = async (name: string, rawValues: string): Promise<{ ok: boolean; error?: string }> => {
  const trimmedName = name.trim()
  if (!trimmedName) return { ok: false, error: 'Dataset name is required.' }

  const values = parseInput(rawValues)
  if (values.length < 2) return { ok: false, error: 'At least 2 numeric values are required.' }

  const datasets = await loadDatasets()
  if (datasets.some((d) => d.name === trimmedName)) {
    return { ok: false, error: `Dataset "${trimmedName}" already exists.` }
  }

  const stats = computeStats(values)
  datasets.push({ name: trimmedName, values, stats })
  await saveDatasets(datasets)
  return { ok: true }
}

const removeDataset = async (index: number): Promise<void> => {
  const datasets = await loadDatasets()
  if (index >= 0 && index < datasets.length) {
    datasets.splice(index, 1)
    await saveDatasets(datasets)
  }
}

const clearAllDatasets = async (): Promise<void> => {
  await saveDatasets([])
}

export const render = async (): Promise<string> => {
  const datasets = await loadDatasets()
  const ssr = createSSR()
  return ssr(renderPage(datasets))
}

export const handleAction = async (
  action: string,
  payload?: { name?: string; values?: string; index?: number }
): Promise<{ html: string; error?: string }> => {
  let error: string | undefined

  switch (action) {
    case 'add-dataset': {
      const result = await addDataset(payload?.name ?? '', payload?.values ?? '')
      if (!result.ok) error = result.error
      break
    }
    case 'delete-dataset': {
      await removeDataset(payload?.index ?? -1)
      break
    }
    case 'clear-all': {
      await clearAllDatasets()
      break
    }
  }

  const html = await render()
  return { html, error }
}

// CLI entry point: render or process actions
const main = async () => {
  const args = process.argv.slice(2)

  if (args.length === 0) {
    // Render the current state
    console.log(await render())
    return
  }

  const action = args[0]

  if (action === 'add' && args.length >= 3) {
    const name = args[1]
    const rawValues = args.slice(2).join(' ')
    const result = await handleAction('add-dataset', { name, values: rawValues })
    if (result.error) {
      console.error(`Error: ${result.error}`)
      process.exit(1)
    }
    console.log(result.html)
  } else if (action === 'remove' && args[2] !== undefined) {
    const index = parseInt(args[1], 10)
    const result = await handleAction('delete-dataset', { index })
    console.log(result.html)
  } else if (action === 'clear') {
    const result = await handleAction('clear-all')
    console.log(result.html)
  } else if (action === 'stats') {
    // Quick CLI: output JSON stats for inline data
    const rawValues = args.slice(1).join(' ')
    const values = parseInput(rawValues)
    if (values.length < 2) {
      console.error('At least 2 numeric values are required.')
      process.exit(1)
    }
    const stats = computeStats(values)
    console.log(JSON.stringify(stats, null, 2))
  } else {
    console.log(`Usage:
  bun run index.ts                     Render current datasets
  bun run index.ts add <name> <vals>   Add a dataset (CSV or JSON array)
  bun run index.ts remove <index>      Remove a dataset by index
  bun run index.ts clear               Remove all datasets
  bun run index.ts stats <vals>        Compute stats for inline data`)
  }
}

main()

