export type DatasetStats = {
  name: string
  count: number
  mean: number
  median: number
  mode: number[]
  stdDev: number
  variance: number
  min: number
  max: number
  range: number
  q1: number
  q3: number
  iqr: number
  sorted: number[]
}

const sortNumeric = (arr: number[]): number[] =>
  [...arr].sort((a, b) => a - b)

const sum = (arr: number[]): number =>
  arr.reduce((acc, v) => acc + v, 0)

const computeMean = (arr: number[]): number =>
  sum(arr) / arr.length

const computeMedian = (sorted: number[]): number => {
  const mid = Math.floor(sorted.length / 2)
  return sorted.length % 2 === 0
    ? (sorted[mid - 1] + sorted[mid]) / 2
    : sorted[mid]
}

const computeMode = (arr: number[]): number[] => {
  const freq = new Map<number, number>()
  for (const v of arr) {
    freq.set(v, (freq.get(v) ?? 0) + 1)
  }
  const maxFreq = Math.max(...freq.values())
  if (maxFreq === 1) return [] // no mode when all values appear once
  const modes: number[] = []
  for (const [val, count] of freq) {
    if (count === maxFreq) modes.push(val)
  }
  return modes.sort((a, b) => a - b)
}

const computeQuartile = (sorted: number[], q: 0.25 | 0.75): number => {
  const pos = q * (sorted.length - 1)
  const lower = Math.floor(pos)
  const upper = Math.ceil(pos)
  if (lower === upper) return sorted[lower]
  return sorted[lower] + (pos - lower) * (sorted[upper] - sorted[lower])
}

const computeVariance = (arr: number[], mean: number): number =>
  sum(arr.map(v => (v - mean) ** 2)) / arr.length

export const computeStats = (name: string, data: number[]): DatasetStats => {
  if (data.length === 0) {
    return {
      name,
      count: 0,
      mean: NaN,
      median: NaN,
      mode: [],
      stdDev: NaN,
      variance: NaN,
      min: NaN,
      max: NaN,
      range: NaN,
      q1: NaN,
      q3: NaN,
      iqr: NaN,
      sorted: [],
    }
  }

  const sorted = sortNumeric(data)
  const mean = computeMean(sorted)
  const variance = computeVariance(sorted, mean)
  const q1 = computeQuartile(sorted, 0.25)
  const q3 = computeQuartile(sorted, 0.75)

  return {
    name,
    count: sorted.length,
    mean,
    median: computeMedian(sorted),
    mode: computeMode(sorted),
    stdDev: Math.sqrt(variance),
    variance,
    min: sorted[0],
    max: sorted[sorted.length - 1],
    range: sorted[sorted.length - 1] - sorted[0],
    q1,
    q3,
    iqr: q3 - q1,
    sorted,
  }
}

export const parseInput = (input: string): number[] => {
  const trimmed = input.trim()
  // Try JSON array first
  if (trimmed.startsWith('[')) {
    const parsed = JSON.parse(trimmed)
    if (!Array.isArray(parsed)) throw new Error('Input must be an array')
    return parsed.map((v: unknown) => {
      const n = Number(v)
      if (Number.isNaN(n)) throw new Error(`Invalid number: ${v}`)
      return n
    })
  }
  // Comma-separated
  return trimmed.split(',').map(s => {
    const n = Number(s.trim())
    if (Number.isNaN(n)) throw new Error(`Invalid number: ${s.trim()}`)
    return n
  })
}

export type DatasetsInput = Record<string, number[]>

export const parseDatasets = (body: unknown): DatasetsInput => {
  if (typeof body === 'string') {
    return { Dataset: parseInput(body) }
  }
  if (typeof body === 'object' && body !== null) {
    const obj = body as Record<string, unknown>
    // { datasets: { name: [...] } }
    if ('datasets' in obj && typeof obj.datasets === 'object' && obj.datasets !== null) {
      const datasets = obj.datasets as Record<string, unknown>
      const result: DatasetsInput = {}
      for (const [key, val] of Object.entries(datasets)) {
        if (typeof val === 'string') {
          result[key] = parseInput(val)
        } else if (Array.isArray(val)) {
          result[key] = val.map((v: unknown) => {
            const n = Number(v)
            if (Number.isNaN(n)) throw new Error(`Invalid number in ${key}: ${v}`)
            return n
          })
        } else {
          throw new Error(`Invalid dataset value for "${key}"`)
        }
      }
      return result
    }
    // { data: "1,2,3" } or { data: [1,2,3] }
    if ('data' in obj) {
      if (typeof obj.data === 'string') return { Dataset: parseInput(obj.data) }
      if (Array.isArray(obj.data)) {
        return {
          Dataset: obj.data.map((v: unknown) => {
            const n = Number(v)
            if (Number.isNaN(n)) throw new Error(`Invalid number: ${v}`)
            return n
          }),
        }
      }
    }
  }
  throw new Error('Invalid input format')
}

export const fmt = (n: number, precision = 4): string =>
  Number.isNaN(n) ? 'N/A' : Number(n.toFixed(precision)).toString()

