// ── SVG Box Plot ──

const SVG_W = 800
const SVG_BOX_H = 120
const BOX_PAD = 60

const renderBoxPlot = (allStats: DatasetStats[]) => {
  const globalMin = Math.min(...allStats.map(s => s.min))
  const globalMax = Math.max(...allStats.map(s => s.max))
  const span = globalMax - globalMin || 1
  const plotW = SVG_W - BOX_PAD * 2
  const totalH = allStats.length * SVG_BOX_H + 40

  const scale = (v: number): number =>
    BOX_PAD + ((v - globalMin) / span) * plotW

  // Tick marks
  const tickCount = 8
  const tickStep = span / tickCount
  const ticks = Array.from({ length: tickCount + 1 }, (_, i) => globalMin + i * tickStep)

  const tickElements = ticks.map(t =>
    h('g', {},
      h('line', {
        x1: String(scale(t)), y1: '0',
        x2: String(scale(t)), y2: String(totalH - 30),
        stroke: '#e2e8f0', 'stroke-width': '1',
      }),
      h('text', {
        x: String(scale(t)), y: String(totalH - 10),
        'text-anchor': 'middle', fill: '#94a3b8', 'font-size': '11',
      }, fmt(t, 2))
    )
  )

  const boxElements = allStats.map((s, i) => {
    const y = i * SVG_BOX_H + 20
    const boxH = SVG_BOX_H - 40
    const color = colorFor(i)

    // Whisker bounds: min/max clamped to 1.5*IQR from quartiles
    const whiskerLow = Math.max(s.min, s.q1 - 1.5 * s.iqr)
    const whiskerHigh = Math.min(s.max, s.q3 + 1.5 * s.iqr)

    // Outliers
    const outliers = s.sorted.filter(v => v < whiskerLow || v > whiskerHigh)

    return h('g', {},
      // Dataset label
      h('text', {
        x: String(BOX_PAD - 8), y: String(y + boxH / 2 + 4),
        'text-anchor': 'end', fill: color, 'font-size': '13', 'font-weight': '600',
      }, s.name),

      // Whisker line
      h('line', {
        x1: String(scale(whiskerLow)), y1: String(y + boxH / 2),
        x2: String(scale(whiskerHigh)), y2: String(y + boxH / 2),
        stroke: color, 'stroke-width': '2',
      }),

      // Whisker caps
      h('line', {
        x1: String(scale(whiskerLow)), y1: String(y + 10),
        x2: String(scale(whiskerLow)), y2: String(y + boxH - 10),
        stroke: color, 'stroke-width': '2',
      }),
      h('line', {
        x1: String(scale(whiskerHigh)), y1: String(y + 10),
        x2: String(scale(whiskerHigh)), y2: String(y + boxH - 10),
        stroke: color, 'stroke-width': '2',
      }),

      // Box (Q1 to Q3)
      h('rect', {
        x: String(scale(s.q1)), y: String(y),
        width: String(scale(s.q3) - scale(s.q1)),
        height: String(boxH),
        fill: color, 'fill-opacity': '0.15',
        stroke: color, 'stroke-width': '2',
        rx: '3',
      }),

      // Median line
      h('line', {
        x1: String(scale(s.median)), y1: String(y),
        x2: String(scale(s.median)), y2: String(y + boxH),
        stroke: color, 'stroke-width': '3',
      }),

      // Mean marker (diamond)
      h('polygon', {
        points: [
          `${scale(s.mean)},${y + 4}`,
          `${scale(s.mean) + 6},${y + boxH / 2}`,
          `${scale(s.mean)},${y + boxH - 4}`,
          `${scale(s.mean) - 6},${y + boxH / 2}`,
        ].join(' '),
        fill: color, 'fill-opacity': '0.6',
      }),

      // Outlier dots
      ...outliers.map(o =>
        h('circle', {
          cx: String(scale(o)), cy: String(y + boxH / 2), r: '4',
          fill: 'none', stroke: color, 'stroke-width': '1.5',
        })
      )
    )
  })

  return h('div', { style: { ...styles.chartContainer, ...styles.section } },
    h('h2', { style: styles.sectionTitle }, 'Box Plot'),
    h('svg', {
      viewBox: `0 0 ${SVG_W} ${totalH}`,
      width: '100%',
      style: { display: 'block' },
    },
      ...tickElements,
      ...boxElements
    ),
    h('p', { style: { fontSize: '12px', color: '#94a3b8', marginTop: '8px' } },
      'Diamond = mean, vertical line in box = median, open circles = outliers'
    )
  )
}

// ── SVG Histogram ──

const HIST_H = 260
const HIST_PAD_L = 50
const HIST_PAD_R = 20
const HIST_PAD_T = 10
const HIST_PAD_B = 40

const computeBins = (sorted: number[], binCount: number, globalMin: number, globalMax: number) => {
  const binWidth = (globalMax - globalMin) / binCount
  const bins = new Array(binCount).fill(0) as number[]
  for (const v of sorted) {
    let idx = Math.floor((v - globalMin) / binWidth)
    if (idx >= binCount) idx = binCount - 1
    bins[idx]++
  }
  return { bins, binWidth }
}

const renderHistogram = (allStats: DatasetStats[]) => {
  const globalMin = Math.min(...allStats.map(s => s.min))
  const globalMax = Math.max(...allStats.map(s => s.max))
  const binCount = Math.max(5, Math.min(30, Math.ceil(Math.sqrt(Math.max(...allStats.map(s => s.count))))))
  const span = globalMax - globalMin || 1

  const allBins = allStats.map(s => computeBins(s.sorted, binCount, globalMin, globalMax))
  const maxBinVal = Math.max(...allBins.flatMap(b => b.bins))
  const plotW = SVG_W - HIST_PAD_L - HIST_PAD_R
  const plotH = HIST_H - HIST_PAD_T - HIST_PAD_B
  const barGroupW = plotW / binCount

  const scaleX = (v: number): number =>
    HIST_PAD_L + ((v - globalMin) / span) * plotW

  const scaleY = (v: number): number =>
    HIST_PAD_T + plotH - (v / (maxBinVal || 1)) * plotH

  // Axis ticks (x)
  const xTickCount = Math.min(binCount, 10)
  const xTickStep = Math.ceil(binCount / xTickCount)
  const xTicks = Array.from({ length: Math.floor(binCount / xTickStep) + 1 }, (_, i) => {
    const binIdx = i * xTickStep
    return globalMin + binIdx * (span / binCount)
  })

  // Axis ticks (y)
  const yTickCount = 5
  const yTickStep = maxBinVal / yTickCount
  const yTicks = Array.from({ length: yTickCount + 1 }, (_, i) => Math.round(i * yTickStep))

  const barWidth = barGroupW / allStats.length

  const barElements = allBins.flatMap((binData, di) =>
    binData.bins.map((count, bi) => {
      const x = HIST_PAD_L + bi * barGroupW + di * barWidth
      const barH = (count / (maxBinVal || 1)) * plotH
      return h('rect', {
        x: String(x + 1),
        y: String(HIST_PAD_T + plotH - barH),
        width: String(Math.max(barWidth - 2, 1)),
        height: String(barH),
        fill: colorFor(di),
        'fill-opacity': '0.6',
        stroke: colorFor(di),
        'stroke-width': '1',
      })
    })
  )

  const legendItems = allStats.map((s, i) =>
    h('g', { transform: `translate(${HIST_PAD_L + i * 120}, ${HIST_H - 5})` },
      h('rect', { x: '0', y: '-8', width: '12', height: '12', fill: colorFor(i), 'fill-opacity': '0.6', rx: '2' }),
      h('text', { x: '16', y: '2', 'font-size': '12', fill: '#475569' }, s.name)
    )
  )

  return h('div', { style: { ...styles.chartContainer, ...styles.section } },
    h('h2', { style: styles.sectionTitle }, 'Histogram'),
    h('svg', {
      viewBox: `0 0 ${SVG_W} ${HIST_H + (allStats.length > 1 ? 20 : 0)}`,
      width: '100%',
      style: { display: 'block' },
    },
      // Y axis
      h('line', {
        x1: String(HIST_PAD_L), y1: String(HIST_PAD_T),
        x2: String(HIST_PAD_L), y2: String(HIST_PAD_T + plotH),
        stroke: '#cbd5e1', 'stroke-width': '1',
      }),
      // X axis
      h('line', {
        x1: String(HIST_PAD_L), y1: String(HIST_PAD_T + plotH),
        x2: String(SVG_W - HIST_PAD_R), y2: String(HIST_PAD_T + plotH),
        stroke: '#cbd5e1', 'stroke-width': '1',
      }),
      // Y ticks
      ...yTicks.map(t =>
        h('g', {},
          h('line', {
            x1: String(HIST_PAD_L - 4), y1: String(scaleY(t)),
            x2: String(HIST_PAD_L), y2: String(scaleY(t)),
            stroke: '#94a3b8', 'stroke-width': '1',
          }),
          h('text', {
            x: String(HIST_PAD_L - 8), y: String(scaleY(t) + 4),
            'text-anchor': 'end', fill: '#94a3b8', 'font-size': '11',
          }, String(t))
        )
      ),
      // X ticks
      ...xTicks.map(t =>
        h('g', {},
          h('text', {
            x: String(scaleX(t)), y: String(HIST_PAD_T + plotH + 18),
            'text-anchor': 'middle', fill: '#94a3b8', 'font-size': '11',
          }, fmt(t, 1))
        )
      ),
      // Bars
      ...barElements,
      // Legend
      ...(allStats.length > 1 ? legendItems : [])
    )
  )
}

