import { createSSR } from 'plaited'
import { computeStats, parseInput, parseDatasets, type DatasetStats } from './stats.ts'
import { renderPage, toJSON } from './render.ts'

const DATA_PATH = './data/history.jsonl'

type HistoryEntry = {
  timestamp: string
  datasets: Record<string, number[]>
  results: ReturnType<typeof toJSON>
}

const saveHistory = async (entry: HistoryEntry) => {
  const file = Bun.file(DATA_PATH)
  const existing = await file.exists() ? await file.text() : ''
  await Bun.write(DATA_PATH, existing + JSON.stringify(entry) + '\n')
}

const processDatasets = (datasets: Record<string, number[]>): DatasetStats[] =>
  Object.entries(datasets).map(([name, data]) => computeStats(name, data))

const parseFormBody = async (req: Request): Promise<Record<string, number[]>> => {
  const formData = await req.formData()
  const result: Record<string, number[]> = {}

  const name1 = (formData.get('name1') as string)?.trim() || 'Dataset A'
  const data1 = (formData.get('data1') as string)?.trim()
  if (data1) {
    result[name1] = parseInput(data1)
  }

  const name2 = (formData.get('name2') as string)?.trim() || 'Dataset B'
  const data2 = (formData.get('data2') as string)?.trim()
  if (data2) {
    result[name2] = parseInput(data2)
  }

  return result
}

const server = Bun.serve({
  port: Number(process.env.PORT) || 3000,

  fetch: async (req) => {
    const url = new URL(req.url)
    const accept = req.headers.get('accept') ?? ''
    const wantsJSON = accept.includes('application/json')

    // ── GET / ── landing page or query-string calculation
    if (req.method === 'GET' && (url.pathname === '/' || url.pathname === '/view')) {
      const dataParam = url.searchParams.get('data')

      if (dataParam) {
        const datasets: Record<string, number[]> = { Dataset: parseInput(dataParam) }
        const allStats = processDatasets(datasets)

        if (wantsJSON) {
          return Response.json(toJSON(allStats))
        }

        const ssr = createSSR()
        return new Response(ssr(renderPage(allStats)), {
          headers: { 'content-type': 'text/html; charset=utf-8' },
        })
      }

      // Show empty form
      const ssr = createSSR()
      return new Response(ssr(renderPage(null)), {
        headers: { 'content-type': 'text/html; charset=utf-8' },
      })
    }

    // ── POST /calculate ── form or JSON body
    if (req.method === 'POST' && url.pathname === '/calculate') {
      const contentType = req.headers.get('content-type') ?? ''
      let datasets: Record<string, number[]>

      if (contentType.includes('application/json')) {
        const body = await req.json()
        datasets = parseDatasets(body)
      } else {
        datasets = await parseFormBody(req)
      }

      if (Object.keys(datasets).length === 0) {
        return new Response('No data provided', { status: 400 })
      }

      const allStats = processDatasets(datasets)
      const jsonResult = toJSON(allStats)

      // Persist to history
      await saveHistory({
        timestamp: new Date().toISOString(),
        datasets,
        results: jsonResult,
      })

      if (wantsJSON) {
        return Response.json(jsonResult)
      }

      const ssr = createSSR()
      return new Response(ssr(renderPage(allStats)), {
        headers: { 'content-type': 'text/html; charset=utf-8' },
      })
    }

    // ── GET /api/history ── retrieve past calculations
    if (req.method === 'GET' && url.pathname === '/api/history') {
      const file = Bun.file(DATA_PATH)
      if (!(await file.exists())) {
        return Response.json([])
      }
      const lines = (await file.text()).trim().split('\n').filter(Boolean)
      const entries = lines.map(line => JSON.parse(line))
      return Response.json(entries)
    }

    return new Response('Not Found', { status: 404 })
  },
})

