export const parseInput = (input: string): number[] => {
  const trimmed = input.trim()

  if (trimmed.startsWith('[')) {
    const parsed = JSON.parse(trimmed) as unknown[]
    if (!Array.isArray(parsed)) throw new Error('Input is not a valid JSON array')
    return parsed.map((v, i) => {
      const n = Number(v)
      if (Number.isNaN(n)) throw new Error(`Invalid number at index ${i}: ${v}`)
      return n
    })
  }

  return trimmed.split(',').map((s, i) => {
    const n = Number(s.trim())
    if (Number.isNaN(n)) throw new Error(`Invalid number at position ${i + 1}: "${s.trim()}"`)
    return n
  })
}

export type Stats = {
  mean: number
  median: number
  mode: number[]
  standardDeviation: number
  variance: number
  min: number
  max: number
  range: number
  q1: number
  q3: number
  iqr: number
  count: number
}

const sorted = (arr: number[]): number[] => [...arr].sort((a, b) => a - b)

const percentile = (sortedArr: number[], p: number): number => {
  const idx = (p / 100) * (sortedArr.length - 1)
  const lower = Math.floor(idx)
  const upper = Math.ceil(idx)
  if (lower === upper) return sortedArr[lower]
  const frac = idx - lower
  return sortedArr[lower] * (1 - frac) + sortedArr[upper] * frac
}

export const calculateStats = (values: number[]): Stats => {
  if (values.length === 0) throw new Error('Dataset must contain at least one value')

  const s = sorted(values)
  const count = s.length

  const sum = s.reduce((a, b) => a + b, 0)
  const mean = sum / count

  const median = percentile(s, 50)

  const freqMap = new Map<number, number>()
  let maxFreq = 0
  for (const v of s) {
    const f = (freqMap.get(v) ?? 0) + 1
    freqMap.set(v, f)
    if (f > maxFreq) maxFreq = f
  }
  const mode = maxFreq > 1
    ? [...freqMap.entries()].filter(([, f]) => f === maxFreq).map(([v]) => v)
    : [...s]

  const variance = s.reduce((acc, v) => acc + (v - mean) ** 2, 0) / count
  const standardDeviation = Math.sqrt(variance)

  const min = s[0]
  const max = s[count - 1]
  const range = max - min

  const q1 = percentile(s, 25)
  const q3 = percentile(s, 75)
  const iqr = q3 - q1

  return { mean, median, mode, standardDeviation, variance, min, max, range, q1, q3, iqr, count }
}

export const roundStat = (value: number, decimals = 4): number =>
  Math.round(value * 10 ** decimals) / 10 ** decimals

import { h, Fragment } from 'plaited'
import { type Stats, roundStat } from './stats.js'
import type { Dataset } from './parser.js'

type DatasetWithStats = {
  name: string
