  stats: Stats
}

const COLORS = ['#4e79a7', '#f28e2b', '#e15759', '#76b7b2', '#59a14f', '#edc948', '#b07aa1', '#ff9da7']

const colorFor = (i: number): string => COLORS[i % COLORS.length]

// --- Summary Table ---

const STAT_ROWS: { label: string; key: keyof Stats }[] = [
  { label: 'Count', key: 'count' },
  { label: 'Mean', key: 'mean' },
  { label: 'Median', key: 'median' },
  { label: 'Mode', key: 'mode' },
  { label: 'Std Dev', key: 'standardDeviation' },
  { label: 'Variance', key: 'variance' },
  { label: 'Min', key: 'min' },
  { label: 'Max', key: 'max' },
  { label: 'Range', key: 'range' },
  { label: 'Q1 (25%)', key: 'q1' },
  { label: 'Q3 (75%)', key: 'q3' },
  { label: 'IQR', key: 'iqr' },
]

const formatStatValue = (value: number | number[]): string => {
  if (Array.isArray(value)) {
    if (value.length > 5) return value.slice(0, 5).map(v => roundStat(v)).join(', ') + '...'
    return value.map(v => roundStat(v)).join(', ')
  }
  return String(roundStat(value))
}

export const renderSummaryTable = (datasets: DatasetWithStats[]): string => {
