// --- Box Plot ---

const BOX_PLOT_WIDTH = 600
const BOX_PLOT_PADDING = 60
const BOX_HEIGHT = 30
const BOX_GAP = 20

export const renderBoxPlot = (datasets: DatasetWithStats[]): string => {
  const allValues = datasets.flatMap(ds => ds.values)
  const globalMin = Math.min(...allValues)
  const globalMax = Math.max(...allValues)
  const valueRange = globalMax - globalMin || 1
  const plotWidth = BOX_PLOT_WIDTH - BOX_PLOT_PADDING * 2
  const totalHeight = BOX_PLOT_PADDING * 2 + datasets.length * (BOX_HEIGHT + BOX_GAP)

  const scaleX = (v: number): number =>
    BOX_PLOT_PADDING + ((v - globalMin) / valueRange) * plotWidth

  const tickCount = 6
  const tickStep = valueRange / (tickCount - 1)
  const ticks = Array.from({ length: tickCount }, (_, i) => globalMin + i * tickStep)

  const tickElements = ticks.map(t => {
    const x = scaleX(t)
    return h('g', {},
      h('line', { x1: String(x), y1: String(BOX_PLOT_PADDING - 10), x2: String(x), y2: String(totalHeight - BOX_PLOT_PADDING + 10), stroke: '#e0e0e0', 'stroke-dasharray': '3,3' }),
      h('text', { x: String(x), y: String(totalHeight - BOX_PLOT_PADDING + 25), 'text-anchor': 'middle', 'font-size': '11', fill: '#666' }, String(roundStat(t, 2)))
    )
  })

  const boxes = datasets.map((ds, i) => {
    const { min, max, q1, q3, median } = ds.stats
    const y = BOX_PLOT_PADDING + i * (BOX_HEIGHT + BOX_GAP)
    const color = colorFor(i)

    const whiskerMin = scaleX(min)
    const whiskerMax = scaleX(max)
    const boxLeft = scaleX(q1)
    const boxRight = scaleX(q3)
    const medianX = scaleX(median)
    const midY = y + BOX_HEIGHT / 2

    return h('g', {},
      // label
      h('text', { x: String(BOX_PLOT_PADDING - 8), y: String(midY + 4), 'text-anchor': 'end', 'font-size': '12', fill: '#333', 'font-weight': '600' }, ds.name),
      // whisker line
      h('line', { x1: String(whiskerMin), y1: String(midY), x2: String(whiskerMax), y2: String(midY), stroke: color, 'stroke-width': '1.5' }),
      // whisker caps
      h('line', { x1: String(whiskerMin), y1: String(y + 5), x2: String(whiskerMin), y2: String(y + BOX_HEIGHT - 5), stroke: color, 'stroke-width': '1.5' }),
      h('line', { x1: String(whiskerMax), y1: String(y + 5), x2: String(whiskerMax), y2: String(y + BOX_HEIGHT - 5), stroke: color, 'stroke-width': '1.5' }),
      // box
      h('rect', { x: String(boxLeft), y: String(y), width: String(boxRight - boxLeft), height: String(BOX_HEIGHT), fill: color, opacity: '0.3', stroke: color, 'stroke-width': '1.5', rx: '2' }),
      // median
      h('line', { x1: String(medianX), y1: String(y), x2: String(medianX), y2: String(y + BOX_HEIGHT), stroke: color, 'stroke-width': '2.5' }),
    )
  })

  return h('svg', { viewBox: `0 0 ${BOX_PLOT_WIDTH} ${totalHeight}`, width: String(BOX_PLOT_WIDTH), xmlns: 'http://www.w3.org/2000/svg', style: 'font-family:system-ui,sans-serif' },
    h('text', { x: String(BOX_PLOT_WIDTH / 2), y: '20', 'text-anchor': 'middle', 'font-size': '14', 'font-weight': '600', fill: '#333' }, 'Box Plot'),
    ...tickElements,
    ...boxes,
  )
}

// --- Histogram ---

const HIST_WIDTH = 600
const HIST_HEIGHT = 300
const HIST_PADDING = 60

export const renderHistogram = (datasets: DatasetWithStats[]): string => {
  const allValues = datasets.flatMap(ds => ds.values)
  const globalMin = Math.min(...allValues)
  const globalMax = Math.max(...allValues)
  const valueRange = globalMax - globalMin || 1

  const binCount = Math.max(5, Math.min(20, Math.ceil(Math.sqrt(allValues.length))))
  const binWidth = valueRange / binCount

  const datasetBins = datasets.map(ds => {
    const bins = new Array(binCount).fill(0) as number[]
    for (const v of ds.values) {
      let idx = Math.floor((v - globalMin) / binWidth)
      if (idx >= binCount) idx = binCount - 1
      bins[idx]++
    }
    return bins
  })

  const maxBinValue = Math.max(...datasetBins.flat(), 1)

  const plotWidth = HIST_WIDTH - HIST_PADDING * 2
  const plotHeight = HIST_HEIGHT - HIST_PADDING * 2
  const barGroupWidth = plotWidth / binCount
  const barWidth = barGroupWidth / datasets.length - 1

  const scaleY = (v: number): number =>
    HIST_PADDING + plotHeight - (v / maxBinValue) * plotHeight

  // y-axis ticks
  const yTickCount = 5
  const yTicks = Array.from({ length: yTickCount }, (_, i) => Math.round((maxBinValue / (yTickCount - 1)) * i))

  const yTickElements = yTicks.map(t => {
    const y = scaleY(t)
    return h('g', {},
      h('line', { x1: String(HIST_PADDING - 5), y1: String(y), x2: String(HIST_WIDTH - HIST_PADDING), y2: String(y), stroke: '#e0e0e0' }),
      h('text', { x: String(HIST_PADDING - 8), y: String(y + 4), 'text-anchor': 'end', 'font-size': '11', fill: '#666' }, String(t))
    )
  })

  // x-axis labels
  const xLabels = Array.from({ length: binCount + 1 }, (_, i) => {
    if (i % Math.ceil(binCount / 6) !== 0 && i !== binCount) return ''
    return String(roundStat(globalMin + i * binWidth, 2))
  })

  const xLabelElements = xLabels.map((label, i) => {
    if (!label) return ''
    const x = HIST_PADDING + i * barGroupWidth
    return h('text', { x: String(x), y: String(HIST_HEIGHT - HIST_PADDING + 20), 'text-anchor': 'middle', 'font-size': '11', fill: '#666' }, label)
  }).filter(Boolean)

  // bars
  const bars = datasetBins.flatMap((bins, dsIdx) =>
    bins.map((count, binIdx) => {
      if (count === 0) return ''
      const x = HIST_PADDING + binIdx * barGroupWidth + dsIdx * (barWidth + 1)
      const barH = (count / maxBinValue) * plotHeight
      const y = HIST_PADDING + plotHeight - barH
      return h('rect', {
        x: String(x),
        y: String(y),
        width: String(barWidth),
        height: String(barH),
        fill: colorFor(dsIdx),
        opacity: '0.7',
        rx: '1',
      })
    }).filter(Boolean)
  )

  // legend
  const legend = datasets.map((ds, i) =>
    h('g', { transform: `translate(${HIST_PADDING + i * 120}, ${HIST_HEIGHT - 15})` },
      h('rect', { width: '12', height: '12', fill: colorFor(i), opacity: '0.7', rx: '2' }),
      h('text', { x: '16', y: '11', 'font-size': '11', fill: '#333' }, ds.name),
    )
  )

  return h('svg', { viewBox: `0 0 ${HIST_WIDTH} ${HIST_HEIGHT}`, width: String(HIST_WIDTH), xmlns: 'http://www.w3.org/2000/svg', style: 'font-family:system-ui,sans-serif' },
    h('text', { x: String(HIST_WIDTH / 2), y: '20', 'text-anchor': 'middle', 'font-size': '14', 'font-weight': '600', fill: '#333' }, 'Histogram'),
    // axes
    h('line', { x1: String(HIST_PADDING), y1: String(HIST_PADDING), x2: String(HIST_PADDING), y2: String(HIST_HEIGHT - HIST_PADDING), stroke: '#333', 'stroke-width': '1' }),
    h('line', { x1: String(HIST_PADDING), y1: String(HIST_HEIGHT - HIST_PADDING), x2: String(HIST_WIDTH - HIST_PADDING), y2: String(HIST_HEIGHT - HIST_PADDING), stroke: '#333', 'stroke-width': '1' }),
    ...yTickElements,
    ...xLabelElements,
    ...bars,
    ...legend,
  )
}

