    h('div', { style: 'margin-top:32px' }, renderHistogram(datasets)),
  )

  return `<!DOCTYPE html>
<html lang="en">
<head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Statistics Calculator</title>
<style>body{margin:0;background:#fafafa;color:#222}table{margin:0 auto}</style></head>
<body>${container}</body></html>`
}

import type { Dataset } from './parser.js'

const DATA_PATH = new URL('./data/datasets.json', import.meta.url).pathname

export const loadDatasets = async (): Promise<Dataset[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  return JSON.parse(text) as Dataset[]
}

export const saveDatasets = async (datasets: Dataset[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(datasets, null, 2))
}

import { parseInput, type Dataset } from './parser.js'
import { calculateStats, type Stats } from './stats.js'
import { renderPage, renderSummaryTable, renderBoxPlot, renderHistogram } from './render.js'
import { loadDatasets, saveDatasets } from './storage.js'

type DatasetWithStats = {
  name: string
  values: number[]
  stats: Stats
}

const enrichDataset = (ds: Dataset): DatasetWithStats => ({
  name: ds.name,
  values: ds.values,
  stats: calculateStats(ds.values),
})

// --- CLI interface ---

const printUsage = () => {
  console.log(`
Statistics Calculator

Usage:
  bun run index.ts add <name> <data>       Add a named dataset (CSV or JSON array)
  bun run index.ts remove <name>           Remove a dataset by name
  bun run index.ts list                    List all stored datasets
  bun run index.ts stats [name]            Show statistics (all datasets or one)
  bun run index.ts render [output.html]    Render visualizations to HTML
  bun run index.ts clear                   Remove all datasets

Data formats:
  CSV:   "1, 2, 3, 4, 5"
  JSON:  "[1, 2, 3, 4, 5]"

Examples:
  bun run index.ts add scores "85, 90, 78, 92, 88, 76, 95, 89"
  bun run index.ts add grades "[72, 85, 90, 68, 95, 88]"
  bun run index.ts stats
  bun run index.ts render report.html
`)
}

const formatStats = (ds: DatasetWithStats): string => {
  const { stats } = ds
  const r = (v: number) => Math.round(v * 10000) / 10000
  return `
Dataset: ${ds.name} (${stats.count} values)
${'─'.repeat(40)}
  Mean:       ${r(stats.mean)}
  Median:     ${r(stats.median)}
  Mode:       ${stats.mode.length <= 5 ? stats.mode.map(r).join(', ') : `${stats.mode.slice(0, 5).map(r).join(', ')}... (${stats.mode.length} values)`}
  Std Dev:    ${r(stats.standardDeviation)}
  Variance:   ${r(stats.variance)}
  Min:        ${r(stats.min)}
  Max:        ${r(stats.max)}
  Range:      ${r(stats.range)}
  Q1 (25%):   ${r(stats.q1)}
  Q3 (75%):   ${r(stats.q3)}
  IQR:        ${r(stats.iqr)}
`
}

const run = async () => {
  const args = process.argv.slice(2)
  const command = args[0]

  if (!command || command === 'help' || command === '--help') {
    printUsage()
    return
  }

  const datasets = await loadDatasets()

  switch (command) {
    case 'add': {
      const name = args[1]
      const data = args.slice(2).join(' ')
      if (!name || !data) {
        console.error('Error: provide a name and data. Example: bun run index.ts add scores "1,2,3"')
        process.exit(1)
      }
      const values = parseInput(data)
      if (values.length === 0) {
        console.error('Error: dataset must contain at least one number')
        process.exit(1)
      }
      const existing = datasets.findIndex(ds => ds.name === name)
      if (existing >= 0) {
        datasets[existing] = { name, values }
        console.log(`Updated dataset "${name}" with ${values.length} values`)
      } else {
        datasets.push({ name, values })
        console.log(`Added dataset "${name}" with ${values.length} values`)
      }
      await saveDatasets(datasets)
      const enriched = enrichDataset({ name, values })
      console.log(formatStats(enriched))
      break
    }

    case 'remove': {
      const name = args[1]
      if (!name) {
        console.error('Error: provide a dataset name to remove')
        process.exit(1)
      }
      const idx = datasets.findIndex(ds => ds.name === name)
      if (idx < 0) {
        console.error(`Error: dataset "${name}" not found`)
        process.exit(1)
      }
      datasets.splice(idx, 1)
      await saveDatasets(datasets)
      console.log(`Removed dataset "${name}"`)
      break
    }

    case 'list': {
      if (datasets.length === 0) {
        console.log('No datasets stored. Use "add" to create one.')
        return
      }
      console.log('Stored datasets:')
      for (const ds of datasets) {
        console.log(`  - ${ds.name} (${ds.values.length} values)`)
      }
      break
    }

    case 'stats': {
      const name = args[1]
      let targets: Dataset[]
      if (name) {
        const ds = datasets.find(d => d.name === name)
        if (!ds) {
          console.error(`Error: dataset "${name}" not found`)
          process.exit(1)
        }
        targets = [ds]
      } else {
        targets = datasets
      }
      if (targets.length === 0) {
        console.log('No datasets stored. Use "add" to create one.')
        return
      }
      for (const ds of targets) {
        console.log(formatStats(enrichDataset(ds)))
      }
      break
    }

    case 'render': {
      if (datasets.length === 0) {
        console.log('No datasets to render. Use "add" to create one.')
        return
      }
      const enriched = datasets.map(enrichDataset)
      const html = renderPage(enriched)
      const outputPath = args[1] ?? 'statistics-report.html'
      await Bun.write(outputPath, html)
      console.log(`Report written to ${outputPath}`)
      break
    }

    case 'clear': {
      await saveDatasets([])
      console.log('All datasets cleared')
      break
    }

    default:
      console.error(`Unknown command: ${command}`)
      printUsage()
      process.exit(1)
  }
}

run().catch(err => {
  console.error('Error:', err instanceof Error ? err.message : err)
  process.exit(1)
})

export { enrichDataset, formatStats }
export type { DatasetWithStats }

