import type { Playlist, Song, AppState, PlaybackState } from './types'

const DATA_PATH = `${import.meta.dir}/data/playlists.json`

const defaultPlayback: PlaybackState = {
  currentPlaylistId: null,
  currentSongIndex: 0,
  isPlaying: false,
  shuffle: false,
  repeat: 'none',
  elapsed: 0,
  shuffleOrder: [],
}

const generateId = (): string => crypto.randomUUID()

const loadPlaylists = async (): Promise<Playlist[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  const text = await file.text()
  return JSON.parse(text) as Playlist[]
}

const savePlaylists = async (playlists: Playlist[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(playlists, null, 2))
}

const createAppState = async (): Promise<AppState> => ({
  playlists: await loadPlaylists(),
  playback: { ...defaultPlayback },
  activePlaylistId: null,
})

const createPlaylist = async (state: AppState, name: string): Promise<AppState> => {
  const now = new Date().toISOString()
  const playlist: Playlist = {
    id: generateId(),
    name,
    songs: [],
    createdAt: now,
    updatedAt: now,
  }
  const playlists = [...state.playlists, playlist]
  await savePlaylists(playlists)
  return { ...state, playlists, activePlaylistId: playlist.id }
}

const deletePlaylist = async (state: AppState, playlistId: string): Promise<AppState> => {
  const playlists = state.playlists.filter((p) => p.id !== playlistId)
  await savePlaylists(playlists)
  const activePlaylistId = state.activePlaylistId === playlistId ? null : state.activePlaylistId
  const playback =
    state.playback.currentPlaylistId === playlistId ? { ...defaultPlayback } : state.playback
  return { ...state, playlists, activePlaylistId, playback }
}

const renamePlaylist = async (
  state: AppState,
  playlistId: string,
  name: string
): Promise<AppState> => {
  const playlists = state.playlists.map((p) =>
    p.id === playlistId ? { ...p, name, updatedAt: new Date().toISOString() } : p
  )
  await savePlaylists(playlists)
  return { ...state, playlists }
}

const addSong = async (
  state: AppState,
  playlistId: string,
  song: Omit<Song, 'id'>
): Promise<AppState> => {
  const newSong: Song = { ...song, id: generateId() }
  const playlists = state.playlists.map((p) =>
    p.id === playlistId
      ? { ...p, songs: [...p.songs, newSong], updatedAt: new Date().toISOString() }
      : p
  )
  await savePlaylists(playlists)
  return { ...state, playlists }
}

const removeSong = async (
  state: AppState,
  playlistId: string,
  songId: string
): Promise<AppState> => {
  const playlists = state.playlists.map((p) =>
    p.id === playlistId
      ? {
          ...p,
          songs: p.songs.filter((s) => s.id !== songId),
          updatedAt: new Date().toISOString(),
        }
      : p
  )
  await savePlaylists(playlists)
  return { ...state, playlists }
}

const reorderSongs = async (
  state: AppState,
  playlistId: string,
  fromIndex: number,
  toIndex: number
): Promise<AppState> => {
  const playlist = state.playlists.find((p) => p.id === playlistId)
  if (!playlist) return state
  const songs = [...playlist.songs]
  const [moved] = songs.splice(fromIndex, 1)
  songs.splice(toIndex, 0, moved)
  const playlists = state.playlists.map((p) =>
    p.id === playlistId ? { ...p, songs, updatedAt: new Date().toISOString() } : p
  )
  await savePlaylists(playlists)
  return { ...state, playlists }
}

const generateShuffleOrder = (length: number, currentIndex: number): number[] => {
  const indices = Array.from({ length }, (_, i) => i).filter((i) => i !== currentIndex)
  for (let i = indices.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1))
    ;[indices[i], indices[j]] = [indices[j], indices[i]]
  }
  return [currentIndex, ...indices]
}

const playSong = (state: AppState, playlistId: string, songIndex: number): AppState => {
  const playlist = state.playlists.find((p) => p.id === playlistId)
  if (!playlist || songIndex < 0 || songIndex >= playlist.songs.length) return state
  const shuffleOrder = state.playback.shuffle
    ? generateShuffleOrder(playlist.songs.length, songIndex)
    : []
  return {
    ...state,
    playback: {
      ...state.playback,
      currentPlaylistId: playlistId,
      currentSongIndex: songIndex,
      isPlaying: true,
      elapsed: 0,
      shuffleOrder,
    },
  }
}

const togglePlay = (state: AppState): AppState => ({
  ...state,
  playback: { ...state.playback, isPlaying: !state.playback.isPlaying },
})

const getNextIndex = (state: AppState): number | null => {
  const { playback } = state
  const playlist = state.playlists.find((p) => p.id === playback.currentPlaylistId)
  if (!playlist || playlist.songs.length === 0) return null

  if (playback.repeat === 'one') return playback.currentSongIndex

  if (playback.shuffle && playback.shuffleOrder.length > 0) {
    const currentShufflePos = playback.shuffleOrder.indexOf(playback.currentSongIndex)
    const nextShufflePos = currentShufflePos + 1
    if (nextShufflePos < playback.shuffleOrder.length) {
      return playback.shuffleOrder[nextShufflePos]
    }
    return playback.repeat === 'all' ? playback.shuffleOrder[0] : null
  }

  const next = playback.currentSongIndex + 1
  if (next < playlist.songs.length) return next
  return playback.repeat === 'all' ? 0 : null
}

const getPrevIndex = (state: AppState): number | null => {
  const { playback } = state
  const playlist = state.playlists.find((p) => p.id === playback.currentPlaylistId)
  if (!playlist || playlist.songs.length === 0) return null

  if (playback.shuffle && playback.shuffleOrder.length > 0) {
    const currentShufflePos = playback.shuffleOrder.indexOf(playback.currentSongIndex)
    const prevShufflePos = currentShufflePos - 1
    if (prevShufflePos >= 0) return playback.shuffleOrder[prevShufflePos]
    return playback.repeat === 'all'
      ? playback.shuffleOrder[playback.shuffleOrder.length - 1]
      : null
  }

  const prev = playback.currentSongIndex - 1
  if (prev >= 0) return prev
  return playback.repeat === 'all' ? playlist.songs.length - 1 : null
}

const skipNext = (state: AppState): AppState => {
  const nextIndex = getNextIndex(state)
  if (nextIndex === null) return { ...state, playback: { ...state.playback, isPlaying: false } }
  return {
    ...state,
    playback: { ...state.playback, currentSongIndex: nextIndex, elapsed: 0 },
  }
}

const skipPrev = (state: AppState): AppState => {
  if (state.playback.elapsed > 3) {
    return { ...state, playback: { ...state.playback, elapsed: 0 } }
  }
  const prevIndex = getPrevIndex(state)
  if (prevIndex === null) return { ...state, playback: { ...state.playback, elapsed: 0 } }
  return {
    ...state,
    playback: { ...state.playback, currentSongIndex: prevIndex, elapsed: 0 },
  }
}

const toggleShuffle = (state: AppState): AppState => {
  const shuffle = !state.playback.shuffle
  const playlist = state.playlists.find((p) => p.id === state.playback.currentPlaylistId)
  const shuffleOrder =
    shuffle && playlist
      ? generateShuffleOrder(playlist.songs.length, state.playback.currentSongIndex)
      : []
  return {
    ...state,
    playback: { ...state.playback, shuffle, shuffleOrder },
  }
}

const cycleRepeat = (state: AppState): AppState => {
  const modes: Array<'none' | 'all' | 'one'> = ['none', 'all', 'one']
  const current = modes.indexOf(state.playback.repeat)
  const next = modes[(current + 1) % modes.length]
  return { ...state, playback: { ...state.playback, repeat: next } }
}

const seekTo = (state: AppState, seconds: number): AppState => ({
  ...state,
  playback: { ...state.playback, elapsed: Math.max(0, seconds) },
})

const getCurrentSong = (state: AppState): Song | null => {
  const { playback } = state
  const playlist = state.playlists.find((p) => p.id === playback.currentPlaylistId)
  if (!playlist) return null
  return playlist.songs[playback.currentSongIndex] ?? null
}

