const formatDuration = (seconds: number): string => {
  const mins = Math.floor(seconds / 60)
  const secs = Math.floor(seconds % 60)
  return `${mins}:${secs.toString().padStart(2, '0')}`
}

const formatTotalDuration = (songs: Song[]): string => {
  const total = songs.reduce((sum, s) => sum + s.duration, 0)
  const hours = Math.floor(total / 3600)
  const mins = Math.floor((total % 3600) / 60)
  if (hours > 0) return `${hours} hr ${mins} min`
  return `${mins} min`
}

const repeatLabel = (mode: RepeatMode): string => {
  if (mode === 'all') return 'Repeat All'
  if (mode === 'one') return 'Repeat One'
  return 'Repeat'
}

const repeatIcon = (mode: RepeatMode): string => {
  if (mode === 'one') return '\u{1F502}'
  return '\u{1F501}'
}

