      'Create a playlist or select one from the sidebar'
    )
  )

const renderNowPlayingBar = (state: AppState): string => {
  const song = getCurrentSong(state)
  const { playback } = state

  const art = song
    ? song.albumArtUrl
      ? h('img', { src: song.albumArtUrl, style: styleStr(styles.nowPlayingArt), alt: song.album })
      : h('div', { style: styleStr(styles.nowPlayingArtPlaceholder) }, '\u{1F3B5}')
    : h('div', { style: styleStr(styles.nowPlayingArtPlaceholder) }, '')

  const info = song
    ? h('div', { style: styleStr(styles.nowPlayingText) },
        h('div', { style: styleStr(styles.nowPlayingTitle) }, song.title),
        h('div', { style: styleStr(styles.nowPlayingArtist) }, `${song.artist} \u{2014} ${song.album}`)
      )
    : h('div', { style: styleStr(styles.nowPlayingText) },
        h('div', { style: styleStr(styles.nowPlayingTitle) }, ''),
        h('div', { style: styleStr(styles.nowPlayingArtist) }, '')
      )

  const duration = song ? song.duration : 0
  const pct = duration > 0 ? (playback.elapsed / duration) * 100 : 0

  const shuffleStyle = {
    ...styles.controlBtn,
    ...(playback.shuffle ? styles.controlBtnActive : {}),
  }
  const repeatStyle = {
    ...styles.controlBtn,
    ...(playback.repeat !== 'none' ? styles.controlBtnActive : {}),
  }

  return h('div', { style: styleStr(styles.nowPlayingBar), 'p-target': 'nowPlaying' },
    h('div', { style: styleStr(styles.nowPlayingInfo) }, art, info),
    h('div', { style: styleStr(styles.controls) },
      h('div', { style: styleStr(styles.controlButtons) },
        h('button', {
          style: styleStr(shuffleStyle),
          'p-trigger': 'toggleShuffle',
          title: playback.shuffle ? 'Shuffle On' : 'Shuffle Off',
        }, '\u{1F500}'),
        h('button', {
          style: styleStr(styles.controlBtn),
          'p-trigger': 'skipPrev',
          title: 'Previous',
        }, '\u{23EE}'),
        h('button', {
          style: styleStr(styles.playBtn),
          'p-trigger': 'togglePlay',
          title: playback.isPlaying ? 'Pause' : 'Play',
        }, playback.isPlaying ? '\u{23F8}' : '\u{25B6}'),
        h('button', {
          style: styleStr(styles.controlBtn),
          'p-trigger': 'skipNext',
          title: 'Next',
        }, '\u{23ED}'),
        h('button', {
          style: styleStr(repeatStyle),
          'p-trigger': 'cycleRepeat',
          title: repeatLabel(playback.repeat),
        }, repeatIcon(playback.repeat))
      ),
      h('div', { style: styleStr(styles.progressContainer) },
        h('span', { style: styleStr(styles.progressTime) }, formatDuration(playback.elapsed)),
        h('div', {
          style: styleStr(styles.progressBar),
          'p-trigger': 'seekProgress',
          'p-target': 'progressBar',
        },
          h('div', {
            style: styleStr({
              ...styles.progressFill,
              width: `${Math.min(100, pct)}%`,
            }),
            'p-target': 'progressFill',
          })
        ),
        h('span', {
          style: styleStr({ ...styles.progressTime, ...styles.progressTimeRight }),
        }, song ? formatDuration(duration) : '--:--')
      )
    ),
    h('div', { style: styleStr(styles.extraControls) })
  )
}

const renderApp = (state: AppState, addSongExpanded: boolean): string => {
  const activePlaylist = state.playlists.find((p) => p.id === state.activePlaylistId)

  const mainContent = activePlaylist
    ? renderPlaylistView(state, activePlaylist, addSongExpanded)
    : renderEmptyState()

  return h('div', { style: styleStr(styles.root) },
    renderSidebar(state),
    h('main', { style: styleStr(styles.mainContent) }, mainContent),
    renderNowPlayingBar(state)
  )
}

export { renderApp, formatDuration }

import type { AppState, Song } from './types'
import {
  createAppState,
  createPlaylist,
  deletePlaylist,
  renamePlaylist,
  addSong,
  removeSong,
  reorderSongs,
  playSong,
  togglePlay,
  skipNext,
  skipPrev,
  toggleShuffle,
  cycleRepeat,
  seekTo,
  getCurrentSong,
} from './store'

type ActionResult = {
  state: AppState
  addSongExpanded: boolean
}

type ActionContext = {
  state: AppState
  addSongExpanded: boolean
}

const handleCreatePlaylist = async (ctx: ActionContext): Promise<ActionResult> => {
  const name = `New Playlist ${ctx.state.playlists.length + 1}`
  const state = await createPlaylist(ctx.state, name)
  return { state, addSongExpanded: false }
}

const handleDeletePlaylist = async (
  ctx: ActionContext,
  playlistId: string
): Promise<ActionResult> => {
  const state = await deletePlaylist(ctx.state, playlistId)
  return { state, addSongExpanded: false }
}

const handleSelectPlaylist = (
  ctx: ActionContext,
  playlistId: string
): ActionResult => ({
  state: { ...ctx.state, activePlaylistId: playlistId },
  addSongExpanded: false,
})

const handleRenamePlaylist = async (
  ctx: ActionContext,
  playlistId: string,
  newName: string
): Promise<ActionResult> => {
  if (!newName.trim()) return ctx
  const state = await renamePlaylist(ctx.state, playlistId, newName.trim())
  return { ...ctx, state }
}

const handleAddSong = async (
  ctx: ActionContext,
  playlistId: string,
  songData: Omit<Song, 'id'>
): Promise<ActionResult> => {
  const state = await addSong(ctx.state, playlistId, songData)
  return { state, addSongExpanded: true }
}

const handleRemoveSong = async (
  ctx: ActionContext,
  playlistId: string,
  songId: string
): Promise<ActionResult> => {
  const state = await removeSong(ctx.state, playlistId, songId)
  return { ...ctx, state }
}

const handleReorderSongs = async (
  ctx: ActionContext,
  playlistId: string,
  fromIndex: number,
  toIndex: number
): Promise<ActionResult> => {
  const state = await reorderSongs(ctx.state, playlistId, fromIndex, toIndex)
  return { ...ctx, state }
}

const handlePlaySong = (
  ctx: ActionContext,
  songIndex: number
): ActionResult => {
  const playlistId = ctx.state.activePlaylistId
  if (!playlistId) return ctx
  const state = playSong(ctx.state, playlistId, songIndex)
  return { ...ctx, state }
}

const handleTogglePlay = (ctx: ActionContext): ActionResult => ({
  ...ctx,
  state: togglePlay(ctx.state),
})

const handleSkipNext = (ctx: ActionContext): ActionResult => ({
  ...ctx,
  state: skipNext(ctx.state),
})

const handleSkipPrev = (ctx: ActionContext): ActionResult => ({
  ...ctx,
  state: skipPrev(ctx.state),
})

const handleToggleShuffle = (ctx: ActionContext): ActionResult => ({
  ...ctx,
  state: toggleShuffle(ctx.state),
})

const handleCycleRepeat = (ctx: ActionContext): ActionResult => ({
  ...ctx,
  state: cycleRepeat(ctx.state),
})

const handleSeek = (ctx: ActionContext, seconds: number): ActionResult => ({
  ...ctx,
  state: seekTo(ctx.state, seconds),
})

const handleToggleAddSong = (ctx: ActionContext): ActionResult => ({
  ...ctx,
  addSongExpanded: !ctx.addSongExpanded,
})

const handleTickPlayback = (ctx: ActionContext): ActionResult => {
  if (!ctx.state.playback.isPlaying) return ctx
  const song = getCurrentSong(ctx.state)
  if (!song) return ctx

  const newElapsed = ctx.state.playback.elapsed + 1
  if (newElapsed >= song.duration) {
    const nextState = skipNext(ctx.state)
    return { ...ctx, state: nextState }
  }

  return {
    ...ctx,
    state: seekTo(ctx.state, newElapsed),
  }
}

