import { createSSR } from 'plaited'
import { renderApp } from './components'
import { createAppState } from './store'
import type { AppState, Song } from './types'
import type { ActionContext, ActionResult } from './handlers'
import {
  handleCreatePlaylist,
  handleDeletePlaylist,
  handleSelectPlaylist,
  handleRenamePlaylist,
  handleAddSong,
  handleRemoveSong,
  handleReorderSongs,
  handlePlaySong,
  handleTogglePlay,
  handleSkipNext,
  handleSkipPrev,
  handleToggleShuffle,
  handleCycleRepeat,
  handleSeek,
  handleToggleAddSong,
  handleTickPlayback,
} from './handlers'

type ServerState = {
  app: AppState
  addSongExpanded: boolean
}

let serverState: ServerState | null = null

const getState = async (): Promise<ServerState> => {
  if (!serverState) {
    serverState = {
      app: await createAppState(),
      addSongExpanded: false,
    }
  }
  return serverState
}

const ctx = (s: ServerState): ActionContext => ({
  state: s.app,
  addSongExpanded: s.addSongExpanded,
})

const applyResult = (result: ActionResult): ServerState => {
  const newState: ServerState = {
    app: result.state,
    addSongExpanded: result.addSongExpanded,
  }
  serverState = newState
  return newState
}

const renderPage = (state: ServerState): string => {
  const ssr = createSSR()
  const appHtml = renderApp(state.app, state.addSongExpanded)

  const clientScript = `
    <script>
      // Drag-and-drop reordering
      let dragSrcIndex = null;

      document.addEventListener('dragstart', (e) => {
        const row = e.target.closest('[data-song-index]');
        if (!row) return;
        dragSrcIndex = parseInt(row.dataset.songIndex, 10);
        e.target.style.opacity = '0.5';
        e.dataTransfer.effectAllowed = 'move';
        e.dataTransfer.setData('text/plain', dragSrcIndex);
      });

      document.addEventListener('dragover', (e) => {
        const row = e.target.closest('[data-song-index]');
        if (!row) return;
        e.preventDefault();
        e.dataTransfer.dropEffect = 'move';
        row.style.borderTop = '2px solid #1db954';
      });

      document.addEventListener('dragleave', (e) => {
        const row = e.target.closest('[data-song-index]');
        if (row) row.style.borderTop = '';
      });

      document.addEventListener('dragend', (e) => {
        e.target.style.opacity = '';
        document.querySelectorAll('[data-song-index]').forEach(r => r.style.borderTop = '');
      });

      document.addEventListener('drop', (e) => {
        e.preventDefault();
        const row = e.target.closest('[data-song-index]');
        if (!row) return;
        row.style.borderTop = '';
        const toIndex = parseInt(row.dataset.songIndex, 10);
        if (dragSrcIndex !== null && dragSrcIndex !== toIndex) {
          fetch('/api/reorder', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ fromIndex: dragSrcIndex, toIndex }),
          }).then(() => location.reload());
        }
        dragSrcIndex = null;
      });

      // Click handlers via p-trigger
      document.addEventListener('click', (e) => {
        const el = e.target.closest('[p-trigger]');
        if (!el) return;
        const trigger = el.getAttribute('p-trigger');
        const [action, param] = trigger.split(':');

        const actions = {
          createPlaylist: () => fetch('/api/playlist', { method: 'POST' }).then(() => location.reload()),
          deletePlaylist: () => {
            if (confirm('Delete this playlist?')) {
              fetch('/api/playlist/' + param, { method: 'DELETE' }).then(() => location.reload());
            }
          },
          selectPlaylist: () => fetch('/api/select/' + param, { method: 'POST' }).then(() => location.reload()),
          renamePlaylist: () => {
            const name = prompt('Rename playlist:', el.textContent);
            if (name) fetch('/api/playlist/' + param + '/rename', {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({ name }),
            }).then(() => location.reload());
          },
          playSong: () => fetch('/api/play/' + param, { method: 'POST' }).then(() => location.reload()),
          togglePlay: () => fetch('/api/toggle-play', { method: 'POST' }).then(() => location.reload()),
          skipNext: () => fetch('/api/skip-next', { method: 'POST' }).then(() => location.reload()),
          skipPrev: () => fetch('/api/skip-prev', { method: 'POST' }).then(() => location.reload()),
          toggleShuffle: () => fetch('/api/shuffle', { method: 'POST' }).then(() => location.reload()),
          cycleRepeat: () => fetch('/api/repeat', { method: 'POST' }).then(() => location.reload()),
          toggleAddSong: () => fetch('/api/toggle-add-song', { method: 'POST' }).then(() => location.reload()),
        };

        if (actions[action]) {
          e.preventDefault();
          e.stopPropagation();
          actions[action]();
        }
      });

      // Form submit for add song
      document.addEventListener('submit', (e) => {
        const form = e.target.closest('form[p-trigger]');
        if (!form) return;
        e.preventDefault();
        const trigger = form.getAttribute('p-trigger');
        const [action, playlistId] = trigger.split(':');
        if (action !== 'submitSong') return;

        const fd = new FormData(form);
        const mins = parseInt(fd.get('durationMinutes') || '0', 10);
        const secs = parseInt(fd.get('durationSeconds') || '0', 10);
        fetch('/api/playlist/' + playlistId + '/songs', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            title: fd.get('title'),
            artist: fd.get('artist'),
            album: fd.get('album') || 'Unknown Album',
            duration: mins * 60 + secs,
            albumArtUrl: fd.get('albumArtUrl') || '',
          }),
        }).then(() => location.reload());
      });

      // Progress bar seek
      document.addEventListener('click', (e) => {
        const bar = e.target.closest('[p-trigger="seekProgress"]');
        if (!bar) return;
        const rect = bar.getBoundingClientRect();
        const pct = (e.clientX - rect.left) / rect.width;
        fetch('/api/seek', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ pct }),
        }).then(() => location.reload());
      });

      // Simulated playback tick
      setInterval(() => {
        fetch('/api/tick', { method: 'POST' }).then(r => r.json()).then(data => {
          if (data.changed) location.reload();
        });
      }, 1000);
    </script>
  `

  return ssr(
    `<!DOCTYPE html>
    <html lang="en">
    <head>
      <meta charset="UTF-8">
      <meta name="viewport" content="width=device-width, initial-scale=1.0">
      <title>Playlist Manager</title>
      <style>
        * { margin: 0; padding: 0; box-sizing: border-box; }
        body { overflow: hidden; }
        ::-webkit-scrollbar { width: 8px; }
        ::-webkit-scrollbar-track { background: transparent; }
        ::-webkit-scrollbar-thumb { background: #333; border-radius: 4px; }
        ::-webkit-scrollbar-thumb:hover { background: #555; }
        button:hover { filter: brightness(1.2); }
        [draggable="true"] { user-select: none; }
        [draggable="true"]:hover { background: #1a1a1a; }
      </style>
    </head>
    <body>
      ${appHtml}
      ${clientScript}
    </body>
    </html>`
  )
}

const parseSongBody = (body: unknown): Omit<Song, 'id'> => {
  const b = body as Record<string, unknown>
  return {
    title: String(b.title || ''),
    artist: String(b.artist || ''),
    album: String(b.album || 'Unknown Album'),
    duration: Number(b.duration) || 0,
    albumArtUrl: String(b.albumArtUrl || ''),
  }
}

const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url)
    const path = url.pathname
    const method = req.method

    // API routes
    if (path.startsWith('/api/')) {
      const state = await getState()

      if (path === '/api/playlist' && method === 'POST') {
        const result = await handleCreatePlaylist(ctx(state))
        applyResult(result)
        return Response.json({ ok: true })
      }

      const deleteMatch = path.match(/^\/api\/playlist\/(.+)$/)
      if (deleteMatch && method === 'DELETE') {
        const result = await handleDeletePlaylist(ctx(state), deleteMatch[1])
        applyResult(result)
        return Response.json({ ok: true })
      }

      const renameMatch = path.match(/^\/api\/playlist\/(.+)\/rename$/)
      if (renameMatch && method === 'POST') {
        const body = (await req.json()) as { name: string }
        const result = await handleRenamePlaylist(ctx(state), renameMatch[1], body.name)
        applyResult(result)
        return Response.json({ ok: true })
      }

      const songsMatch = path.match(/^\/api\/playlist\/(.+)\/songs$/)
      if (songsMatch && method === 'POST') {
        const body = await req.json()
        const songData = parseSongBody(body)
        const result = await handleAddSong(ctx(state), songsMatch[1], songData)
        applyResult(result)
        return Response.json({ ok: true })
      }

      const selectMatch = path.match(/^\/api\/select\/(.+)$/)
      if (selectMatch && method === 'POST') {
        const result = handleSelectPlaylist(ctx(state), selectMatch[1])
        applyResult(result)
        return Response.json({ ok: true })
      }

      const playMatch = path.match(/^\/api\/play\/(\d+)$/)
      if (playMatch && method === 'POST') {
        const result = handlePlaySong(ctx(state), parseInt(playMatch[1], 10))
        applyResult(result)
        return Response.json({ ok: true })
      }

      if (path === '/api/toggle-play' && method === 'POST') {
        const result = handleTogglePlay(ctx(state))
        applyResult(result)
        return Response.json({ ok: true })
      }

      if (path === '/api/skip-next' && method === 'POST') {
        const result = handleSkipNext(ctx(state))
        applyResult(result)
        return Response.json({ ok: true })
      }

      if (path === '/api/skip-prev' && method === 'POST') {
        const result = handleSkipPrev(ctx(state))
        applyResult(result)
        return Response.json({ ok: true })
      }

      if (path === '/api/shuffle' && method === 'POST') {
        const result = handleToggleShuffle(ctx(state))
        applyResult(result)
        return Response.json({ ok: true })
      }

      if (path === '/api/repeat' && method === 'POST') {
        const result = handleCycleRepeat(ctx(state))
        applyResult(result)
        return Response.json({ ok: true })
      }

      if (path === '/api/toggle-add-song' && method === 'POST') {
        const result = handleToggleAddSong(ctx(state))
        applyResult(result)
        return Response.json({ ok: true })
      }

      if (path === '/api/reorder' && method === 'POST') {
        const body = (await req.json()) as { fromIndex: number; toIndex: number }
        const playlistId = state.app.activePlaylistId
        if (playlistId) {
          const result = await handleReorderSongs(
            ctx(state),
            playlistId,
            body.fromIndex,
            body.toIndex
          )
          applyResult(result)
        }
        return Response.json({ ok: true })
      }

      if (path === '/api/seek' && method === 'POST') {
        const body = (await req.json()) as { pct: number }
        const { getCurrentSong } = await import('./store')
        const song = getCurrentSong(state.app)
        if (song) {
          const seconds = Math.floor(body.pct * song.duration)
          const result = handleSeek(ctx(state), seconds)
          applyResult(result)
        }
        return Response.json({ ok: true })
      }

      if (path === '/api/tick' && method === 'POST') {
        const before = state.app.playback.elapsed
        const result = handleTickPlayback(ctx(state))
        const changed =
          result.state.playback.elapsed !== before ||
          result.state.playback.currentSongIndex !== state.app.playback.currentSongIndex ||
          result.state.playback.isPlaying !== state.app.playback.isPlaying
        applyResult(result)
        return Response.json({ ok: true, changed })
      }

      return Response.json({ error: 'Not found' }, { status: 404 })
    }

    // Serve the page
    const state = await getState()
    const html = renderPage(state)
    return new Response(html, {
      headers: { 'Content-Type': 'text/html; charset=utf-8' },
    })
  },
})

