export type Song = {
  id: string
  title: string
  artist: string
  album: string
  duration: number
  albumArtUrl: string
}

export type Playlist = {
  id: string
  name: string
  createdAt: string
  songs: Song[]
}

export type PlaylistStore = {
  playlists: Playlist[]
}

export type RepeatMode = 'off' | 'all' | 'one'

export type PlayerState = {
  currentPlaylistId: string | null
  currentSongIndex: number
  isPlaying: boolean
  shuffle: boolean
  repeat: RepeatMode
  elapsed: number
  shuffleOrder: number[]
}

export type AddSongInput = {
  title: string
  artist: string
  album: string
  duration: number
  albumArtUrl: string
}

export type ReorderInput = {
  fromIndex: number
  toIndex: number
}

import type { Playlist, PlaylistStore, Song, AddSongInput, ReorderInput } from './types'

const DATA_PATH = `${import.meta.dir}/data/playlists.json`

const readStore = async (): Promise<PlaylistStore> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return { playlists: [] }
  return file.json()
}

const writeStore = async (store: PlaylistStore): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(store, null, 2))
}

const generateId = (): string =>
  `${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`

export const getPlaylists = async (): Promise<Playlist[]> => {
  const store = await readStore()
  return store.playlists
}

export const getPlaylist = async (id: string): Promise<Playlist | null> => {
  const store = await readStore()
  return store.playlists.find((p) => p.id === id) ?? null
}

export const createPlaylist = async (name: string): Promise<Playlist> => {
  const store = await readStore()
  const playlist: Playlist = {
    id: generateId(),
    name,
    createdAt: new Date().toISOString(),
    songs: [],
  }
  store.playlists.push(playlist)
  await writeStore(store)
  return playlist
}

export const deletePlaylist = async (id: string): Promise<boolean> => {
  const store = await readStore()
  const index = store.playlists.findIndex((p) => p.id === id)
  if (index === -1) return false
  store.playlists.splice(index, 1)
  await writeStore(store)
  return true
}

export const renamePlaylist = async (id: string, name: string): Promise<Playlist | null> => {
  const store = await readStore()
  const playlist = store.playlists.find((p) => p.id === id)
  if (!playlist) return null
  playlist.name = name
  await writeStore(store)
  return playlist
}

export const addSong = async (playlistId: string, input: AddSongInput): Promise<Song | null> => {
  const store = await readStore()
  const playlist = store.playlists.find((p) => p.id === playlistId)
  if (!playlist) return null
  const song: Song = { id: generateId(), ...input }
  playlist.songs.push(song)
  await writeStore(store)
  return song
}

export const removeSong = async (playlistId: string, songId: string): Promise<boolean> => {
  const store = await readStore()
  const playlist = store.playlists.find((p) => p.id === playlistId)
  if (!playlist) return false
  const index = playlist.songs.findIndex((s) => s.id === songId)
  if (index === -1) return false
  playlist.songs.splice(index, 1)
  await writeStore(store)
  return true
}

export const reorderSong = async (playlistId: string, input: ReorderInput): Promise<boolean> => {
  const store = await readStore()
  const playlist = store.playlists.find((p) => p.id === playlistId)
  if (!playlist) return false
  const { fromIndex, toIndex } = input
  if (fromIndex < 0 || fromIndex >= playlist.songs.length) return false
  if (toIndex < 0 || toIndex >= playlist.songs.length) return false
  const [song] = playlist.songs.splice(fromIndex, 1)
  playlist.songs.splice(toIndex, 0, song)
  await writeStore(store)
  return true
}

import type { PlayerState, RepeatMode, Song } from './types'
import { getPlaylist } from './store'

let state: PlayerState = {
  currentPlaylistId: null,
  currentSongIndex: 0,
  isPlaying: false,
  shuffle: false,
  repeat: 'off',
  elapsed: 0,
  shuffleOrder: [],
}

const generateShuffleOrder = (length: number, currentIndex: number): number[] => {
  const indices = Array.from({ length }, (_, i) => i).filter((i) => i !== currentIndex)
  for (let i = indices.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1))
    ;[indices[i], indices[j]] = [indices[j], indices[i]]
  }
  return [currentIndex, ...indices]
}

export const getPlayerState = (): PlayerState => ({ ...state })

export const loadPlaylist = (playlistId: string, startIndex = 0): void => {
  state = {
    currentPlaylistId: playlistId,
    currentSongIndex: startIndex,
    isPlaying: false,
    shuffle: false,
    repeat: 'off',
    elapsed: 0,
    shuffleOrder: [],
  }
}

export const play = (): void => {
  state.isPlaying = true
}

export const pause = (): void => {
  state.isPlaying = false
}

export const togglePlayPause = (): void => {
  state.isPlaying = !state.isPlaying
}

export const setElapsed = (seconds: number): void => {
  state.elapsed = Math.max(0, seconds)
}

export const getCurrentSong = async (): Promise<Song | null> => {
  if (!state.currentPlaylistId) return null
  const playlist = await getPlaylist(state.currentPlaylistId)
  if (!playlist || playlist.songs.length === 0) return null

  const effectiveIndex = state.shuffle
    ? state.shuffleOrder[state.currentSongIndex] ?? state.currentSongIndex
    : state.currentSongIndex

  return playlist.songs[effectiveIndex] ?? null
}

export const skipNext = async (): Promise<Song | null> => {
  if (!state.currentPlaylistId) return null
  const playlist = await getPlaylist(state.currentPlaylistId)
  if (!playlist || playlist.songs.length === 0) return null

  const totalSongs = playlist.songs.length

  if (state.repeat === 'one') {
    state.elapsed = 0
    return getCurrentSong()
  }

  const nextIndex = state.currentSongIndex + 1

  if (nextIndex >= totalSongs) {
    if (state.repeat === 'all') {
      state.currentSongIndex = 0
      if (state.shuffle) {
        state.shuffleOrder = generateShuffleOrder(totalSongs, 0)
      }
    } else {
      state.isPlaying = false
      return null
    }
  } else {
    state.currentSongIndex = nextIndex
  }

  state.elapsed = 0
  return getCurrentSong()
}

export const skipPrevious = async (): Promise<Song | null> => {
  if (!state.currentPlaylistId) return null
  const playlist = await getPlaylist(state.currentPlaylistId)
  if (!playlist || playlist.songs.length === 0) return null

  if (state.elapsed > 3) {
    state.elapsed = 0
    return getCurrentSong()
  }

  const prevIndex = state.currentSongIndex - 1
  if (prevIndex < 0) {
    if (state.repeat === 'all') {
      state.currentSongIndex = playlist.songs.length - 1
    } else {
      state.elapsed = 0
      return getCurrentSong()
    }
  } else {
    state.currentSongIndex = prevIndex
  }

  state.elapsed = 0
  return getCurrentSong()
}

export const toggleShuffle = async (): Promise<void> => {
  state.shuffle = !state.shuffle
  if (state.shuffle && state.currentPlaylistId) {
    const playlist = await getPlaylist(state.currentPlaylistId)
    if (playlist) {
      state.shuffleOrder = generateShuffleOrder(playlist.songs.length, state.currentSongIndex)
    }
  }
}

export const cycleRepeat = (): RepeatMode => {
  const modes: RepeatMode[] = ['off', 'all', 'one']
  const currentIdx = modes.indexOf(state.repeat)
  state.repeat = modes[(currentIdx + 1) % modes.length]
  return state.repeat
}

export const playSongAtIndex = (index: number): void => {
  state.currentSongIndex = index
  state.elapsed = 0
  state.isPlaying = true
}

export const formatDuration = (seconds: number): string => {
  const mins = Math.floor(seconds / 60)
  const secs = Math.floor(seconds % 60)
  return `${mins}:${secs.toString().padStart(2, '0')}`
}

export const formatTotalDuration = (songs: { duration: number }[]): string => {
  const total = songs.reduce((sum, s) => sum + s.duration, 0)
  const hours = Math.floor(total / 3600)
  const mins = Math.floor((total % 3600) / 60)
  if (hours > 0) return `${hours} hr ${mins} min`
  return `${mins} min`
}

