const styleStr = (obj: Record<string, string | number>): string =>
  Object.entries(obj)
    .map(([k, v]) => {
      const kebab = k.replace(/[A-Z]/g, (m) => `-${m.toLowerCase()}`)
      return `${kebab}:${typeof v === 'number' && !kebab.includes('flex') && !kebab.includes('z-index') && !kebab.includes('opacity') && !kebab.includes('font-weight') && !kebab.includes('line-height') ? `${v}px` : v}`
    })
    .join(';')

