// Client-side script for playlist manager interactivity
// Injected into the HTML page as a <script> block

export const clientScript = `
<script>
(function() {
  let dragSrcIndex = null;
  let playbackTimer = null;

  // Navigation
  document.addEventListener('click', async (e) => {
    const trigger = e.target.closest('[p-trigger]');
    if (!trigger) return;

    const action = trigger.getAttribute('p-trigger');

    // Select playlist
    if (action.startsWith('select-playlist:')) {
      const id = action.split(':')[1];
      window.location.href = '/playlists/' + id;
      return;
    }

    // Play entire playlist
    if (action.startsWith('play-playlist:')) {
      const id = action.split(':')[1];
      const res = await fetch('/api/player/load', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ playlistId: id, startIndex: 0 }),
      });
      if (res.ok) {
        await fetch('/api/player/play', { method: 'POST' });
        window.location.reload();
      }
      return;
    }

    // Play specific song
    if (action.startsWith('play-song:')) {
      const index = parseInt(action.split(':')[1], 10);
      const playlistId = document.querySelector('[data-active-playlist]')?.getAttribute('data-active-playlist');
      if (!playlistId) return;
      await fetch('/api/player/load', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ playlistId, startIndex: index }),
      });
      await fetch('/api/player/play', { method: 'POST' });
      window.location.reload();
      return;
    }

    // Remove song
    if (action.startsWith('remove-song:')) {
      e.stopPropagation();
      const songId = action.split(':')[1];
      const playlistId = document.querySelector('[data-active-playlist]')?.getAttribute('data-active-playlist');
      if (!playlistId) return;
      await fetch('/api/playlists/' + playlistId + '/songs/' + songId, { method: 'DELETE' });
      window.location.reload();
      return;
    }

    // Transport controls
    if (action === 'toggle-play') {
      await fetch('/api/player/toggle', { method: 'POST' });
      window.location.reload();
      return;
    }

    if (action === 'skip-next') {
      await fetch('/api/player/next', { method: 'POST' });
      window.location.reload();
      return;
    }

    if (action === 'skip-previous') {
      await fetch('/api/player/previous', { method: 'POST' });
      window.location.reload();
      return;
    }

    if (action === 'toggle-shuffle') {
      await fetch('/api/player/shuffle', { method: 'POST' });
      window.location.reload();
      return;
    }

    if (action === 'cycle-repeat') {
      await fetch('/api/player/repeat', { method: 'POST' });
      window.location.reload();
      return;
    }

    // Modals
    if (action === 'add-song') {
      document.getElementById('add-song-modal').style.display = 'flex';
      return;
    }

    if (action === 'create-playlist') {
      document.getElementById('create-playlist-modal').style.display = 'flex';
      return;
    }

    if (action === 'close-modal') {
      document.querySelectorAll('.modal-overlay').forEach(m => m.style.display = 'none');
      return;
    }
  });

  // Seek on progress bar click
  document.addEventListener('click', async (e) => {
    const bar = e.target.closest('[p-trigger="seek"]');
    if (!bar) return;
    const rect = bar.getBoundingClientRect();
    const pct = (e.clientX - rect.left) / rect.width;
    await fetch('/api/player/seek', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ percent: Math.max(0, Math.min(1, pct)) }),
    });
    window.location.reload();
  });

  // Form submissions
  document.addEventListener('submit', async (e) => {
    const form = e.target;
    if (form.id === 'add-song-form') {
      e.preventDefault();
      const data = new FormData(form);
      const playlistId = document.querySelector('[data-active-playlist]')?.getAttribute('data-active-playlist');
      if (!playlistId) return;
      await fetch('/api/playlists/' + playlistId + '/songs', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          title: data.get('title'),
          artist: data.get('artist'),
          album: data.get('album'),
          duration: parseInt(data.get('duration'), 10) || 0,
          albumArtUrl: data.get('albumArtUrl') || 'https://placeholders.dev/300x300?text=Music',
        }),
      });
      window.location.reload();
      return;
    }

    if (form.id === 'create-playlist-form') {
      e.preventDefault();
      const data = new FormData(form);
      const res = await fetch('/api/playlists', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ name: data.get('name') }),
      });
      if (res.ok) {
        const pl = await res.json();
        window.location.href = '/playlists/' + pl.id;
      }
      return;
    }
  });

  // Drag and drop reorder
  const tbody = document.getElementById('song-list-body');
  if (tbody) {
    tbody.addEventListener('dragstart', (e) => {
      const row = e.target.closest('tr[data-song-index]');
      if (!row) return;
      dragSrcIndex = parseInt(row.getAttribute('data-song-index'), 10);
      row.style.opacity = '0.4';
      e.dataTransfer.effectAllowed = 'move';
      e.dataTransfer.setData('text/plain', String(dragSrcIndex));
    });

    tbody.addEventListener('dragover', (e) => {
      e.preventDefault();
      e.dataTransfer.dropEffect = 'move';
      const row = e.target.closest('tr[data-song-index]');
      if (row) {
        row.style.borderTop = '2px solid #1db954';
      }
    });

    tbody.addEventListener('dragleave', (e) => {
      const row = e.target.closest('tr[data-song-index]');
      if (row) {
        row.style.borderTop = '';
      }
    });

    tbody.addEventListener('drop', async (e) => {
      e.preventDefault();
      const row = e.target.closest('tr[data-song-index]');
      if (!row) return;
      row.style.borderTop = '';
      const toIndex = parseInt(row.getAttribute('data-song-index'), 10);
      if (dragSrcIndex === null || dragSrcIndex === toIndex) return;

      const playlistId = document.querySelector('[data-active-playlist]')?.getAttribute('data-active-playlist');
      if (!playlistId) return;

      await fetch('/api/playlists/' + playlistId + '/reorder', {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ fromIndex: dragSrcIndex, toIndex }),
      });
      window.location.reload();
    });

    tbody.addEventListener('dragend', (e) => {
      const row = e.target.closest('tr[data-song-index]');
      if (row) row.style.opacity = '1';
      dragSrcIndex = null;
    });
  }

  // Simulated playback timer (advances elapsed time)
  const startPlaybackPolling = () => {
    if (playbackTimer) clearInterval(playbackTimer);
    playbackTimer = setInterval(async () => {
      const res = await fetch('/api/player/tick', { method: 'POST' });
      if (res.ok) {
        const data = await res.json();
        if (data.advanced) {
          window.location.reload();
        } else if (data.elapsed !== undefined) {
          // Update progress bar without full reload
          const bar = document.querySelector('[p-target="progress-bar"]');
          if (bar && data.duration > 0) {
            bar.style.width = ((data.elapsed / data.duration) * 100) + '%';
          }
          // Update time display
          const timeEls = document.querySelectorAll('[p-target="now-playing"] .time-current');
          // minimal time update handled via reload on song change
        }
      }
    }, 1000);
  };

  // Start polling if playing
  const playBtn = document.querySelector('[p-trigger="toggle-play"]');
  if (playBtn && playBtn.textContent.trim() === '\\u23F8') {
    startPlaybackPolling();
  }
})();
<\/script>`;

