const json = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const path = url.pathname
  const method = req.method

  // --- API Routes ---

  // List playlists
  if (method === 'GET' && path === '/api/playlists') {
    const playlists = await getPlaylists()
    return json(playlists)
  }

  // Create playlist
  if (method === 'POST' && path === '/api/playlists') {
    const body = await req.json() as { name: string }
    const playlist = await createPlaylist(body.name)
    return json(playlist, 201)
  }

  // Get playlist
  if (method === 'GET' && path.match(/^\/api\/playlists\/[^/]+$/)) {
    const id = path.split('/')[3]
    const playlist = await getPlaylist(id)
    if (!playlist) return json({ error: 'Not found' }, 404)
    return json(playlist)
  }

  // Delete playlist
  if (method === 'DELETE' && path.match(/^\/api\/playlists\/[^/]+$/)) {
    const id = path.split('/')[3]
    const ok = await deletePlaylist(id)
    if (!ok) return json({ error: 'Not found' }, 404)
    return json({ ok: true })
  }

  // Rename playlist
  if (method === 'PUT' && path.match(/^\/api\/playlists\/[^/]+$/)) {
    const id = path.split('/')[3]
    const body = await req.json() as { name: string }
    const playlist = await renamePlaylist(id, body.name)
    if (!playlist) return json({ error: 'Not found' }, 404)
    return json(playlist)
  }

  // Add song
  if (method === 'POST' && path.match(/^\/api\/playlists\/[^/]+\/songs$/)) {
    const id = path.split('/')[3]
    const body = await req.json() as AddSongInput
    const song = await addSong(id, body)
    if (!song) return json({ error: 'Playlist not found' }, 404)
    return json(song, 201)
  }

  // Remove song
  if (method === 'DELETE' && path.match(/^\/api\/playlists\/[^/]+\/songs\/[^/]+$/)) {
    const parts = path.split('/')
    const playlistId = parts[3]
    const songId = parts[5]
    const ok = await removeSong(playlistId, songId)
    if (!ok) return json({ error: 'Not found' }, 404)
    return json({ ok: true })
  }

  // Reorder songs
  if (method === 'PUT' && path.match(/^\/api\/playlists\/[^/]+\/reorder$/)) {
    const id = path.split('/')[3]
    const body = await req.json() as ReorderInput
    const ok = await reorderSong(id, body)
    if (!ok) return json({ error: 'Failed to reorder' }, 400)
    return json({ ok: true })
  }

  // --- Player API ---

  if (method === 'POST' && path === '/api/player/load') {
    const body = await req.json() as { playlistId: string; startIndex: number }
    loadPlaylist(body.playlistId, body.startIndex)
    return json({ ok: true })
  }

  if (method === 'POST' && path === '/api/player/play') {
    play()
    return json({ ok: true })
  }

  if (method === 'POST' && path === '/api/player/pause') {
    pause()
    return json({ ok: true })
  }

  if (method === 'POST' && path === '/api/player/toggle') {
    togglePlayPause()
    return json({ ok: true })
  }

  if (method === 'POST' && path === '/api/player/next') {
    const song = await skipNext()
    return json({ song })
  }

  if (method === 'POST' && path === '/api/player/previous') {
    const song = await skipPrevious()
    return json({ song })
  }

  if (method === 'POST' && path === '/api/player/shuffle') {
    await toggleShuffle()
    const ps = getPlayerState()
    return json({ shuffle: ps.shuffle })
  }

  if (method === 'POST' && path === '/api/player/repeat') {
    const mode = cycleRepeat()
    return json({ repeat: mode })
  }

  if (method === 'POST' && path === '/api/player/seek') {
    const body = await req.json() as { percent: number }
    const song = await getCurrentSong()
    if (song) {
      setElapsed(body.percent * song.duration)
    }
    return json({ ok: true })
  }

  if (method === 'POST' && path === '/api/player/tick') {
    const ps = getPlayerState()
    if (!ps.isPlaying) return json({ elapsed: ps.elapsed })
    const song = await getCurrentSong()
    if (!song) return json({ elapsed: 0 })
    const newElapsed = ps.elapsed + 1
    if (newElapsed >= song.duration) {
      const nextSong = await skipNext()
      return json({ advanced: true, song: nextSong })
    }
    setElapsed(newElapsed)
    return json({ elapsed: newElapsed, duration: song.duration })
  }

  if (method === 'GET' && path === '/api/player/state') {
    const ps = getPlayerState()
    const song = await getCurrentSong()
    return json({ ...ps, currentSong: song })
  }

  if (method === 'POST' && path.match(/^\/api\/player\/play-index\/\d+$/)) {
    const index = parseInt(path.split('/').pop()!, 10)
    playSongAtIndex(index)
    return json({ ok: true })
  }

  // --- Page Routes ---

  // Playlist detail page
  if (method === 'GET' && path.match(/^\/playlists\/[^/]+$/)) {
    const id = path.split('/')[2]
    const playlists = await getPlaylists()
    const activePlaylist = await getPlaylist(id)
    if (!activePlaylist) {
      return new Response('Playlist not found', { status: 404 })
    }
    const playerState = getPlayerState()
    const currentSong = await getCurrentSong()
    const page = renderPage(playlists, activePlaylist, currentSong, playerState)
    return new Response(html(createSSR(page), id), {
      headers: { 'Content-Type': 'text/html' },
    })
  }

  // Home page
  if (method === 'GET' && (path === '/' || path === '/playlists')) {
    const playlists = await getPlaylists()
    const playerState = getPlayerState()
    const currentSong = await getCurrentSong()
    // Auto-select first playlist if available
    const activePlaylist = playlists.length > 0 ? playlists[0] : null
    const page = renderPage(playlists, activePlaylist, currentSong, playerState)
    return new Response(
      html(createSSR(page), activePlaylist?.id),
      { headers: { 'Content-Type': 'text/html' } },
    )
  }

  return new Response('Not Found', { status: 404 })
}

