import type { AppState, Playlist } from './types'

const DATA_PATH = './data/playlists.json'

const defaultState: AppState = {
  playlists: [],
  playback: {
    currentPlaylistId: null,
    currentSongIndex: 0,
    isPlaying: false,
    progress: 0,
    elapsed: 0,
    shuffle: false,
    repeat: 'off',
    shuffleQueue: [],
    shuffleIndex: 0,
  },
  activePlaylistId: null,
}

export const loadState = async (): Promise<AppState> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) {
    await saveState(defaultState)
    return { ...defaultState }
  }
  const raw = await file.json()
  return {
    ...defaultState,
    ...raw,
    playback: {
      ...defaultState.playback,
      ...(raw.playback ?? {}),
      isPlaying: false,
      progress: 0,
      elapsed: 0,
    },
  }
}

export const saveState = async (state: AppState): Promise<void> => {
  const { playback, ...persistable } = state
  const persistedPlayback = {
    currentPlaylistId: playback.currentPlaylistId,
    currentSongIndex: playback.currentSongIndex,
    shuffle: playback.shuffle,
    repeat: playback.repeat,
    shuffleQueue: playback.shuffleQueue,
    shuffleIndex: playback.shuffleIndex,
  }
  await Bun.write(DATA_PATH, JSON.stringify({ ...persistable, playback: persistedPlayback }, null, 2))
}

export const savePlaylists = async (playlists: Playlist[]): Promise<void> => {
  const state = await loadState()
  state.playlists = playlists
  await saveState(state)
}

import type { Playlist, Song, AddSongInput, ReorderInput } from './types'
import { loadState, savePlaylists } from './store'

const generateId = (): string => crypto.randomUUID()

export const createPlaylist = async (name: string): Promise<Playlist> => {
  const state = await loadState()
  const now = new Date().toISOString()
  const playlist: Playlist = {
    id: generateId(),
    name,
    songs: [],
    createdAt: now,
    updatedAt: now,
  }
  state.playlists.push(playlist)
  await savePlaylists(state.playlists)
  return playlist
}

export const deletePlaylist = async (playlistId: string): Promise<void> => {
  const state = await loadState()
  state.playlists = state.playlists.filter((p) => p.id !== playlistId)
  await savePlaylists(state.playlists)
}

export const renamePlaylist = async (playlistId: string, name: string): Promise<Playlist | null> => {
  const state = await loadState()
  const playlist = state.playlists.find((p) => p.id === playlistId)
  if (!playlist) return null
  playlist.name = name
  playlist.updatedAt = new Date().toISOString()
  await savePlaylists(state.playlists)
  return playlist
}

export const addSong = async (playlistId: string, input: AddSongInput): Promise<Song | null> => {
  const state = await loadState()
  const playlist = state.playlists.find((p) => p.id === playlistId)
  if (!playlist) return null
  const song: Song = {
    id: generateId(),
    ...input,
  }
  playlist.songs.push(song)
  playlist.updatedAt = new Date().toISOString()
  await savePlaylists(state.playlists)
  return song
}

export const removeSong = async (playlistId: string, songId: string): Promise<void> => {
  const state = await loadState()
  const playlist = state.playlists.find((p) => p.id === playlistId)
  if (!playlist) return
  playlist.songs = playlist.songs.filter((s) => s.id !== songId)
  playlist.updatedAt = new Date().toISOString()
  await savePlaylists(state.playlists)
}

export const reorderSong = async ({ playlistId, fromIndex, toIndex }: ReorderInput): Promise<void> => {
  const state = await loadState()
  const playlist = state.playlists.find((p) => p.id === playlistId)
  if (!playlist) return
  if (fromIndex < 0 || fromIndex >= playlist.songs.length) return
  if (toIndex < 0 || toIndex >= playlist.songs.length) return
  const [moved] = playlist.songs.splice(fromIndex, 1)
  playlist.songs.splice(toIndex, 0, moved)
  playlist.updatedAt = new Date().toISOString()
  await savePlaylists(state.playlists)
}

export const getPlaylist = async (playlistId: string): Promise<Playlist | null> => {
  const state = await loadState()
  return state.playlists.find((p) => p.id === playlistId) ?? null
}

export const getAllPlaylists = async (): Promise<Playlist[]> => {
  const state = await loadState()
  return state.playlists
}

import type { PlaybackState, RepeatMode, Playlist } from './types'
import { loadState, saveState } from './store'

const generateShuffleQueue = (length: number, currentIndex: number): number[] => {
  const indices = Array.from({ length }, (_, i) => i).filter((i) => i !== currentIndex)
  for (let i = indices.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1))
    ;[indices[i], indices[j]] = [indices[j], indices[i]]
  }
  return [currentIndex, ...indices]
}

export const play = async (playlistId: string, songIndex = 0): Promise<PlaybackState> => {
  const state = await loadState()
  const playlist = state.playlists.find((p) => p.id === playlistId)
  if (!playlist || playlist.songs.length === 0) return state.playback

  const clampedIndex = Math.max(0, Math.min(songIndex, playlist.songs.length - 1))
  state.playback.currentPlaylistId = playlistId
  state.playback.currentSongIndex = clampedIndex
  state.playback.isPlaying = true
  state.playback.progress = 0
  state.playback.elapsed = 0

  if (state.playback.shuffle) {
    state.playback.shuffleQueue = generateShuffleQueue(playlist.songs.length, clampedIndex)
    state.playback.shuffleIndex = 0
  }

  await saveState(state)
  return state.playback
}

export const pause = async (): Promise<PlaybackState> => {
  const state = await loadState()
  state.playback.isPlaying = false
  await saveState(state)
  return state.playback
}

export const resume = async (): Promise<PlaybackState> => {
  const state = await loadState()
  if (state.playback.currentPlaylistId) {
    state.playback.isPlaying = true
    await saveState(state)
  }
  return state.playback
}

export const togglePlayPause = async (): Promise<PlaybackState> => {
  const state = await loadState()
  if (!state.playback.currentPlaylistId) return state.playback
  state.playback.isPlaying = !state.playback.isPlaying
  await saveState(state)
  return state.playback
}

const resolveNextIndex = (playback: PlaybackState, playlist: Playlist, direction: 1 | -1): number | null => {
  const { shuffle, repeat, shuffleQueue, shuffleIndex, currentSongIndex } = playback
  const len = playlist.songs.length

  if (repeat === 'one') return currentSongIndex

  if (shuffle) {
    const nextShuffleIdx = shuffleIndex + direction
    if (nextShuffleIdx >= 0 && nextShuffleIdx < shuffleQueue.length) {
      return shuffleQueue[nextShuffleIdx]
    }
    if (repeat === 'all') {
      const newQueue = generateShuffleQueue(len, shuffleQueue[shuffleIndex])
      playback.shuffleQueue = newQueue
      playback.shuffleIndex = direction === 1 ? 0 : newQueue.length - 1
      return newQueue[playback.shuffleIndex]
    }
    return null
  }

  const nextIdx = currentSongIndex + direction
  if (nextIdx >= 0 && nextIdx < len) return nextIdx
  if (repeat === 'all') return direction === 1 ? 0 : len - 1
  return null
}

export const skipNext = async (): Promise<PlaybackState> => {
  const state = await loadState()
  const { playback } = state
  if (!playback.currentPlaylistId) return playback

  const playlist = state.playlists.find((p) => p.id === playback.currentPlaylistId)
  if (!playlist) return playback

  const nextIndex = resolveNextIndex(playback, playlist, 1)
  if (nextIndex === null) {
    playback.isPlaying = false
    await saveState(state)
    return playback
  }

  playback.currentSongIndex = nextIndex
  playback.progress = 0
  playback.elapsed = 0
  if (playback.shuffle) {
    playback.shuffleIndex = playback.shuffleQueue.indexOf(nextIndex)
  }

  await saveState(state)
  return playback
}

export const skipPrevious = async (): Promise<PlaybackState> => {
  const state = await loadState()
  const { playback } = state
  if (!playback.currentPlaylistId) return playback

  // If past 3 seconds, restart current song
  if (playback.elapsed > 3) {
    playback.progress = 0
    playback.elapsed = 0
    await saveState(state)
    return playback
  }

  const playlist = state.playlists.find((p) => p.id === playback.currentPlaylistId)
  if (!playlist) return playback

  const prevIndex = resolveNextIndex(playback, playlist, -1)
  if (prevIndex === null) {
    playback.progress = 0
    playback.elapsed = 0
    await saveState(state)
    return playback
  }

  playback.currentSongIndex = prevIndex
  playback.progress = 0
  playback.elapsed = 0
  if (playback.shuffle) {
    playback.shuffleIndex = playback.shuffleQueue.indexOf(prevIndex)
  }

  await saveState(state)
  return playback
}

export const toggleShuffle = async (): Promise<PlaybackState> => {
  const state = await loadState()
  const { playback } = state
  playback.shuffle = !playback.shuffle

  if (playback.shuffle && playback.currentPlaylistId) {
    const playlist = state.playlists.find((p) => p.id === playback.currentPlaylistId)
    if (playlist) {
      playback.shuffleQueue = generateShuffleQueue(playlist.songs.length, playback.currentSongIndex)
      playback.shuffleIndex = 0
    }
  } else {
    playback.shuffleQueue = []
    playback.shuffleIndex = 0
  }

  await saveState(state)
  return playback
}

export const cycleRepeat = async (): Promise<PlaybackState> => {
  const state = await loadState()
  const modes: RepeatMode[] = ['off', 'all', 'one']
  const currentIdx = modes.indexOf(state.playback.repeat)
  state.playback.repeat = modes[(currentIdx + 1) % modes.length]
  await saveState(state)
  return state.playback
}

export const seek = async (progress: number): Promise<PlaybackState> => {
  const state = await loadState()
  const clamped = Math.max(0, Math.min(1, progress))
  state.playback.progress = clamped

  if (state.playback.currentPlaylistId) {
    const playlist = state.playlists.find((p) => p.id === state.playback.currentPlaylistId)
    if (playlist) {
      const song = playlist.songs[state.playback.currentSongIndex]
      if (song) {
        state.playback.elapsed = Math.round(clamped * song.duration)
      }
    }
  }

  await saveState(state)
  return state.playback
}

export const getPlaybackState = async (): Promise<PlaybackState> => {
  const state = await loadState()
  return state.playback
}

export const getNowPlaying = async () => {
  const state = await loadState()
  const { playback } = state
  if (!playback.currentPlaylistId) return null

  const playlist = state.playlists.find((p) => p.id === playback.currentPlaylistId)
  if (!playlist) return null

  const song = playlist.songs[playback.currentSongIndex]
  if (!song) return null

  return {
    song,
    playlist: { id: playlist.id, name: playlist.name },
    playback,
  }
}

