const styleStr = (obj: Record<string, string | number>): string =>
  Object.entries(obj)
    .map(([k, v]) => `${k.replace(/[A-Z]/g, (m) => `-${m.toLowerCase()}`)}:${typeof v === 'number' ? `${v}px` : v}`)
    .join(';')

const repeatLabel = (mode: RepeatMode): string => {
  if (mode === 'off') return '\u{1F501}'
  if (mode === 'all') return '\u{1F501}'
  return '\u{1F502}'
}

export const renderPlaylistSidebar = (playlists: Playlist[], activeId: string | null): string => {
  const items = playlists.map((p) => {
    const isActive = p.id === activeId
    const combinedStyle = {
      ...styles.playlistItem,
      ...(isActive ? styles.playlistItemActive : {}),
    }
    return h('div', {
      style: styleStr(combinedStyle),
      'p-trigger': `select-playlist:${p.id}`,
    },
      h('span', {}, p.name),
      h('span', { style: 'font-size:12px;color:#666' }, `${p.songs.length} songs`),
    )
  })

  return h('div', { style: styleStr(styles.sidebar) },
    h('div', { style: styleStr(styles.sectionTitle) }, 'Your Library'),
    ...items,
    h('div', { style: 'margin-top:12px' },
      h('button', {
        style: styleStr(styles.btnSmall),
        'p-trigger': 'create-playlist',
      }, '+ New Playlist'),
    ),
  )
}

export const renderSongRow = (
  song: Song,
  index: number,
  playlistId: string,
  isCurrentlyPlaying: boolean,
): string => {
  const rowStyle = {
    ...styles.songRow,
    ...(isCurrentlyPlaying ? styles.songRowPlaying : {}),
  }
  const titleStyle = {
    ...styles.songTitle,
    ...(isCurrentlyPlaying ? { color: '#1db954' } : {}),
  }

  return h('div', {
    style: styleStr(rowStyle),
    draggable: 'true',
    'data-index': String(index),
    'data-playlist-id': playlistId,
    'p-trigger': `play-song:${playlistId}:${index}`,
  },
    h('span', { style: styleStr(styles.dragHandle) }, '\u2630'),
    h('span', { style: styleStr(styles.songIndex) },
      isCurrentlyPlaying ? '\u266B' : String(index + 1),
    ),
    h('img', {
      src: song.albumArtUrl || 'data:image/svg+xml,<svg xmlns="http://www.w3.org/2000/svg" width="40" height="40"><rect fill="%23333" width="40" height="40"/><text x="12" y="24" fill="%23666" font-size="14">\u266B</text></svg>',
      alt: song.album,
      style: styleStr(styles.albumArt),
    }),
    h('div', { style: styleStr(styles.songInfo) },
      h('div', { style: styleStr(titleStyle) }, song.title),
      h('div', { style: styleStr(styles.songArtist) }, `${song.artist} \u2022 ${song.album}`),
    ),
    h('span', { style: styleStr(styles.songDuration) }, formatDuration(song.duration)),
    h('button', {
      style: styleStr(styles.btnDanger),
      'p-trigger': `remove-song:${playlistId}:${song.id}`,
    }, '\u2715'),
  )
}

export const renderPlaylistView = (
  playlist: Playlist,
  playback: PlaybackState,
): string => {
  const isPlayingThisPlaylist = playback.currentPlaylistId === playlist.id

  const songRows = playlist.songs.map((song, i) => {
    const isCurrent = isPlayingThisPlaylist && playback.currentSongIndex === i
    return renderSongRow(song, i, playlist.id, isCurrent)
  })

  const totalDuration = playlist.songs.reduce((sum, s) => sum + s.duration, 0)

  return h('div', { style: styleStr(styles.content) },
    h('div', { style: 'display:flex;align-items:center;gap:16px;margin-bottom:20px' },
      h('button', {
        style: styleStr(styles.btnPrimary),
        'p-trigger': `play-playlist:${playlist.id}`,
      }, isPlayingThisPlaylist && playback.isPlaying ? '\u275A\u275A Pause' : '\u25B6 Play'),
      h('h2', { style: 'margin:0;font-size:28px;font-weight:700' }, playlist.name),
    ),
    h('div', { style: 'font-size:12px;color:#888;margin-bottom:16px' },
      `${playlist.songs.length} songs \u2022 ${formatDuration(totalDuration)} total`,
    ),
    h('div', {
      'p-target': 'song-list',
      style: 'margin-bottom:120px',
    },
      playlist.songs.length === 0
        ? h('div', { style: styleStr(styles.empty) }, 'No songs yet. Add some tracks to get started.')
        : '',
      ...songRows,
    ),
    h('div', { style: 'margin-top:16px;margin-bottom:16px' },
      h('button', {
        style: styleStr(styles.btnSmall),
        'p-trigger': `show-add-song-form:${playlist.id}`,
      }, '+ Add Song'),
      h('button', {
        style: `${styleStr(styles.btnSmall)};margin-left:8px`,
        'p-trigger': `rename-playlist:${playlist.id}`,
      }, 'Rename'),
      h('button', {
        style: `${styleStr(styles.btnDanger)};margin-left:8px`,
        'p-trigger': `delete-playlist:${playlist.id}`,
      }, 'Delete Playlist'),
    ),
  )
}

