import { createSSR } from 'plaited'
import { loadState, saveState } from './store'
import {
  createPlaylist,
  deletePlaylist,
  renamePlaylist,
  addSong,
  removeSong,
  reorderSong,
  getPlaylist,
  getAllPlaylists,
} from './playlist'
import {
  play,
  pause,
  resume,
  togglePlayPause,
  skipNext,
  skipPrevious,
  toggleShuffle,
  cycleRepeat,
  seek,
  getNowPlaying,
} from './player'
import {
  renderApp,
  renderAddSongForm,
  renderCreatePlaylistForm,
} from './views'
import type { AddSongInput } from './types'

const ssr = createSSR()

const renderPage = async (activePlaylistId?: string | null) => {
  const state = await loadState()
  const playlists = state.playlists
  const activeId = activePlaylistId ?? state.activePlaylistId
  const activePlaylist = activeId ? playlists.find((p) => p.id === activeId) ?? null : null

  const nowPlaying = await getNowPlaying()
  const nowPlayingSong = nowPlaying?.song ?? null
  const nowPlayingPlaylistName = nowPlaying?.playlist.name ?? ''

  const html = renderApp(
    playlists,
    activePlaylist,
    state.playback,
    nowPlayingSong,
    nowPlayingPlaylistName,
  )

  return ssr(html)
}

const jsonResponse = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const htmlResponse = async (activePlaylistId?: string | null) => {
  const rendered = await renderPage(activePlaylistId)
  return new Response(rendered, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })
}

const parseBody = async <T>(req: Request): Promise<T> => {
  return req.json() as Promise<T>
}

const router = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const path = url.pathname
  const method = req.method

  // --- HTML page ---
  if (method === 'GET' && path === '/') {
    return htmlResponse()
  }

  // --- Playlist CRUD API ---
  if (method === 'GET' && path === '/api/playlists') {
    const playlists = await getAllPlaylists()
    return jsonResponse(playlists)
  }

  if (method === 'POST' && path === '/api/playlists') {
    const { name } = await parseBody<{ name: string }>(req)
    if (!name?.trim()) return jsonResponse({ error: 'Name is required' }, 400)
    const playlist = await createPlaylist(name.trim())
    const state = await loadState()
    state.activePlaylistId = playlist.id
    await saveState(state)
    return jsonResponse(playlist, 201)
  }

  if (method === 'GET' && path.startsWith('/api/playlists/')) {
    const id = path.split('/')[3]
    const playlist = await getPlaylist(id)
    if (!playlist) return jsonResponse({ error: 'Not found' }, 404)
    return jsonResponse(playlist)
  }

  if (method === 'PATCH' && path.startsWith('/api/playlists/') && !path.includes('/songs')) {
    const id = path.split('/')[3]
    const { name } = await parseBody<{ name: string }>(req)
    const playlist = await renamePlaylist(id, name)
    if (!playlist) return jsonResponse({ error: 'Not found' }, 404)
    return jsonResponse(playlist)
  }

  if (method === 'DELETE' && path.startsWith('/api/playlists/') && !path.includes('/songs')) {
    const id = path.split('/')[3]
    await deletePlaylist(id)
    const state = await loadState()
    if (state.activePlaylistId === id) {
      state.activePlaylistId = state.playlists[0]?.id ?? null
      await saveState(state)
    }
    return jsonResponse({ ok: true })
  }

  // --- Song management API ---
  if (method === 'POST' && path.match(/^\/api\/playlists\/[^/]+\/songs$/)) {
    const playlistId = path.split('/')[3]
    const input = await parseBody<AddSongInput>(req)
    if (!input.title?.trim()) return jsonResponse({ error: 'Title is required' }, 400)
    const song = await addSong(playlistId, {
      title: input.title.trim(),
      artist: input.artist?.trim() ?? 'Unknown Artist',
      album: input.album?.trim() ?? 'Unknown Album',
      duration: input.duration ?? 180,
      albumArtUrl: input.albumArtUrl?.trim() ?? '',
    })
    if (!song) return jsonResponse({ error: 'Playlist not found' }, 404)
    return jsonResponse(song, 201)
  }

  if (method === 'DELETE' && path.match(/^\/api\/playlists\/[^/]+\/songs\/[^/]+$/)) {
    const parts = path.split('/')
    const playlistId = parts[3]
    const songId = parts[5]
    await removeSong(playlistId, songId)
    return jsonResponse({ ok: true })
  }

  if (method === 'PATCH' && path.match(/^\/api\/playlists\/[^/]+\/reorder$/)) {
    const playlistId = path.split('/')[3]
    const { fromIndex, toIndex } = await parseBody<{ fromIndex: number; toIndex: number }>(req)
    await reorderSong({ playlistId, fromIndex, toIndex })
    return jsonResponse({ ok: true })
  }

  // --- Playback API ---
  if (method === 'POST' && path === '/api/player/play') {
    const { playlistId, songIndex } = await parseBody<{ playlistId: string; songIndex?: number }>(req)
    const playback = await play(playlistId, songIndex)
    return jsonResponse(playback)
  }

  if (method === 'POST' && path === '/api/player/pause') {
    const playback = await pause()
    return jsonResponse(playback)
  }

  if (method === 'POST' && path === '/api/player/resume') {
    const playback = await resume()
    return jsonResponse(playback)
  }

  if (method === 'POST' && path === '/api/player/toggle') {
    const playback = await togglePlayPause()
    return jsonResponse(playback)
  }

  if (method === 'POST' && path === '/api/player/next') {
    const playback = await skipNext()
    return jsonResponse(playback)
  }

  if (method === 'POST' && path === '/api/player/previous') {
    const playback = await skipPrevious()
    return jsonResponse(playback)
  }

  if (method === 'POST' && path === '/api/player/shuffle') {
    const playback = await toggleShuffle()
    return jsonResponse(playback)
  }

  if (method === 'POST' && path === '/api/player/repeat') {
    const playback = await cycleRepeat()
    return jsonResponse(playback)
  }

  if (method === 'POST' && path === '/api/player/seek') {
    const { progress } = await parseBody<{ progress: number }>(req)
    const playback = await seek(progress)
    return jsonResponse(playback)
  }

  if (method === 'GET' && path === '/api/player/now-playing') {
    const nowPlaying = await getNowPlaying()
    return jsonResponse(nowPlaying)
  }

  if (method === 'GET' && path === '/api/player/state') {
    const state = await loadState()
    return jsonResponse(state.playback)
  }

  // --- Select active playlist ---
  if (method === 'POST' && path === '/api/active-playlist') {
    const { playlistId } = await parseBody<{ playlistId: string }>(req)
    const state = await loadState()
    state.activePlaylistId = playlistId
    await saveState(state)
    return jsonResponse({ ok: true })
  }

  // --- Page views for forms ---
  if (method === 'GET' && path === '/view/add-song-form') {
    const playlistId = url.searchParams.get('playlistId') ?? ''
    const html = renderAddSongForm(playlistId)
    return new Response(ssr(html), {
      headers: { 'Content-Type': 'text/html; charset=utf-8' },
    })
  }

  if (method === 'GET' && path === '/view/create-playlist-form') {
    const html = renderCreatePlaylistForm()
    return new Response(ssr(html), {
      headers: { 'Content-Type': 'text/html; charset=utf-8' },
    })
  }

  // --- Page view with active playlist ---
  if (method === 'GET' && path.startsWith('/playlist/')) {
    const id = path.split('/')[2]
    const state = await loadState()
    state.activePlaylistId = id
    await saveState(state)
    return htmlResponse(id)
  }

  return jsonResponse({ error: 'Not found' }, 404)
}

const server = Bun.serve({
  port: Number(process.env.PORT ?? 3000),
  fetch: router,
})

console.log(`Playlist Manager running at http://localhost:${server.port}`)

export { router }

/**
 * Client-side script for playlist manager interactivity.
 * Handles drag-to-reorder, playback simulation, and UI event delegation.
 */

type ClientPlaybackState = {
  isPlaying: boolean
  currentPlaylistId: string | null
  currentSongIndex: number
  progress: number
  elapsed: number
  shuffle: boolean
  repeat: 'off' | 'all' | 'one'
  duration: number
}

const state: ClientPlaybackState = {
  isPlaying: false,
  currentPlaylistId: null,
  currentSongIndex: 0,
  progress: 0,
  elapsed: 0,
  shuffle: false,
  repeat: 'off',
  duration: 0,
}

let progressInterval: ReturnType<typeof setInterval> | null = null

const api = async (path: string, method = 'POST', body?: unknown) => {
  const opts: RequestInit = { method, headers: { 'Content-Type': 'application/json' } }
  if (body !== undefined) opts.body = JSON.stringify(body)
  const res = await fetch(`/api${path}`, opts)
  return res.json()
}

const reload = () => {
  window.location.reload()
}

// --- Playback simulation ---

const startProgressSimulation = () => {
  stopProgressSimulation()
  progressInterval = setInterval(async () => {
    if (!state.isPlaying || state.duration <= 0) return
    state.elapsed += 1
    state.progress = state.elapsed / state.duration
    updateProgressUI()
    if (state.elapsed >= state.duration) {
      await api('/player/next')
      reload()
    }
  }, 1000)
}

const stopProgressSimulation = () => {
  if (progressInterval) {
    clearInterval(progressInterval)
    progressInterval = null
  }
}

const updateProgressUI = () => {
  const fill = document.querySelector('[p-target="progress-bar"] > div') as HTMLElement | null
  if (fill) {
    fill.style.width = `${(state.progress * 100).toFixed(1)}%`
  }
  const timeEls = document.querySelectorAll('[p-target="now-playing"] .progress-time')
  if (timeEls.length >= 1) {
    const m = Math.floor(state.elapsed / 60)
    const s = Math.floor(state.elapsed % 60)
    timeEls[0].textContent = `${m}:${String(s).padStart(2, '0')}`
  }
}

// --- Drag and drop ---

let dragFromIndex: number | null = null
let dragPlaylistId: string | null = null

const setupDragAndDrop = () => {
  const songList = document.querySelector('[p-target="song-list"]')
  if (!songList) return

  songList.addEventListener('dragstart', (e: Event) => {
    const evt = e as DragEvent
    const row = (evt.target as HTMLElement).closest('[draggable="true"]') as HTMLElement | null
    if (!row) return
    dragFromIndex = Number(row.dataset.index)
    dragPlaylistId = row.dataset.playlistId ?? null
    if (evt.dataTransfer) {
      evt.dataTransfer.effectAllowed = 'move'
      evt.dataTransfer.setData('text/plain', String(dragFromIndex))
    }
    row.style.opacity = '0.5'
  })

  songList.addEventListener('dragover', (e: Event) => {
    e.preventDefault()
    const evt = e as DragEvent
    if (evt.dataTransfer) evt.dataTransfer.dropEffect = 'move'
  })

  songList.addEventListener('dragend', (e: Event) => {
    const row = (e.target as HTMLElement).closest('[draggable="true"]') as HTMLElement | null
    if (row) row.style.opacity = '1'
  })

  songList.addEventListener('drop', async (e: Event) => {
    e.preventDefault()
    const evt = e as DragEvent
    const target = (evt.target as HTMLElement).closest('[draggable="true"]') as HTMLElement | null
    if (!target || dragFromIndex === null || !dragPlaylistId) return

    const toIndex = Number(target.dataset.index)
    if (dragFromIndex === toIndex) return

    await api(`/playlists/${dragPlaylistId}/reorder`, 'PATCH', {
      fromIndex: dragFromIndex,
      toIndex,
    })

    dragFromIndex = null
    dragPlaylistId = null
    reload()
  })
}

// --- Event delegation ---

const setupEventDelegation = () => {
  document.addEventListener('click', async (e: MouseEvent) => {
    const el = (e.target as HTMLElement).closest('[p-trigger]') as HTMLElement | null
    if (!el) return

    const trigger = el.getAttribute('p-trigger') ?? ''
    const parts = trigger.split(':')
    const action = parts[0]

    e.preventDefault()

    switch (action) {
      case 'select-playlist': {
        const id = parts[1]
        await api('/active-playlist', 'POST', { playlistId: id })
        reload()
        break
      }

      case 'create-playlist': {
        const name = prompt('Playlist name:')
        if (name?.trim()) {
          await api('/playlists', 'POST', { name: name.trim() })
          reload()
        }
        break
      }

      case 'submit-create-playlist': {
        const input = document.querySelector('[p-target="input-playlist-name"]') as HTMLInputElement | null
        if (input?.value.trim()) {
          await api('/playlists', 'POST', { name: input.value.trim() })
          reload()
        }
        break
      }

      case 'delete-playlist': {
        const id = parts[1]
        if (confirm('Delete this playlist?')) {
          await api(`/playlists/${id}`, 'DELETE')
          reload()
        }
        break
      }

      case 'rename-playlist': {
        const id = parts[1]
        const newName = prompt('New playlist name:')
        if (newName?.trim()) {
          await api(`/playlists/${id}`, 'PATCH', { name: newName.trim() })
          reload()
        }
        break
      }

      case 'show-add-song-form': {
        const playlistId = parts[1]
        const title = prompt('Song title:')
        if (!title?.trim()) break
        const artist = prompt('Artist:') ?? 'Unknown Artist'
        const album = prompt('Album:') ?? 'Unknown Album'
        const durationStr = prompt('Duration in seconds:') ?? '180'
        const albumArtUrl = prompt('Album art URL (optional):') ?? ''
        await api(`/playlists/${playlistId}/songs`, 'POST', {
          title: title.trim(),
          artist: artist.trim(),
          album: album.trim(),
          duration: Number(durationStr) || 180,
          albumArtUrl: albumArtUrl.trim(),
        })
        reload()
        break
      }

      case 'submit-add-song': {
        const playlistId = parts[1]
        const titleInput = document.querySelector('[p-target="input-title"]') as HTMLInputElement
        const artistInput = document.querySelector('[p-target="input-artist"]') as HTMLInputElement
        const albumInput = document.querySelector('[p-target="input-album"]') as HTMLInputElement
        const durationInput = document.querySelector('[p-target="input-duration"]') as HTMLInputElement
        const artInput = document.querySelector('[p-target="input-art"]') as HTMLInputElement
        await api(`/playlists/${playlistId}/songs`, 'POST', {
          title: titleInput?.value.trim() ?? '',
          artist: artistInput?.value.trim() ?? 'Unknown Artist',
          album: albumInput?.value.trim() ?? 'Unknown Album',
          duration: Number(durationInput?.value) || 180,
          albumArtUrl: artInput?.value.trim() ?? '',
        })
        reload()
        break
      }

      case 'remove-song': {
        const playlistId = parts[1]
        const songId = parts[2]
        await api(`/playlists/${playlistId}/songs/${songId}`, 'DELETE')
        reload()
        break
      }

      case 'play-playlist': {
        const playlistId = parts[1]
        state.isPlaying = true
        await api('/player/play', 'POST', { playlistId, songIndex: 0 })
        reload()
        break
      }

      case 'play-song': {
        const playlistId = parts[1]
        const songIndex = Number(parts[2])
        await api('/player/play', 'POST', { playlistId, songIndex })
        reload()
        break
      }

      case 'toggle-play': {
        await api('/player/toggle')
        reload()
        break
      }

      case 'skip-next': {
        await api('/player/next')
        reload()
        break
      }

      case 'skip-previous': {
        await api('/player/previous')
        reload()
        break
      }

      case 'toggle-shuffle': {
        await api('/player/shuffle')
        reload()
        break
      }

      case 'cycle-repeat': {
        await api('/player/repeat')
        reload()
        break
      }

      case 'seek': {
        const bar = el.closest('[p-target="progress-bar"]') as HTMLElement
        if (bar) {
          const rect = bar.getBoundingClientRect()
          const x = (e as MouseEvent).clientX - rect.left
          const progress = Math.max(0, Math.min(1, x / rect.width))
          await api('/player/seek', 'POST', { progress })
          reload()
        }
        break
      }
    }
  })
}

// --- Init ---

const init = async () => {
  const nowPlaying = await fetch('/api/player/now-playing').then((r) => r.json())
  if (nowPlaying?.playback) {
    state.isPlaying = nowPlaying.playback.isPlaying
    state.currentPlaylistId = nowPlaying.playback.currentPlaylistId
    state.currentSongIndex = nowPlaying.playback.currentSongIndex
    state.progress = nowPlaying.playback.progress
    state.elapsed = nowPlaying.playback.elapsed
    state.shuffle = nowPlaying.playback.shuffle
    state.repeat = nowPlaying.playback.repeat
    state.duration = nowPlaying.song?.duration ?? 0
    if (state.isPlaying) startProgressSimulation()
  }
  setupDragAndDrop()
  setupEventDelegation()
}

document.addEventListener('DOMContentLoaded', init)

