const clientScript = `
var elements = null;
fetch('/api/elements').then(r => r.json()).then(d => { elements = d; });

function handleSearch(val) {
  var q = val.toLowerCase().trim();
  var select = document.getElementById('category-select');
  select.value = '';
  var cells = document.querySelectorAll('.element-cell');
  cells.forEach(function(cell) {
    if (!q) { cell.classList.remove('dimmed'); return; }
    var name = cell.getAttribute('data-name');
    var symbol = cell.getAttribute('data-symbol');
    var atomic = cell.getAttribute('data-atomic');
    var match = name.indexOf(q) !== -1 || symbol.indexOf(q) !== -1 || atomic === q;
    cell.classList.toggle('dimmed', !match);
  });
}

function filterByCategory(cat) {
  var input = document.getElementById('search-input');
  input.value = '';
  var select = document.getElementById('category-select');
  if (cat && select.value !== cat) select.value = cat;
  if (!cat) select.value = '';
  var cells = document.querySelectorAll('.element-cell');
  cells.forEach(function(cell) {
    if (!cat) { cell.classList.remove('dimmed'); return; }
    cell.classList.toggle('dimmed', cell.getAttribute('data-category') !== cat);
  });
}

function selectElement(e) {
  var cell = e.target.closest('.element-cell');
  if (!cell || !elements) return;
  var num = parseInt(cell.getAttribute('data-atomic'), 10);
  var el = elements.find(function(e) { return e.atomicNumber === num; });
  if (!el) return;
  var catMap = ${JSON.stringify(categoryMap)};
  var info = catMap[el.category];
  document.getElementById('detail-symbol').textContent = el.symbol;
  document.getElementById('detail-symbol').style.background = info.color;
  document.getElementById('detail-name').textContent = el.name;
  document.getElementById('detail-subtitle').textContent =
    '#' + el.atomicNumber + ' \\u2022 ' + el.atomicMass + ' u';
  document.getElementById('detail-econfig').textContent = el.electronConfiguration;
  document.getElementById('detail-oxidation').textContent = el.oxidationStates;
  document.getElementById('detail-melting').textContent =
    el.meltingPoint === 'N/A' ? 'Unknown' : el.meltingPoint + ' \\u00b0C';
  document.getElementById('detail-boiling').textContent =
    el.boilingPoint === 'N/A' ? 'Unknown' : el.boilingPoint + ' \\u00b0C';
  document.getElementById('detail-year').textContent = el.discoveryYear;
  document.getElementById('detail-category').textContent = info.label;
  document.getElementById('detail-desc').textContent = el.description;
  document.getElementById('detail-overlay').classList.add('open');
}

function closeDetail(e, force) {
  if (force || e.target.id === 'detail-overlay') {
    document.getElementById('detail-overlay').classList.remove('open');
  }
}

document.addEventListener('click', function(e) {
  var cell = e.target.closest('.element-cell');
  if (cell) selectElement(e);
});

document.addEventListener('keydown', function(e) {
  if (e.key === 'Escape') {
    document.getElementById('detail-overlay').classList.remove('open');
  }
});
`;

