import { createSSR } from 'plaited';
import { renderPage } from './render';
import type { Element } from './types';

const DATA_PATH = new URL('../data/elements.json', import.meta.url).pathname;

const loadElements = async (): Promise<Element[]> => {
  const file = Bun.file(DATA_PATH);
  const data = await file.json();
  return data as Element[];
};

const serve = async () => {
  const elements = await loadElements();
  const html = createSSR(renderPage(elements));

  Bun.serve({
    port: 3000,
    fetch: async (req) => {
      const url = new URL(req.url);

      if (url.pathname === '/api/elements') {
        return new Response(JSON.stringify(elements), {
          headers: { 'Content-Type': 'application/json' },
        });
      }

      if (url.pathname === '/api/elements/search') {
        const query = (url.searchParams.get('q') ?? '').toLowerCase();
        const category = url.searchParams.get('category') ?? '';

        const filtered = elements.filter((el) => {
          const matchesQuery = !query
            || el.name.toLowerCase().includes(query)
            || el.symbol.toLowerCase().includes(query)
            || String(el.atomicNumber) === query;
          const matchesCategory = !category || el.category === category;
          return matchesQuery && matchesCategory;
        });

        return new Response(JSON.stringify(filtered), {
          headers: { 'Content-Type': 'application/json' },
        });
      }

      return new Response(`<!DOCTYPE html>${html}`, {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      });
    },
  });

  console.log('Periodic Table Explorer running at http://localhost:3000');
};

serve();

