import type { Element, Category } from './types'

const DATA_PATH = new URL('../data/elements.json', import.meta.url).pathname

let cachedElements: Element[] | null = null

export const loadElements = async (): Promise<Element[]> => {
  if (cachedElements) return cachedElements
  const file = Bun.file(DATA_PATH)
  cachedElements = (await file.json()) as Element[]
  return cachedElements
}

export const getElementById = async (atomicNumber: number): Promise<Element | undefined> => {
  const elements = await loadElements()
  return elements.find((e) => e.atomicNumber === atomicNumber)
}

export const searchElements = async (query: string): Promise<Element[]> => {
  const elements = await loadElements()
  const q = query.toLowerCase().trim()
  if (!q) return elements
  return elements.filter(
    (e) =>
      e.name.toLowerCase().includes(q) ||
      e.symbol.toLowerCase() === q ||
      String(e.atomicNumber) === q,
  )
}

export const filterByCategory = async (category: Category): Promise<Element[]> => {
  const elements = await loadElements()
  return elements.filter((e) => e.category === category)
}

