const isMatch = (el: Element, filter: FilterState): boolean => {
  if (filter.category !== 'all' && el.category !== filter.category) return false
  if (filter.search) {
    const q = filter.search.toLowerCase()
    return (
      el.name.toLowerCase().includes(q) ||
      el.symbol.toLowerCase().includes(q) ||
      String(el.atomicNumber).includes(q)
    )
  }
  return true
}

