import { h, createSSR } from 'plaited'
import type { Element, Category, FilterState, AppState } from './types'
import { tableStyles as s } from './styles'
import { renderControls, renderLegend, renderGrid, renderDetailPanel } from './render'

const styleStr = (obj: Record<string, string | number>): string =>
  Object.entries(obj)
    .map(([k, v]) => `${k.replace(/[A-Z]/g, m => `-${m.toLowerCase()}`)}:${v}`)
    .join(';')

const loadElements = async (): Promise<Element[]> => {
  const file = Bun.file(new URL('../data/elements.json', import.meta.url).pathname)
  const data = await file.json()
  return data as Element[]
}

const createState = (elements: Element[]): AppState => ({
  elements,
  filter: { search: '', category: 'all' },
  selectedElement: null,
})

const renderApp = (state: AppState) => {
  const { elements, filter, selectedElement } = state

  return h('div', { style: styleStr(s.container) },
    h('h1', { style: styleStr(s.title) }, 'Periodic Table of Elements'),
    renderControls(filter),
    renderLegend(),
    renderGrid(elements, filter),
    ...(selectedElement ? [renderDetailPanel(selectedElement)] : []),
  )
}

export const handleSearch = (state: AppState, query: string): AppState => ({
  ...state,
  filter: { ...state.filter, search: query },
})

export const handleCategoryFilter = (state: AppState, category: string): AppState => ({
  ...state,
  filter: { ...state.filter, category: category as Category | 'all' },
})

export const handleElementClick = (state: AppState, atomicNumber: number): AppState => {
  const element = state.elements.find(el => el.atomicNumber === atomicNumber) ?? null
  return { ...state, selectedElement: element }
}

export const handleCloseDetail = (state: AppState): AppState => ({
  ...state,
  selectedElement: null,
})

export const render = async (): Promise<string> => {
  const elements = await loadElements()
  const state = createState(elements)
  const template = renderApp(state)
  const { html } = createSSR(template)
  return html
}

export {
  loadElements,
  createState,
  renderApp,
}

export type { Element, Category, FilterState, AppState }

