import type {
  PendulumParams,
  PendulumState,
  ProjectileParams,
  ProjectileState,
  SpringParams,
  SpringState,
  Vec2,
} from './types'

// --- Pendulum (RK4 integration) ---

type PendulumODE = { theta: number; omega: number }

const pendulumDerivative = (
  state: PendulumODE,
  params: PendulumParams,
): PendulumODE => {
  const g = params.gravity
  const L = params.length
  const b = params.damping
  return {
    theta: state.omega,
    omega: -(g / L) * Math.sin(state.theta) - b * state.omega,
  }
}

const rk4Step = (
  state: PendulumODE,
  params: PendulumParams,
  dt: number,
): PendulumODE => {
  const k1 = pendulumDerivative(state, params)
  const k2 = pendulumDerivative(
    { theta: state.theta + (dt / 2) * k1.theta, omega: state.omega + (dt / 2) * k1.omega },
    params,
  )
  const k3 = pendulumDerivative(
    { theta: state.theta + (dt / 2) * k2.theta, omega: state.omega + (dt / 2) * k2.omega },
    params,
  )
  const k4 = pendulumDerivative(
    { theta: state.theta + dt * k3.theta, omega: state.omega + dt * k3.omega },
    params,
  )
  return {
    theta: state.theta + (dt / 6) * (k1.theta + 2 * k2.theta + 2 * k3.theta + k4.theta),
    omega: state.omega + (dt / 6) * (k1.omega + 2 * k2.omega + 2 * k3.omega + k4.omega),
  }
}

export const createPendulumState = (params: PendulumParams): PendulumState => {
  const angle = (params.initialAngle * Math.PI) / 180
  const L = params.length
  return {
    angle,
    angularVelocity: 0,
    angularAcceleration: -(params.gravity / L) * Math.sin(angle),
    position: { x: L * Math.sin(angle), y: L * Math.cos(angle) },
    velocity: 0,
    acceleration: Math.abs(params.gravity * Math.sin(angle)),
    kineticEnergy: 0,
    potentialEnergy: params.gravity * L * (1 - Math.cos(angle)),
    time: 0,
  }
}

export const stepPendulum = (
  state: PendulumState,
  params: PendulumParams,
  dt: number,
): PendulumState => {
  const ode: PendulumODE = { theta: state.angle, omega: state.angularVelocity }
  const next = rk4Step(ode, params, dt)
  const L = params.length
  const angularAcceleration = -(params.gravity / L) * Math.sin(next.theta) - params.damping * next.omega
  const linearVelocity = Math.abs(next.omega * L)
  const linearAcceleration = Math.abs(angularAcceleration * L)
  const height = L * (1 - Math.cos(next.theta))

  return {
    angle: next.theta,
    angularVelocity: next.omega,
    angularAcceleration,
    position: { x: L * Math.sin(next.theta), y: L * Math.cos(next.theta) },
    velocity: linearVelocity,
    acceleration: linearAcceleration,
    kineticEnergy: 0.5 * L * linearVelocity * linearVelocity,
    potentialEnergy: params.gravity * height,
    time: state.time + dt,
  }
}

// --- Projectile Motion (analytical) ---

export const createProjectileState = (params: ProjectileParams): ProjectileState => {
  const angleRad = (params.angle * Math.PI) / 180
  const v0 = params.initialVelocity
  return {
    position: { x: 0, y: 0 },
    velocity: { x: v0 * Math.cos(angleRad), y: v0 * Math.sin(angleRad) },
    acceleration: { x: 0, y: -params.gravity },
    speed: v0,
    time: 0,
    kineticEnergy: 0.5 * v0 * v0,
    potentialEnergy: 0,
    trail: [{ x: 0, y: 0 }],
    landed: false,
  }
}

export const stepProjectile = (
  state: ProjectileState,
  params: ProjectileParams,
  dt: number,
): ProjectileState => {
  if (state.landed) return state

  const newTime = state.time + dt
  const angleRad = (params.angle * Math.PI) / 180
  const v0 = params.initialVelocity
  const g = params.gravity

  const x = v0 * Math.cos(angleRad) * newTime
  const y = v0 * Math.sin(angleRad) * newTime - 0.5 * g * newTime * newTime
  const vx = v0 * Math.cos(angleRad)
  const vy = v0 * Math.sin(angleRad) - g * newTime
  const speed = Math.sqrt(vx * vx + vy * vy)
  const landed = y <= 0 && newTime > 0.01

  const position: Vec2 = { x, y: Math.max(0, y) }
  const trail = [...state.trail, { x: position.x, y: position.y }]

  // Limit trail length to prevent memory issues
  const trimmedTrail = trail.length > 500 ? trail.slice(trail.length - 500) : trail

  return {
    position,
    velocity: { x: vx, y: landed ? 0 : vy },
    acceleration: { x: 0, y: -g },
    speed: landed ? 0 : speed,
    time: newTime,
    kineticEnergy: 0.5 * speed * speed,
    potentialEnergy: g * Math.max(0, y),
    trail: trimmedTrail,
    landed,
  }
}

// --- Spring-Mass System (RK4 integration) ---

type SpringODE = { x: number; v: number }

const springDerivative = (state: SpringODE, params: SpringParams): SpringODE => {
  const omega2 = params.springConstant / params.mass
  return {
    x: state.v,
    v: -omega2 * state.x - params.damping * state.v,
  }
}

const springRK4Step = (
  state: SpringODE,
  params: SpringParams,
  dt: number,
): SpringODE => {
  const k1 = springDerivative(state, params)
  const k2 = springDerivative(
    { x: state.x + (dt / 2) * k1.x, v: state.v + (dt / 2) * k1.v },
    params,
  )
  const k3 = springDerivative(
    { x: state.x + (dt / 2) * k2.x, v: state.v + (dt / 2) * k2.v },
    params,
  )
  const k4 = springDerivative(
    { x: state.x + dt * k3.x, v: state.v + dt * k3.v },
    params,
  )
  return {
    x: state.x + (dt / 6) * (k1.x + 2 * k2.x + 2 * k3.x + k4.x),
    v: state.v + (dt / 6) * (k1.v + 2 * k2.v + 2 * k3.v + k4.v),
  }
}

export const createSpringState = (params: SpringParams): SpringState => {
  const x0 = params.initialDisplacement
  const k = params.springConstant
  return {
    displacement: x0,
    velocity: 0,
    acceleration: -(k / params.mass) * x0,
    time: 0,
    kineticEnergy: 0,
    potentialEnergy: 0.5 * k * x0 * x0,
  }
}

export const stepSpring = (
  state: SpringState,
  params: SpringParams,
  dt: number,
): SpringState => {
  const ode: SpringODE = { x: state.displacement, v: state.velocity }
  const next = springRK4Step(ode, params, dt)
  const acc = -(params.springConstant / params.mass) * next.x - params.damping * next.v
  const k = params.springConstant

  return {
    displacement: next.x,
    velocity: next.v,
    acceleration: acc,
    time: state.time + dt,
    kineticEnergy: 0.5 * params.mass * next.v * next.v,
    potentialEnergy: 0.5 * k * next.x * next.x,
  }
}

