// --- Pendulum SVG ---
const renderPendulumCanvas = (state: PendulumState, params: PendulumParams) => {
  const cx = CANVAS_W / 2
  const cy = 60
  const scale = 120 / params.length // pixels per meter, normalized
  const bobX = cx + state.position.x * scale
  const bobY = cy + state.position.y * scale
  const bobRadius = 16

  // Arc showing initial angle range
  const arcRadius = 40
  const arcStartAngle = -params.initialAngle * Math.PI / 180
  const arcEndAngle = params.initialAngle * Math.PI / 180
  const arcX1 = cx + arcRadius * Math.sin(arcStartAngle)
  const arcY1 = cy + arcRadius * Math.cos(arcStartAngle)
  const arcX2 = cx + arcRadius * Math.sin(arcEndAngle)
  const arcY2 = cy + arcRadius * Math.cos(arcEndAngle)

  return h('svg', {
    width: String(CANVAS_W),
    height: String(CANVAS_H),
    style: `background:${colors.bg};border-radius:8px;border:1px solid ${colors.border}`,
  },
    // Grid lines
    ...Array.from({ length: 7 }, (_, i) => {
      const y = (i + 1) * (CANVAS_H / 8)
      return h('line', {
        x1: '0', y1: String(y), x2: String(CANVAS_W), y2: String(y),
        stroke: colors.grid, 'stroke-width': '1', 'stroke-dasharray': '4,4',
      })
    }),
    // Pivot point
    h('circle', { cx: String(cx), cy: String(cy), r: '5', fill: colors.ground }),
    // Angle arc
    h('path', {
      d: `M ${arcX1} ${arcY1} A ${arcRadius} ${arcRadius} 0 0 1 ${arcX2} ${arcY2}`,
      fill: 'none', stroke: colors.textMuted, 'stroke-width': '1', 'stroke-dasharray': '3,3',
    }),
    // Vertical reference line
    h('line', {
      x1: String(cx), y1: String(cy), x2: String(cx), y2: String(cy + 50),
      stroke: colors.textMuted, 'stroke-width': '1', 'stroke-dasharray': '3,3',
    }),
    // Rod
    h('line', {
      x1: String(cx), y1: String(cy), x2: String(bobX), y2: String(bobY),
      stroke: colors.pendulumRod, 'stroke-width': '2',
    }),
    // Bob
    h('circle', {
      cx: String(bobX), cy: String(bobY), r: String(bobRadius),
      fill: colors.pendulumBob, stroke: '#d97706', 'stroke-width': '2',
    }),
    // Velocity vector
    h('line', {
      x1: String(bobX),
      y1: String(bobY),
      x2: String(bobX + state.angularVelocity * scale * 0.5),
      y2: String(bobY),
      stroke: colors.energy.kinetic, 'stroke-width': '2',
      'marker-end': 'url(#arrow)',
    }),
    // Arrow marker def
    h('defs', {},
      h('marker', {
        id: 'arrow', viewBox: '0 0 10 10', refX: '10', refY: '5',
        markerWidth: '6', markerHeight: '6', orient: 'auto-start-reverse',
      },
        h('path', { d: 'M 0 0 L 10 5 L 0 10 z', fill: colors.energy.kinetic }),
      ),
    ),
    // Labels
    h('text', {
      x: '10', y: '25', fill: colors.textMuted, 'font-size': '12', 'font-family': 'monospace',
    }, `\u03B8 = ${formatNum((state.angle * 180) / Math.PI, 1)}\u00B0`),
    h('text', {
      x: '10', y: '42', fill: colors.textMuted, 'font-size': '12', 'font-family': 'monospace',
    }, `t = ${formatNum(state.time, 1)}s`),
  )
}

// --- Projectile SVG ---
const renderProjectileCanvas = (state: ProjectileState, params: ProjectileParams) => {
  // Calculate range for scaling
  const angleRad = (params.angle * Math.PI) / 180
  const v0 = params.initialVelocity
  const g = params.gravity
  const maxRange = (v0 * v0 * Math.sin(2 * angleRad)) / g
  const maxHeight = (v0 * v0 * Math.sin(angleRad) * Math.sin(angleRad)) / (2 * g)

  const margin = 40
  const plotW = CANVAS_W - 2 * margin
  const plotH = CANVAS_H - 2 * margin
  const scaleX = plotW / Math.max(maxRange * 1.1, 1)
  const scaleY = plotH / Math.max(maxHeight * 1.3, 1)
  const scale = Math.min(scaleX, scaleY)

  const groundY = CANVAS_H - margin

  const toScreenX = (x: number) => margin + x * scale
  const toScreenY = (y: number) => groundY - y * scale

  // Trail path
  const trailPoints = state.trail
    .map((p) => `${toScreenX(p.x)},${toScreenY(p.y)}`)
    .join(' ')

  return h('svg', {
    width: String(CANVAS_W),
    height: String(CANVAS_H),
    style: `background:${colors.bg};border-radius:8px;border:1px solid ${colors.border}`,
  },
    // Ground
    h('line', {
      x1: String(margin), y1: String(groundY),
      x2: String(CANVAS_W - margin), y2: String(groundY),
      stroke: colors.ground, 'stroke-width': '2',
    }),
    // Y axis
    h('line', {
      x1: String(margin), y1: String(margin),
      x2: String(margin), y2: String(groundY),
      stroke: colors.ground, 'stroke-width': '1',
    }),
    // Grid
    ...Array.from({ length: 5 }, (_, i) => {
      const y = groundY - ((i + 1) * plotH) / 6
      return h('line', {
        x1: String(margin), y1: String(y),
        x2: String(CANVAS_W - margin), y2: String(y),
        stroke: colors.grid, 'stroke-width': '1', 'stroke-dasharray': '4,4',
      })
    }),
    // Trajectory trail
    state.trail.length > 1
      ? h('polyline', {
          points: trailPoints,
          fill: 'none', stroke: colors.trajectory, 'stroke-width': '2', opacity: '0.7',
        })
      : h('g', {}),
    // Launch angle indicator
    h('line', {
      x1: String(toScreenX(0)), y1: String(toScreenY(0)),
      x2: String(toScreenX(maxRange * 0.15 * Math.cos(angleRad))),
      y2: String(toScreenY(maxRange * 0.15 * Math.sin(angleRad))),
      stroke: colors.textMuted, 'stroke-width': '1', 'stroke-dasharray': '4,4',
    }),
    // Projectile
    h('circle', {
      cx: String(toScreenX(state.position.x)),
      cy: String(toScreenY(state.position.y)),
      r: '8',
      fill: colors.projectile, stroke: '#dc2626', 'stroke-width': '2',
    }),
    // Velocity vector
    h('line', {
      x1: String(toScreenX(state.position.x)),
      y1: String(toScreenY(state.position.y)),
      x2: String(toScreenX(state.position.x) + state.velocity.x * 1.5),
      y2: String(toScreenY(state.position.y) - state.velocity.y * 1.5),
      stroke: colors.energy.kinetic, 'stroke-width': '2',
    }),
    // Labels
    h('text', {
      x: '10', y: '20', fill: colors.textMuted, 'font-size': '12', 'font-family': 'monospace',
    }, `Range: ${formatNum(maxRange, 1)}m`),
    h('text', {
      x: '10', y: '37', fill: colors.textMuted, 'font-size': '12', 'font-family': 'monospace',
    }, `Max H: ${formatNum(maxHeight, 1)}m`),
    h('text', {
      x: '10', y: '54', fill: colors.textMuted, 'font-size': '12', 'font-family': 'monospace',
    }, `t = ${formatNum(state.time, 1)}s`),
  )
}

// --- Spring-Mass SVG ---
const renderSpringCanvas = (state: SpringState, params: SpringParams) => {
  const anchorX = 80
  const anchorY = CANVAS_H / 2
  const equilibriumX = CANVAS_W / 2
  const scale = 150 // pixels per meter
  const massX = equilibriumX + state.displacement * scale
  const massSize = 30

  // Draw spring zigzag from anchor to mass
  const numCoils = 12
  const springStartX = anchorX + 20
  const springEndX = massX - massSize / 2
  const coilWidth = (springEndX - springStartX) / numCoils
  const coilAmplitude = 15

  const springPathParts: string[] = [`M ${springStartX} ${anchorY}`]
  for (let i = 0; i < numCoils; i++) {
    const x1 = springStartX + (i + 0.25) * coilWidth
    const x2 = springStartX + (i + 0.75) * coilWidth
    const x3 = springStartX + (i + 1) * coilWidth
    const yOff = i % 2 === 0 ? -coilAmplitude : coilAmplitude
    springPathParts.push(`L ${x1} ${anchorY + yOff}`)
    springPathParts.push(`L ${x2} ${anchorY - yOff}`)
    springPathParts.push(`L ${x3} ${anchorY}`)
  }
  const springPath = springPathParts.join(' ')

  // Energy bar heights
  const maxEnergy = 0.5 * params.springConstant * params.initialDisplacement * params.initialDisplacement
  const keBarH = maxEnergy > 0 ? (state.kineticEnergy / maxEnergy) * 80 : 0
  const peBarH = maxEnergy > 0 ? (state.potentialEnergy / maxEnergy) * 80 : 0

  return h('svg', {
    width: String(CANVAS_W),
    height: String(CANVAS_H),
    style: `background:${colors.bg};border-radius:8px;border:1px solid ${colors.border}`,
  },
    // Wall
    h('rect', {
      x: String(anchorX - 5), y: String(anchorY - 60),
      width: '10', height: '120',
      fill: colors.ground, rx: '2',
    }),
    // Wall hatching
    ...Array.from({ length: 6 }, (_, i) => {
      const y = anchorY - 50 + i * 20
      return h('line', {
        x1: String(anchorX - 5), y1: String(y),
        x2: String(anchorX - 15), y2: String(y + 10),
        stroke: colors.ground, 'stroke-width': '1',
      })
    }),
    // Equilibrium line
    h('line', {
      x1: String(equilibriumX), y1: String(anchorY - 80),
      x2: String(equilibriumX), y2: String(anchorY + 80),
      stroke: colors.textMuted, 'stroke-width': '1', 'stroke-dasharray': '4,4',
    }),
    h('text', {
      x: String(equilibriumX - 5), y: String(anchorY + 95),
      fill: colors.textMuted, 'font-size': '10', 'font-family': 'monospace',
    }, 'x=0'),
    // Spring
    h('path', {
      d: springPath,
      fill: 'none', stroke: colors.spring, 'stroke-width': '2.5',
      'stroke-linecap': 'round', 'stroke-linejoin': 'round',
    }),
    // Mass block
    h('rect', {
      x: String(massX - massSize / 2), y: String(anchorY - massSize / 2),
      width: String(massSize), height: String(massSize),
      fill: colors.springMass, stroke: '#db2777', 'stroke-width': '2', rx: '4',
    }),
    h('text', {
      x: String(massX - 5), y: String(anchorY + 4),
      fill: '#fff', 'font-size': '11', 'font-family': 'monospace', 'font-weight': 'bold',
    }, 'm'),
    // Ground/rail
    h('line', {
      x1: String(anchorX), y1: String(anchorY + massSize / 2 + 5),
      x2: String(CANVAS_W - 40), y2: String(anchorY + massSize / 2 + 5),
      stroke: colors.ground, 'stroke-width': '1', 'stroke-dasharray': '6,3',
    }),
    // Energy bars
    h('rect', {
      x: String(CANVAS_W - 60), y: String(CANVAS_H - 30 - keBarH),
      width: '18', height: String(Math.max(keBarH, 1)),
      fill: colors.energy.kinetic, rx: '2',
    }),
    h('text', {
      x: String(CANVAS_W - 56), y: String(CANVAS_H - 12),
      fill: colors.energy.kinetic, 'font-size': '9', 'font-family': 'monospace',
    }, 'KE'),
    h('rect', {
      x: String(CANVAS_W - 35), y: String(CANVAS_H - 30 - peBarH),
      width: '18', height: String(Math.max(peBarH, 1)),
      fill: colors.energy.potential, rx: '2',
    }),
    h('text', {
      x: String(CANVAS_W - 31), y: String(CANVAS_H - 12),
      fill: colors.energy.potential, 'font-size': '9', 'font-family': 'monospace',
    }, 'PE'),
    // Labels
    h('text', {
      x: '10', y: '25', fill: colors.textMuted, 'font-size': '12', 'font-family': 'monospace',
    }, `x = ${formatNum(state.displacement, 3)}m`),
    h('text', {
      x: '10', y: '42', fill: colors.textMuted, 'font-size': '12', 'font-family': 'monospace',
    }, `t = ${formatNum(state.time, 1)}s`),
  )
}

// --- Real-time values panel ---
const renderPendulumValues = (state: PendulumState) =>
  h('div', { style: `display:grid;grid-template-columns:1fr 1fr;gap:6px 16px` },
    renderValueItem('Angle', `${formatNum((state.angle * 180) / Math.PI, 1)}\u00B0`),
    renderValueItem('Angular Vel', `${formatNum(state.angularVelocity, 3)} rad/s`),
    renderValueItem('Position X', `${formatNum(state.position.x, 3)} m`),
    renderValueItem('Position Y', `${formatNum(state.position.y, 3)} m`),
    renderValueItem('Velocity', `${formatNum(state.velocity, 3)} m/s`),
    renderValueItem('Acceleration', `${formatNum(state.acceleration, 3)} m/s\u00B2`),
    renderValueItem('Kinetic E', `${formatNum(state.kineticEnergy, 3)} J`, colors.energy.kinetic),
    renderValueItem('Potential E', `${formatNum(state.potentialEnergy, 3)} J`, colors.energy.potential),
