  const { type, pendulum, projectile, spring } = state

  const canvas = type === 'pendulum'
    ? renderPendulumCanvas(pendulum.state, pendulum.params)
    : type === 'projectile'
      ? renderProjectileCanvas(projectile.state, projectile.params)
      : renderSpringCanvas(spring.state, spring.params)

  const values = type === 'pendulum'
    ? renderPendulumValues(pendulum.state)
    : type === 'projectile'
      ? renderProjectileValues(projectile.state)
      : renderSpringValues(spring.state)

  const sliders = type === 'pendulum'
    ? renderPendulumSliders(pendulum.params)
    : type === 'projectile'
      ? renderProjectileSliders(projectile.params)
      : renderSpringSliders(spring.params)

  const simTitle = type === 'pendulum'
    ? 'Simple Pendulum'
    : type === 'projectile'
      ? 'Projectile Motion'
      : 'Spring-Mass System'

  const simDescription = type === 'pendulum'
    ? 'F = -mg sin(\u03B8) \u2014 Oscillation under gravity'
    : type === 'projectile'
      ? 'F = mg \u2014 Parabolic trajectory under uniform gravity'
      : 'F = -kx \u2014 Simple harmonic motion (Hooke\'s Law)'

  return h('div', {
    id: 'newton-sim-root',
    style: `
      font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,sans-serif;
      background:${colors.bg};color:${colors.text};
      max-width:720px;margin:0 auto;padding:20px;
