  });
};

const updatePlayBtn = () => {
  const btn = document.getElementById('play-btn');
  if (!btn) return;
  const isPlaying = state.playback === 'playing';
  btn.textContent = isPlaying ? 'Pause' : 'Play';
  btn.style.background = isPlaying ? colors.panel : colors.accent;
};

const sliderConfigs = {
  pendulum: [
    {id:'length',label:'Length',min:0.5,max:3,step:0.1,unit:'m',key:'length'},
    {id:'gravity',label:'Gravity',min:1,max:20,step:0.5,unit:'m/s\\u00B2',key:'gravity'},
    {id:'initialAngle',label:'Start Angle',min:5,max:80,step:1,unit:'\\u00B0',key:'initialAngle'},
  ],
  projectile: [
    {id:'angle',label:'Launch Angle',min:5,max:85,step:1,unit:'\\u00B0',key:'angle'},
    {id:'initialVelocity',label:'Init Velocity',min:5,max:50,step:1,unit:'m/s',key:'initialVelocity'},
    {id:'gravity',label:'Gravity',min:1,max:20,step:0.5,unit:'m/s\\u00B2',key:'gravity'},
  ],
  spring: [
    {id:'springConstant',label:'Spring k',min:1,max:50,step:1,unit:'N/m',key:'springConstant'},
    {id:'mass',label:'Mass',min:0.5,max:10,step:0.5,unit:'kg',key:'mass'},
    {id:'initialDisplacement',label:'Init Displ',min:0.1,max:1,step:0.05,unit:'m',key:'initialDisplacement'},
  ],
};

const getParams = () => {
  if (state.type === 'pendulum') return state.pendulum.params;
  if (state.type === 'projectile') return state.projectile.params;
  return state.spring.params;
};

const updateSliders = () => {
  const container = document.getElementById('sim-sliders');
  const configs = sliderConfigs[state.type];
  const params = getParams();
  let html = '';
  configs.forEach(c => {
    const val = params[c.key];
    html += '<div style="display:flex;align-items:center;gap:8px;margin:4px 0">';
    html += '<label for="'+c.id+'" style="color:'+colors.textMuted+';font-size:12px;min-width:100px">'+c.label+'</label>';
    html += '<input type="range" id="slider-'+c.id+'" min="'+c.min+'" max="'+c.max+'" step="'+c.step+'" value="'+val+'" data-param="'+c.key+'" style="flex:1;accent-color:'+colors.accent+'">';
    html += '<span id="val-'+c.id+'" style="color:'+colors.text+';font-size:12px;min-width:60px;text-align:right">'+fmt(val, c.step<1?2:1)+' '+c.unit+'</span>';
    html += '</div>';
  });
  container.innerHTML = html;

  // Rebind slider events
  configs.forEach(c => {
    const slider = document.getElementById('slider-'+c.id);
    if (!slider) return;
    slider.addEventListener('input', (e) => {
      const v = parseFloat(e.target.value);
      const params = getParams();
