export const renderSSR = (): string => {
  const sim = createSimulation()
  const appTemplate = renderApp(sim.getState())
  // The plaited template returns a template result that can be stringified
  return String(appTemplate)
}

/**
 * Starts the Bun HTTP server serving the interactive simulator.
 */
const serve = () => {
  Bun.serve({
    port: PORT,
    fetch: (req: Request): Response => {
      const url = new URL(req.url)

      if (url.pathname === '/' || url.pathname === '/index.html') {
        return new Response(generatePage(), {
          headers: { 'Content-Type': 'text/html; charset=utf-8' },
        })
      }

      if (url.pathname === '/api/state') {
        const sim = createSimulation()
        return Response.json(sim.getState())
      }

      return new Response('Not Found', { status: 404 })
    },
  })

  console.log(`Newton's Laws Simulator running at http://localhost:${PORT}`)
}

