import type {
  PendulumParams,
  PendulumState,
  ProjectileParams,
  ProjectileState,
  SpringParams,
  SpringState,
  Vector2,
} from './types'

const DEG_TO_RAD = Math.PI / 180

// --- Pendulum ---
// Uses Runge-Kutta 4th order integration for accuracy
// θ'' = -(g/L) * sin(θ)

export const createPendulumState = (params: PendulumParams): PendulumState => {
  const theta = params.initialAngle * DEG_TO_RAD
  const { length } = params
  return {
    theta,
    omega: 0,
    alpha: -(params.gravity / length) * Math.sin(theta),
    position: {
      x: length * Math.sin(theta),
      y: -length * Math.cos(theta),
    },
    velocity: { x: 0, y: 0 },
    acceleration: { x: 0, y: 0 },
    time: 0,
  }
}

export const stepPendulum = (
  state: PendulumState,
  params: PendulumParams,
  dt: number,
): PendulumState => {
  const { gravity, length } = params
  const gOverL = gravity / length

  // RK4 integration
  const f = (theta: number, omega: number): { dTheta: number; dOmega: number } => ({
    dTheta: omega,
    dOmega: -gOverL * Math.sin(theta),
  })

  const k1 = f(state.theta, state.omega)
  const k2 = f(state.theta + 0.5 * dt * k1.dTheta, state.omega + 0.5 * dt * k1.dOmega)
  const k3 = f(state.theta + 0.5 * dt * k2.dTheta, state.omega + 0.5 * dt * k2.dOmega)
  const k4 = f(state.theta + dt * k3.dTheta, state.omega + dt * k3.dOmega)

  const theta = state.theta + (dt / 6) * (k1.dTheta + 2 * k2.dTheta + 2 * k3.dTheta + k4.dTheta)
  const omega = state.omega + (dt / 6) * (k1.dOmega + 2 * k2.dOmega + 2 * k3.dOmega + k4.dOmega)
  const alpha = -gOverL * Math.sin(theta)

  const x = length * Math.sin(theta)
  const y = -length * Math.cos(theta)
  const vx = length * omega * Math.cos(theta)
  const vy = length * omega * Math.sin(theta)
  const ax = length * (alpha * Math.cos(theta) - omega * omega * Math.sin(theta))
  const ay = length * (alpha * Math.sin(theta) + omega * omega * Math.cos(theta))

  return {
    theta,
    omega,
    alpha,
    position: { x, y },
    velocity: { x: vx, y: vy },
    acceleration: { x: ax, y: ay },
    time: state.time + dt,
  }
}

// --- Projectile ---
// x(t) = v₀·cos(α)·t
// y(t) = v₀·sin(α)·t - ½·g·t²

export const createProjectileState = (params: ProjectileParams): ProjectileState => {
  const angleRad = params.angle * DEG_TO_RAD
  return {
    landed: false,
    trajectoryPoints: [{ x: 0, y: 0 }],
    position: { x: 0, y: 0 },
    velocity: {
      x: params.initialVelocity * Math.cos(angleRad),
      y: params.initialVelocity * Math.sin(angleRad),
    },
    acceleration: { x: 0, y: -params.gravity },
    time: 0,
  }
}

export const stepProjectile = (
  state: ProjectileState,
  params: ProjectileParams,
  dt: number,
): ProjectileState => {
  if (state.landed) return state

  const newTime = state.time + dt
  const angleRad = params.angle * DEG_TO_RAD
  const v0x = params.initialVelocity * Math.cos(angleRad)
  const v0y = params.initialVelocity * Math.sin(angleRad)

  const x = v0x * newTime
  const y = v0y * newTime - 0.5 * params.gravity * newTime * newTime

  const landed = y <= 0 && newTime > 0.01

  const clampedY = landed ? 0 : y
  const finalTime = landed
    ? (2 * v0y) / params.gravity
    : newTime
  const finalX = landed ? v0x * finalTime : x

  const newPoint: Vector2 = { x: finalX, y: clampedY }
  const trajectoryPoints = [...state.trajectoryPoints, newPoint]

  return {
    landed,
    trajectoryPoints,
    position: { x: finalX, y: clampedY },
    velocity: {
      x: v0x,
      y: landed ? 0 : v0y - params.gravity * newTime,
    },
    acceleration: { x: 0, y: landed ? 0 : -params.gravity },
    time: landed ? finalTime : newTime,
  }
}

// --- Spring-Mass ---
// x(t) = A·cos(ωt), where ω = √(k/m)
// Analytical solution for simple harmonic motion

export const createSpringState = (params: SpringParams): SpringState => {
  const { initialDisplacement } = params
  const omega = Math.sqrt(params.springConstant / params.mass)
  return {
    displacement: initialDisplacement,
    springVelocity: 0,
    springAcceleration: -(params.springConstant / params.mass) * initialDisplacement,
    position: { x: initialDisplacement, y: 0 },
    velocity: { x: 0, y: 0 },
    acceleration: { x: -(params.springConstant / params.mass) * initialDisplacement, y: 0 },
    time: 0,
  }
}

export const stepSpring = (
  state: SpringState,
  params: SpringParams,
  dt: number,
): SpringState => {
  const newTime = state.time + dt
  const omega = Math.sqrt(params.springConstant / params.mass)
  const A = params.initialDisplacement

  const displacement = A * Math.cos(omega * newTime)
  const springVelocity = -A * omega * Math.sin(omega * newTime)
  const springAcceleration = -A * omega * omega * Math.cos(omega * newTime)

  return {
    displacement,
    springVelocity,
    springAcceleration,
    position: { x: displacement, y: 0 },
    velocity: { x: springVelocity, y: 0 },
    acceleration: { x: springAcceleration, y: 0 },
    time: newTime,
  }
}

