    h('div', { style: styleToStr(styles.sliderLabel) },
      h('span', { style: styleToStr(styles.sliderLabelText) }, config.label),
      h('span', { style: styleToStr(styles.sliderValue), id: `val-${config.id}` },
        `${config.value} ${config.unit}`),
