const clientScript = (): string => `
(function() {
  const DEG = Math.PI / 180;
  const canvas = document.getElementById('sim-canvas');
  const ctx = canvas.getContext('2d');
  const dpr = window.devicePixelRatio || 1;

  // Hi-DPI setup
  const rect = canvas.getBoundingClientRect();
  canvas.width = rect.width * dpr;
  canvas.height = rect.height * dpr;
  ctx.scale(dpr, dpr);
  const W = rect.width;
  const H = rect.height;

  const colors = {
    pendulum: '#4f8ff7',
    projectile: '#34d399',
    spring: '#fbbf24',
    grid: '#1e2130',
    axis: '#2a2d3a',
    text: '#8b8fa3',
    trail: '#4f8ff733',
  };

  let activeSim = 'pendulum';
  let playing = false;
  let speed = 1;
  let lastFrame = 0;

  // Pendulum state
  let pend = { L: 2, g: 9.81, angle0: 30, theta: 0, omega: 0, time: 0, trail: [] };
  // Projectile state
  let proj = { angle: 45, v0: 20, g: 9.81, time: 0, landed: false, trail: [] };
  // Spring state
  let spr = { k: 10, m: 1, x0: 1, time: 0, trail: [] };

  const resetPendulum = () => {
    pend.theta = pend.angle0 * DEG;
    pend.omega = 0;
    pend.time = 0;
    pend.trail = [];
  };

  const resetProjectile = () => {
    proj.time = 0;
    proj.landed = false;
    proj.trail = [{ x: 0, y: 0 }];
  };

  const resetSpring = () => {
    spr.time = 0;
    spr.trail = [];
  };

  const resetAll = () => { resetPendulum(); resetProjectile(); resetSpring(); };

  // --- Physics step functions ---

  const stepPend = (dt) => {
    const gL = pend.g / pend.L;
    const steps = 4;
    const h = dt / steps;
    for (let i = 0; i < steps; i++) {
      const k1t = pend.omega;
      const k1o = -gL * Math.sin(pend.theta);
      const k2t = pend.omega + 0.5 * h * k1o;
      const k2o = -gL * Math.sin(pend.theta + 0.5 * h * k1t);
      const k3t = pend.omega + 0.5 * h * k2o;
      const k3o = -gL * Math.sin(pend.theta + 0.5 * h * k2t);
      const k4t = pend.omega + h * k3o;
      const k4o = -gL * Math.sin(pend.theta + h * k3t);
      pend.theta += (h / 6) * (k1t + 2*k2t + 2*k3t + k4t);
      pend.omega += (h / 6) * (k1o + 2*k2o + 2*k3o + k4o);
    }
    pend.time += dt;
    const x = pend.L * Math.sin(pend.theta);
    const y = -pend.L * Math.cos(pend.theta);
    pend.trail.push({ x, y });
    if (pend.trail.length > 300) pend.trail.shift();
  };

  const getProj = (t) => {
    const ar = proj.angle * DEG;
    const vx = proj.v0 * Math.cos(ar);
    const vy = proj.v0 * Math.sin(ar);
    return {
      x: vx * t,
      y: vy * t - 0.5 * proj.g * t * t,
      vx,
      vy: vy - proj.g * t,
    };
  };

  const stepProj = (dt) => {
    if (proj.landed) return;
    proj.time += dt;
    const p = getProj(proj.time);
    if (p.y <= 0 && proj.time > 0.05) {
      const ar = proj.angle * DEG;
      const vy = proj.v0 * Math.sin(ar);
      proj.time = (2 * vy) / proj.g;
      proj.landed = true;
      const pf = getProj(proj.time);
      proj.trail.push({ x: pf.x, y: 0 });
    } else {
      proj.trail.push({ x: p.x, y: p.y });
    }
  };

  const stepSpr = (dt) => {
    spr.time += dt;
    spr.trail.push({ t: spr.time, x: spr.x0 * Math.cos(Math.sqrt(spr.k / spr.m) * spr.time) });
    if (spr.trail.length > 500) spr.trail.shift();
  };

  // --- Drawing ---

  const drawGrid = (ox, oy, scaleX, scaleY, labelX, labelY) => {
    ctx.strokeStyle = colors.grid;
    ctx.lineWidth = 1;
    for (let i = -20; i <= 20; i++) {
      const gx = ox + i * scaleX;
      if (gx >= 0 && gx <= W) {
        ctx.beginPath(); ctx.moveTo(gx, 0); ctx.lineTo(gx, H); ctx.stroke();
      }
      const gy = oy + i * scaleY;
      if (gy >= 0 && gy <= H) {
        ctx.beginPath(); ctx.moveTo(0, gy); ctx.lineTo(W, gy); ctx.stroke();
      }
    }
    ctx.strokeStyle = colors.axis;
    ctx.lineWidth = 1.5;
    ctx.beginPath(); ctx.moveTo(0, oy); ctx.lineTo(W, oy); ctx.stroke();
    ctx.beginPath(); ctx.moveTo(ox, 0); ctx.lineTo(ox, H); ctx.stroke();
  };

  const drawPendulum = () => {
    const ox = W / 2;
    const oy = 80;
    const scale = Math.min(180, (H - 120) / (pend.L * 1.2));

    // Draw faint grid
    ctx.strokeStyle = colors.grid;
    ctx.lineWidth = 0.5;
    for (let i = 0; i < 10; i++) {
      ctx.beginPath();
      ctx.arc(ox, oy, (i + 1) * scale * 0.5, 0, Math.PI * 2);
      ctx.stroke();
    }

    // Trail (angle vs time)
    if (pend.trail.length > 1) {
      ctx.strokeStyle = colors.trail;
      ctx.lineWidth = 1.5;
      ctx.beginPath();
      pend.trail.forEach((p, i) => {
        const px = ox + p.x * scale;
        const py = oy - p.y * scale;
        i === 0 ? ctx.moveTo(px, py) : ctx.lineTo(px, py);
      });
      ctx.stroke();
    }

    const bx = ox + pend.L * Math.sin(pend.theta) * scale;
    const by = oy + pend.L * Math.cos(pend.theta) * scale;

    // Rod
    ctx.strokeStyle = '#556';
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.moveTo(ox, oy);
    ctx.lineTo(bx, by);
    ctx.stroke();

    // Pivot
    ctx.fillStyle = '#888';
    ctx.beginPath();
    ctx.arc(ox, oy, 5, 0, Math.PI * 2);
    ctx.fill();

    // Bob
    const grad = ctx.createRadialGradient(bx - 3, by - 3, 2, bx, by, 18);
    grad.addColorStop(0, '#7ab4ff');
    grad.addColorStop(1, colors.pendulum);
    ctx.fillStyle = grad;
    ctx.beginPath();
    ctx.arc(bx, by, 16, 0, Math.PI * 2);
    ctx.fill();

    ctx.shadowColor = colors.pendulum;
    ctx.shadowBlur = 12;
    ctx.beginPath();
    ctx.arc(bx, by, 16, 0, Math.PI * 2);
    ctx.fill();
    ctx.shadowBlur = 0;

    // Labels
    ctx.fillStyle = colors.text;
    ctx.font = '12px Inter, sans-serif';
    ctx.textAlign = 'left';
    ctx.fillText('L = ' + pend.L.toFixed(1) + ' m', 20, 30);
    ctx.fillText('g = ' + pend.g.toFixed(1) + ' m/s\\u00B2', 20, 48);
    ctx.fillText('\\u03B8 = ' + (pend.theta / DEG).toFixed(1) + '\\u00B0', 20, 66);
  };

  const drawProjectile = () => {
    const ox = 60;
    const oy = H - 60;
    const ar = proj.angle * DEG;
    const v0y = proj.v0 * Math.sin(ar);
    const v0x = proj.v0 * Math.cos(ar);
    const maxH = (v0y * v0y) / (2 * proj.g);
    const range = (proj.v0 * proj.v0 * Math.sin(2 * ar)) / proj.g;

    const scaleX = Math.min((W - 120) / (range * 1.1), 80);
    const scaleY = Math.min((H - 120) / (maxH * 1.3), 80);
    const sc = Math.min(scaleX, scaleY);

    drawGrid(ox, oy, sc * (range / 5), -sc * (maxH / 4), '', '');

    // Trajectory trail
    if (proj.trail.length > 1) {
      ctx.strokeStyle = colors.projectile;
      ctx.lineWidth = 2.5;
      ctx.setLineDash([]);
      ctx.beginPath();
      proj.trail.forEach((p, i) => {
        const px = ox + p.x * sc;
        const py = oy - p.y * sc;
        i === 0 ? ctx.moveTo(px, py) : ctx.lineTo(px, py);
      });
      ctx.stroke();

      // Ghost full path
      ctx.strokeStyle = colors.projectile + '33';
      ctx.lineWidth = 1;
      ctx.setLineDash([4, 4]);
      ctx.beginPath();
      const tTotal = (2 * v0y) / proj.g;
      for (let t = 0; t <= tTotal; t += tTotal / 100) {
        const px = ox + v0x * t * sc;
        const py = oy - (v0y * t - 0.5 * proj.g * t * t) * sc;
        t === 0 ? ctx.moveTo(px, py) : ctx.lineTo(px, py);
      }
      ctx.stroke();
      ctx.setLineDash([]);
    }

    // Current position dot
    const cp = getProj(proj.time);
    const cpx = ox + cp.x * sc;
    const cpy = oy - Math.max(0, cp.y) * sc;
    const grad = ctx.createRadialGradient(cpx - 2, cpy - 2, 1, cpx, cpy, 12);
    grad.addColorStop(0, '#6ee7b7');
    grad.addColorStop(1, colors.projectile);
    ctx.fillStyle = grad;
    ctx.beginPath();
    ctx.arc(cpx, cpy, 10, 0, Math.PI * 2);
    ctx.fill();
    ctx.shadowColor = colors.projectile;
    ctx.shadowBlur = 10;
    ctx.fill();
    ctx.shadowBlur = 0;

    // Velocity arrow
    if (!proj.landed) {
      const arrScale = 2;
      ctx.strokeStyle = '#f87171';
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.moveTo(cpx, cpy);
      ctx.lineTo(cpx + cp.vx * arrScale, cpy - cp.vy * arrScale);
      ctx.stroke();
      const angle = Math.atan2(-cp.vy, cp.vx);
      ctx.fillStyle = '#f87171';
      ctx.beginPath();
      ctx.moveTo(cpx + cp.vx * arrScale, cpy - cp.vy * arrScale);
      ctx.lineTo(cpx + cp.vx * arrScale - 8 * Math.cos(angle - 0.4), cpy - cp.vy * arrScale - 8 * Math.sin(angle - 0.4));
      ctx.lineTo(cpx + cp.vx * arrScale - 8 * Math.cos(angle + 0.4), cpy - cp.vy * arrScale - 8 * Math.sin(angle + 0.4));
      ctx.closePath();
      ctx.fill();
    }

    // Labels
    ctx.fillStyle = colors.text;
    ctx.font = '12px Inter, sans-serif';
    ctx.textAlign = 'left';
    ctx.fillText('Range: ' + range.toFixed(1) + ' m', 20, 30);
    ctx.fillText('Max Height: ' + maxH.toFixed(1) + ' m', 20, 48);
    ctx.fillText('v\\u2080 = ' + proj.v0 + ' m/s at ' + proj.angle + '\\u00B0', 20, 66);
  };

  const drawSpring = () => {
    const ox = W / 2;
    const oy = H / 2;
    const omega = Math.sqrt(spr.k / spr.m);
    const x = spr.x0 * Math.cos(omega * spr.time);
    const scale = 120;

    // Draw equilibrium line
    ctx.strokeStyle = colors.axis;
    ctx.lineWidth = 1;
    ctx.setLineDash([5, 5]);
    ctx.beginPath();
    ctx.moveTo(ox, 100);
    ctx.lineTo(ox, H - 40);
    ctx.stroke();
    ctx.setLineDash([]);

    // Wall
    ctx.fillStyle = '#2a2d3a';
    ctx.fillRect(60, oy - 60, 12, 120);
    ctx.strokeStyle = '#556';
    ctx.lineWidth = 2;
    for (let i = 0; i < 6; i++) {
      ctx.beginPath();
      ctx.moveTo(60, oy - 50 + i * 20);
      ctx.lineTo(48, oy - 40 + i * 20);
      ctx.stroke();
    }

    // Spring coils
    const massX = ox + x * scale;
    const springStart = 72;
    const coils = 12;
    const springLen = massX - springStart;
    const coilW = springLen / coils;
    const amplitude = 16;

    ctx.strokeStyle = colors.spring;
    ctx.lineWidth = 2.5;
    ctx.beginPath();
    ctx.moveTo(springStart, oy);
    for (let i = 0; i <= coils; i++) {
      const cx = springStart + i * coilW;
      const cy = i % 2 === 0 ? oy - amplitude : oy + amplitude;
      if (i === 0 || i === coils) {
        ctx.lineTo(cx, oy);
      } else {
        ctx.lineTo(cx, cy);
      }
    }
    ctx.stroke();

    // Mass block
    const blockW = 50;
    const blockH = 50;
    const grad = ctx.createLinearGradient(massX, oy - blockH/2, massX + blockW, oy + blockH/2);
    grad.addColorStop(0, '#fde68a');
    grad.addColorStop(1, colors.spring);
    ctx.fillStyle = grad;
    ctx.beginPath();
    ctx.roundRect(massX - blockW/2, oy - blockH/2, blockW, blockH, 8);
    ctx.fill();
    ctx.shadowColor = colors.spring;
    ctx.shadowBlur = 10;
    ctx.fill();
    ctx.shadowBlur = 0;

    ctx.fillStyle = '#000';
    ctx.font = 'bold 14px Inter, sans-serif';
    ctx.textAlign = 'center';
    ctx.fillText(spr.m.toFixed(1) + ' kg', massX, oy + 5);

    // Displacement arrow
    if (Math.abs(x) > 0.02) {
      ctx.strokeStyle = '#f87171';
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.moveTo(ox, oy + 50);
      ctx.lineTo(massX, oy + 50);
      ctx.stroke();
      const dir = x > 0 ? 1 : -1;
      ctx.fillStyle = '#f87171';
      ctx.beginPath();
      ctx.moveTo(massX, oy + 50);
      ctx.lineTo(massX - dir * 8, oy + 44);
      ctx.lineTo(massX - dir * 8, oy + 56);
      ctx.closePath();
      ctx.fill();
      ctx.fillStyle = colors.text;
      ctx.font = '12px Inter, sans-serif';
      ctx.fillText('x = ' + x.toFixed(3) + ' m', (ox + massX) / 2, oy + 72);
    }

    // Displacement-time graph
    const graphX = 60;
    const graphY = H - 130;
    const graphW = W - 120;
    const graphH = 90;

    ctx.strokeStyle = colors.border;
    ctx.lineWidth = 1;
    ctx.strokeRect(graphX, graphY, graphW, graphH);
    ctx.strokeStyle = colors.axis;
    ctx.beginPath();
    ctx.moveTo(graphX, graphY + graphH / 2);
    ctx.lineTo(graphX + graphW, graphY + graphH / 2);
    ctx.stroke();

    ctx.fillStyle = colors.text;
    ctx.font = '10px Inter, sans-serif';
    ctx.textAlign = 'left';
    ctx.fillText('x(t)', graphX + 4, graphY + 14);

    if (spr.trail.length > 1) {
      const tMax = Math.max(spr.trail[spr.trail.length - 1].t, 5);
      const tMin = spr.trail[0].t;
      ctx.strokeStyle = colors.spring;
      ctx.lineWidth = 2;
      ctx.beginPath();
      spr.trail.forEach((p, i) => {
        const px = graphX + ((p.t - tMin) / (tMax - tMin)) * graphW;
        const py = graphY + graphH / 2 - (p.x / spr.x0) * (graphH / 2 - 8);
        i === 0 ? ctx.moveTo(px, py) : ctx.lineTo(px, py);
      });
      ctx.stroke();
    }

    // Labels
    ctx.fillStyle = colors.text;
    ctx.font = '12px Inter, sans-serif';
    ctx.textAlign = 'left';
    ctx.fillText('k = ' + spr.k + ' N/m', 20, 30);
    ctx.fillText('m = ' + spr.m.toFixed(1) + ' kg', 20, 48);
    ctx.fillText('\\u03C9 = ' + omega.toFixed(2) + ' rad/s', 20, 66);
    ctx.fillText('T = ' + (2 * Math.PI / omega).toFixed(2) + ' s', 20, 84);
  };

  const draw = () => {
    ctx.clearRect(0, 0, W, H);
    ctx.fillStyle = '#141720';
    ctx.fillRect(0, 0, W, H);

    if (activeSim === 'pendulum') drawPendulum();
    else if (activeSim === 'projectile') drawProjectile();
    else drawSpring();
  };

  // --- Readouts ---

  const updateReadouts = () => {
    const fmt = (n) => n.toFixed(2);
    const el = (id) => document.getElementById(id);
    if (!el('r-pos')) return;

    if (activeSim === 'pendulum') {
      const x = pend.L * Math.sin(pend.theta);
      const y = -pend.L * Math.cos(pend.theta);
      const v = pend.L * Math.abs(pend.omega);
      const a = pend.L * Math.abs(-pend.g / pend.L * Math.sin(pend.theta));
      const pe = pend.g * pend.L * (1 - Math.cos(pend.theta));
      const ke = 0.5 * pend.L * pend.L * pend.omega * pend.omega;
      el('r-pos').textContent = '(' + fmt(x) + ', ' + fmt(y) + ') m';
      el('r-vel').textContent = fmt(v) + ' m/s';
      el('r-acc').textContent = fmt(a) + ' m/s\\u00B2';
      el('r-energy').textContent = fmt(pe + ke) + ' J';
      el('r-time').textContent = fmt(pend.time) + ' s';
    } else if (activeSim === 'projectile') {
      const p = getProj(proj.time);
      const spd = Math.sqrt(p.vx * p.vx + p.vy * p.vy);
      const ke = 0.5 * spd * spd;
      const pe = proj.g * Math.max(0, p.y);
      el('r-pos').textContent = '(' + fmt(p.x) + ', ' + fmt(Math.max(0, p.y)) + ') m';
      el('r-vel').textContent = '(' + fmt(p.vx) + ', ' + fmt(p.vy) + ') m/s';
      el('r-acc').textContent = '(0, -' + fmt(proj.g) + ') m/s\\u00B2';
      el('r-energy').textContent = fmt(ke + pe) + ' J';
      el('r-time').textContent = fmt(proj.time) + ' s';
    } else {
      const omega = Math.sqrt(spr.k / spr.m);
      const x = spr.x0 * Math.cos(omega * spr.time);
      const v = -spr.x0 * omega * Math.sin(omega * spr.time);
      const a = -spr.x0 * omega * omega * Math.cos(omega * spr.time);
      const pe = 0.5 * spr.k * x * x;
      const ke = 0.5 * spr.m * v * v;
      el('r-pos').textContent = fmt(x) + ' m';
      el('r-vel').textContent = fmt(v) + ' m/s';
      el('r-acc').textContent = fmt(a) + ' m/s\\u00B2';
      el('r-energy').textContent = fmt(pe + ke) + ' J';
      el('r-time').textContent = fmt(spr.time) + ' s';
    }
  };

  // --- Animation loop ---

  const loop = (ts) => {
    if (!lastFrame) lastFrame = ts;
    const rawDt = (ts - lastFrame) / 1000;
    lastFrame = ts;

    if (playing) {
      const dt = Math.min(rawDt, 0.05) * speed;
      if (activeSim === 'pendulum') stepPend(dt);
      else if (activeSim === 'projectile') stepProj(dt);
      else stepSpr(dt);
    }

    draw();
    updateReadouts();
    requestAnimationFrame(loop);
  };

  requestAnimationFrame(loop);

  // --- Event handlers ---

  const switchTab = (sim) => {
    activeSim = sim;
    playing = false;
    document.getElementById('btn-play').textContent = 'Play';
    document.getElementById('btn-play').style.background = '${colors.green}';
    ['pendulum', 'projectile', 'spring'].forEach((s) => {
      const btn = document.getElementById('tab-' + s);
      if (s === sim) {
        btn.style.background = '${colors.accent}';
        btn.style.color = '#fff';
        btn.style.boxShadow = '0 2px 8px ${colors.accent}44';
      } else {
        btn.style.background = 'transparent';
        btn.style.color = '${colors.textDim}';
        btn.style.boxShadow = 'none';
      }
    });
    updateSliders();
  };

  const updateSliders = () => {
    const container = document.getElementById('params-container');
    const configs = {
      pendulum: [
        { id: 'pend-length', label: 'Length', min: 0.5, max: 5, step: 0.1, val: pend.L, unit: 'm' },
        { id: 'pend-gravity', label: 'Gravity', min: 1, max: 20, step: 0.1, val: pend.g, unit: 'm/s\\u00B2' },
        { id: 'pend-angle', label: 'Initial Angle', min: 5, max: 90, step: 1, val: pend.angle0, unit: '\\u00B0' },
      ],
      projectile: [
        { id: 'proj-angle', label: 'Launch Angle', min: 5, max: 85, step: 1, val: proj.angle, unit: '\\u00B0' },
        { id: 'proj-velocity', label: 'Initial Velocity', min: 5, max: 50, step: 1, val: proj.v0, unit: 'm/s' },
        { id: 'proj-gravity', label: 'Gravity', min: 1, max: 20, step: 0.1, val: proj.g, unit: 'm/s\\u00B2' },
      ],
      spring: [
        { id: 'spr-k', label: 'Spring Constant (k)', min: 1, max: 100, step: 1, val: spr.k, unit: 'N/m' },
        { id: 'spr-mass', label: 'Mass', min: 0.1, max: 10, step: 0.1, val: spr.m, unit: 'kg' },
        { id: 'spr-disp', label: 'Initial Displacement', min: 0.1, max: 2, step: 0.1, val: spr.x0, unit: 'm' },
      ],
    };
    const sliders = configs[activeSim];
    container.innerHTML = sliders.map((s) => {
      return '<div style="margin-bottom:14px">' +
        '<div style="display:flex;justify-content:space-between;font-size:13px;margin-bottom:6px">' +
        '<span style="color:${colors.textDim}">' + s.label + '</span>' +
        '<span style="color:${colors.accent};font-weight:600;font-family:JetBrains Mono,monospace" id="val-' + s.id + '">' + s.val + ' ' + s.unit + '</span></div>' +
        '<input type="range" id="' + s.id + '" min="' + s.min + '" max="' + s.max + '" step="' + s.step + '" value="' + s.val + '" ' +
        'style="width:100%;height:4px;border-radius:2px;-webkit-appearance:none;appearance:none;background:${colors.border};outline:none;cursor:pointer"></div>';
    }).join('');

    sliders.forEach((s) => {
      document.getElementById(s.id).addEventListener('input', (e) => {
        const v = parseFloat(e.target.value);
        document.getElementById('val-' + s.id).textContent = v + ' ' + s.unit;
        handleSlider(s.id, v);
      });
    });
  };

  const handleSlider = (id, v) => {
    switch (id) {
      case 'pend-length': pend.L = v; resetPendulum(); break;
      case 'pend-gravity': pend.g = v; resetPendulum(); break;
      case 'pend-angle': pend.angle0 = v; resetPendulum(); break;
      case 'proj-angle': proj.angle = v; resetProjectile(); break;
      case 'proj-velocity': proj.v0 = v; resetProjectile(); break;
      case 'proj-gravity': proj.g = v; resetProjectile(); break;
      case 'spr-k': spr.k = v; resetSpring(); break;
      case 'spr-mass': spr.m = v; resetSpring(); break;
      case 'spr-disp': spr.x0 = v; resetSpring(); break;
      case 'speed': speed = v; break;
    }
  };

  // Tab buttons
  document.getElementById('tab-pendulum').addEventListener('click', () => switchTab('pendulum'));
  document.getElementById('tab-projectile').addEventListener('click', () => switchTab('projectile'));
  document.getElementById('tab-spring').addEventListener('click', () => switchTab('spring'));

  // Play / pause
  document.getElementById('btn-play').addEventListener('click', () => {
    playing = !playing;
    const btn = document.getElementById('btn-play');
    btn.textContent = playing ? 'Pause' : 'Play';
    btn.style.background = playing ? '${colors.yellow}' : '${colors.green}';
    btn.style.color = '#000';
  });

  // Reset
  document.getElementById('btn-reset').addEventListener('click', () => {
    playing = false;
    document.getElementById('btn-play').textContent = 'Play';
    document.getElementById('btn-play').style.background = '${colors.green}';
    resetAll();
    lastFrame = 0;
  });

  // Speed slider
  document.getElementById('speed').addEventListener('input', (e) => {
    speed = parseFloat(e.target.value);
    document.getElementById('val-speed').textContent = speed + ' x';
  });

  // Initial draw
  resetAll();
  draw();
  updateReadouts();
})();
`

import { renderPage } from './render'
import type { SimulationConfig } from './types'

const DATA_PATH = './data/state.json'

const loadConfig = async (): Promise<SimulationConfig> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (exists) {
    const raw = await file.json()
    return { ...raw, playing: false }
  }
  return defaultConfig()
}

const saveConfig = async (config: SimulationConfig): Promise<void> => {
  const { playing, ...rest } = config
  await Bun.write(DATA_PATH, JSON.stringify(rest, null, 2))
}

const defaultConfig = (): SimulationConfig => ({
  activeSimulation: 'pendulum',
  speed: 1.0,
  playing: false,
  pendulum: {
    length: 2.0,
    gravity: 9.81,
    initialAngle: 30,
  },
  projectile: {
    angle: 45,
    initialVelocity: 20,
    gravity: 9.81,
  },
  spring: {
    springConstant: 10,
    mass: 1.0,
    initialDisplacement: 1.0,
  },
})

const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url)

    if (url.pathname === '/' || url.pathname === '/index.html') {
      const config = await loadConfig()
      const html = renderPage(config)
      return new Response(html, {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      })
    }

    if (url.pathname === '/api/config' && req.method === 'GET') {
      const config = await loadConfig()
      return Response.json(config)
    }

    if (url.pathname === '/api/config' && req.method === 'POST') {
      const body = await req.json() as Partial<SimulationConfig>
      const current = await loadConfig()
      const updated: SimulationConfig = { ...current, ...body }
      await saveConfig(updated)
      return Response.json({ ok: true })
    }

    return new Response('Not Found', { status: 404 })
  },
})

console.log(`Newton's Laws Simulator running at http://localhost:${server.port}`)
